from std.math import max, min

comptime MIN_COP: Float64 = 0.1
comptime MIN_PLR: Float64 = 1e-6
comptime MIN_EIR: Float64 = 0.1


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def absorption_df_cooling_batch(
    n: Int,
    cap_ref_ptr: Int,
    cop_cool_ref_ptr: Int,
    plr_ptr: Int,
    cap_ft_ptr: Int,
    eir_ft_ptr: Int,
    out_q_cool_ptr: Int,
    out_q_fuel_ptr: Int,
) -> None:
    """Cooling-only batch for N direct-fired absorption chillers.

    For each chiller i:
        plr_clamped = clamp(plr[i], 0, 1)
        if plr_clamped < MIN_PLR: q_cool = 0, q_fuel = 0
        else:
            q_cool[i] = cap_ref[i] * cap_ft[i] * plr_clamped
            q_fuel[i] = q_cool[i] / (max(MIN_COP, cop_cool_ref[i]) * max(MIN_EIR, eir_ft[i]))

    Arguments:
      - `n`               — number of chillers.
      - `cap_ref_ptr`     — float64[N] rated cooling capacity [W].
      - `cop_cool_ref_ptr`— float64[N] rated cooling COP at reference conditions.
      - `plr_ptr`         — float64[N] part-load ratio (input, clamped to [0, 1]).
      - `cap_ft_ptr`      — float64[N] capacity correction factor (f(T)).
      - `eir_ft_ptr`      — float64[N] EIR correction factor (f(T)), >= MIN_EIR.
      - `out_q_cool_ptr`  — float64[N] cooling output [W], written.
      - `out_q_fuel_ptr`  — float64[N] fuel input [W], written.

    Edge cases:
      - `n <= 0`          — no-op.
      - `plr < MIN_PLR`   — q_cool = 0, q_fuel = 0 (chiller off).
      - `cop_cool_ref`    — clamped to >= MIN_COP.
      - `eir_ft`          — clamped to >= MIN_EIR.
    """
    if n <= 0:
        return

    var cap_ref = _ptr(cap_ref_ptr)
    var cop_cool_ref = _ptr(cop_cool_ref_ptr)
    var plr = _ptr(plr_ptr)
    var cap_ft = _ptr(cap_ft_ptr)
    var eir_ft = _ptr(eir_ft_ptr)
    var out_q_cool = _ptr(out_q_cool_ptr)
    var out_q_fuel = _ptr(out_q_fuel_ptr)

    for i in range(n):
        var p = plr[i]
        # Clamp PLR to [0, 1]
        if p < 0.0:
            p = 0.0
        if p > 1.0:
            p = 1.0

        if p < MIN_PLR:
            out_q_cool[i] = 0.0
            out_q_fuel[i] = 0.0
            continue

        var q_cool = cap_ref[i] * cap_ft[i] * p
        var cop_safe = max(Float64(MIN_COP), cop_cool_ref[i])
        var eir_safe = max(Float64(MIN_EIR), eir_ft[i])
        out_q_cool[i] = q_cool
        out_q_fuel[i] = q_cool / (cop_safe * eir_safe)


@export
def absorption_df_heating_batch(
    n: Int,
    q_fuel_ptr: Int,
    cop_heat_ref_ptr: Int,
    plr_heat_ptr: Int,
    out_q_heat_ptr: Int,
) -> None:
    """Heat-recovery batch for N direct-fired absorption chillers.

    Heat recovery from exhaust/condenser side:
        plr_heat_clamped = clamp(plr_heat[i], 0, 1)
        q_heat[i] = q_fuel[i] * max(MIN_COP, cop_heat_ref[i]) * plr_heat_clamped

    Arguments:
      - `n`               — number of chillers.
      - `q_fuel_ptr`      — float64[N] fuel input [W] (from cooling step).
      - `cop_heat_ref_ptr`— float64[N] rated heating COP, >= MIN_COP.
      - `plr_heat_ptr`    — float64[N] heating part-load ratio (clamped to [0, 1]).
      - `out_q_heat_ptr`  — float64[N] heat output [W], written.

    Edge cases:
      - `n <= 0`          — no-op.
      - `cop_heat_ref`    — clamped to >= MIN_COP.
      - `plr_heat`        — clamped to [0, 1].
    """
    if n <= 0:
        return

    var q_fuel = _ptr(q_fuel_ptr)
    var cop_heat_ref = _ptr(cop_heat_ref_ptr)
    var plr_heat = _ptr(plr_heat_ptr)
    var out_q_heat = _ptr(out_q_heat_ptr)

    for i in range(n):
        var ph = plr_heat[i]
        if ph < 0.0:
            ph = 0.0
        if ph > 1.0:
            ph = 1.0
        var cop_h = max(Float64(MIN_COP), cop_heat_ref[i])
        out_q_heat[i] = q_fuel[i] * cop_h * ph


@export
def absorption_df_full_batch(
    n: Int,
    cap_ref_ptr: Int,
    cop_cool_ref_ptr: Int,
    cop_heat_ref_ptr: Int,
    plr_ptr: Int,
    plr_heat_ptr: Int,
    cap_ft_ptr: Int,
    eir_ft_ptr: Int,
    out_q_cool_ptr: Int,
    out_q_heat_ptr: Int,
    out_q_fuel_ptr: Int,
    out_q_cond_ptr: Int,
) -> None:
    """Full combined cooling + heating batch for N direct-fired absorption chillers.

    For each chiller i:
        plr_clamped = clamp(plr[i], 0, 1)
        if plr_clamped < MIN_PLR: q_cool = 0, q_fuel = 0
        else:
            q_cool[i] = cap_ref[i] * cap_ft[i] * plr_clamped
            q_fuel[i] = q_cool[i] / (max(MIN_COP, cop_cool_ref[i]) * max(MIN_EIR, eir_ft[i]))

        plr_heat_clamped = clamp(plr_heat[i], 0, 1)
        q_heat[i] = q_fuel[i] * max(MIN_COP, cop_heat_ref[i]) * plr_heat_clamped
        q_cond[i] = q_cool[i] + q_heat[i]

    Arguments:
      - `n`                — number of chillers.
      - `cap_ref_ptr`      — float64[N] rated cooling capacity [W].
      - `cop_cool_ref_ptr` — float64[N] rated cooling COP, >= MIN_COP.
      - `cop_heat_ref_ptr` — float64[N] rated heating COP, >= MIN_COP.
      - `plr_ptr`          — float64[N] cooling part-load ratio (clamped to [0, 1]).
      - `plr_heat_ptr`     — float64[N] heating part-load ratio (clamped to [0, 1]).
      - `cap_ft_ptr`       — float64[N] capacity correction factor (f(T)).
      - `eir_ft_ptr`       — float64[N] EIR correction factor (f(T)), >= MIN_EIR.
      - `out_q_cool_ptr`   — float64[N] cooling output [W], written.
      - `out_q_heat_ptr`   — float64[N] heat recovery output [W], written.
      - `out_q_fuel_ptr`   — float64[N] fuel input [W], written.
      - `out_q_cond_ptr`   — float64[N] total condenser heat rejected [W], written.

    Edge cases:
      - `n <= 0`           — no-op.
      - `plr < MIN_PLR`    — q_cool = 0, q_fuel = 0, q_heat = 0, q_cond = 0.
    """
    if n <= 0:
        return

    var cap_ref = _ptr(cap_ref_ptr)
    var cop_cool_ref = _ptr(cop_cool_ref_ptr)
    var cop_heat_ref = _ptr(cop_heat_ref_ptr)
    var plr = _ptr(plr_ptr)
    var plr_heat = _ptr(plr_heat_ptr)
    var cap_ft = _ptr(cap_ft_ptr)
    var eir_ft = _ptr(eir_ft_ptr)
    var out_q_cool = _ptr(out_q_cool_ptr)
    var out_q_heat = _ptr(out_q_heat_ptr)
    var out_q_fuel = _ptr(out_q_fuel_ptr)
    var out_q_cond = _ptr(out_q_cond_ptr)

    for i in range(n):
        # ── Cooling PLR ───────────────────────────────────────────────────────
        var p = plr[i]
        if p < 0.0:
            p = 0.0
        if p > 1.0:
            p = 1.0

        var q_cool: Float64
        var q_fuel: Float64
        if p < MIN_PLR:
            q_cool = 0.0
            q_fuel = 0.0
        else:
            q_cool = cap_ref[i] * cap_ft[i] * p
            var cop_safe = max(Float64(MIN_COP), cop_cool_ref[i])
            var eir_safe = max(Float64(MIN_EIR), eir_ft[i])
            q_fuel = q_cool / (cop_safe * eir_safe)

        out_q_cool[i] = q_cool
        out_q_fuel[i] = q_fuel

        # ── Heating PLR ───────────────────────────────────────────────────────
        var ph = plr_heat[i]
        if ph < 0.0:
            ph = 0.0
        if ph > 1.0:
            ph = 1.0
        var cop_h = max(Float64(MIN_COP), cop_heat_ref[i])
        var q_heat = q_fuel * cop_h * ph

        out_q_heat[i] = q_heat
        out_q_cond[i] = q_cool + q_heat

from std.math import exp


@export
def afn_duct_heat_loss_batch(
    n: Int,
    diameter_m_ptr: Int,
    length_m_ptr: Int,
    u_w_m2k_ptr: Int,
    m_dot_air_ptr: Int,
    cp_air_ptr: Int,
    t_air_in_c_ptr: Int,
    t_surround_c_ptr: Int,
    out_q_loss_w_ptr: Int,
    out_t_air_out_c_ptr: Int,
):
    """Per-segment effectiveness-NTU duct heat loss for N AFN duct records.

    Arguments:
      - `n`                    — number of duct segments.
      - `diameter_m_ptr`       — float64[n] hydraulic diameter (m).
      - `length_m_ptr`         — float64[n] segment length (m).
      - `u_w_m2k_ptr`          — float64[n] overall heat-transfer coefficient
                                  (W/m²K) referenced to the duct outer surface.
      - `m_dot_air_ptr`        — float64[n] air mass flow rate (kg/s).
      - `cp_air_ptr`           — float64[n] air specific heat (J/kg-K).
      - `t_air_in_c_ptr`       — float64[n] duct inlet air temperature (°C).
      - `t_surround_c_ptr`     — float64[n] surrounding-zone air temperature
                                  (°C); typically the attic.
      - `out_q_loss_w_ptr`     — float64[n] output heat-loss buffer (W),
                                  positive when air loses heat to surroundings.
      - `out_t_air_out_c_ptr`  — float64[n] output duct outlet temperature
                                  buffer (°C).

    No-op when `n <= 0`. When `m_dot_air[i] * cp_air[i] == 0`, the
    segment is degenerate: `q_loss = 0` and `T_out = T_in`.
    """
    if n <= 0:
        return

    var diameter = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=diameter_m_ptr
    )
    var length = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=length_m_ptr
    )
    var u_duct = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=u_w_m2k_ptr
    )
    var m_dot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_air_ptr
    )
    var cp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_air_ptr
    )
    var t_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_air_in_c_ptr
    )
    var t_surr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_surround_c_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_loss_w_ptr
    )
    var out_t = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_air_out_c_ptr
    )

    var pi = 3.141592653589793

    for i in range(n):
        var ti = t_in[i]
        var mc = m_dot[i] * cp[i]
        if mc == 0.0:
            # Degenerate: no flow / no heat capacity → no transfer.
            out_q[i] = 0.0
            out_t[i] = ti
            continue
        var ua = pi * diameter[i] * length[i] * u_duct[i]
        var ntu = ua / mc
        var eps = 1.0 - exp(-ntu)
        var q = eps * mc * (ti - t_surr[i])
        out_q[i] = q
        out_t[i] = ti - q / mc

from std.math import log, exp


# ---- helpers ---------------------------------------------------------------


@always_inline
def _ptrf(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _ptri(addr: Int) -> UnsafePointer[Int64, MutAnyOrigin]:
    return UnsafePointer[Int64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _abs(x: Float64) -> Float64:
    return x if x >= 0.0 else -x


# Python `_DP_REG_PA` — ΔP below this magnitude falls into the linearised
# regime where the analytic power-law derivative `n·|dp|^(n-1)` would
# diverge for `n < 1`.
comptime _DP_REG_PA: Float64 = 1.0e-4
comptime _GRAVITY: Float64 = 9.80665


@always_inline
def _powf(base: Float64, expn: Float64) -> Float64:
    # `base ** expn` for base > 0 (we only call it with `_abs(dp) > 0`).
    return exp(expn * log(base))


# ---- in-place Gaussian elimination with partial pivoting -------------------
# Mirrors `network_solver._gauss_solve`. `a` is row-major n×n, augmented
# in-place with `b` as the (n+1)-th column would be — but here we keep
# `b` separate and apply row swaps / eliminations to both. Result lands
# in `b`.


def _gauss_solve(
    a: UnsafePointer[Float64, MutAnyOrigin],
    b: UnsafePointer[Float64, MutAnyOrigin],
    n: Int,
):
    for k in range(n):
        var pivot = k
        var pivot_val = _abs(a[k * n + k])
        for i in range(k + 1, n):
            var v = _abs(a[i * n + k])
            if v > pivot_val:
                pivot = i
                pivot_val = v
        if pivot != k:
            for j in range(n):
                var t = a[k * n + j]
                a[k * n + j] = a[pivot * n + j]
                a[pivot * n + j] = t
            var tb = b[k]
            b[k] = b[pivot]
            b[pivot] = tb
        var akk = a[k * n + k]
        if akk == 0.0:
            continue
        for i in range(k + 1, n):
            var factor = a[i * n + k] / akk
            if factor == 0.0:
                continue
            for j in range(k, n):
                a[i * n + j] -= factor * a[k * n + j]
            b[i] -= factor * b[k]

    var k = n - 1
    while k >= 0:
        var s = b[k]
        for i in range(k + 1, n):
            s -= a[k * n + i] * b[i]
        b[k] = s / a[k * n + k]
        k -= 1


# ---- per-link power-law flow & derivative (Python-reference parity) --------


@always_inline
def _link_flow(c: Float64, expn: Float64, dp: Float64) -> Float64:
    """Python `FlowComponent.mass_flow(dp)`.

    Linearised regime uses the TANGENT slope at `|dp| == _DP_REG_PA`:
        slope = C · n · _DP_REG_PA^(n-1)
        m = slope · dp
    Non-linear regime uses the analytic `sign(dp) · C · |dp|^n`.
    """
    var ap = _abs(dp)
    if ap < _DP_REG_PA:
        var slope = c * expn * _powf(_DP_REG_PA, expn - 1.0)
        return slope * dp
    var pow_term = _powf(ap, expn)
    if dp > 0.0:
        return c * pow_term
    return -c * pow_term


@always_inline
def _link_deriv(c: Float64, expn: Float64, dp: Float64) -> Float64:
    """Python `FlowComponent.derivative(dp)`: `C · n · max(|dp|, _DP_REG_PA)^(n-1)`.
    """
    var ap = _abs(dp)
    if ap < _DP_REG_PA:
        ap = _DP_REG_PA
    return c * expn * _powf(ap, expn - 1.0)


# ---- public entry point ----------------------------------------------------


@export
def afn_pressure_flow_solve(
    n_int: Int,
    n_link: Int,
    p_int_addr: Int,
    jac_addr: Int,
    residual_addr: Int,
    link_from_addr: Int,
    link_to_addr: Int,
    link_c_addr: Int,
    link_n_addr: Int,
    link_height_delta_m_addr: Int,
    link_p_fixed_from_addr: Int,
    link_p_fixed_to_addr: Int,
    m_dot_addr: Int,
    zone_net_addr: Int,
    air_density_kg_m3: Float64,
    max_iter: Int,
    abs_tol: Float64,
    rel_tol: Float64,
    step_clip_pa: Float64,
) -> Int:
    """Newton-Raphson pressure-flow solve, parity with Python
    `network_solver.solve_pressure_flow`.

    Inputs:
      - `p_int_addr`               float64[n_int]  in/out — initial guess /
                                                   converged interior pressures.
      - `jac_addr`                 float64[n_int*n_int] scratch (row-major).
      - `residual_addr`            float64[n_int]  scratch.
      - `link_from_addr`,
        `link_to_addr`             int64[n_link]   node indices; `-1` = fixed
                                                   boundary (reads
                                                   `link_p_fixed_*`).
      - `link_c_addr`              float64[n_link] power-law coefficients.
      - `link_n_addr`              float64[n_link] power-law exponents.
      - `link_height_delta_m_addr` float64[n_link] elevation of `to` minus
                                                   `from` for stack/buoyancy.
      - `link_p_fixed_from_addr`,
        `link_p_fixed_to_addr`     float64[n_link] used per-link when the
                                                   matching endpoint is fixed.
      - `m_dot_addr`               float64[n_link] OUT — per-link mass flow
                                                   at the converged solution
                                                   (positive from→to).
      - `zone_net_addr`            float64[n_int]  OUT — net mass flow INTO
                                                   each interior node summed
                                                   over its incident links.
      - `air_density_kg_m3`        float64         used for the
                                                   `ρ·g·ΔZ` buoyancy term.
      - `max_iter`, `abs_tol`,
        `rel_tol`, `step_clip_pa`  Newton stopping / safety knobs (match the
                                                   Python defaults: 100,
                                                   1e-8 kg/s, 1e-6, 50 Pa).

    Return value: encoded iteration count:
      - >=  0 — Newton converged after that many iterations
                (0 means n_int == 0, evaluated boundary-only flows).
      - <   0 — failed to converge in `max_iter` steps. The absolute
                value is the iteration count actually executed (which
                will be `max_iter`). The interior pressures and m_dot
                are still written with the best-effort iterate, matching
                the Python `converged=False` return.
    """
    var p_int = _ptrf(p_int_addr)
    var jac = _ptrf(jac_addr)
    var res = _ptrf(residual_addr)
    var lfrom = _ptri(link_from_addr)
    var lto = _ptri(link_to_addr)
    var lc = _ptrf(link_c_addr)
    var ln = _ptrf(link_n_addr)
    var lh = _ptrf(link_height_delta_m_addr)
    var lpf = _ptrf(link_p_fixed_from_addr)
    var lpt = _ptrf(link_p_fixed_to_addr)
    var m_dot = _ptrf(m_dot_addr)
    var z_net = _ptrf(zone_net_addr)

    var buoy_const = air_density_kg_m3 * _GRAVITY

    # --- n_int == 0 fast path: evaluate boundary-driven flows once and exit.
    if n_int <= 0:
        for k in range(n_link):
            var fk = Int(lfrom[k])
            var tk = Int(lto[k])
            var pf = lpf[k] if fk < 0 else 0.0
            var pt = lpt[k] if tk < 0 else 0.0
            var dp = pf - pt - buoy_const * lh[k]
            m_dot[k] = _link_flow(lc[k], ln[k], dp)
        return 0

    var nn = n_int * n_int
    var converged = False
    var iters_used: Int = 0

    for it in range(max_iter):
        iters_used = it + 1

        # Zero scratch.
        for i in range(nn):
            jac[i] = 0.0
        for i in range(n_int):
            res[i] = 0.0

        # Assemble residual + dense Jacobian.
        #
        # Python convention (matched exactly):
        #   residual_i  = sum of m_dot leaving node i.
        #   m_dot       = sign(dp) · C · |dp|^n.
        #   For each link i_from -> i_to:
        #     residual[i_from] += m_dot
        #     residual[i_to]   -= m_dot
        #     jac[i_from][i_from] += dm_ddp
        #     jac[i_from][i_to]   -= dm_ddp     (if i_to interior)
        #     jac[i_to][i_to]     += dm_ddp
        #     jac[i_to][i_from]   -= dm_ddp     (if i_from interior)
        for k in range(n_link):
            var fk = Int(lfrom[k])
            var tk = Int(lto[k])
            var pf: Float64 = 0.0
            if fk >= 0:
                pf = p_int[fk]
            else:
                pf = lpf[k]
            var pt: Float64 = 0.0
            if tk >= 0:
                pt = p_int[tk]
            else:
                pt = lpt[k]
            var dp = pf - pt - buoy_const * lh[k]
            var mdot = _link_flow(lc[k], ln[k], dp)
            var dm_ddp = _link_deriv(lc[k], ln[k], dp)

            if fk >= 0:
                res[fk] += mdot
                jac[fk * n_int + fk] += dm_ddp
                if tk >= 0:
                    jac[fk * n_int + tk] -= dm_ddp
            if tk >= 0:
                res[tk] -= mdot
                jac[tk * n_int + tk] += dm_ddp
                if fk >= 0:
                    jac[tk * n_int + fk] -= dm_ddp

        # L∞ residual norm; absolute-tolerance exit.
        var res_inf: Float64 = 0.0
        for i in range(n_int):
            var a = _abs(res[i])
            if a > res_inf:
                res_inf = a
        if res_inf < abs_tol:
            converged = True
            break

        # Solve  J · delta = -residual.  Flip sign of `res` in place;
        # `_gauss_solve` overwrites it with `delta`.
        for i in range(n_int):
            res[i] = -res[i]
        _gauss_solve(jac, res, n_int)

        # Step-clip on L∞ norm of delta (Python parity: 50 Pa default).
        var max_abs_delta: Float64 = 0.0
        for i in range(n_int):
            var a = _abs(res[i])
            if a > max_abs_delta:
                max_abs_delta = a
        if max_abs_delta > step_clip_pa:
            var scale = step_clip_pa / max_abs_delta
            for i in range(n_int):
                res[i] *= scale
            max_abs_delta = step_clip_pa

        # Apply Newton update.
        for i in range(n_int):
            p_int[i] += res[i]

        # Relative-change exit (Python parity): only when the residual is
        # already small (< 1e-3 kg/s) so we don't bail before the residual
        # actually settles.
        var denom: Float64 = 1.0
        for i in range(n_int):
            var ap = _abs(p_int[i])
            if ap > denom:
                denom = ap
        if max_abs_delta / denom < rel_tol and res_inf < 1.0e-3:
            converged = True
            break

    # --- Final evaluation pass: compute m_dot at the (converged or best-
    # effort) pressure vector and accumulate the per-zone net inflow ledger.
    # Mirrors `_finalise_solution` in the Python reference.
    for i in range(n_int):
        z_net[i] = 0.0
    for k in range(n_link):
        var fk = Int(lfrom[k])
        var tk = Int(lto[k])
        var pf: Float64 = 0.0
        if fk >= 0:
            pf = p_int[fk]
        else:
            pf = lpf[k]
        var pt: Float64 = 0.0
        if tk >= 0:
            pt = p_int[tk]
        else:
            pt = lpt[k]
        var dp = pf - pt - buoy_const * lh[k]
        var mdot = _link_flow(lc[k], ln[k], dp)
        m_dot[k] = mdot
        # Net mass flow INTO interior endpoints (positive = entering).
        if fk >= 0:
            z_net[fk] -= mdot
        if tk >= 0:
            z_net[tk] += mdot

    if converged:
        return iters_used
    return -iters_used

comptime CP_AIR: Float64 = 1006.0
# Latent heat of vaporisation of water at ~25 °C [J/kg]
comptime H_FG: Float64 = 2.45e6
# Minimum allowable mass flow rate to avoid divide-by-zero [kg/s]
comptime MIN_MDOT: Float64 = 1e-9
# Minimum allowable supply humidity ratio [kg_w/kg_da]
comptime MIN_W: Float64 = 0.0
# Maximum allowable supply humidity ratio [kg_w/kg_da]
comptime MAX_W: Float64 = 0.05


@export
def ahr_sensible_batch(
    n: Int,
    t_supply_in_ptr: Int,
    t_exhaust_in_ptr: Int,
    m_dot_supply_ptr: Int,
    m_dot_exhaust_ptr: Int,
    eps_s_ptr: Int,
    out_t_supply_out_ptr: Int,
    out_q_sensible_ptr: Int,
) -> None:
    """Effectiveness-NTU sensible heat recovery for N air-to-air HX records.

    For each record i:

        C_supply   = max(m_dot_supply[i], MIN_MDOT) * CP_AIR
        C_exhaust  = max(m_dot_exhaust[i], MIN_MDOT) * CP_AIR
        C_min      = min(C_supply, C_exhaust)
        Q_max      = C_min * (T_exhaust_in[i] - T_supply_in[i])

        If Q_max <= 0: Q_sensible = 0, T_supply_out = T_supply_in
        Else:
            eps_s_clamped  = clamp(eps_s[i], 0, 1)
            Q_sensible     = eps_s_clamped * Q_max
            T_supply_out   = T_supply_in[i] + Q_sensible / C_supply

    Parameters
    ----------
    n                  : number of HX records
    t_supply_in_ptr    : Float64[n]  supply-side inlet dry-bulb temperature (°C)
    t_exhaust_in_ptr   : Float64[n]  exhaust-side inlet dry-bulb temperature (°C)
    m_dot_supply_ptr   : Float64[n]  supply-side mass flow rate (kg/s)
    m_dot_exhaust_ptr  : Float64[n]  exhaust-side mass flow rate (kg/s)
    eps_s_ptr          : Float64[n]  sensible effectiveness (dimensionless, [0, 1])
    out_t_supply_out_ptr: Float64[n] supply outlet temperature (°C)  [output]
    out_q_sensible_ptr : Float64[n]  sensible heat recovered (W)     [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var t_supply_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_supply_in_ptr
    )
    var t_exhaust_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_exhaust_in_ptr
    )
    var m_dot_supply = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_supply_ptr
    )
    var m_dot_exhaust = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_exhaust_ptr
    )
    var eps_s = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eps_s_ptr
    )
    var out_t_supply_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_supply_out_ptr
    )
    var out_q_sensible = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_sensible_ptr
    )

    for i in range(n):
        # Clamp mass flow rates to avoid divide-by-zero
        var mds = m_dot_supply[i]
        if mds < MIN_MDOT:
            mds = MIN_MDOT
        var mde = m_dot_exhaust[i]
        if mde < MIN_MDOT:
            mde = MIN_MDOT

        var c_supply = mds * CP_AIR
        var c_exhaust = mde * CP_AIR

        var c_min = c_supply if c_supply < c_exhaust else c_exhaust

        var q_max = c_min * (t_exhaust_in[i] - t_supply_in[i])

        if q_max <= 0.0:
            out_t_supply_out[i] = t_supply_in[i]
            out_q_sensible[i] = 0.0
        else:
            # Clamp effectiveness to [0, 1]
            var eps = eps_s[i]
            if eps < 0.0:
                eps = 0.0
            if eps > 1.0:
                eps = 1.0

            var q_sensible = eps * q_max
            out_t_supply_out[i] = t_supply_in[i] + q_sensible / c_supply
            out_q_sensible[i] = q_sensible


@export
def ahr_latent_batch(
    n: Int,
    w_supply_in_ptr: Int,
    w_exhaust_in_ptr: Int,
    m_dot_supply_ptr: Int,
    eps_l_ptr: Int,
    out_w_supply_out_ptr: Int,
    out_q_latent_ptr: Int,
) -> None:
    """Latent (moisture) energy recovery for N air-to-air HX records.

    For each record i:

        eps_l_clamped   = clamp(eps_l[i], 0, 1)
        W_supply_out    = W_supply_in[i] + eps_l_clamped * (W_exhaust_in[i] - W_supply_in[i])
        W_supply_out    = clamp(W_supply_out, MIN_W, MAX_W)
        Q_latent        = max(m_dot_supply[i], MIN_MDOT) * H_FG
                          * (W_supply_out - W_supply_in[i])

    Parameters
    ----------
    n                   : number of HX records
    w_supply_in_ptr     : Float64[n]  supply-side inlet humidity ratio (kg_w/kg_da)
    w_exhaust_in_ptr    : Float64[n]  exhaust-side inlet humidity ratio (kg_w/kg_da)
    m_dot_supply_ptr    : Float64[n]  supply-side mass flow rate (kg/s)
    eps_l_ptr           : Float64[n]  latent effectiveness (dimensionless, [0, 1])
    out_w_supply_out_ptr: Float64[n]  supply outlet humidity ratio (kg_w/kg_da) [output]
    out_q_latent_ptr    : Float64[n]  latent heat recovered (W)                 [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var w_supply_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_supply_in_ptr
    )
    var w_exhaust_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_exhaust_in_ptr
    )
    var m_dot_supply = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_supply_ptr
    )
    var eps_l = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eps_l_ptr
    )
    var out_w_supply_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_w_supply_out_ptr
    )
    var out_q_latent = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_latent_ptr
    )

    for i in range(n):
        # Clamp latent effectiveness to [0, 1]
        var eps = eps_l[i]
        if eps < 0.0:
            eps = 0.0
        if eps > 1.0:
            eps = 1.0

        var w_in = w_supply_in[i]
        var w_out = w_in + eps * (w_exhaust_in[i] - w_in)

        # Clamp outlet humidity ratio to physical bounds
        if w_out < MIN_W:
            w_out = MIN_W
        if w_out > MAX_W:
            w_out = MAX_W

        # Clamp mass flow rate to avoid degenerate result
        var mds = m_dot_supply[i]
        if mds < MIN_MDOT:
            mds = MIN_MDOT

        var q_latent = mds * H_FG * (w_out - w_in)

        out_w_supply_out[i] = w_out
        out_q_latent[i] = q_latent

@export
def availability_manager_eval_batch(
    n: Int,
    main_schedule_ptr: Int,
    t_zone_ptr: Int,
    t_setpoint_ptr: Int,
    tolerance_ptr: Int,
    out_available_ptr: Int,
) -> None:
    """Evaluate AvailabilityManager:NightCycle for `n` zone-timesteps.

    Arguments:
      - `n`                  — number of (zone × timestep) records.
      - `main_schedule_ptr`  — Float64[n] availability schedule value;
                                > 0 forces the fan on regardless of T.
      - `t_zone_ptr`         — Float64[n] zone air temperature (°C).
      - `t_setpoint_ptr`     — Float64[n] night-cycle setpoint (°C).
      - `tolerance_ptr`      — Float64[n] half-band tolerance (K).
      - `out_available_ptr`  — Float64[n] output buffer; receives 1.0
                                when the fan is available, 0.0 otherwise.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var main_schedule = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=main_schedule_ptr
    )
    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var t_setpoint = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_setpoint_ptr
    )
    var tolerance = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=tolerance_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_available_ptr
    )

    for i in range(n):
        var sched = main_schedule[i]
        var tz = t_zone[i]
        var tsp = t_setpoint[i]
        var tol = tolerance[i]
        var available = (sched > 0.0) or (tz < tsp - tol) or (tz > tsp + tol)
        out[i] = 1.0 if available else 0.0

from std.math import max, min

comptime SOC_MIN_DEFAULT: Float64 = 0.2
comptime SOC_MAX_DEFAULT: Float64 = 0.9
comptime ETA_MIN: Float64 = 0.5
comptime ETA_MAX: Float64 = 1.0
comptime P_MAX_W: Float64 = 1.0e8
comptime CAP_MIN_WH: Float64 = 1.0e-3


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def battery_soc_step_batch(
    n: Int,
    soc_ptr: Int,
    p_request_ptr: Int,
    capacity_wh_ptr: Int,
    eta_charge_ptr: Int,
    eta_discharge_ptr: Int,
    soc_min_ptr: Int,
    soc_max_ptr: Int,
    dt_h: Float64,
    out_soc_new_ptr: Int,
    out_p_actual_ptr: Int,
) -> None:
    """Advance N independent batteries one timestep (explicit Euler SOC).

    Each input/output buffer is a raw int64 address of a Float64[N] array
    (typically NumPy ``__array_interface__["data"][0]``). No-op when n <= 0.

    Per-cell semantics:
      - p_request > 0 → charging; p_request < 0 → discharging.
      - p_request is clamped to [-P_MAX_W, P_MAX_W].
      - eta_charge / eta_discharge are clamped to [ETA_MIN, ETA_MAX].
      - Available charge power:     p_avail_c =  (soc_max - soc) * cap / dt_h
      - Available discharge power:  p_avail_d = -(soc - soc_min) * cap / dt_h
      - p_actual = clamp(p_request, p_avail_d, p_avail_c)
      - delta_soc = (p_actual * eta_c * dt_h) / cap   when p_actual > 0
      - delta_soc = (p_actual / eta_d * dt_h) / cap   when p_actual < 0
      - soc_new = clamp(soc + delta_soc, soc_min, soc_max)
      - Guard: capacity_wh < 1e-3 → out_soc_new = soc, out_p_actual = 0
    """
    if n <= 0:
        return

    var soc = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=soc_ptr)
    var p_req = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=p_request_ptr
    )
    var cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=capacity_wh_ptr
    )
    var eta_c = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eta_charge_ptr
    )
    var eta_d = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eta_discharge_ptr
    )
    var soc_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=soc_min_ptr
    )
    var soc_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=soc_max_ptr
    )
    var out_soc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_soc_new_ptr
    )
    var out_p = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_p_actual_ptr
    )

    for i in range(n):
        var cap_i = cap[i]

        # Guard: degenerate battery
        if cap_i < CAP_MIN_WH:
            out_soc[i] = soc[i]
            out_p[i] = 0.0
            continue

        var soc_i = soc[i]
        var smin_i = soc_lo[i]
        var smax_i = soc_hi[i]

        # Clamp efficiencies
        var ec_i = eta_c[i]
        if ec_i < ETA_MIN:
            ec_i = ETA_MIN
        if ec_i > ETA_MAX:
            ec_i = ETA_MAX

        var ed_i = eta_d[i]
        if ed_i < ETA_MIN:
            ed_i = ETA_MIN
        if ed_i > ETA_MAX:
            ed_i = ETA_MAX

        # Clamp power request
        var pr_i = p_req[i]
        if pr_i < -P_MAX_W:
            pr_i = -P_MAX_W
        if pr_i > P_MAX_W:
            pr_i = P_MAX_W

        # Available charge / discharge power limits
        var p_avail_c = (smax_i - soc_i) * cap_i / dt_h
        var p_avail_d = -(soc_i - smin_i) * cap_i / dt_h

        # Clamp p_avail_c to be non-negative, p_avail_d to be non-positive
        if p_avail_c < 0.0:
            p_avail_c = 0.0
        if p_avail_d > 0.0:
            p_avail_d = 0.0

        # Actual power: clamp request between discharge limit (negative) and charge limit (positive)
        var p_act = pr_i
        if p_act < p_avail_d:
            p_act = p_avail_d
        if p_act > p_avail_c:
            p_act = p_avail_c

        # SOC update
        var delta_soc: Float64 = 0.0
        if p_act > 0.0:
            delta_soc = (p_act * ec_i * dt_h) / cap_i
        elif p_act < 0.0:
            delta_soc = (p_act / ed_i * dt_h) / cap_i

        var soc_new = soc_i + delta_soc
        if soc_new < smin_i:
            soc_new = smin_i
        if soc_new > smax_i:
            soc_new = smax_i

        out_soc[i] = soc_new
        out_p[i] = p_act


@export
def battery_round_trip_efficiency_batch(
    n: Int,
    eta_charge_ptr: Int,
    eta_discharge_ptr: Int,
    out_rte_ptr: Int,
) -> None:
    """Round-trip efficiency for N batteries.

    rte[i] = clamp(eta_charge[i], ETA_MIN, ETA_MAX)
           * clamp(eta_discharge[i], ETA_MIN, ETA_MAX)

    Output is clamped to [0, 1].
    """
    if n <= 0:
        return

    var eta_c = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eta_charge_ptr
    )
    var eta_d = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eta_discharge_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_rte_ptr
    )

    for i in range(n):
        var ec_i = eta_c[i]
        if ec_i < ETA_MIN:
            ec_i = ETA_MIN
        if ec_i > ETA_MAX:
            ec_i = ETA_MAX

        var ed_i = eta_d[i]
        if ed_i < ETA_MIN:
            ed_i = ETA_MIN
        if ed_i > ETA_MAX:
            ed_i = ETA_MAX

        var rte = ec_i * ed_i
        if rte < 0.0:
            rte = 0.0
        if rte > 1.0:
            rte = 1.0
        out[i] = rte

@always_inline
def _clamp_nonneg(x: Float64) -> Float64:
    return x if x > 0.0 else 0.0


@always_inline
def _min2(a: Float64, b: Float64) -> Float64:
    return a if a < b else b


@export
def battery_step_batch(
    n: Int,
    capacity_j_ptr: Int,
    soc_j_ptr: Int,
    surplus_w_ptr: Int,
    deficit_w_ptr: Int,
    dt_s_ptr: Int,
    charge_eff_ptr: Int,
    discharge_eff_ptr: Int,
    max_charge_w_ptr: Int,
    max_discharge_w_ptr: Int,
    soc_min_frac_ptr: Int,
    soc_max_frac_ptr: Int,
    out_soc_j_ptr: Int,
    out_charge_w_ptr: Int,
    out_discharge_w_ptr: Int,
) -> None:
    """Advance N independent simple-storage batteries one timestep.

    Each input/output buffer is a raw int64 address of a Float64[N] array
    (typically NumPy `__array_interface__["data"][0]`). No-op when `n <= 0`.

    Per-cell semantics:
      - soc_max = capacity_j * soc_max_frac
      - soc_min = capacity_j * soc_min_frac
      - charge:    p_in  = clamp(surplus_w, 0, max_charge_w);
                   added = min(p_in * charge_eff * dt, soc_max - soc);
                   out_charge_w = (added / charge_eff) / dt  (≥0; 0 if eff==0)
      - discharge: p_out = clamp(deficit_w, 0, max_discharge_w);
                   removed = min((p_out / discharge_eff) * dt, soc - soc_min);
                   out_discharge_w = (removed * discharge_eff) / dt
                                                          (≥0; 0 if eff==0)
      - out_soc_j = soc + added - removed
    """
    if n <= 0:
        return

    var capacity = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=capacity_j_ptr
    )
    var soc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=soc_j_ptr
    )
    var surplus = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=surplus_w_ptr
    )
    var deficit = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=deficit_w_ptr
    )
    var dt = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=dt_s_ptr)
    var ceff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=charge_eff_ptr
    )
    var deff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=discharge_eff_ptr
    )
    var pc_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=max_charge_w_ptr
    )
    var pd_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=max_discharge_w_ptr
    )
    var smin = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=soc_min_frac_ptr
    )
    var smax = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=soc_max_frac_ptr
    )
    var out_soc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_soc_j_ptr
    )
    var out_pc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_charge_w_ptr
    )
    var out_pd = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_discharge_w_ptr
    )

    for i in range(n):
        var cap_i = capacity[i]
        var soc_i = soc[i]
        var dt_i = dt[i]
        var ce_i = ceff[i]
        var de_i = deff[i]
        var pcmax_i = pc_max[i]
        var pdmax_i = pd_max[i]
        var soc_lo = cap_i * smin[i]
        var soc_hi = cap_i * smax[i]

        # ---- charge leg --------------------------------------------------
        var p_in = _clamp_nonneg(surplus[i])
        if p_in > pcmax_i:
            p_in = pcmax_i
        # Energy actually added to the battery, after charge efficiency,
        # capped by remaining headroom to soc_hi.
        var added_j = p_in * ce_i * dt_i
        var head = soc_hi - soc_i
        if head < 0.0:
            head = 0.0
        if added_j > head:
            added_j = head
        # Back out the electrical power that produced this energy. If
        # ce_i == 0 we can't charge, regardless of input.
        var pc_out: Float64 = 0.0
        if ce_i > 0.0 and dt_i > 0.0:
            pc_out = (added_j / ce_i) / dt_i
        else:
            added_j = 0.0

        var soc_after_charge = soc_i + added_j

        # ---- discharge leg ----------------------------------------------
        var p_out = _clamp_nonneg(deficit[i])
        if p_out > pdmax_i:
            p_out = pdmax_i
        # Energy that must leave the battery to satisfy that electrical
        # output, after discharge efficiency, capped by SOC above the
        # floor.
        var removed_j: Float64 = 0.0
        var pd_out: Float64 = 0.0
        if de_i > 0.0 and dt_i > 0.0:
            removed_j = (p_out / de_i) * dt_i
            var avail = soc_after_charge - soc_lo
            if avail < 0.0:
                avail = 0.0
            if removed_j > avail:
                removed_j = avail
            pd_out = (removed_j * de_i) / dt_i

        out_soc[i] = soc_after_charge - removed_j
        out_pc[i] = pc_out
        out_pd[i] = pd_out

comptime PLR_OPT: Float64 = 0.7
# Parabolic efficiency penalty coefficient
comptime EFF_BONUS_COEF: Float64 = 0.1
# Maximum allowable per-unit PLR (slightly above 1 to allow overload)
comptime PLR_MAX: Float64 = 1.05
# Minimum acceptable system COP (guard against divide-by-very-small-power)
comptime COP_SYS_MIN: Float64 = 0.1


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def chiller_active_count_batch(
    n: Int,
    total_load_w_ptr: Int,
    cap_per_chiller_w_ptr: Int,
    n_total_ptr: Int,
    out_n_active_ptr: Int,
) -> None:
    """Compute the optimal number of active chillers for N plant-loop instances.

    For each instance:

        n_act = Int(total_load_w / (cap_per_chiller_w * PLR_OPT))
        n_act clamped to [1, n_total]
        out_n_active = Float64(n_act)

    Parameters
    ----------
    n                  : number of plant-loop instances
    total_load_w_ptr   : Float64[n]  total cooling load (W)
    cap_per_chiller_w_ptr : Float64[n]  per-chiller capacity (W)
    n_total_ptr        : Float64[n]  total number of chillers available
    out_n_active_ptr   : Float64[n]  optimal active chiller count  [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var total_load = _ptr(total_load_w_ptr)
    var cap = _ptr(cap_per_chiller_w_ptr)
    var n_total = _ptr(n_total_ptr)
    var out_n_active = _ptr(out_n_active_ptr)

    for i in range(n):
        var denom = cap[i] * PLR_OPT
        if denom < 1e-3:
            denom = 1e-3
        var n_act = Int(total_load[i] / denom)
        if n_act < 1:
            n_act = 1
        var nt = Int(n_total[i])
        if n_act > nt:
            n_act = nt
        out_n_active[i] = Float64(n_act)


@export
def chiller_per_unit_plr_batch(
    n: Int,
    total_load_w_ptr: Int,
    cap_per_chiller_w_ptr: Int,
    n_active_ptr: Int,
    out_load_each_ptr: Int,
    out_plr_ptr: Int,
) -> None:
    """Compute per-chiller load and PLR for N plant-loop instances.

    For each instance:

        load_each = total_load_w / max(1, Int(n_active))
        plr       = load_each / max(1e-3, cap_per_chiller_w)
        plr clamped to [0, PLR_MAX]

    Parameters
    ----------
    n                     : number of plant-loop instances
    total_load_w_ptr      : Float64[n]  total cooling load (W)
    cap_per_chiller_w_ptr : Float64[n]  per-chiller capacity (W)
    n_active_ptr          : Float64[n]  number of active chillers
    out_load_each_ptr     : Float64[n]  per-chiller load (W)          [output]
    out_plr_ptr           : Float64[n]  per-chiller PLR (dimensionless) [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var total_load = _ptr(total_load_w_ptr)
    var cap = _ptr(cap_per_chiller_w_ptr)
    var n_active = _ptr(n_active_ptr)
    var out_load_each = _ptr(out_load_each_ptr)
    var out_plr = _ptr(out_plr_ptr)

    for i in range(n):
        var n_act = Int(n_active[i])
        if n_act < 1:
            n_act = 1
        var load_each = total_load[i] / Float64(n_act)

        var cap_i = cap[i]
        if cap_i < 1e-3:
            cap_i = 1e-3
        var plr = load_each / cap_i

        if plr < 0.0:
            plr = 0.0
        if plr > PLR_MAX:
            plr = PLR_MAX

        out_load_each[i] = load_each
        out_plr[i] = plr


@export
def chiller_staging_efficiency_batch(
    n: Int,
    plr_ptr: Int,
    cop_rated_ptr: Int,
    out_eff_bonus_ptr: Int,
    out_cop_actual_ptr: Int,
) -> None:
    """Compute staging efficiency bonus and actual COP for N chillers.

    For each chiller:

        eff_bonus  = 1.0 - (plr - PLR_OPT)^2 * EFF_BONUS_COEF
        cop_actual = cop_rated * eff_bonus   (unconstrained)

    Parameters
    ----------
    n                  : number of chiller instances
    plr_ptr            : Float64[n]  part-load ratio (dimensionless)
    cop_rated_ptr      : Float64[n]  rated COP at full load
    out_eff_bonus_ptr  : Float64[n]  staging efficiency bonus        [output]
    out_cop_actual_ptr : Float64[n]  actual COP after staging penalty [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var plr = _ptr(plr_ptr)
    var cop_rated = _ptr(cop_rated_ptr)
    var out_eff_bonus = _ptr(out_eff_bonus_ptr)
    var out_cop_actual = _ptr(out_cop_actual_ptr)

    for i in range(n):
        var dp = plr[i] - PLR_OPT
        var eff_bonus = 1.0 - dp * dp * EFF_BONUS_COEF
        out_eff_bonus[i] = eff_bonus
        out_cop_actual[i] = cop_rated[i] * eff_bonus


@export
def chiller_staging_full_batch(
    n: Int,
    total_load_w_ptr: Int,
    cap_per_chiller_w_ptr: Int,
    n_total_ptr: Int,
    cop_rated_ptr: Int,
    out_n_active_ptr: Int,
    out_plr_ptr: Int,
    out_cop_sys_ptr: Int,
    out_w_total_ptr: Int,
) -> None:
    """Full multi-chiller staging step for N plant-loop instances.

    For each instance:

        n_act     = Int(total_load / max(1e-3, cap * PLR_OPT))
                    clamped to [1, n_total]
        load_each = total_load / max(1, n_act)
        plr       = load_each / max(1e-3, cap)   clamped to [0, PLR_MAX]
        eff_bonus = 1.0 - (plr - PLR_OPT)^2 * EFF_BONUS_COEF
        w_lead    = load_each / max(0.1, cop_rated * eff_bonus)
        w_total   = n_act * w_lead
        cop_sys   = total_load / max(1e-6, w_total)

    Parameters
    ----------
    n                     : number of plant-loop instances
    total_load_w_ptr      : Float64[n]  total cooling load (W)
    cap_per_chiller_w_ptr : Float64[n]  per-chiller capacity (W)
    n_total_ptr           : Float64[n]  total chillers available
    cop_rated_ptr         : Float64[n]  rated COP of each chiller
    out_n_active_ptr      : Float64[n]  optimal active chiller count   [output]
    out_plr_ptr           : Float64[n]  per-unit PLR                   [output]
    out_cop_sys_ptr       : Float64[n]  system COP                     [output]
    out_w_total_ptr       : Float64[n]  total plant power (W)          [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var total_load = _ptr(total_load_w_ptr)
    var cap = _ptr(cap_per_chiller_w_ptr)
    var n_total = _ptr(n_total_ptr)
    var cop_rated = _ptr(cop_rated_ptr)
    var out_n_active = _ptr(out_n_active_ptr)
    var out_plr = _ptr(out_plr_ptr)
    var out_cop_sys = _ptr(out_cop_sys_ptr)
    var out_w_total = _ptr(out_w_total_ptr)

    for i in range(n):
        var load = total_load[i]
        var cap_i = cap[i]

        # --- Optimal active chiller count ---
        var denom = cap_i * PLR_OPT
        if denom < 1e-3:
            denom = 1e-3
        var n_act = Int(load / denom)
        if n_act < 1:
            n_act = 1
        var nt = Int(n_total[i])
        if n_act > nt:
            n_act = nt

        # --- Per-unit load and PLR ---
        var load_each = load / Float64(n_act)

        var cap_safe = cap_i
        if cap_safe < 1e-3:
            cap_safe = 1e-3
        var plr = load_each / cap_safe
        if plr < 0.0:
            plr = 0.0
        if plr > PLR_MAX:
            plr = PLR_MAX

        # --- Efficiency bonus (parabolic around PLR_OPT) ---
        var dp = plr - PLR_OPT
        var eff_bonus = 1.0 - dp * dp * EFF_BONUS_COEF

        # --- Lead chiller power ---
        var cop_eff = cop_rated[i] * eff_bonus
        if cop_eff < 0.1:
            cop_eff = 0.1
        var w_lead = load_each / cop_eff

        # --- Total plant power and system COP ---
        var w_total = Float64(n_act) * w_lead
        var w_safe = w_total
        if w_safe < 1e-6:
            w_safe = 1e-6
        var cop_sys = load / w_safe

        # Write outputs
        out_n_active[i] = Float64(n_act)
        out_plr[i] = plr
        out_cop_sys[i] = cop_sys
        out_w_total[i] = w_total

from std.math import exp

comptime ONE: Float64 = 1.0
comptime ZERO: Float64 = 0.0
# Tolerance for the balanced C_r ≈ 1 branch (same value as heating coil).
comptime CR_BALANCED_TOL: Float64 = 1.0e-12


@always_inline
def _max(a: Float64, b: Float64) -> Float64:
    return a if a > b else b


@always_inline
def _min(a: Float64, b: Float64) -> Float64:
    return a if a < b else b


@always_inline
def _abs(a: Float64) -> Float64:
    return a if a >= ZERO else -a


@export
def coil_cooling_water_eps_ntu_batch(
    n_coils: Int,
    m_dot_air_ptr: Int,
    m_dot_water_ptr: Int,
    cp_air_ptr: Int,
    cp_water_ptr: Int,
    ua_w_per_k_ptr: Int,
    t_air_in_c_ptr: Int,
    t_water_in_c_ptr: Int,
    shr_ptr: Int,
    out_q_sens_w_ptr: Int,
    out_q_total_w_ptr: Int,
    out_t_air_out_c_ptr: Int,
    out_t_water_out_c_ptr: Int,
):
    """Evaluate N counter-flow chilled-water cooling coils via ε-NTU.

    Writes sensible cooling (W), total cooling (W, = q_sens/SHR), and
    outlet air / water temperatures (°C) into the four output buffers.
    All quantities are positive when the coil is actively cooling.

    No-op when `n_coils == 0`.
    """
    if n_coils <= 0:
        return

    var m_dot_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_air_ptr
    )
    var m_dot_water = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_water_ptr
    )
    var cp_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_air_ptr
    )
    var cp_water = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_water_ptr
    )
    var ua = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=ua_w_per_k_ptr
    )
    var t_air_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_air_in_c_ptr
    )
    var t_water_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_water_in_c_ptr
    )
    var shr = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=shr_ptr)
    var out_q_sens = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_sens_w_ptr
    )
    var out_q_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_total_w_ptr
    )
    var out_t_air_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_air_out_c_ptr
    )
    var out_t_water_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_water_out_c_ptr
    )

    for i in range(n_coils):
        var mda = m_dot_air[i]
        var mdw = m_dot_water[i]
        var cpa = cp_air[i]
        var cpw = cp_water[i]
        var ua_i = ua[i]
        var tai = t_air_in[i]
        var twi = t_water_in[i]
        var shr_i = shr[i]

        # Degenerate inputs or no driving temperature difference → no cooling.
        if (
            mda <= ZERO
            or mdw <= ZERO
            or cpa <= ZERO
            or cpw <= ZERO
            or ua_i <= ZERO
            or tai <= twi
        ):
            out_q_sens[i] = ZERO
            out_q_total[i] = ZERO
            out_t_air_out[i] = tai
            out_t_water_out[i] = twi
            continue

        var c_air = mda * cpa
        var c_water = mdw * cpw
        var c_min = _min(c_air, c_water)
        var c_max = _max(c_air, c_water)
        var c_r = c_min / c_max
        var ntu = ua_i / c_min

        var eps: Float64
        if _abs(ONE - c_r) < CR_BALANCED_TOL:
            # Balanced counter-flow: ε = NTU / (1 + NTU).
            eps = ntu / (ONE + ntu)
        else:
            var e = exp(-ntu * (ONE - c_r))
            eps = (ONE - e) / (ONE - c_r * e)

        # Sensible heat removed from air [W, positive = cooling].
        var q_sens = eps * c_min * (tai - twi)
        if q_sens < ZERO:
            q_sens = ZERO

        # Clamp SHR to (0, 1] so division is safe and physics-consistent.
        var shr_clamped = shr_i
        if shr_clamped <= ZERO:
            shr_clamped = ONE
        if shr_clamped > ONE:
            shr_clamped = ONE

        # Total heat removed (sensible + latent): q_total = q_sens / SHR.
        var q_total = q_sens / shr_clamped

        out_q_sens[i] = q_sens
        out_q_total[i] = q_total

        # Air outlet cools by q_sens / C_air (sensible only on air side).
        out_t_air_out[i] = tai - q_sens / c_air

        # Water outlet warms by q_total / C_water (total heat absorbed by water).
        out_t_water_out[i] = twi + q_total / c_water

from std.math import exp


# ---------------------------------------------------------------------------
# Compile-time constants
# ---------------------------------------------------------------------------

comptime ONE: Float64 = 1.0
comptime ZERO: Float64 = 0.0
# Minimum PLF clamp — prevents divide-by-zero in part-load power calculation.
comptime PLF_MIN: Float64 = 1.0e-6


# ---------------------------------------------------------------------------
# Inline helpers
# ---------------------------------------------------------------------------


@always_inline
def _biquadratic(
    coeffs: UnsafePointer[Float64, MutAnyOrigin],
    base: Int,
    x: Float64,
    y: Float64,
) -> Float64:
    """Evaluate bi-quadratic f(x,y) using 6 coefficients at `coeffs[base:]`.

    f(x, y) = c0 + c1·x + c2·x² + c3·y + c4·y² + c5·x·y
    """
    var c0 = coeffs[base + 0]
    var c1 = coeffs[base + 1]
    var c2 = coeffs[base + 2]
    var c3 = coeffs[base + 3]
    var c4 = coeffs[base + 4]
    var c5 = coeffs[base + 5]
    return c0 + c1 * x + c2 * x * x + c3 * y + c4 * y * y + c5 * x * y


@always_inline
def _quadratic(
    coeffs: UnsafePointer[Float64, MutAnyOrigin],
    base: Int,
    z: Float64,
) -> Float64:
    """Evaluate quadratic f(z) using 3 coefficients at `coeffs[base:]`.

    f(z) = c0 + c1·z + c2·z²
    """
    var c0 = coeffs[base + 0]
    var c1 = coeffs[base + 1]
    var c2 = coeffs[base + 2]
    return c0 + c1 * z + c2 * z * z


@always_inline
def _max(a: Float64, b: Float64) -> Float64:
    return a if a > b else b


@always_inline
def _min(a: Float64, b: Float64) -> Float64:
    return a if a < b else b


