@export
def coil_dx_heating_single_speed_batch(
    n_coils: Int,
    rated_cap_w_ptr: Int,
    rated_cop_ptr: Int,
    t_indoor_db_ptr: Int,
    t_outdoor_db_ptr: Int,
    flow_fraction_ptr: Int,
    plr_ptr: Int,
    cap_coeffs_ptr: Int,
    eir_coeffs_ptr: Int,
    capff_coeffs_ptr: Int,
    eirff_coeffs_ptr: Int,
    plf_coeffs_ptr: Int,
    out_heating_cap_w_ptr: Int,
    out_heating_power_w_ptr: Int,
) -> None:
    """Evaluate N single-speed DX *heating* coils in one FFI round trip.

    For each coil i the kernel evaluates the full EnergyPlus
    ``CalcDXHeatingCoil`` biquadratic/quadratic performance chain:

        CapFT   = biquad(cap_coeffs[i],   t_indoor_db, t_outdoor_db)
        EIRFT   = biquad(eir_coeffs[i],   t_indoor_db, t_outdoor_db)
        CapFF   = quad  (capff_coeffs[i], flow_fraction)
        EIRFF   = quad  (eirff_coeffs[i], flow_fraction)
        PLF     = quad  (plf_coeffs[i],   plr)          [clamped ≥ PLF_MIN]

        heating_cap_w[i]   = rated_cap[i] · CapFT · CapFF        [≥ 0]
        heating_power_w[i] = heating_cap_w[i] · EIRFT · EIRFF
                             / (rated_cop[i] · PLF)

    Coefficient buffers are packed:
      - `cap_coeffs_ptr`   / `eir_coeffs_ptr`   — Float64[n*6], biquadratic
      - `capff_coeffs_ptr` / `eirff_coeffs_ptr` / `plf_coeffs_ptr`
                                                 — Float64[n*3], quadratic

    Guard conditions (per coil):
      - `rated_cap ≤ 0`  → `cap_w = power_w = 0.0`
      - `rated_cop ≤ 0`  → `power_w = 0.0` (capacity still written)
      - `CapFT < 0`      → clamped to 0 (negative capacity unphysical)
      - `PLF < PLF_MIN`  → clamped to `PLF_MIN` (prevents Inf power)

    No-op when `n_coils == 0`.
    """
    if n_coils <= 0:
        return

    var rated_cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_cap_w_ptr
    )
    var rated_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_cop_ptr
    )
    var t_indoor_db = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_indoor_db_ptr
    )
    var t_outdoor_db = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_db_ptr
    )
    var flow_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=flow_fraction_ptr
    )
    var plr = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=plr_ptr)
    var cap_coeffs = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_coeffs_ptr
    )
    var eir_coeffs = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eir_coeffs_ptr
    )
    var capff_coeffs = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=capff_coeffs_ptr
    )
    var eirff_coeffs = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eirff_coeffs_ptr
    )
    var plf_coeffs = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=plf_coeffs_ptr
    )
    var out_cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_heating_cap_w_ptr
    )
    var out_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_heating_power_w_ptr
    )

    for i in range(n_coils):
        var cap_rated = rated_cap[i]
        var cop_rated = rated_cop[i]

        # Degenerate: zero or negative rated capacity → no output.
        if cap_rated <= ZERO:
            out_cap[i] = ZERO
            out_power[i] = ZERO
            continue

        var tdb_in = t_indoor_db[i]
        var tdb_out = t_outdoor_db[i]
        var ff = flow_frac[i]
        var plr_i = plr[i]

        # CapFT: capacity correction for temperature (biquadratic).
        var cap_ft = _biquadratic(cap_coeffs, i * 6, tdb_in, tdb_out)
        # Clamp negative CapFT — a coefficient set with a bad extrapolation
        # region should not produce negative capacity.
        if cap_ft < ZERO:
            cap_ft = ZERO

        # EIRFT: EIR (= 1/COP) correction for temperature (biquadratic).
        var eir_ft = _biquadratic(eir_coeffs, i * 6, tdb_in, tdb_out)
        # Negative EIRFT → effectively infinite COP; clamp to avoid sign flip.
        if eir_ft < ZERO:
            eir_ft = ZERO

        # CapFF / EIRFF: flow-fraction corrections (quadratic in ff).
        var cap_ff = _quadratic(capff_coeffs, i * 3, ff)
        var eir_ff = _quadratic(eirff_coeffs, i * 3, ff)
        # Flow-fraction modifiers can go slightly negative on extrapolation;
        # clamp to zero — zero modifier implies zero output at that condition.
        if cap_ff < ZERO:
            cap_ff = ZERO
        if eir_ff < ZERO:
            eir_ff = ZERO

        # PLF: part-load fraction curve (quadratic in PLR).
        # PLF ≥ 1 physically (compressor cycling degrades COP); values < 1
        # are a data error — let the user know by still producing a result
        # rather than NaN, but clamp so we don't divide by near-zero.
        var plf = _quadratic(plf_coeffs, i * 3, plr_i)
        if plf < PLF_MIN:
            plf = PLF_MIN

        # Gross heating capacity [W].
        var cap_w = cap_rated * cap_ft * cap_ff
        out_cap[i] = cap_w

        # Electrical power [W] = cap × EIR_total / PLF.
        # rated EIR = 1 / rated_cop.
        if cop_rated <= ZERO:
            out_power[i] = ZERO
        else:
            var eir_total = (ONE / cop_rated) * eir_ft * eir_ff
            out_power[i] = cap_w * eir_total / plf

comptime ONE: Float64 = 1.0


@always_inline
def _max(a: Float64, b: Float64) -> Float64:
    return a if a > b else b


@always_inline
def _min(a: Float64, b: Float64) -> Float64:
    return a if a < b else b


@export
def coil_dx_single_speed_capacity_batch(
    n_coils: Int,
    gross_rated_total_w_ptr: Int,
    gross_rated_shr_ptr: Int,
    gross_rated_cop_ptr: Int,
    rated_air_flow_m3s_ptr: Int,
    t_inlet_db_ptr: Int,
    w_inlet_ptr: Int,
    t_condenser_ptr: Int,
    actual_flow_m3s_ptr: Int,
    out_total_cap_w_ptr: Int,
    out_sensible_cap_w_ptr: Int,
    out_power_w_ptr: Int,
):
    """Evaluate N DX single-speed coils in one FFI round trip.

    For each coil i:
      total_cap  = rated_total[i] * cap_ft * cap_ff
      sens_cap   = total_cap * rated_shr[i]      (capped at total_cap)
      eir        = (1 / rated_cop[i]) * eir_ft * eir_ff
      power      = total_cap * eir

    In v1 `cap_ft = eir_ft = 1.0` (no temperature dependence) and the
    airflow-fraction modifier `cap_ff = eir_ff = 1.0` (no flow-fraction
    dependence). The inputs `t_inlet_db`, `w_inlet`, `t_condenser`,
    `actual_flow_m3s` are accepted for ABI stability — once curves are
    introduced in v2 they become the curve arguments. They are still
    read so the call site can wire up real buffers today.

    No-op when `n_coils == 0`. Division by `rated_cop` happens only after
    a positive check (Python wrapper rejects ≤ 0 up-front; we guard here
    too for defence in depth — a zero COP yields zero power rather than
    NaN/Inf).
    """
    if n_coils <= 0:
        return

    var rated_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=gross_rated_total_w_ptr
    )
    var rated_shr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=gross_rated_shr_ptr
    )
    var rated_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=gross_rated_cop_ptr
    )
    var rated_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_air_flow_m3s_ptr
    )
    var t_db = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_inlet_db_ptr
    )
    var w_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_inlet_ptr
    )
    var t_cond = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_condenser_ptr
    )
    var actual_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=actual_flow_m3s_ptr
    )
    var out_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_total_cap_w_ptr
    )
    var out_sens = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_sensible_cap_w_ptr
    )
    var out_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_w_ptr
    )

    for i in range(n_coils):
        # Touch the curve inputs so v2 wiring is exercised end-to-end.
        # Sum-into-_unused is folded away by the optimizer.
        var _unused = t_db[i] + w_in[i] + t_cond[i] + actual_flow[i]

        # v1 performance curves: cap_ft = eir_ft = cap_ff = eir_ff = 1.0.
        var cap_ft: Float64 = ONE
        var eir_ft: Float64 = ONE
        var cap_ff: Float64 = ONE
        var eir_ff: Float64 = ONE

        var total_cap = rated_total[i] * cap_ft * cap_ff
        # Clamp negative rated values to 0 — upstream surfaces these as
        # errors before sizing; here we degrade gracefully.
        if total_cap < 0.0:
            total_cap = 0.0
        out_total[i] = total_cap

        var shr = rated_shr[i]
        if shr < 0.0:
            shr = 0.0
        if shr > ONE:
            shr = ONE
        out_sens[i] = _min(total_cap * shr, total_cap)

        var cop = rated_cop[i]
        if cop <= 0.0:
            out_power[i] = 0.0
        else:
            var eir = (ONE / cop) * eir_ft * eir_ff
            out_power[i] = total_cap * eir

        # Silence the unused-touch.
        _ = rated_flow[i]
        _ = _unused

@always_inline
def _biquadratic(
    coeffs: UnsafePointer[Float64, MutAnyOrigin],
    base: Int,
    x: Float64,
    y: Float64,
) -> Float64:
    # 6 coeffs starting at `base`: c0 + c1·x + c2·x² + c3·y + c4·y² + c5·x·y.
    var c0 = coeffs[base + 0]
    var c1 = coeffs[base + 1]
    var c2 = coeffs[base + 2]
    var c3 = coeffs[base + 3]
    var c4 = coeffs[base + 4]
    var c5 = coeffs[base + 5]
    return c0 + c1 * x + c2 * x * x + c3 * y + c4 * y * y + c5 * x * y


@export
def coil_dx_two_stage_batch(
    n_coils: Int,
    t_wb_in_c_ptr: Int,
    t_db_out_c_ptr: Int,
    ffraction_ptr: Int,
    plr_ptr: Int,
    rated_q_w_stage1_ptr: Int,
    rated_q_w_stage2_ptr: Int,
    rated_eir_stage1_ptr: Int,
    rated_eir_stage2_ptr: Int,
    stage1_coeffs_ptr: Int,
    stage2_coeffs_ptr: Int,
    out_q_total_w_ptr: Int,
    out_eir_ptr: Int,
):
    """Evaluate N two-stage DX humidity-control coils in one FFI round trip.

    For each coil i:

        q_k     = rated_q_k[i]   · biquad(stageK_coeffs[i], t_wb, t_db) · ff
        q_total = (1 − plr)·q_1 + plr·q_2
        eir     = (1 − plr)·rated_eir_1 + plr·rated_eir_2

    PLR is clamped to `[0, 1]` so callers can't drag the blend outside the
    convex hull of the two stages by accident. `q_total` is clamped at 0 from
    below — a pathological negative coefficient set would otherwise emit a
    negative capacity which is physically meaningless.

    No-op when `n_coils == 0`.
    """
    if n_coils <= 0:
        return

    var t_wb = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_wb_in_c_ptr
    )
    var t_db = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_db_out_c_ptr
    )
    var ff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=ffraction_ptr
    )
    var plr = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=plr_ptr)
    var rq1 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_q_w_stage1_ptr
    )
    var rq2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_q_w_stage2_ptr
    )
    var re1 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_eir_stage1_ptr
    )
    var re2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_eir_stage2_ptr
    )
    var c1 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=stage1_coeffs_ptr
    )
    var c2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=stage2_coeffs_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_total_w_ptr
    )
    var out_eir = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_eir_ptr
    )

    for i in range(n_coils):
        var x = t_wb[i]
        var y = t_db[i]
        var f = ff[i]
        var w = plr[i]
        if w < 0.0:
            w = 0.0
        if w > 1.0:
            w = 1.0

        var capft1 = _biquadratic(c1, i * 6, x, y)
        var capft2 = _biquadratic(c2, i * 6, x, y)

        var q1 = rq1[i] * capft1 * f
        var q2 = rq2[i] * capft2 * f
        var q_total = (1.0 - w) * q1 + w * q2
        if q_total < 0.0:
            q_total = 0.0
        out_q[i] = q_total
        out_eir[i] = (1.0 - w) * re1[i] + w * re2[i]

@always_inline
def _clamp_f64(v: Float64, lo: Float64, hi: Float64) -> Float64:
    if v < lo:
        return lo
    if v > hi:
        return hi
    return v


@always_inline
def _max_f64(a: Float64, b: Float64) -> Float64:
    return a if a > b else b


@export
def dx_vs_speed_fraction_batch(
    n: Int,
    plr_ptr: Int,
    speed_max_ptr: Int,
    out_speed_frac_ptr: Int,
    out_speed_idx_ptr: Int,
):
    """Compute effective speed fraction and integer speed index for N coils.

    For each coil i:
        speed_frac = PLR[i] * speed_max[i], clamped to [0, speed_max[i]]
        speed_idx  = floor(speed_frac), clamped to [0, speed_max[i]-1]
        out_speed_idx stores the result as Float64 (integer cast).

    speed_max is stored as Float64 (per repo convention) but cast to Int
    internally before use. No-op when n == 0.
    """
    if n <= 0:
        return

    var plr = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=plr_ptr)
    var speed_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_max_ptr
    )
    var out_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_speed_frac_ptr
    )
    var out_idx = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_speed_idx_ptr
    )

    for i in range(n):
        var sm = speed_max[i]
        # Guard: speed_max must be at least 1
        if sm < 1.0:
            sm = 1.0
        var sf = plr[i] * sm
        # Clamp speed_frac to [0, speed_max]
        sf = _clamp_f64(sf, 0.0, sm)
        # Floor via modulo (sf is non-negative)
        var sf_floor = sf - (sf % 1.0)
        var idx_f = sf_floor
        # Clamp index to [0, speed_max-1]
        var idx_max = sm - 1.0
        if idx_max < 0.0:
            idx_max = 0.0
        idx_f = _clamp_f64(idx_f, 0.0, idx_max)
        out_frac[i] = sf
        out_idx[i] = idx_f


@export
def dx_vs_capacity_batch(
    n: Int,
    cap_rated_ptr: Int,
    speed_frac_ptr: Int,
    speed_max_ptr: Int,
    cap_ft_ptr: Int,
    cap_ff_ptr: Int,
    out_cap_ptr: Int,
):
    """Compute variable-speed corrected capacity for N coils.

    For each coil i:
        cap = cap_rated[i] * (speed_frac[i] / speed_max[i]) * cap_ft[i] * cap_ff[i]

    Capacity scales linearly with speed fraction. All factors and cap are
    guarded: negative results are clamped to zero.
    No-op when n == 0.
    """
    if n <= 0:
        return

    var cap_rated = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_rated_ptr
    )
    var speed_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_frac_ptr
    )
    var speed_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_max_ptr
    )
    var cap_ft = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_ft_ptr
    )
    var cap_ff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_ff_ptr
    )
    var out_cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cap_ptr
    )

    for i in range(n):
        var sm = speed_max[i]
        if sm < 1.0:
            sm = 1.0
        var sf = speed_frac[i]
        if sf < 0.0:
            sf = 0.0
        var ft = cap_ft[i]
        if ft < 0.0:
            ft = 0.0
        var ff = cap_ff[i]
        if ff < 0.0:
            ff = 0.0
        var cap = cap_rated[i] * (sf / sm) * ft * ff
        if cap < 0.0:
            cap = 0.0
        out_cap[i] = cap


@export
def dx_vs_cop_batch(
    n: Int,
    cop_rated_ptr: Int,
    speed_frac_ptr: Int,
    speed_max_ptr: Int,
    cop_ft_ptr: Int,
    cop_ff_ptr: Int,
    cop_plr_a_ptr: Int,
    cop_plr_b_ptr: Int,
    out_cop_ptr: Int,
):
    """Compute variable-speed COP with PLR and correction factors for N coils.

    For each coil i:
        plr     = speed_frac[i] / max(1e-6, speed_max[i])
        cop_plr = cop_plr_a[i] + cop_plr_b[i] * plr      (linear PLR correction)
        cop     = cop_rated[i] * cop_ft[i] * cop_ff[i] * cop_plr
        cop     clamped to [0.5, 8.0]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var cop_rated = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_rated_ptr
    )
    var speed_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_frac_ptr
    )
    var speed_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_max_ptr
    )
    var cop_ft = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_ft_ptr
    )
    var cop_ff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_ff_ptr
    )
    var cop_plr_a = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_plr_a_ptr
    )
    var cop_plr_b = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_plr_b_ptr
    )
    var out_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_ptr
    )

    for i in range(n):
        var sm = _max_f64(1.0e-6, speed_max[i])
        var sf = speed_frac[i]
        if sf < 0.0:
            sf = 0.0
        var plr = sf / sm
        var cop_plr_val = cop_plr_a[i] + cop_plr_b[i] * plr
        var cop = cop_rated[i] * cop_ft[i] * cop_ff[i] * cop_plr_val
        # Clamp COP to physically reasonable bounds [0.5, 8.0]
        cop = _clamp_f64(cop, 0.5, 8.0)
        out_cop[i] = cop


@export
def dx_vs_sensible_heat_ratio_batch(
    n: Int,
    shr_rated_ptr: Int,
    cap_ft_ptr: Int,
    wb_correction_ptr: Int,
    out_shr_ptr: Int,
):
    """Compute corrected sensible heat ratio for N variable-speed coils.

    For each coil i:
        shr = shr_rated[i] * cap_ft[i] * wb_correction[i]
        shr clamped to [0.5, 1.0]

    wb_correction accounts for the wet-bulb temperature dependence of the
    latent-to-total capacity split.
    No-op when n == 0.
    """
    if n <= 0:
        return

    var shr_rated = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=shr_rated_ptr
    )
    var cap_ft = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_ft_ptr
    )
    var wb_correction = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wb_correction_ptr
    )
    var out_shr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_shr_ptr
    )

    for i in range(n):
        var shr = shr_rated[i] * cap_ft[i] * wb_correction[i]
        # SHR is a fraction bounded by [0.5, 1.0]
        shr = _clamp_f64(shr, 0.5, 1.0)
        out_shr[i] = shr

from std.math import exp

comptime ONE: Float64 = 1.0
comptime ZERO: Float64 = 0.0
# Tolerance for the C_r ≈ 1 balanced branch. 1e-12 is well inside Float64
# precision but loose enough to absorb the rounding C_min / C_max picks up
# when C_air and C_water are equal modulo a few ULPs.
comptime CR_BALANCED_TOL: Float64 = 1.0e-12


@always_inline
def _max(a: Float64, b: Float64) -> Float64:
    return a if a > b else b


@always_inline
def _min(a: Float64, b: Float64) -> Float64:
    return a if a < b else b


@always_inline
def _abs(a: Float64) -> Float64:
    return a if a >= 0.0 else -a


@export
def coil_heating_water_eps_ntu_batch(
    n_coils: Int,
    m_dot_air_ptr: Int,
    m_dot_water_ptr: Int,
    cp_air_ptr: Int,
    cp_water_ptr: Int,
    ua_w_per_k_ptr: Int,
    t_air_in_c_ptr: Int,
    t_water_in_c_ptr: Int,
    out_q_w_ptr: Int,
    out_t_air_out_c_ptr: Int,
    out_t_water_out_c_ptr: Int,
):
    """Evaluate N counter-flow water-air heating coils via ε-NTU.

    Writes heating capacity (W, positive when water > air) and outlet
    air / water temperatures (°C) into the three output buffers.

    No-op when `n_coils == 0`.
    """
    if n_coils <= 0:
        return

    var m_dot_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_air_ptr
    )
    var m_dot_water = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_water_ptr
    )
    var cp_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_air_ptr
    )
    var cp_water = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_water_ptr
    )
    var ua = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=ua_w_per_k_ptr
    )
    var t_air_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_air_in_c_ptr
    )
    var t_water_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_water_in_c_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_w_ptr
    )
    var out_t_air_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_air_out_c_ptr
    )
    var out_t_water_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_water_out_c_ptr
    )

    for i in range(n_coils):
        var mda = m_dot_air[i]
        var mdw = m_dot_water[i]
        var cpa = cp_air[i]
        var cpw = cp_water[i]
        var ua_i = ua[i]
        var tai = t_air_in[i]
        var twi = t_water_in[i]

        # Degenerate inputs ⇒ no heat transfer. Outlets equal inlets so
        # downstream node math sees a passthrough rather than NaN/Inf.
        if mda <= 0.0 or mdw <= 0.0 or cpa <= 0.0 or cpw <= 0.0 or ua_i <= 0.0:
            out_q[i] = 0.0
            out_t_air_out[i] = tai
            out_t_water_out[i] = twi
            continue

        var c_air = mda * cpa
        var c_water = mdw * cpw
        var c_min = _min(c_air, c_water)
        var c_max = _max(c_air, c_water)
        var c_r = c_min / c_max
        var ntu = ua_i / c_min

        var eps: Float64
        if _abs(ONE - c_r) < CR_BALANCED_TOL:
            # Balanced counter-flow branch: ε = NTU / (1 + NTU).
            eps = ntu / (ONE + ntu)
        else:
            var e = exp(-ntu * (ONE - c_r))
            eps = (ONE - e) / (ONE - c_r * e)

        var q = eps * c_min * (twi - tai)
        out_q[i] = q
        out_t_air_out[i] = tai + q / c_air
        out_t_water_out[i] = twi - q / c_water

from std.math import exp, max, min

# Decay constant for the CLF exponential rise for occupants [1/h]
comptime CLF_PEOPLE_DECAY: Float64 = 0.5
# Decay constant for the CLF exponential rise for lights [1/h]
comptime CLF_LIGHTS_DECAY: Float64 = 0.6
# Minimum CLF output (clamped lower bound)
comptime CLF_MIN: Float64 = 0.0
# Maximum CLF output (clamped upper bound)
comptime CLF_MAX: Float64 = 1.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def clf_people_batch(
    n: Int,
    hours_ptr: Int,
    out_clf_ptr: Int,
) -> None:
    """Sensible Cooling Load Factor for N zones based on hours since occupant entry.

    The CLF represents the fraction of sensible heat gain from occupants that
    becomes an instantaneous cooling load, modelled as an exponential rise
    toward unity as the room thermal mass charges up:

        CLF[i] = clamp(1 - exp(-CLF_PEOPLE_DECAY * hours_since_entry[i]),
                       CLF_MIN, CLF_MAX)

    where CLF_PEOPLE_DECAY = 0.5 [1/h].

    At t=0 (occupants just entered) CLF=0; as time → ∞ CLF → 1.

    Parameters
    ----------
    n           : number of zones
    hours_ptr   : Float64[n]  hours since occupant entry (h), non-negative
    out_clf_ptr : Float64[n]  Cooling Load Factor in [0, 1]  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var hours = _ptr(hours_ptr)
    var out = _ptr(out_clf_ptr)

    for i in range(n):
        var clf = 1.0 - exp(-CLF_PEOPLE_DECAY * hours[i])
        if clf < CLF_MIN:
            clf = CLF_MIN
        elif clf > CLF_MAX:
            clf = CLF_MAX
        out[i] = clf


@export
def clf_lights_batch(
    n: Int,
    t_on_ptr: Int,
    out_clf_ptr: Int,
) -> None:
    """Cooling Load Factor for N zones based on hours lights have been on.

    The CLF represents the fraction of heat gain from lighting that becomes an
    instantaneous cooling load, modelled as an exponential rise toward unity:

        CLF[i] = clamp(1 - exp(-CLF_LIGHTS_DECAY * t_on[i]),
                       CLF_MIN, CLF_MAX)

    where CLF_LIGHTS_DECAY = 0.6 [1/h].

    At t_on=0 (lights just switched on) CLF=0; as time → ∞ CLF → 1.

    Parameters
    ----------
    n           : number of zones
    t_on_ptr    : Float64[n]  hours the lights have been on (h), non-negative
    out_clf_ptr : Float64[n]  Cooling Load Factor in [0, 1]  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var t_on = _ptr(t_on_ptr)
    var out = _ptr(out_clf_ptr)

    for i in range(n):
        var clf = 1.0 - exp(-CLF_LIGHTS_DECAY * t_on[i])
        if clf < CLF_MIN:
            clf = CLF_MIN
        elif clf > CLF_MAX:
            clf = CLF_MAX
        out[i] = clf

@always_inline
def _roll_and_insert(
    ptr: UnsafePointer[Float64, MutAnyOrigin], n: Int, new_val: Float64
):
    """In-place right-shift by 1, then write `new_val` at index 0.

    Equivalent to: `arr = np.roll(arr, 1); arr[0] = new_val` but zero-copy.
    Iterates right-to-left to avoid overwriting values still in use.
    """
    var i = n - 1
    while i > 0:
        ptr[i] = ptr[i - 1]
        i -= 1
    ptr[0] = new_val


@always_inline
def _dot(
    a: UnsafePointer[Float64, MutAnyOrigin],
    b: UnsafePointer[Float64, MutAnyOrigin],
    n: Int,
) -> Float64:
    """Dot product of two float64 arrays of length n."""
    var s: Float64 = 0.0
    for i in range(n):
        s += a[i] * b[i]
    return s


@export
def ctf_step(
    z_addr: Int,
    z_n: Int,
    y_addr: Int,
    y_n: Int,
    x_addr: Int,
    x_n: Int,
    f_addr: Int,
    f_n: Int,
    t_in_hist_addr: Int,
    t_out_hist_addr: Int,
    q_in_hist_addr: Int,
    q_out_hist_addr: Int,
    t_in_now: Float64,
    t_out_now: Float64,
    result_addr: Int,
    s_inf_addr: Int,
    s_inf_n: Int,
    s_inside_hist_addr: Int,
    s_inside_now: Float64,
):
    """Advance one surface's CTF history by one timestep.

    Mirrors `heat_balance.surface.step()`.  Mutates the four history arrays
    in-place (zero-copy roll + insert).  Writes q_in to result[0] and
    q_out to result[1].

    Sign convention: q_in > 0 means the wall releases heat into the zone;
    q_out > 0 means the wall absorbs heat from outdoors.
    """
    var z = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=z_addr)
    var y = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=y_addr)
    var x = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=x_addr)
    var f = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=f_addr)
    var t_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_in_hist_addr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_out_hist_addr
    )
    var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_in_hist_addr
    )
    var q_out_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_out_hist_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    # 1. Roll temperature histories; insert current values at index 0.
    _roll_and_insert(t_in, z_n, t_in_now)
    _roll_and_insert(t_out, y_n, t_out_now)

    # 2. Temperature-driven flux terms.
    #    q_in  = -Z·T_in  + Y·T_out
    #    q_out =  Y·T_in  - X·T_out
    var q_in: Float64 = 0.0
    var q_out: Float64 = 0.0
    for i in range(z_n):
        q_in -= z[i] * t_in[i]
    for i in range(y_n):
        q_in += y[i] * t_out[i]
        q_out += y[i] * t_in[i]
    for i in range(x_n):
        q_out -= x[i] * t_out[i]

    # 2b. M6.x foundation (#463a): roll s_inside history & add S-input
    # convolution. Skipped entirely when `s_inf_n == 0` (default Python
    # fallback path). Touches the buffer only when active; with all-zero
    # s_inside history and `s_inside_now == 0.0`, the dot product is
    # exactly 0.0 — bit-for-bit parity with the legacy two-input CTF.
    if s_inf_n > 0:
        var s_inf = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=s_inf_addr
        )
        var s_hist = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=s_inside_hist_addr
        )
        _roll_and_insert(s_hist, s_inf_n, s_inside_now)
        for i in range(s_inf_n):
            q_in += s_inf[i] * s_hist[i]

    # 3. Phi-recursion flux-history feedback (F arrays; empty for NoMass).
    #    Reads q histories BEFORE rolling them.
    for i in range(f_n):
        q_in -= f[i] * q_in_h[i]
        q_out -= f[i] * q_out_h[i]

    # 4. Roll flux histories and insert just-computed values.
    var nf1 = f_n + 1
    _roll_and_insert(q_in_h, nf1, q_in)
    _roll_and_insert(q_out_h, nf1, q_out)

    result[0] = q_in
    result[1] = q_out


@export
def ctf_decompose_flux(
    z_addr: Int,
    z_n: Int,
    y_addr: Int,
    y_n: Int,
    f_addr: Int,
    f_n: Int,
    t_in_hist_addr: Int,
    t_out_hist_addr: Int,
    q_in_hist_addr: Int,
    t_out_now: Float64,
    result_addr: Int,
    s_inf_addr: Int,
    s_inf_n: Int,
    s_inside_hist_addr: Int,
    s_inside_now: Float64,
):
    """Linearise inside-surface flux for implicit zone solve.

    Mirrors `heat_balance.surface.decompose_flux()`.  Does NOT mutate any
    history array (read-only).  Writes q_const to result[0] and q_coef to
    result[1] such that:

        q_inside ≈ q_const + q_coef * t_inside_now

    The driver sums A*q_const and A*q_coef across surfaces, solves for T_zone
    implicitly, then calls ctf_step with the solved T_zone.
    """
    var z = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=z_addr)
    var y = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=y_addr)
    var f = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=f_addr)
    var t_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_in_hist_addr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_out_hist_addr
    )
    var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_in_hist_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    # Leading Z[0] term is factored out as the coefficient of t_inside_now.
    var q_coef = -z[0]

    # Constant part: past T_inside terms (Z[1:] · t_in_hist[0:z_n-1]).
    var q_const: Float64 = 0.0
    for i in range(1, z_n):
        q_const -= z[i] * t_in[i - 1]

    # Current outside temperature via leading Y[0], plus past T_outside terms.
    q_const += y[0] * t_out_now
    for i in range(1, y_n):
        q_const += y[i] * t_out[i - 1]

    # Phi-recursion flux-history feedback.
    for i in range(f_n):
        q_const -= f[i] * q_in_h[i]

    # M6.x foundation (#463a): S-input contribution. Read-only; uses
    # pre-roll history (the i>=1 terms map index k to post-roll k+1,
    # which is exactly the pre-roll k entry). Leading S_inf[0] uses the
    # caller-supplied `s_inside_now`.
    if s_inf_n > 0:
        var s_inf = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=s_inf_addr
        )
        var s_hist = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=s_inside_hist_addr
        )
        q_const += s_inf[0] * s_inside_now
        for i in range(1, s_inf_n):
            q_const += s_inf[i] * s_hist[i - 1]

    result[0] = q_const
    result[1] = q_coef


@export
def ctf_decompose_flux_outside(
    x_addr: Int,
    x_n: Int,
    y_addr: Int,
    y_n: Int,
    f_addr: Int,
    f_n: Int,
    t_in_hist_addr: Int,
    t_out_hist_addr: Int,
    q_out_hist_addr: Int,
    t_in_now: Float64,
    result_addr: Int,
):
    """Linearise outside-surface flux for the multi-zone ZONE-BC reciprocal injection.

    Mirrors `heat_balance.surface.decompose_flux_outside()`. Read-only.
    Writes q_const to result[0] and q_coef to result[1] such that:

        q_outside ≈ q_const + q_coef * t_outside_now

    The multi-zone driver uses this to compose the source surface's
    q_outside (linearised in the destination zone's T_zone) into the
    destination zone's air balance.
    """
    var x = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=x_addr)
    var y = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=y_addr)
    var f = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=f_addr)
    var t_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_in_hist_addr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_out_hist_addr
    )
    var q_out_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_out_hist_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    # Leading -X[0] term is the coefficient of t_outside_now.
    var q_coef = -x[0]

    # Constant part: Y[0] * t_inside_now + past T_inside terms.
    var q_const: Float64 = y[0] * t_in_now
    for i in range(1, y_n):
        q_const += y[i] * t_in[i - 1]

    # Past T_outside terms: -X[1:] * t_out_hist[0:x_n-1].
    for i in range(1, x_n):
        q_const -= x[i] * t_out[i - 1]

    # Phi-recursion flux-history feedback on outside flux.
    for i in range(f_n):
        q_const -= f[i] * q_out_h[i]

    result[0] = q_const
    result[1] = q_coef


# ---- Batch wrappers (one FFI per timestep, all N surfaces) -----------------
# Per-surface dispatch is currently the dominant Python-side overhead in
# the CTF runtime hot loop: ~6 surfaces × 2 kernel calls × 8760 timesteps
# = 105 k ctypes round-trips per annual run. Each round-trip is ~1-3 us
# of Python frame setup + ctypes argument marshalling -- the kernel
# itself finishes in tens of nanoseconds.
#
# These batch kernels collapse the per-surface loop into Mojo. The
# caller passes one packed int64 array of per-surface (coeffs + state)
# addresses + lengths, plus parallel input/output Float64 arrays, and
# Mojo dispatches the full N surfaces in one FFI round-trip.
#
# Layout of `surf_args[12*n]` (Int64, interleaved per-surface):
#     [0]  z_addr
#     [1]  z_n
#     [2]  y_addr
#     [3]  y_n
#     [4]  x_addr
#     [5]  x_n
#     [6]  f_addr
#     [7]  f_n
#     [8]  t_in_hist_addr
#     [9]  t_out_hist_addr
#     [10] q_in_hist_addr
#     [11] q_out_hist_addr
# Same packing accepted by both ctf_step_batch and ctf_decompose_flux_batch
# (the latter ignores indices 4, 5, 11).


@export
def ctf_step_batch(
    n: Int,
    surf_args_addr: Int,
    t_in_now_addr: Int,
    t_out_now_addr: Int,
    result_addr: Int,
    s_args_addr: Int,
    s_inside_now_addr: Int,
):
    """Advance N surfaces' CTF history by one timestep.

    Reads 12 Int64 per surface from `surf_args_addr` (coeffs + state
    addresses and lengths), per-surface scalars from `t_in_now_addr`
    (Float64[n]) and `t_out_now_addr` (Float64[n]). Writes
    `(q_in, q_out)` per surface to `result_addr` (Float64[2*n]).
    Mutates each state's history arrays in-place.
    """
    var args = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=surf_args_addr
    )
    var t_in_now = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_in_now_addr
    )
    var t_out_now = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_out_now_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    for i in range(n):
        var base = 12 * i
        var z = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 0])
        )
        var z_n = Int(args[base + 1])
        var y = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 2])
        )
        var y_n = Int(args[base + 3])
        var x = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 4])
        )
        var x_n = Int(args[base + 5])
        var f = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 6])
        )
        var f_n = Int(args[base + 7])
        var t_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )
        var q_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 11])
        )

        # Same per-surface logic as ctf_step (above).
        _roll_and_insert(t_in_h, z_n, t_in_now[i])
        _roll_and_insert(t_out_h, y_n, t_out_now[i])

        var q_in: Float64 = 0.0
        var q_out: Float64 = 0.0
        for k in range(z_n):
            q_in -= z[k] * t_in_h[k]
        for k in range(y_n):
            q_in += y[k] * t_out_h[k]
            q_out += y[k] * t_in_h[k]
        for k in range(x_n):
            q_out -= x[k] * t_out_h[k]

        # M6.x foundation (#463a): per-surface S-input convolution.
        # `s_args_addr == 0` is the legacy fast-path: skip entirely.
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                _roll_and_insert(s_hist, s_inf_n, s_inside_now_arr[i])
                for k in range(s_inf_n):
                    q_in += s_inf[k] * s_hist[k]

        for k in range(f_n):
            q_in -= f[k] * q_in_h[k]
            q_out -= f[k] * q_out_h[k]

        var nf1 = f_n + 1
        _roll_and_insert(q_in_h, nf1, q_in)
        _roll_and_insert(q_out_h, nf1, q_out)

        result[2 * i] = q_in
        result[2 * i + 1] = q_out


