            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )

        # Same per-surface logic as ctf_decompose_flux.
        var q_coef = -z[0]
        var q_const: Float64 = 0.0
        for k in range(1, z_n):
            q_const -= z[k] * t_in_h[k - 1]
        q_const += y[0] * t_out_now[i]
        for k in range(1, y_n):
            q_const += y[k] * t_out_h[k - 1]
        for k in range(f_n):
            q_const -= f[k] * q_in_h[k]

        # M6.x foundation (#463a): S-input contribution. Skipped entirely
        # when `s_args_addr == 0` (legacy fast-path).
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                q_const += s_inf[0] * s_inside_now_arr[i]
                for k in range(1, s_inf_n):
                    q_const += s_inf[k] * s_hist[k - 1]

        result[2 * i] = q_const
        result[2 * i + 1] = q_coef


@export
def ctf_decompose_flux_batch_reduce(
    n: Int,
    surf_args_addr: Int,
    t_out_now_addr: Int,
    area_addr: Int,
    result_addr: Int,
    s_args_addr: Int,
    s_inside_now_addr: Int,
):
    """Like ctf_decompose_flux_batch, but with the zone reduction folded in.

    Emits the area-weighted reduction directly:
        result[0] = sum_i (q_const[i] * area[i])
        result[1] = sum_i (q_coef[i]  * area[i])

    Saves the per-surface Python reduction loop in the runtime standard
    path. The carroll_mrt_implicit path needs per-surface q values; it
    keeps using ctf_decompose_flux_batch.

    Reads (Float64[n]): t_out_now, area. Writes (Float64[2]): result.
    """
    var args = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=surf_args_addr
    )
    var t_out_now = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_out_now_addr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    var sum_a_const: Float64 = 0.0
    var sum_a_coef: Float64 = 0.0

    for i in range(n):
        var base = 12 * i
        var z = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 0])
        )
        var z_n = Int(args[base + 1])
        var y = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 2])
        )
        var y_n = Int(args[base + 3])
        var f = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 6])
        )
        var f_n = Int(args[base + 7])
        var t_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )

        var q_coef = -z[0]
        var q_const: Float64 = 0.0
        for k in range(1, z_n):
            q_const -= z[k] * t_in_h[k - 1]
        q_const += y[0] * t_out_now[i]
        for k in range(1, y_n):
            q_const += y[k] * t_out_h[k - 1]
        for k in range(f_n):
            q_const -= f[k] * q_in_h[k]

        # M6.x foundation (#463a): S-input contribution, area-reduced.
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                q_const += s_inf[0] * s_inside_now_arr[i]
                for k in range(1, s_inf_n):
                    q_const += s_inf[k] * s_hist[k - 1]

        var a = area[i]
        sum_a_const += q_const * a
        sum_a_coef += q_coef * a

    result[0] = sum_a_const
    result[1] = sum_a_coef

comptime CO2_GEN_PERSON: Float64 = 0.0052   # m³/s per person
comptime CO2_OUTDOOR: Float64 = 400.0        # ppm
comptime CO2_MAX_PPM: Float64 = 5000.0       # ppm
comptime CO2_RANGE_MIN: Float64 = 50.0       # ppm
comptime V_ZONE_MIN: Float64 = 1.0           # m³
comptime PPM_SCALE: Float64 = 1.0e6
comptime ZERO: Float64 = 0.0
comptime ONE: Float64 = 1.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _clamp(v: Float64, lo: Float64, hi: Float64) -> Float64:
    """Clamp v to [lo, hi]."""
    if v < lo:
        return lo
    if v > hi:
        return hi
    return v


@always_inline
def _max(a: Float64, b: Float64) -> Float64:
    """Return the larger of a and b."""
    if a > b:
        return a
    return b


@export
def dcv_oa_fraction_batch(
    n: Int,
    co2_ppm_ptr: Int,
    co2_setpoint_ptr: Int,
    co2_max_ptr: Int,
    oa_min_ptr: Int,
    oa_max_ptr: Int,
    out_oa_required_ptr: Int,
    out_oa_frac_ptr: Int,
):
    """Batched DCV outdoor-air fraction and required OA flow from zone CO2.

    For each zone i in [0, n):

        co2_excess[i]  = max(0, co2_ppm[i] - co2_setpoint[i])
        co2_range[i]   = max(CO2_RANGE_MIN, co2_max[i] - co2_setpoint[i])
        oa_frac[i]     = clamp(co2_excess[i] / co2_range[i], 0.0, 1.0)
        oa_required[i] = clamp(oa_min[i] + oa_frac[i] * (oa_max[i] - oa_min[i]),
                               oa_min[i], oa_max[i])

    Arguments:
      - `n`                  — batch size (number of zones).
      - `co2_ppm_ptr`        — float64[n] current zone CO2 concentration (ppm).
      - `co2_setpoint_ptr`   — float64[n] CO2 setpoint / lower limit (ppm).
      - `co2_max_ptr`        — float64[n] CO2 upper limit for full OA (ppm).
      - `oa_min_ptr`         — float64[n] minimum OA flow (m³/s).
      - `oa_max_ptr`         — float64[n] maximum OA flow (m³/s).
      - `out_oa_required_ptr` — float64[n] required OA flow (m³/s)  [output].
      - `out_oa_frac_ptr`    — float64[n] OA modulation fraction [0, 1] [output].

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var co2_ppm = _ptr(co2_ppm_ptr)
    var co2_setpoint = _ptr(co2_setpoint_ptr)
    var co2_max = _ptr(co2_max_ptr)
    var oa_min = _ptr(oa_min_ptr)
    var oa_max = _ptr(oa_max_ptr)
    var out_oa_required = _ptr(out_oa_required_ptr)
    var out_oa_frac = _ptr(out_oa_frac_ptr)

    for i in range(n):
        var excess = _max(ZERO, co2_ppm[i] - co2_setpoint[i])
        var span = _max(CO2_RANGE_MIN, co2_max[i] - co2_setpoint[i])
        var frac = _clamp(excess / span, ZERO, ONE)
        var oa_req = _clamp(
            oa_min[i] + frac * (oa_max[i] - oa_min[i]),
            oa_min[i],
            oa_max[i],
        )
        out_oa_required[i] = oa_req
        out_oa_frac[i] = frac


@export
def dcv_co2_update_batch(
    n: Int,
    co2_ppm_ptr: Int,
    n_people_ptr: Int,
    oa_flow_ptr: Int,
    zone_volume_ptr: Int,
    dt_ptr: Int,
    out_co2_new_ptr: Int,
):
    """Batched CO2 concentration update via 1-step explicit Euler mass balance.

    For each zone i in [0, n):

        co2_gen[i]  = n_people[i] * CO2_GEN_PERSON   (= 0.0052 m³/s per person)
        v_zone[i]   = max(V_ZONE_MIN, zone_volume[i])
        co2_new[i]  = co2_ppm[i]
                      + dt[i] * (co2_gen[i] - oa_flow[i] * (co2_ppm[i] - CO2_OUTDOOR))
                      / v_zone[i] * PPM_SCALE
        co2_new[i]  = clamp(co2_new[i], CO2_OUTDOOR, CO2_MAX_PPM)

    Arguments:
      - `n`               — batch size (number of zones).
      - `co2_ppm_ptr`     — float64[n] current zone CO2 concentration (ppm).
      - `n_people_ptr`    — float64[n] number of occupants in zone.
      - `oa_flow_ptr`     — float64[n] outdoor-air flow rate into zone (m³/s).
      - `zone_volume_ptr` — float64[n] zone air volume (m³).
      - `dt_ptr`          — float64[n] timestep duration (s).
      - `out_co2_new_ptr` — float64[n] updated CO2 concentration (ppm) [output].

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var co2_ppm = _ptr(co2_ppm_ptr)
    var n_people = _ptr(n_people_ptr)
    var oa_flow = _ptr(oa_flow_ptr)
    var zone_volume = _ptr(zone_volume_ptr)
    var dt = _ptr(dt_ptr)
    var out_co2_new = _ptr(out_co2_new_ptr)

    for i in range(n):
        var gen = n_people[i] * CO2_GEN_PERSON
        var v = _max(V_ZONE_MIN, zone_volume[i])
        var co2_new = co2_ppm[i] + dt[i] * (gen - oa_flow[i] * (co2_ppm[i] - CO2_OUTDOOR)) / v * PPM_SCALE
        out_co2_new[i] = _clamp(co2_new, CO2_OUTDOOR, CO2_MAX_PPM)

from std.math import max, min

# ---------------------------------------------------------------------------
# Compile-time constants
# ---------------------------------------------------------------------------

comptime MIN_ETA: Float64 = 0.5  # minimum allowed efficiency
comptime MAX_ETA: Float64 = 1.0  # maximum allowed efficiency
comptime MIN_ECAP: Float64 = 1000.0  # minimum capacity (J)
comptime SOC_MIN_DEFAULT: Float64 = 0.1  # default SOC floor
comptime SOC_MAX_DEFAULT: Float64 = 0.95  # default SOC ceiling
comptime KWH_TO_J: Float64 = 3.6e6  # kWh → J conversion factor


# ---------------------------------------------------------------------------
# Internal helpers
# ---------------------------------------------------------------------------


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _guard_eta(eta: Float64) -> Float64:
    """Clamp efficiency to (MIN_ETA, MAX_ETA]; never zero or above 1."""
    if eta <= MIN_ETA:
        return MIN_ETA + 1e-9
    if eta > MAX_ETA:
        return MAX_ETA
    return eta


@always_inline
def _guard_ecap(e_cap_j: Float64) -> Float64:
    """Ensure capacity is at least MIN_ECAP Joules."""
    if e_cap_j < MIN_ECAP:
        return MIN_ECAP
    return e_cap_j


