# Exported: battery_step_soc_batch
# ---------------------------------------------------------------------------


@export
def battery_step_soc_batch(
    n: Int,
    soc_ptr: Int,
    p_charge_req_ptr: Int,
    p_discharge_req_ptr: Int,
    p_charge_max_ptr: Int,
    p_discharge_max_ptr: Int,
    eta_charge_ptr: Int,
    eta_discharge_ptr: Int,
    capacity_kwh_ptr: Int,
    soc_min_ptr: Int,
    soc_max_ptr: Int,
    dt_s: Float64,
    out_soc_new_ptr: Int,
    out_p_charge_actual_ptr: Int,
    out_p_discharge_actual_ptr: Int,
) -> None:
    """Advance N Li-ion batteries one timestep; update SOC and actual powers.

    Each input/output buffer is a raw int64 address of a Float64[N] C-contiguous
    array. No-op when n <= 0.

    Parameters
    ----------
    n                      : number of batteries
    soc_ptr                : Float64[n]  current state of charge (fraction 0–1)
    p_charge_req_ptr       : Float64[n]  requested charging power (W, ≥ 0)
    p_discharge_req_ptr    : Float64[n]  requested discharging power (W, ≥ 0)
    p_charge_max_ptr       : Float64[n]  maximum charging power (W)
    p_discharge_max_ptr    : Float64[n]  maximum discharging power (W)
    eta_charge_ptr         : Float64[n]  charging efficiency (0.5, 1.0]
    eta_discharge_ptr      : Float64[n]  discharging efficiency (0.5, 1.0]
    capacity_kwh_ptr       : Float64[n]  battery capacity (kWh)
    soc_min_ptr            : Float64[n]  minimum SOC fraction
    soc_max_ptr            : Float64[n]  maximum SOC fraction
    dt_s                   : timestep duration (s) — scalar
    out_soc_new_ptr        : Float64[n]  updated SOC (fraction)            [output]
    out_p_charge_actual_ptr: Float64[n]  actual charging power (W)         [output]
    out_p_discharge_actual_ptr: Float64[n] actual discharging power (W)    [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var soc = _ptr(soc_ptr)
    var p_charge_req = _ptr(p_charge_req_ptr)
    var p_discharge_req = _ptr(p_discharge_req_ptr)
    var p_charge_max = _ptr(p_charge_max_ptr)
    var p_discharge_max = _ptr(p_discharge_max_ptr)
    var eta_c = _ptr(eta_charge_ptr)
    var eta_d = _ptr(eta_discharge_ptr)
    var cap_kwh = _ptr(capacity_kwh_ptr)
    var soc_min = _ptr(soc_min_ptr)
    var soc_max = _ptr(soc_max_ptr)
    var out_soc = _ptr(out_soc_new_ptr)
    var out_pc = _ptr(out_p_charge_actual_ptr)
    var out_pd = _ptr(out_p_discharge_actual_ptr)

    for i in range(n):
        var soc_i = soc[i]
        var soc_lo = soc_min[i]
        var soc_hi = soc_max[i]
        var ec_i = _guard_eta(eta_c[i])
        var ed_i = _guard_eta(eta_d[i])
        var e_cap = _guard_ecap(cap_kwh[i] * KWH_TO_J)

        # ---- charging leg -------------------------------------------------
        # Simple model: actual = min(requested, max)
        var pc_req = p_charge_req[i]
        if pc_req < 0.0:
            pc_req = 0.0
        var pc_act = min(pc_req, p_charge_max[i])
        if pc_act < 0.0:
            pc_act = 0.0

        # Energy that would be stored (after efficiency loss)
        var e_stored = pc_act * dt_s * ec_i

        # Clamp: cannot push SOC above soc_max
        var e_head = (soc_hi - soc_i) * e_cap
        if e_head < 0.0:
            e_head = 0.0
        if e_stored > e_head:
            e_stored = e_head
            # Back-calculate the actual charge power consumed from grid
            if dt_s > 0.0 and ec_i > 0.0:
                pc_act = e_stored / (dt_s * ec_i)
            else:
                pc_act = 0.0
                e_stored = 0.0

        var soc_after_charge = soc_i + e_stored / e_cap

        # ---- discharging leg ----------------------------------------------
        var pd_req = p_discharge_req[i]
        if pd_req < 0.0:
            pd_req = 0.0
        var pd_act = min(pd_req, p_discharge_max[i])
        if pd_act < 0.0:
            pd_act = 0.0

        # Energy drawn from battery to deliver requested power
        var e_draw: Float64 = 0.0
        if dt_s > 0.0 and ed_i > 0.0:
            e_draw = pd_act * dt_s / ed_i
        else:
            pd_act = 0.0

        # Clamp: cannot pull SOC below soc_min
        var e_avail = (soc_after_charge - soc_lo) * e_cap
        if e_avail < 0.0:
            e_avail = 0.0
        if e_draw > e_avail:
            e_draw = e_avail
            # Back-calculate actual discharge power delivered
            if dt_s > 0.0:
                pd_act = e_draw * ed_i / dt_s
            else:
                pd_act = 0.0
                e_draw = 0.0

        # ---- SOC update ---------------------------------------------------
        var soc_new = soc_after_charge - e_draw / e_cap
        # Final clamp to guard against floating-point drift
        if soc_new < soc_lo:
            soc_new = soc_lo
        if soc_new > soc_hi:
            soc_new = soc_hi

        out_soc[i] = soc_new
        out_pc[i] = pc_act
        out_pd[i] = pd_act


