@export
def battery_available_energy_batch(
    n: Int,
    soc_ptr: Int,
    soc_min_ptr: Int,
    capacity_kwh_ptr: Int,
    out_e_avail_j_ptr: Int,
) -> None:
    """Compute available energy above SOC floor for N batteries.

    For each battery:
        E_avail[i] = max(0, soc[i] - soc_min[i]) * capacity_kwh[i] * 3.6e6

    Parameters
    ----------
    n                : number of batteries
    soc_ptr          : Float64[n]  current state of charge (fraction)
    soc_min_ptr      : Float64[n]  minimum SOC fraction (floor)
    capacity_kwh_ptr : Float64[n]  battery capacity (kWh)
    out_e_avail_j_ptr: Float64[n]  available energy (J)   [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var soc = _ptr(soc_ptr)
    var soc_min = _ptr(soc_min_ptr)
    var cap_kwh = _ptr(capacity_kwh_ptr)
    var out_e = _ptr(out_e_avail_j_ptr)

    for i in range(n):
        var e_cap = _guard_ecap(cap_kwh[i] * KWH_TO_J)
        var delta_soc = soc[i] - soc_min[i]
        if delta_soc < 0.0:
            delta_soc = 0.0
        out_e[i] = delta_soc * e_cap

@export
def equipment_wattage_batch(
    n: Int,
    design_level_w_ptr: Int,
    schedule_value_ptr: Int,
    fraction_latent_ptr: Int,
    fraction_radiant_ptr: Int,
    fraction_lost_ptr: Int,
    out_power_total_ptr: Int,
    out_power_latent_ptr: Int,
    out_power_radiant_ptr: Int,
    out_power_lost_ptr: Int,
):
    """Per-timestep equipment power split across heat-balance fractions.

    Arguments:
      - `n`                       — number of equipment records.
      - `design_level_w_ptr`      — raw int64 address of `float64[n]` design
                                     levels in watts.
      - `schedule_value_ptr`      — raw int64 address of `float64[n]`
                                     schedule values (typically in [0, 1]).
      - `fraction_latent_ptr`     — raw int64 address of `float64[n]` latent
                                     fractions (in [0, 1]).
      - `fraction_radiant_ptr`    — raw int64 address of `float64[n]` radiant
                                     fractions (in [0, 1]).
      - `fraction_lost_ptr`       — raw int64 address of `float64[n]` lost
                                     fractions (in [0, 1]).
      - `out_power_total_ptr`     — raw int64 address of `float64[n]` total
                                     power output buffer (design * schedule).
      - `out_power_latent_ptr`    — raw int64 address of `float64[n]` latent
                                     power output buffer.
      - `out_power_radiant_ptr`   — raw int64 address of `float64[n]` radiant
                                     power output buffer.
      - `out_power_lost_ptr`      — raw int64 address of `float64[n]` lost
                                     power output buffer.

    The convected component is derivable as
    `total - (latent + radiant + lost)` and is not written here.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var design = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_level_w_ptr
    )
    var sched = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_value_ptr
    )
    var f_lat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=fraction_latent_ptr
    )
    var f_rad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=fraction_radiant_ptr
    )
    var f_lost = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=fraction_lost_ptr
    )
    var out_tot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_total_ptr
    )
    var out_lat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_latent_ptr
    )
    var out_rad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_radiant_ptr
    )
    var out_lost = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_lost_ptr
    )

    for i in range(n):
        var total = design[i] * sched[i]
        out_tot[i] = total
        out_lat[i] = total * f_lat[i]
        out_rad[i] = total * f_rad[i]
        out_lost[i] = total * f_lost[i]

@export
def apply_binary_batch(
    n: Int,
    op_codes_ptr: Int,
    a_ptr: Int,
    b_ptr: Int,
    out_ptr: Int,
):
    """Apply N binary ERL operators element-wise.

    Arguments:
      - `n`            — number of elements to process.
      - `op_codes_ptr` — raw int64 address of `int32[n]` op codes (see table
                          above).
      - `a_ptr`        — raw int64 address of `float64[n]` left operands.
      - `b_ptr`        — raw int64 address of `float64[n]` right operands.
      - `out_ptr`      — raw int64 address of `float64[n]` output buffer.

    Division by zero yields NaN (matches the Python wrapper's contract — the
    shim coerces inf/zero handling on the caller side; the kernel never
    raises).

    Logical operators (`&&`, `||`) treat any non-zero operand as truthy and
    write 1.0 / 0.0 — mirroring Python's `float(bool(a) and bool(b))`.

    No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var ops = UnsafePointer[Int32, MutAnyOrigin](
        unsafe_from_address=op_codes_ptr
    )
    var a = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=a_ptr)
    var b = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=b_ptr)
    var out = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=out_ptr)

    var nan: Float64 = 0.0 / 0.0

    for i in range(n):
        var op = Int(ops[i])
        var x = a[i]
        var y = b[i]
        var r: Float64 = 0.0
        if op == 0:
            r = x + y
        elif op == 1:
            r = x - y
        elif op == 2:
            r = x * y
        elif op == 3:
            # Match Python's `0/0 -> NaN`, `x/0 -> NaN` policy used by the
            # ERL shim. The wrapper documents this contract.
            if y == 0.0:
                r = nan
            else:
                r = x / y
        elif op == 4:
            r = 1.0 if x < y else 0.0
        elif op == 5:
            r = 1.0 if x > y else 0.0
        elif op == 6:
            r = 1.0 if x <= y else 0.0
        elif op == 7:
            r = 1.0 if x >= y else 0.0
        elif op == 8:
            r = 1.0 if x == y else 0.0
        elif op == 9:
            r = 1.0 if x != y else 0.0
        elif op == 10:
            r = 1.0 if (x != 0.0 and y != 0.0) else 0.0
        elif op == 11:
            r = 1.0 if (x != 0.0 or y != 0.0) else 0.0
        else:
            r = nan
        out[i] = r

from std.math import log10, floor, isnan, isinf


# Maximum bytes the formatter can emit for a single record. rid (≤ 20
# digits for Int63) + ',' + %.6g (≤ 13 chars worst case: sign, leading
# digit, '.', 5 fractional digits, 'e', sign, 3-digit exponent) + '\n'
# = ~36 bytes. 64 leaves comfortable slack for unusual inputs.
comptime _MAX_RECORD_BYTES: Int = 64

# Significant-digit precision for the `%g` conversion. Hard-coded to
# match upstream's `{:.6g}`.
comptime _G_PRECISION: Int = 6

# ASCII codepoints — avoids depending on `ord()` builtin availability.
comptime _ASCII_0: UInt8 = 48  # '0'
comptime _ASCII_MINUS: UInt8 = 45  # '-'
comptime _ASCII_PLUS: UInt8 = 43  # '+'
comptime _ASCII_DOT: UInt8 = 46  # '.'
comptime _ASCII_COMMA: UInt8 = 44  # ','
comptime _ASCII_E: UInt8 = 101  # 'e'
comptime _ASCII_LF: UInt8 = 10  # '\n'
comptime _ASCII_n: UInt8 = 110  # 'n'
comptime _ASCII_a: UInt8 = 97  # 'a'
comptime _ASCII_i: UInt8 = 105  # 'i'
comptime _ASCII_f: UInt8 = 102  # 'f'


@always_inline
def _u8_ptr(addr: Int) -> UnsafePointer[UInt8, MutAnyOrigin]:
    return UnsafePointer[UInt8, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _i32_ptr(addr: Int) -> UnsafePointer[Int32, MutAnyOrigin]:
    return UnsafePointer[Int32, MutAnyOrigin](unsafe_from_address=addr)


def _put(buf: UnsafePointer[UInt8, MutAnyOrigin], pos: Int, c: UInt8) -> Int:
    buf[pos] = c
    return pos + 1


def _write_uint(
    buf: UnsafePointer[UInt8, MutAnyOrigin], offset: Int, value: Int
) -> Int:
    """Write decimal ASCII for non-negative `value` at `offset`. Returns new offset.
    """
    if value == 0:
        buf[offset] = _ASCII_0
        return offset + 1
    var start = offset
    var v = value
    while v > 0:
        var d = v % 10
        buf[start] = _ASCII_0 + UInt8(d)
        v //= 10
        start += 1
    # Reverse [offset, start) in place.
    var i = offset
    var j = start - 1
    while i < j:
        var t = buf[i]
        buf[i] = buf[j]
        buf[j] = t
        i += 1
        j -= 1
    return start


def _put_digit(
    buf: UnsafePointer[UInt8, MutAnyOrigin], pos: Int, d: Int
) -> Int:
    buf[pos] = _ASCII_0 + UInt8(d)
    return pos + 1


def _put_nan(buf: UnsafePointer[UInt8, MutAnyOrigin], offset: Int) -> Int:
    buf[offset] = _ASCII_n
    buf[offset + 1] = _ASCII_a
    buf[offset + 2] = _ASCII_n
    return offset + 3


def _put_inf(buf: UnsafePointer[UInt8, MutAnyOrigin], offset: Int) -> Int:
    buf[offset] = _ASCII_i
    buf[offset + 1] = _ASCII_n
    buf[offset + 2] = _ASCII_f
    return offset + 3


def _format_g6(
    buf: UnsafePointer[UInt8, MutAnyOrigin], offset: Int, value: Float64
) -> Int:
    """Write `%.6g` representation of `value` at `offset`. Returns new offset.
    """
    # Special values — match glibc printf's spellings.
    if isnan(value):
        return _put_nan(buf, offset)
    if isinf(value):
        if value < 0.0:
            var p = _put(buf, offset, _ASCII_MINUS)
            return _put_inf(buf, p)
        return _put_inf(buf, offset)

    var pos = offset
    var v = value
    if v < 0.0:
        pos = _put(buf, pos, _ASCII_MINUS)
        v = -v
    # Note: positive zero falls through and prints as "0"; negative zero
    # was sign-stripped above and now prints as "-0", matching printf.

    if v == 0.0:
        return _put(buf, pos, _ASCII_0)

    # Compute exponent X = floor(log10(v)). log10 can be off by ulps near
    # powers of 10; correct after the fact so v ∈ [10^X, 10^(X+1)).
    var x = Int(floor(log10(v)))
    # 10^x via repeated multiplication keeps us off Mojo's `**` operator
    # (which may or may not bind for Float64 in this toolchain version).
    var scale: Float64 = 1.0
    if x >= 0:
        for _ in range(x):
            scale *= 10.0
    else:
        for _ in range(-x):
            scale /= 10.0
    if v >= 10.0 * scale:
        x += 1
        scale *= 10.0
    elif v < scale:
        x -= 1
        scale /= 10.0

    # Produce enough decimal digits to safely round at 6 significant
    # digits. We extract 18 digits — well beyond double precision — so
    # the round-half-to-even tie-break has the trailing-nonzero signal
    # it needs to be correct.
    comptime DIGIT_COUNT: Int = 18
    var mant = v / scale  # in [1, 10)
    # Small heap-backed digit buffer. The List call site is once per format
    # invocation; we considered InlineArray but stick with List to match the
    # rest of the kernels' style and avoid version-specific APIs.
    var digits = List[Int]()
    for _ in range(DIGIT_COUNT):
        var d = Int(floor(mant))
        if d > 9:
            d = 9
        if d < 0:
            d = 0
        digits.append(d)
        mant = (mant - Float64(d)) * 10.0

    # Round to 6 significant digits, half-to-even.
    var round_digit = digits[_G_PRECISION]
    var trailing_nonzero = False
    for k in range(_G_PRECISION + 1, DIGIT_COUNT):
        if digits[k] != 0:
            trailing_nonzero = True
            break

    var bump = False
    if round_digit > 5:
        bump = True
    elif round_digit == 5:
        if trailing_nonzero:
            bump = True
        elif (_G_PRECISION > 0) and ((digits[_G_PRECISION - 1] % 2) == 1):
            # Half-to-even: bump only when the kept digit is odd.
            bump = True

    var carry = 0
    if bump:
        var idx = _G_PRECISION - 1
        carry = 1
        while idx >= 0 and carry == 1:
            var nv = digits[idx] + 1
            if nv == 10:
                digits[idx] = 0
                idx -= 1
            else:
                digits[idx] = nv
                carry = 0

    # Effective significand layout: `sig_len` digits starting at `sig_offset`
    # within the `digits` buffer (offset = -1 means "prepend a 1" from carry).
    var sig_len = _G_PRECISION
    var leading_one = False
    if carry == 1:
        # 9.99999... → 10. Prepend a 1, drop the now-trailing zero, bump exp.
        leading_one = True
        x += 1
        # The digits[0.._G_PRECISION-1] are all 0 after the carry; effectively
        # we render '1' followed by (_G_PRECISION - 1) zeros — which will all
        # be stripped as trailing zeros anyway. Set sig_len = _G_PRECISION
        # and rely on the trailing-zero strip below.

    # Strip trailing zeros from the kept significand. With `leading_one`,
    # all kept digits are zero so sig_len becomes 0 (only the prepended '1'
    # survives — handled in the emitters below).
    while sig_len > 0 and digits[sig_len - 1] == 0:
        sig_len -= 1

    # Decide notation: scientific iff x < -4 or x >= precision (printf %g).
    var use_scientific = x < -4 or x >= _G_PRECISION

    if use_scientific:
        # d.dddddE±xx — leading digit, optional '.', remaining digits.
        if leading_one:
            pos = _put_digit(buf, pos, 1)
        else:
            pos = _put_digit(buf, pos, digits[0])
        var frac_start = 0 if leading_one else 1
        if sig_len > frac_start:
            pos = _put(buf, pos, _ASCII_DOT)
            for k in range(frac_start, sig_len):
                pos = _put_digit(buf, pos, digits[k])
        pos = _put(buf, pos, _ASCII_E)
        if x < 0:
            pos = _put(buf, pos, _ASCII_MINUS)
        else:
            pos = _put(buf, pos, _ASCII_PLUS)
        # printf %g uses at least 2 exponent digits.
        var ax = x if x >= 0 else -x
        if ax < 10:
            pos = _put(buf, pos, _ASCII_0)
        pos = _write_uint(buf, pos, ax)
        return pos

    # Fixed notation. Place the decimal point so that exactly (x+1) digits
    # land before it; pad with zeros on either side if sig is shorter.
    #
    # Indexing into `digits` accounts for `leading_one` (the implicit '1'
    # at virtual position -1).
    if x >= 0:
        var int_digits = x + 1
        for k in range(int_digits):
            if leading_one and k == 0:
                pos = _put_digit(buf, pos, 1)
            else:
                var src = k - 1 if leading_one else k
                if src < sig_len:
                    pos = _put_digit(buf, pos, digits[src])
                else:
                    pos = _put(buf, pos, _ASCII_0)
        # Fractional digits (only if the significand has any past int_digits).
        var src_start = int_digits - 1 if leading_one else int_digits
        if sig_len > src_start:
            pos = _put(buf, pos, _ASCII_DOT)
            for k in range(src_start, sig_len):
                pos = _put_digit(buf, pos, digits[k])
        return pos

    # x in [-4, -1] — leading 0., then -x-1 padding zeros, then sig digits.
    pos = _put(buf, pos, _ASCII_0)
    pos = _put(buf, pos, _ASCII_DOT)
    for _ in range(-x - 1):
        pos = _put(buf, pos, _ASCII_0)
    if leading_one:
        pos = _put_digit(buf, pos, 1)
    for k in range(sig_len):
        pos = _put_digit(buf, pos, digits[k])
    return pos


@export
def format_eso_value(
    report_id: Int,
    value: Float64,
    out_buf_addr: Int,
    out_len_addr: Int,
    buf_size: Int,
) -> Int32:
    """Format one ESO/MTR record into `out_buf` as ASCII bytes.

    Produces `"<report_id>,<value>\\n"` where `<value>` follows printf
    `%.6g` (6 significant digits, scientific iff exponent < -4 or >= 6,
    trailing zeros stripped, decimal point dropped when no fractional
    digits remain). Writes the byte length to `*out_len`.

    Arguments:
      - `report_id`    — non-negative integer report ID, written verbatim
                          as ASCII digits.
      - `value`        — the numeric value to format.
      - `out_buf_addr` — raw int64 address of a `uint8[buf_size]` output
                          buffer. Must be at least 64 bytes; the kernel
                          writes up to `_MAX_RECORD_BYTES` bytes and does
                          not write a NUL terminator.
      - `out_len_addr` — raw int64 address of an `int32` cell; on success
                          receives the number of bytes written.
      - `buf_size`     — capacity of the output buffer in bytes.

    Return value: 0 on success, negative on overflow / bad input. Callers
    treat any negative return as fatal; the Python wrapper raises.
    """
    if buf_size < _MAX_RECORD_BYTES:
        return Int32(-1)
    if report_id < 0:
        return Int32(-2)

    var buf = _u8_ptr(out_buf_addr)
    var out_len = _i32_ptr(out_len_addr)

    # "<rid>,"
    var pos = _write_uint(buf, 0, report_id)
    pos = _put(buf, pos, _ASCII_COMMA)

    # "<value>"
    pos = _format_g6(buf, pos, value)

    # "\n"
    pos = _put(buf, pos, _ASCII_LF)

    out_len[0] = Int32(pos)
    return Int32(0)

@export
def fan_constant_volume_power_batch(
    n_fans: Int,
    design_flow_m3_s_ptr: Int,
    design_pressure_pa_ptr: Int,
    motor_eff_ptr: Int,
    fan_eff_ptr: Int,
    out_power_w_ptr: Int,
):
    """Batched constant-volume fan electrical power.

    Computes `power_W = (flow × dP) / (fan_eff × motor_eff)` for each fan in
    a single FFI round trip.

    Arguments:
      - `n_fans`                  — number of fans in every input array.
      - `design_flow_m3_s_ptr`    — raw int64 address of `float64[n_fans]`
                                     design volumetric airflow (m³/s).
      - `design_pressure_pa_ptr`  — raw int64 address of `float64[n_fans]`
                                     design pressure rise (Pa).
      - `motor_eff_ptr`           — raw int64 address of `float64[n_fans]`
                                     motor efficiency, in (0, 1].
      - `fan_eff_ptr`             — raw int64 address of `float64[n_fans]`
                                     fan total efficiency, in (0, 1].
      - `out_power_w_ptr`         — raw int64 address of `float64[n_fans]`
                                     output buffer, electrical power (W).

    No-op when `n_fans == 0`. The Python wrapper validates that efficiencies
    are strictly positive — divide-by-zero in the kernel would yield ±inf or
    NaN, which the wrapper rejects up-front rather than propagating.
    """
    if n_fans <= 0:
        return

    var flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_flow_m3_s_ptr
    )
    var dp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_pressure_pa_ptr
    )
    var motor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=motor_eff_ptr
    )
    var fan = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=fan_eff_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_w_ptr
    )

    for i in range(n_fans):
        out[i] = (flow[i] * dp[i]) / (fan[i] * motor[i])

from std.math import max, min

# Reference velocity [m/s] — denominator of the velocity ratio
comptime V_REF: Float64 = 10.0
# Velocity pressure exponent (v² proportionality)
comptime V_EXP: Float64 = 2.0
# Maximum allowable fan outlet velocity [m/s]
comptime MAX_V: Float64 = 50.0
# Minimum system effect coefficient (dimensionless)
comptime C_MIN: Float64 = 0.0
# Maximum system effect coefficient (dimensionless)
comptime C_MAX: Float64 = 1.0
# Maximum system effect factor (dimensionless)
comptime SEF_MAX: Float64 = 5.0
# Maximum total pressure [Pa]
comptime MAX_P: Float64 = 5000.0


@always_inline
def _sef_from_ptr(
    c_se_ptr: UnsafePointer[Float64, MutAnyOrigin],
    v_outlet_ptr: UnsafePointer[Float64, MutAnyOrigin],
    i: Int,
) -> Float64:
    """Compute SEF for element i, with all clamping applied."""
    var v = min(max(v_outlet_ptr[i], 0.0), MAX_V)
    var c = min(max(c_se_ptr[i], C_MIN), C_MAX)
    # V_EXP = 2.0: use direct multiplication instead of pow/exp
    var v_ratio_sq = v * v / (V_REF * V_REF)
    var sef = c * v_ratio_sq
    return min(max(sef, 0.0), SEF_MAX)


@export
def fan_system_effect_factor_batch(
    n: Int,
    c_se_ptr: Int,
    v_outlet_ptr: Int,
    out_sef_ptr: Int,
) -> None:
    """Compute AMCA 201 system effect factor for N fans.

    For each fan:

        v_clamped  = clamp(v_outlet, 0, MAX_V)   [m/s]
        c_clamped  = clamp(c_se, C_MIN, C_MAX)
        SEF        = clamp(c_clamped * (v_clamped / V_REF)^2, 0, SEF_MAX)

    Parameters
    ----------
    n            : number of fans
    c_se_ptr     : Float64[n]  system effect coefficient (dimensionless)
    v_outlet_ptr : Float64[n]  fan outlet velocity (m/s)
    out_sef_ptr  : Float64[n]  system effect factor (dimensionless)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var c_se = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_se_ptr
    )
    var v_outlet = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=v_outlet_ptr
    )
    var out_sef = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_sef_ptr
    )

    for i in range(n):
        out_sef[i] = _sef_from_ptr(c_se, v_outlet, i)


@export
def fan_total_pressure_corrected_batch(
    n: Int,
    p_total_ptr: Int,
    sef_ptr: Int,
    out_p_ptr: Int,
) -> None:
    """Apply system effect factor to fan total pressure for N fans.

    For each fan:

        p_clamped  = clamp(p_total, 0, MAX_P)  [Pa]
        P_eff      = clamp(p_clamped * (1 - SEF), 0, MAX_P)

    Parameters
    ----------
    n          : number of fans
    p_total_ptr: Float64[n]  fan total pressure (Pa)
    sef_ptr    : Float64[n]  system effect factor (dimensionless)
    out_p_ptr  : Float64[n]  corrected total pressure (Pa)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var p_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=p_total_ptr
    )
    var sef = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=sef_ptr)
    var out_p = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_p_ptr
    )

    for i in range(n):
        var p = min(max(p_total[i], 0.0), MAX_P)
        var p_eff = p * (1.0 - sef[i])
        out_p[i] = min(max(p_eff, 0.0), MAX_P)

comptime ZERO: Float64 = 0.0
comptime ONE: Float64 = 1.0


@export
def fan_variable_volume_power_batch(
    n_fans: Int,
    flow_fraction_ptr: Int,
    min_flow_fraction_ptr: Int,
    c1_ptr: Int,
    c2_ptr: Int,
    c3_ptr: Int,
    c4_ptr: Int,
    c5_ptr: Int,
    design_power_w_ptr: Int,
    out_power_w_ptr: Int,
) -> None:
    """Evaluate N VFD fan part-load powers in one FFI round trip.

    Writes `out_power_w[i] = plf[i] * design_power_w[i]` where

        plf = c1 + c2·f + c3·f² + c4·f³ + c5·f⁴
        f   = clamp(flow_fraction, min_flow_fraction, 1.0)

    No-op when `n_fans == 0`. `design_power_w[i] <= 0` → 0 W output.
    """
    if n_fans <= 0:
        return

    var ff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=flow_fraction_ptr
    )
    var ff_min = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=min_flow_fraction_ptr
    )
    var c1 = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c1_ptr)
    var c2 = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c2_ptr)
    var c3 = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c3_ptr)
    var c4 = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c4_ptr)
    var c5 = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c5_ptr)
    var dp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_power_w_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_w_ptr
    )

    for i in range(n_fans):
        var dpow = dp[i]
        if dpow <= ZERO:
            out[i] = ZERO
            continue

        # Clamp flow fraction to [min_flow_fraction, 1.0].
        var f = ff[i]
        var f_lo = ff_min[i]
        if f < f_lo:
            f = f_lo
        if f > ONE:
            f = ONE

        # Horner-scheme polynomial evaluation (c1 + c2·f + c3·f² + c4·f³ + c5·f⁴).
        var plf = c1[i] + f * (c2[i] + f * (c3[i] + f * (c4[i] + f * c5[i])))

        out[i] = plf * dpow

@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _abs(x: Float64) -> Float64:
    return x if x >= 0.0 else -x


# Threshold for treating a pivot as "zero" — matches the structural-zero
# behaviour of the Python reference (which raises on |pivot| < eps).
comptime _PIVOT_EPS: Float64 = 1.0e-30


# ---- gauss_solve_dense -----------------------------------------------------


@export
def gauss_solve_dense(
    n: Int,
    matrix_addr: Int,
    rhs_addr: Int,
    out_x_addr: Int,
) -> Int:
    """Solve A · x = b via Gaussian elimination with partial pivoting.

    Inputs:
      - `n`            — system size (>= 0; 0 is a no-op returning 0).
      - `matrix_addr`  — raw int64 address of Float64 [n*n] row-major A.
      - `rhs_addr`     — raw int64 address of Float64 [n] b vector.
      - `out_x_addr`   — raw int64 address of Float64 [n] output x buffer.

    Returns:
      - 0 on success.
      - 1 if a (near-)zero pivot is encountered (`|pivot| < 1e-30`),
        indicating the matrix is singular to working precision. `out_x`
        contents are unspecified in that case.

    The caller's `matrix_addr` and `rhs_addr` buffers are not mutated:
    the kernel works on its own scratch copies.
    """
    if n <= 0:
        return 0

    var a_in = _ptr(matrix_addr)
    var b_in = _ptr(rhs_addr)
    var x_out = _ptr(out_x_addr)

    var nn = n * n

    # Allocate scratch copies so we don't mutate the caller's buffers.
    var a = alloc[Float64](nn)
    var b = alloc[Float64](n)
    for i in range(nn):
        a[i] = a_in[i]
    for i in range(n):
        b[i] = b_in[i]

    # ---- Forward elimination with partial pivoting -------------------------
    for k in range(n):
        # Find pivot row: max |A[i, k]| for i in [k, n).
        var pivot = k
        var pivot_val = _abs(a[k * n + k])
        for i in range(k + 1, n):
            var v = _abs(a[i * n + k])
            if v > pivot_val:
                pivot = i
                pivot_val = v

        if pivot_val < _PIVOT_EPS:
            # Singular to working precision — bail out.
            a.free()
            b.free()
            return 1

        # Swap rows pivot ↔ k in A and b.
        if pivot != k:
            for j in range(n):
                var t = a[k * n + j]
                a[k * n + j] = a[pivot * n + j]
                a[pivot * n + j] = t
            var tb = b[k]
            b[k] = b[pivot]
            b[pivot] = tb

        # Eliminate below the pivot.
        var akk = a[k * n + k]
        for i in range(k + 1, n):
            var factor = a[i * n + k] / akk
            if factor != 0.0:
                for j in range(k, n):
                    a[i * n + j] -= factor * a[k * n + j]
                b[i] -= factor * b[k]

    # ---- Back substitution -------------------------------------------------
    var k = n - 1
    while k >= 0:
        var s = b[k]
        for j in range(k + 1, n):
            s -= a[k * n + j] * x_out[j]
        x_out[k] = s / a[k * n + k]
        k -= 1

    a.free()
    b.free()
    return 0

from std.math import log, exp, max

comptime PI: Float64 = 3.141592653589793
comptime MIN_R: Float64 = 1e-6
comptime MIN_MDOT: Float64 = 1e-6
comptime MIN_DIAM: Float64 = 1e-3


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def slinky_ghe_resistance_batch(
    n: Int,
    z_burial_ptr: Int,
    d_coil_ptr: Int,
    d_pipe_ptr: Int,
    k_soil_ptr: Int,
    k_pipe_ptr: Int,
    out_r_soil_ptr: Int,
    out_r_pipe_ptr: Int,
    out_r_total_ptr: Int,
) -> None:
    """Soil and pipe thermal resistances for N slinky GHEs.

    Uses the cylindrical source model approximation:

        R_soil = ln(2*z / d_coil) / (2*pi*k_soil)
        R_pipe = ln(d_coil / d_pipe) / (2*pi*k_pipe)
        R_total = R_soil + R_pipe

    where z is burial depth, d_coil is coil diameter, d_pipe is pipe
    outer diameter, k_soil is soil thermal conductivity, and k_pipe is
    pipe thermal conductivity.

    Parameters
    ----------
    n              : number of slinky GHEs
    z_burial_ptr   : Float64[n]  burial depth of coil centre [m]
    d_coil_ptr     : Float64[n]  coil diameter [m]
    d_pipe_ptr     : Float64[n]  pipe outer diameter [m]
    k_soil_ptr     : Float64[n]  soil thermal conductivity [W/(m·K)]
    k_pipe_ptr     : Float64[n]  pipe thermal conductivity [W/(m·K)]
    out_r_soil_ptr : Float64[n]  soil thermal resistance [m·K/W]  [output]
    out_r_pipe_ptr : Float64[n]  pipe thermal resistance [m·K/W]  [output]
    out_r_total_ptr: Float64[n]  total thermal resistance [m·K/W] [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var zb = _ptr(z_burial_ptr)
    var dc = _ptr(d_coil_ptr)
    var dp = _ptr(d_pipe_ptr)
    var ks = _ptr(k_soil_ptr)
    var kp = _ptr(k_pipe_ptr)
    var rs = _ptr(out_r_soil_ptr)
    var rp = _ptr(out_r_pipe_ptr)
    var rt = _ptr(out_r_total_ptr)
    for i in range(n):
        var dcoil = max(dc[i], MIN_DIAM)
        var dpipe = max(dp[i], MIN_DIAM)
        var z = max(zb[i], dcoil * 0.5)
        var r_soil = log(2.0 * z / dcoil) / (2.0 * PI * max(ks[i], MIN_R))
        var ratio = dcoil / max(dpipe, MIN_DIAM * 0.1)
        var r_pipe = log(max(ratio, 1.001)) / (2.0 * PI * max(kp[i], MIN_R))
        rs[i] = r_soil
        rp[i] = r_pipe
        rt[i] = r_soil + r_pipe


@export
def slinky_ghe_heat_exchange_batch(
    n: Int,
    t_fluid_in_ptr: Int,
    t_ground_ptr: Int,
    m_dot_ptr: Int,
    cp_fluid_ptr: Int,
    r_total_ptr: Int,
    length_m_ptr: Int,
    out_q_total_ptr: Int,
    out_t_fluid_out_ptr: Int,
) -> None:
    """Heat exchange rate and outlet temperature for N slinky GHEs.

    For each GHE i:

        q_per_m[i]     = (T_fluid_in[i] - T_ground[i]) / R_total[i]
        q_total[i]     = q_per_m[i] * length_m[i]
        T_fluid_out[i] = T_fluid_in[i] - q_total[i] / (m_dot[i] * cp_fluid[i])

    Sign convention: q_total > 0 means heat is extracted from the ground
    (T_fluid_in < T_ground, heat pump / cooling mode).

    Parameters
    ----------
    n                 : number of slinky GHEs
    t_fluid_in_ptr    : Float64[n]  fluid inlet temperature [°C]
    t_ground_ptr      : Float64[n]  undisturbed ground temperature [°C]
    m_dot_ptr         : Float64[n]  fluid mass flow rate [kg/s]
    cp_fluid_ptr      : Float64[n]  fluid specific heat [J/(kg·K)]
    r_total_ptr       : Float64[n]  total thermal resistance [m·K/W]
    length_m_ptr      : Float64[n]  total slinky coil length [m]
    out_q_total_ptr   : Float64[n]  total heat exchange rate [W]      [output]
    out_t_fluid_out_ptr: Float64[n] fluid outlet temperature [°C]     [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var tf = _ptr(t_fluid_in_ptr)
    var tg = _ptr(t_ground_ptr)
    var md = _ptr(m_dot_ptr)
    var cp = _ptr(cp_fluid_ptr)
    var rt = _ptr(r_total_ptr)
    var lm = _ptr(length_m_ptr)
    var oq = _ptr(out_q_total_ptr)
    var ot = _ptr(out_t_fluid_out_ptr)
    for i in range(n):
        var r_tot = max(rt[i], MIN_R)
        var mdot = max(md[i], MIN_MDOT)
        var q_per_m = (tf[i] - tg[i]) / r_tot
        var q_total = q_per_m * lm[i]
        var t_out = tf[i] - q_total / (mdot * cp[i])
        oq[i] = q_total
        ot[i] = t_out


@export
def slinky_ghe_full_batch(
    n: Int,
    t_fluid_in_ptr: Int,
    t_ground_ptr: Int,
    m_dot_ptr: Int,
    cp_fluid_ptr: Int,
    z_burial_ptr: Int,
    d_coil_ptr: Int,
    d_pipe_ptr: Int,
    k_soil_ptr: Int,
    k_pipe_ptr: Int,
    length_m_ptr: Int,
    out_q_total_ptr: Int,
    out_t_fluid_out_ptr: Int,
    out_r_total_ptr: Int,
) -> None:
    """Combined thermal resistance + heat exchange for N slinky GHEs.

    Computes soil and pipe resistances, then heat exchange and outlet
    temperature in a single pass — avoids storing intermediate resistance
    arrays when the caller only needs heat exchange results.

    For each GHE i:

        R_soil  = ln(2*z / d_coil) / (2*pi*k_soil)
        R_pipe  = ln(d_coil / d_pipe) / (2*pi*k_pipe)
        R_total = R_soil + R_pipe

        q_total     = (T_fluid_in - T_ground) / R_total * length_m
        T_fluid_out = T_fluid_in - q_total / (m_dot * cp_fluid)

    Parameters
    ----------
    n                  : number of slinky GHEs
    t_fluid_in_ptr     : Float64[n]  fluid inlet temperature [°C]
    t_ground_ptr       : Float64[n]  undisturbed ground temperature [°C]
    m_dot_ptr          : Float64[n]  fluid mass flow rate [kg/s]
    cp_fluid_ptr       : Float64[n]  fluid specific heat [J/(kg·K)]
    z_burial_ptr       : Float64[n]  burial depth of coil centre [m]
    d_coil_ptr         : Float64[n]  coil diameter [m]
    d_pipe_ptr         : Float64[n]  pipe outer diameter [m]
    k_soil_ptr         : Float64[n]  soil thermal conductivity [W/(m·K)]
    k_pipe_ptr         : Float64[n]  pipe thermal conductivity [W/(m·K)]
    length_m_ptr       : Float64[n]  total slinky coil length [m]
    out_q_total_ptr    : Float64[n]  total heat exchange rate [W]      [output]
    out_t_fluid_out_ptr: Float64[n]  fluid outlet temperature [°C]     [output]
    out_r_total_ptr    : Float64[n]  total thermal resistance [m·K/W]  [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var tf = _ptr(t_fluid_in_ptr)
    var tg = _ptr(t_ground_ptr)
    var md = _ptr(m_dot_ptr)
    var cp = _ptr(cp_fluid_ptr)
    var zb = _ptr(z_burial_ptr)
    var dc = _ptr(d_coil_ptr)
    var dp = _ptr(d_pipe_ptr)
    var ks = _ptr(k_soil_ptr)
    var kp = _ptr(k_pipe_ptr)
    var lm = _ptr(length_m_ptr)
    var oq = _ptr(out_q_total_ptr)
    var ot = _ptr(out_t_fluid_out_ptr)
    var ort = _ptr(out_r_total_ptr)
    for i in range(n):
        # --- thermal resistances ---
        var dcoil = max(dc[i], MIN_DIAM)
        var dpipe = max(dp[i], MIN_DIAM)
        var z = max(zb[i], dcoil * 0.5)
        var r_soil = log(2.0 * z / dcoil) / (2.0 * PI * max(ks[i], MIN_R))
        var ratio = dcoil / max(dpipe, MIN_DIAM * 0.1)
        var r_pipe = log(max(ratio, 1.001)) / (2.0 * PI * max(kp[i], MIN_R))
        var r_total = r_soil + r_pipe
        # --- heat exchange ---
        var r_tot = max(r_total, MIN_R)
        var mdot = max(md[i], MIN_MDOT)
        var q_per_m = (tf[i] - tg[i]) / r_tot
        var q_total = q_per_m * lm[i]
        var t_out = tf[i] - q_total / (mdot * cp[i])
        oq[i] = q_total
        ot[i] = t_out
        ort[i] = r_total

from std.math import exp

comptime CMIN_GUARD: Float64 = 1.0e-6
comptime CR_EQ1_TOL: Float64 = 1.0e-6
comptime HALF: Float64 = 0.5


@always_inline
def _ntu_eff_scalar(
    ua: Float64,
    c_hot: Float64,
    c_cold: Float64,
    flow_type: Float64,
) -> Float64:
    """Compute NTU-effectiveness for a single fluid-to-fluid HX element.

    Returns effectiveness in [0, 1]. Guards against zero capacity-flow rates.
    Flow type: 0.0 = counterflow, 1.0 = parallel, other = crossflow (≈ counterflow).
    """
    var c_min = c_hot if c_hot < c_cold else c_cold
    var c_max = c_hot if c_hot > c_cold else c_cold
    var c_min_safe = c_min if c_min > CMIN_GUARD else CMIN_GUARD
    var c_max_safe = c_max if c_max > CMIN_GUARD else CMIN_GUARD
    var cr = c_min_safe / c_max_safe
    var ntu = ua / c_min_safe

    var eff: Float64
    # Parallel flow: flow_type ≈ 1.0
    var is_parallel = (flow_type > 0.5) and (flow_type < 1.5)
    if is_parallel:
        eff = (1.0 - exp(-ntu * (1.0 + cr))) / (1.0 + cr)
    else:
        # Counterflow (flow_type ≈ 0.0) and crossflow (≈ 2.0) both use counterflow formula
        var cr_is_one = (cr > 1.0 - CR_EQ1_TOL) and (cr < 1.0 + CR_EQ1_TOL)
        if cr_is_one:
            eff = ntu / (1.0 + ntu)
        else:
            var exponent = -ntu * (1.0 - cr)
            var e = exp(exponent)
            eff = (1.0 - e) / (1.0 - cr * e)

    return eff


@export
def hx_ff_ntu_effectiveness_batch(
    n: Int,
    ua_ptr: Int,
    c_hot_ptr: Int,
    c_cold_ptr: Int,
    flow_type_ptr: Int,
    out_eff_ptr: Int,
) -> None:
    """Compute NTU-effectiveness for N fluid-to-fluid HX elements.

    Writes `eff[n]` (dimensionless, 0–1). No-op for n == 0.

    Parameters
    ----------
    n             : number of HX elements
    ua_ptr        : float64[n]  overall heat transfer conductance UA (W/K)
    c_hot_ptr     : float64[n]  hot-side heat-capacity flow C_hot = m_dot * Cp (W/K)
    c_cold_ptr    : float64[n]  cold-side heat-capacity flow C_cold (W/K)
    flow_type_ptr : float64[n]  0.0=counterflow, 1.0=parallel, 2.0=crossflow
    out_eff_ptr   : float64[n]  effectiveness output (written)
    """
    if n <= 0:
        return

    var ua = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=ua_ptr)
    var c_hot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_hot_ptr
    )
    var c_cold = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_cold_ptr
    )
    var flow_type = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=flow_type_ptr
    )
    var out_eff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_eff_ptr
    )

    for i in range(n):
        out_eff[i] = _ntu_eff_scalar(ua[i], c_hot[i], c_cold[i], flow_type[i])


@export
def hx_ff_heat_transfer_batch(
    n: Int,
    eff_ptr: Int,
    c_hot_ptr: Int,
    c_cold_ptr: Int,
    t_hot_in_ptr: Int,
    t_cold_in_ptr: Int,
    out_q_ptr: Int,
) -> None:
    """Compute heat transfer rate for N fluid-to-fluid HX elements.

    q = eff * C_min * (T_hot_in - T_cold_in), guarded to q >= 0.

    Parameters
    ----------
    n             : number of HX elements
    eff_ptr       : float64[n]  effectiveness (dimensionless)
    c_hot_ptr     : float64[n]  hot-side heat-capacity flow (W/K)
    c_cold_ptr    : float64[n]  cold-side heat-capacity flow (W/K)
    t_hot_in_ptr  : float64[n]  hot-side inlet temperature (°C or K)
    t_cold_in_ptr : float64[n]  cold-side inlet temperature (°C or K)
    out_q_ptr     : float64[n]  heat transfer rate output (W)
    """
    if n <= 0:
        return

    var eff = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=eff_ptr)
    var c_hot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_hot_ptr
    )
    var c_cold = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_cold_ptr
    )
    var t_hot_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_hot_in_ptr
    )
    var t_cold_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_cold_in_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_ptr
    )

    for i in range(n):
        var c_min = c_hot[i] if c_hot[i] < c_cold[i] else c_cold[i]
        var dt = t_hot_in[i] - t_cold_in[i]
        var q = eff[i] * c_min * dt
        out_q[i] = q if q > 0.0 else 0.0


@export
def hx_ff_outlet_temps_batch(
    n: Int,
    q_ptr: Int,
    c_hot_ptr: Int,
    c_cold_ptr: Int,
    t_hot_in_ptr: Int,
    t_cold_in_ptr: Int,
    out_t_hot_out_ptr: Int,
    out_t_cold_out_ptr: Int,
) -> None:
    """Compute outlet temperatures for N fluid-to-fluid HX elements.

    T_hot_out  = T_hot_in  - q / max(1e-6, C_hot)
    T_cold_out = T_cold_in + q / max(1e-6, C_cold)

    Parameters
    ----------
    n                  : number of HX elements
    q_ptr              : float64[n]  heat transfer rate (W)
    c_hot_ptr          : float64[n]  hot-side heat-capacity flow (W/K)
    c_cold_ptr         : float64[n]  cold-side heat-capacity flow (W/K)
    t_hot_in_ptr       : float64[n]  hot-side inlet temperature (°C or K)
    t_cold_in_ptr      : float64[n]  cold-side inlet temperature (°C or K)
    out_t_hot_out_ptr  : float64[n]  hot-side outlet temperature output
    out_t_cold_out_ptr : float64[n]  cold-side outlet temperature output
    """
    if n <= 0:
        return

    var q = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=q_ptr)
    var c_hot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_hot_ptr
    )
    var c_cold = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_cold_ptr
    )
    var t_hot_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_hot_in_ptr
    )
    var t_cold_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_cold_in_ptr
    )
    var out_t_hot_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_hot_out_ptr
    )
    var out_t_cold_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_cold_out_ptr
    )

    for i in range(n):
        var c_h = c_hot[i] if c_hot[i] > CMIN_GUARD else CMIN_GUARD
        var c_c = c_cold[i] if c_cold[i] > CMIN_GUARD else CMIN_GUARD
        out_t_hot_out[i] = t_hot_in[i] - q[i] / c_h
        out_t_cold_out[i] = t_cold_in[i] + q[i] / c_c


@export
def hx_ff_free_cooling_check_batch(
    n: Int,
    t_hot_in_ptr: Int,
    t_cold_in_ptr: Int,
    t_cold_setpoint_ptr: Int,
    out_active_ptr: Int,
) -> None:
    """Check free-cooling (economizer) mode for N fluid-to-fluid HX elements.

    Active = 1.0 if T_cold_in < T_cold_setpoint AND T_hot_in > T_cold_in, else 0.0.

    Parameters
    ----------
    n                   : number of HX elements
    t_hot_in_ptr        : float64[n]  hot-side inlet temperature (°C or K)
    t_cold_in_ptr       : float64[n]  cold-side inlet temperature (°C or K)
    t_cold_setpoint_ptr : float64[n]  cold-side cooling setpoint temperature
    out_active_ptr      : float64[n]  1.0 if free cooling active, else 0.0
    """
    if n <= 0:
        return

    var t_hot_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_hot_in_ptr
    )
    var t_cold_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_cold_in_ptr
    )
    var t_cold_setpoint = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_cold_setpoint_ptr
    )
    var out_active = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_active_ptr
    )

    for i in range(n):
        var cold_below_setpoint = t_cold_in[i] < t_cold_setpoint[i]
        var hot_above_cold = t_hot_in[i] > t_cold_in[i]
        out_active[i] = 1.0 if cold_below_setpoint and hot_above_cold else 0.0


@export
def hx_ff_full_step_batch(
    n: Int,
    ua_ptr: Int,
    c_hot_ptr: Int,
    c_cold_ptr: Int,
    t_hot_in_ptr: Int,
    t_cold_in_ptr: Int,
    flow_type_ptr: Int,
    out_q_ptr: Int,
    out_t_hot_out_ptr: Int,
    out_t_cold_out_ptr: Int,
    out_eff_ptr: Int,
) -> None:
    """Combined NTU → eff → q → outlet temps in one pass for N HX elements.

    Combines hx_ff_ntu_effectiveness_batch, hx_ff_heat_transfer_batch, and
    hx_ff_outlet_temps_batch into a single FFI round trip for performance.

    Parameters
    ----------
    n                  : number of HX elements
    ua_ptr             : float64[n]  overall conductance UA (W/K)
    c_hot_ptr          : float64[n]  hot-side heat-capacity flow (W/K)
    c_cold_ptr         : float64[n]  cold-side heat-capacity flow (W/K)
    t_hot_in_ptr       : float64[n]  hot-side inlet temperature (°C or K)
    t_cold_in_ptr      : float64[n]  cold-side inlet temperature (°C or K)
    flow_type_ptr      : float64[n]  0.0=counterflow, 1.0=parallel, 2.0=crossflow
    out_q_ptr          : float64[n]  heat transfer rate output (W)
    out_t_hot_out_ptr  : float64[n]  hot-side outlet temperature output
    out_t_cold_out_ptr : float64[n]  cold-side outlet temperature output
    out_eff_ptr        : float64[n]  effectiveness output (dimensionless)
    """
    if n <= 0:
        return

    var ua = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=ua_ptr)
    var c_hot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_hot_ptr
    )
    var c_cold = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_cold_ptr
    )
    var t_hot_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_hot_in_ptr
    )
    var t_cold_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_cold_in_ptr
    )
    var flow_type = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=flow_type_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_ptr
    )
    var out_t_hot_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_hot_out_ptr
    )
    var out_t_cold_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_cold_out_ptr
    )
    var out_eff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_eff_ptr
    )

    for i in range(n):
        var c_h = c_hot[i]
        var c_c = c_cold[i]
        var t_hi = t_hot_in[i]
        var t_ci = t_cold_in[i]

        # NTU → effectiveness
        var eff = _ntu_eff_scalar(ua[i], c_h, c_c, flow_type[i])
        out_eff[i] = eff

        # heat transfer
        var c_min = c_h if c_h < c_c else c_c
        var dt = t_hi - t_ci
        var q = eff * c_min * dt
        q = q if q > 0.0 else 0.0
        out_q[i] = q

        # outlet temperatures
        var c_h_safe = c_h if c_h > CMIN_GUARD else CMIN_GUARD
        var c_c_safe = c_c if c_c > CMIN_GUARD else CMIN_GUARD
        out_t_hot_out[i] = t_hi - q / c_h_safe
        out_t_cold_out[i] = t_ci + q / c_c_safe

@export
def awhp_cop_batch(
    n: Int,
    cop_ref_ptr: Int,
    t_load_out_ptr: Int,
    t_src_in_ptr: Int,
    out_cop_ptr: Int,
) -> None:
    """Batched COP evaluation for N air-to-water heat pump units.

    Applies the biquadratic EIR correction to the reference COP:

      dt_load[i] = t_load_out[i] - T_REF_LOAD   (T_REF_LOAD = 35 °C)
      dt_src[i]  = t_src_in[i]  - T_REF_SRC    (T_REF_SRC  =  7 °C)
      cop[i]     = clamp(cop_ref[i] * correction(dt_load, dt_src),
                         COP_MIN=0.5, COP_MAX=10.0)

    Reads (length n, float64):
      cop_ref_ptr   : rated COP at reference conditions [-]
      t_load_out_ptr: load-side outlet temperature [°C]
      t_src_in_ptr  : source-side (outdoor air) inlet temperature [°C]

    Writes (length n, float64):
      out_cop_ptr   : corrected COP, clamped to [COP_MIN, COP_MAX]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var cop_ref = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_ref_ptr
    )
    var t_load_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_load_out_ptr
    )
    var t_src_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_src_in_ptr
    )
    var out_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_ptr
    )

    for i in range(n):
        var dt_load = t_load_out[i] - T_REF_LOAD
        var dt_src = t_src_in[i] - T_REF_SRC
        var cop_raw = cop_ref[i] * _cop_correction(dt_load, dt_src)
        out_cop[i] = max(COP_MIN, min(COP_MAX, cop_raw))


@export
def awhp_heating_batch(
    n: Int,
    cop_ref_ptr: Int,
    cap_ref_ptr: Int,
    t_load_in_ptr: Int,
    t_load_out_ptr: Int,
    t_src_in_ptr: Int,
    m_dot_load_ptr: Int,
    out_cap_ptr: Int,
    out_power_ptr: Int,
    out_cop_ptr: Int,
    out_t_load_out_ptr: Int,
) -> None:
    """Full batched heating step for N air-to-water heat pump units.

    For each unit i, evaluates:

      dt_load[i] = t_load_out[i] - T_REF_LOAD
      dt_src[i]  = t_src_in[i]  - T_REF_SRC

      cop[i] = clamp(cop_ref[i] * (A0 + A1*dt_load + A2*dt_load^2
                                        + A3*dt_src  + A4*dt_src^2
                                        + A5*dt_load*dt_src),
                     COP_MIN, COP_MAX)

      cap[i] = max(0.0, cap_ref[i] * (B0 + B1*dt_load + B2*dt_src))

      power[i]          = cap[i] / max(COP_MIN, cop[i])
      t_load_out_act[i] = t_load_in[i]
                          + cap[i] / max(MIN_MDOTCP, m_dot_load[i] * CP_WATER)

    Reads (length n, float64):
      cop_ref_ptr   : rated COP at reference conditions [-]
      cap_ref_ptr   : rated heating capacity [W]
      t_load_in_ptr : load-side entering water temperature [°C]
      t_load_out_ptr: load-side target/design outlet temperature [°C]
                      (used for curve evaluation, not the computed actual)
      t_src_in_ptr  : source-side (outdoor air) inlet temperature [°C]
      m_dot_load_ptr: load-side water mass flow rate [kg/s]

    Writes (length n, float64):
      out_cap_ptr        : corrected heating capacity [W]
      out_power_ptr      : compressor power draw [W]
      out_cop_ptr        : corrected COP [-]
      out_t_load_out_ptr : actual load-side outlet temperature [°C]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var cop_ref = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_ref_ptr
    )
    var cap_ref = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_ref_ptr
    )
    var t_load_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_load_in_ptr
    )
    var t_load_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_load_out_ptr
    )
    var t_src_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_src_in_ptr
    )
    var m_dot_load = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_load_ptr
    )
    var out_cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cap_ptr
    )
    var out_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_ptr
    )
    var out_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_ptr
    )
    var out_t_load_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_load_out_ptr
    )

    for i in range(n):
        # -- Temperature deltas from reference conditions --------------------
        var dt_load = t_load_out[i] - T_REF_LOAD
        var dt_src = t_src_in[i] - T_REF_SRC

        # -- COP with biquadratic correction, clamped -----------------------
        var cop_raw = cop_ref[i] * _cop_correction(dt_load, dt_src)
        var cop = max(COP_MIN, min(COP_MAX, cop_raw))

        # -- Capacity with linear correction, floored at zero ---------------
        var cap_raw = cap_ref[i] * (B0 + B1 * dt_load + B2 * dt_src)
        var cap = max(0.0, cap_raw)

        # -- Power draw and load-side outlet temperature --------------------
        var power = cap / max(COP_MIN, cop)
        var mdotcp = max(MIN_MDOTCP, m_dot_load[i] * CP_WATER)
        var t_out_act = t_load_in[i] + cap / mdotcp

        out_cap[i] = cap
        out_power[i] = power
        out_cop[i] = cop
        out_t_load_out[i] = t_out_act

var raw = cop_ref * (
        A0
        + A1 * t_load_norm
        + A2 * t_src_norm
        + A3 * t_load_norm * t_load_norm
        + A4 * t_src_norm * t_src_norm
    )
    return max(COP_MIN, min(COP_MAX, raw))


# ---------------------------------------------------------------------------
# Helper: compute cooling COP for a single unit
# ---------------------------------------------------------------------------


@always_inline
def _cop_cool(
    cop_ref: Float64, t_load_norm: Float64, t_src_norm: Float64
) -> Float64:
    """Cooling COP via 3-term polynomial, clamped to [COP_MIN, COP_MAX]."""
    var raw = cop_ref * (B0 + B1 * t_load_norm + B2 * t_src_norm)
    return max(COP_MIN, min(COP_MAX, raw))


