@export
def wwhp_cop_batch(
    n: Int,
    cop_ref_heat_ptr: Int,
    t_load_in_ptr: Int,
    t_src_in_ptr: Int,
    out_cop_heat_ptr: Int,
    out_cop_cool_ptr: Int,
) -> None:
    """Batched COP calculation for N water-to-water heat pumps.

    Computes heating and cooling COP using the EIR polynomial model for each
    heat pump in the batch. Uses default polynomial coefficients.

    Reads (length n):
      - cop_ref_heat_ptr : Float64[n]  rated heating COP [-]
      - t_load_in_ptr    : Float64[n]  load-side entering temperature (K)
      - t_src_in_ptr     : Float64[n]  source-side entering temperature (K)

    Writes (length n):
      - out_cop_heat_ptr : Float64[n]  corrected heating COP [-]
      - out_cop_cool_ptr : Float64[n]  corrected cooling COP (uses cop_ref_heat
                                       as cop_ref_cool proxy) [-]

    Note: cop_ref_heat is reused as cop_ref_cool for the cooling polynomial.
    """
    var cop_ref_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_ref_heat_ptr
    )
    var t_load_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_load_in_ptr
    )
    var t_src_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_src_in_ptr
    )
    var out_cop_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_heat_ptr
    )
    var out_cop_cool = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_cool_ptr
    )

    for i in range(n):
        var tl_norm = t_load_in[i] / T_REF
        var ts_norm = t_src_in[i] / T_REF
        out_cop_heat[i] = _cop_heat(cop_ref_heat[i], tl_norm, ts_norm)
        out_cop_cool[i] = _cop_cool(cop_ref_heat[i], tl_norm, ts_norm)


