@export
def wwhp_heating_batch(
    n: Int,
    cop_ref_heat_ptr: Int,
    t_load_in_ptr: Int,
    t_src_in_ptr: Int,
    q_load_ptr: Int,
    m_dot_load_ptr: Int,
    m_dot_src_ptr: Int,
    out_power_ptr: Int,
    out_cop_ptr: Int,
    out_t_load_out_ptr: Int,
    out_t_src_out_ptr: Int,
) -> None:
    """Batched full heating-mode step for N water-to-water heat pumps.

    Evaluates COP, compressor power, and load/source outlet temperatures for
    each heat pump in the batch operating in heating mode.

    Guard: q_load[i] <= 0 → power = 0, outlet temperatures equal inlet.

    Reads (length n):
      - cop_ref_heat_ptr  : Float64[n]  rated heating COP [-]
      - t_load_in_ptr     : Float64[n]  load-side entering temperature (K)
      - t_src_in_ptr      : Float64[n]  source-side entering temperature (K)
      - q_load_ptr        : Float64[n]  load-side heat transfer demand (W)
      - m_dot_load_ptr    : Float64[n]  load-side mass flow rate (kg/s)
      - m_dot_src_ptr     : Float64[n]  source-side mass flow rate (kg/s)

    Writes (length n):
      - out_power_ptr     : Float64[n]  compressor electrical power (W)
      - out_cop_ptr       : Float64[n]  corrected heating COP [-]
      - out_t_load_out_ptr: Float64[n]  load-side outlet temperature (K)
      - out_t_src_out_ptr : Float64[n]  source-side outlet temperature (K)
    """
    var cop_ref_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cop_ref_heat_ptr
    )
    var t_load_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_load_in_ptr
    )
    var t_src_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_src_in_ptr
    )
    var q_load = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_load_ptr
    )
    var m_dot_load = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_load_ptr
    )
    var m_dot_src = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_src_ptr
    )
    var out_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_ptr
    )
    var out_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_ptr
    )
    var out_t_load_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_load_out_ptr
    )
    var out_t_src_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_src_out_ptr
    )

    for i in range(n):
        var q = q_load[i]

        # Guard: no heating demand → zero power, pass-through temperatures.
        if q <= 0.0:
            out_power[i] = 0.0
            out_cop[i] = COP_MIN
            out_t_load_out[i] = t_load_in[i]
            out_t_src_out[i] = t_src_in[i]
            continue

        var tl_norm = t_load_in[i] / T_REF
        var ts_norm = t_src_in[i] / T_REF
        var cop = _cop_heat(cop_ref_heat[i], tl_norm, ts_norm)

        var power = q / cop
        var q_src = q - power

        var mdotcp_load = max(MIN_MDOTCP, m_dot_load[i] * CP_WATER)
        var mdotcp_src = max(MIN_MDOTCP, m_dot_src[i] * CP_WATER)

        out_power[i] = power
        out_cop[i] = cop
        out_t_load_out[i] = t_load_in[i] + q / mdotcp_load
        out_t_src_out[i] = t_src_in[i] - q_src / mdotcp_src

from std.math import max, min

comptime EPS_RATED: Float64 = 0.80  # rated sensible effectiveness [-]
comptime RPM_RATED: Float64 = 20.0  # rated wheel rotation speed [rpm]
comptime RPM_MAX: Float64 = 30.0  # maximum allowable rotation speed [rpm]
comptime MDOT_MIN: Float64 = 0.001  # minimum mass-flow rate [kg/s]
comptime MDOT_MAX: Float64 = 100.0  # maximum mass-flow rate [kg/s]
comptime EPS_MAX: Float64 = 0.95  # maximum allowable effectiveness [-]
comptime FLOW_IMBALANCE_COEFF: Float64 = 0.3  # flow imbalance penalty coefficient [-]
comptime LAT_MAX: Float64 = 1.0  # maximum latent/sensible ratio [-]


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=Int(addr))


@export
def wheel_sensible_effectiveness_batch(
    n: Int,
    rpm_ptr: Int,
    m_dot_supply_ptr: Int,
    m_dot_exhaust_ptr: Int,
    out_eps_s_ptr: Int,
) -> None:
    """Sensible effectiveness of N heat-recovery wheels.

    For each wheel i:
        rpm_c        = clamp(rpm[i], 0, RPM_MAX)
        m_sup_c      = clamp(m_dot_supply[i],  MDOT_MIN, MDOT_MAX)
        m_exh_c      = clamp(m_dot_exhaust[i], MDOT_MIN, MDOT_MAX)
        speed_factor = clamp(rpm_c / RPM_RATED, 0, 1)
        min_mdot     = min(m_sup_c, m_exh_c)
        max_mdot     = max(m_sup_c, m_exh_c)
        flow_corr    = 1 - FLOW_IMBALANCE_COEFF * max(0, 1 - min_mdot/max_mdot)
        eps_s[i]     = clamp(EPS_RATED * speed_factor * flow_corr, 0, EPS_MAX)

    Arguments:
      - `n`                — number of wheels.
      - `rpm_ptr`          — float64[N] wheel rotation speed (rpm).
      - `m_dot_supply_ptr` — float64[N] supply-side mass-flow rate (kg/s).
      - `m_dot_exhaust_ptr`— float64[N] exhaust-side mass-flow rate (kg/s).
      - `out_eps_s_ptr`    — float64[N] sensible effectiveness output [-].

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var rpm = _ptr(rpm_ptr)
    var m_sup = _ptr(m_dot_supply_ptr)
    var m_exh = _ptr(m_dot_exhaust_ptr)
    var out_eps_s = _ptr(out_eps_s_ptr)

    for i in range(n):
        # Clamp inputs
        var rpm_c = rpm[i]
        if rpm_c < 0.0:
            rpm_c = 0.0
        elif rpm_c > RPM_MAX:
            rpm_c = RPM_MAX

        var ms = m_sup[i]
        if ms < MDOT_MIN:
            ms = MDOT_MIN
        elif ms > MDOT_MAX:
            ms = MDOT_MAX

        var me = m_exh[i]
        if me < MDOT_MIN:
            me = MDOT_MIN
        elif me > MDOT_MAX:
            me = MDOT_MAX

        # Speed factor — clamp to [0, 1]
        var speed_factor = rpm_c / RPM_RATED
        if speed_factor > 1.0:
            speed_factor = 1.0

        # Flow imbalance correction
        var min_mdot = min(ms, me)
        var max_mdot = max(ms, me)
        var imbalance_ratio = 1.0 - min_mdot / max_mdot
        if imbalance_ratio < 0.0:
            imbalance_ratio = 0.0
        var flow_corr = 1.0 - FLOW_IMBALANCE_COEFF * imbalance_ratio

        # Sensible effectiveness
        var eps_s = EPS_RATED * speed_factor * flow_corr

        # Clamp to [0, EPS_MAX]
        if eps_s < 0.0:
            eps_s = 0.0
        elif eps_s > EPS_MAX:
            eps_s = EPS_MAX

        out_eps_s[i] = eps_s


@export
def wheel_latent_effectiveness_batch(
    n: Int,
    eps_s_ptr: Int,
    latent_factor_ptr: Int,
    out_eps_l_ptr: Int,
) -> None:
    """Latent effectiveness of N enthalpy wheels (fraction of sensible).

    For each wheel i:
        lat_f[i]  = clamp(latent_factor[i], 0, LAT_MAX)
        eps_l[i]  = clamp(eps_s[i] * lat_f[i], 0, eps_s[i])

    Latent effectiveness cannot exceed sensible effectiveness.

    Arguments:
      - `n`                — number of wheels.
      - `eps_s_ptr`        — float64[N] sensible effectiveness [-].
      - `latent_factor_ptr`— float64[N] latent/sensible ratio [-].
      - `out_eps_l_ptr`    — float64[N] latent effectiveness output [-].

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var eps_s = _ptr(eps_s_ptr)
    var lat_f = _ptr(latent_factor_ptr)
    var out_eps_l = _ptr(out_eps_l_ptr)

    for i in range(n):
        # Clamp latent factor to [0, LAT_MAX]
        var lf = lat_f[i]
        if lf < 0.0:
            lf = 0.0
        elif lf > LAT_MAX:
            lf = LAT_MAX

        var es = eps_s[i]
        var eps_l = es * lf

        # Clamp to [0, eps_s] — latent cannot exceed sensible
        if eps_l < 0.0:
            eps_l = 0.0
        elif eps_l > es:
            eps_l = es

        out_eps_l[i] = eps_l

from std.math import max, min

# Duct conductance bounds [W/K]
comptime UA_MIN: Float64 = 0.0
comptime UA_MAX: Float64 = 1e5
# Heat transfer limit [W]
comptime Q_MAX: Float64 = 1e7
# Temperature bounds [°C]
comptime T_MIN: Float64 = -50.0
comptime T_MAX: Float64 = 80.0
# Specific heat of air [J/(kg·K)]
comptime CP_AIR: Float64 = 1006.0
# Mass flow rate bounds [kg/s]
comptime MDOT_MIN: Float64 = 1e-4
comptime MDOT_MAX: Float64 = 100.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def duct_heat_gain_batch(
    n: Int,
    ua_duct_ptr: Int,
    t_air_ptr: Int,
    t_surround_ptr: Int,
    out_q_gain_ptr: Int,
) -> None:
    """Compute HVAC duct heat gain from surrounding unconditioned space.

    For each duct section the heat gain is:

        ua_duct_eff  = clamp(ua_duct[i], UA_MIN, UA_MAX)
        t_air_eff    = clamp(t_air[i],   T_MIN,  T_MAX)
        t_surr_eff   = clamp(t_surround[i], T_MIN, T_MAX)
        q_gain[i]    = ua_duct_eff * (t_surr_eff - t_air_eff)
        out_q_gain[i]= clamp(q_gain[i], -Q_MAX, Q_MAX)

    A positive result means the surrounding space is driving heat into the
    duct air (heat gain); negative means heat is leaving the duct (heat loss).

    Parameters
    ----------
    n             : number of duct sections
    ua_duct_ptr   : Float64[n]  duct UA conductance (W/K)
    t_air_ptr     : Float64[n]  supply/return air temperature (°C)
    t_surround_ptr: Float64[n]  surrounding unconditioned space temperature (°C)
    out_q_gain_ptr: Float64[n]  heat gain to duct air (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var ua_duct = _ptr(ua_duct_ptr)
    var t_air = _ptr(t_air_ptr)
    var t_surround = _ptr(t_surround_ptr)
    var out_q_gain = _ptr(out_q_gain_ptr)

    for i in range(n):
        var ua = max(UA_MIN, min(UA_MAX, ua_duct[i]))
        var ta = max(T_MIN, min(T_MAX, t_air[i]))
        var ts = max(T_MIN, min(T_MAX, t_surround[i]))
        var q = ua * (ts - ta)
        out_q_gain[i] = max(-Q_MAX, min(Q_MAX, q))


@export
def duct_leaving_temp_batch(
    n: Int,
    t_supply_ptr: Int,
    q_gain_ptr: Int,
    m_dot_ptr: Int,
    out_t_leaving_ptr: Int,
) -> None:
    """Compute air temperature leaving a duct section after heat exchange.

    For each duct section:

        m_dot_eff      = clamp(m_dot[i], MDOT_MIN, MDOT_MAX)
        q_gain_eff     = clamp(q_gain[i], -Q_MAX, Q_MAX)
        t_leaving[i]   = t_supply[i] + q_gain_eff / (m_dot_eff * CP_AIR)
        out_t_leaving[i] = clamp(t_leaving[i], T_MIN, T_MAX)

    Parameters
    ----------
    n                : number of duct sections
    t_supply_ptr     : Float64[n]  entering air temperature (°C)
    q_gain_ptr       : Float64[n]  heat gain to duct air (W)
    m_dot_ptr        : Float64[n]  air mass flow rate (kg/s)
    out_t_leaving_ptr: Float64[n]  leaving air temperature (°C)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var t_supply = _ptr(t_supply_ptr)
    var q_gain = _ptr(q_gain_ptr)
    var m_dot = _ptr(m_dot_ptr)
    var out_t_leaving = _ptr(out_t_leaving_ptr)

    for i in range(n):
        var mdot = max(MDOT_MIN, min(MDOT_MAX, m_dot[i]))
        var qg = max(-Q_MAX, min(Q_MAX, q_gain[i]))
        var t_leave = t_supply[i] + qg / (mdot * CP_AIR)
        out_t_leaving[i] = max(T_MIN, min(T_MAX, t_leave))

@export
def hx_air_latent_batch(
    n: Int,
    w_supply_in_ptr: Int,
    w_exhaust_in_ptr: Int,
    m_dot_supply_ptr: Int,
    m_dot_exhaust_ptr: Int,
    lat_eff_75_ptr: Int,
    lat_eff_100_ptr: Int,
    ffraction_ptr: Int,
    out_q_latent_kg_s_ptr: Int,
    out_w_supply_out_ptr: Int,
) -> None:
    """Batch latent-side energy balance for the air-to-air HX.

    Arguments:
      - `n`                      — number of HX records.
      - `w_supply_in_ptr`        — Float64[n] supply humidity ratio in (kg/kg).
      - `w_exhaust_in_ptr`       — Float64[n] exhaust humidity ratio in (kg/kg).
      - `m_dot_supply_ptr`       — Float64[n] supply mass flow (kg/s).
      - `m_dot_exhaust_ptr`      — Float64[n] exhaust mass flow (kg/s).
      - `lat_eff_75_ptr`         — Float64[n] latent effectiveness at 75 %
                                   airflow (post-curve).
      - `lat_eff_100_ptr`        — Float64[n] latent effectiveness at 100 %
                                   airflow (post-curve).
      - `ffraction_ptr`          — Float64[n] supply airflow fraction.
      - `out_q_latent_kg_s_ptr`  — Float64[n] output: moisture transfer rate
                                   (kg_water / s) — positive when moisture
                                   moves from supply into exhaust.
      - `out_w_supply_out_ptr`   — Float64[n] output: supply humidity ratio
                                   leaving the HX (kg/kg).

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var w_supply_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_supply_in_ptr
    )
    var w_exhaust_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_exhaust_in_ptr
    )
    var m_dot_supply = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_supply_ptr
    )
    var m_dot_exhaust = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_exhaust_ptr
    )
    var lat_eff_75 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=lat_eff_75_ptr
    )
    var lat_eff_100 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=lat_eff_100_ptr
    )
    var ffraction = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=ffraction_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_latent_kg_s_ptr
    )
    var out_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_w_supply_out_ptr
    )

    for i in range(n):
        var m_s = m_dot_supply[i]
        var m_e = m_dot_exhaust[i]
        var m_min = m_s if m_s < m_e else m_e
        var ff = ffraction[i]
        var e75 = lat_eff_75[i]
        var e100 = lat_eff_100[i]
        # Linear interpolation between the 75 % and 100 % airflow points,
        # parameterised on the supply-flow fraction. At ff = 0.75 returns
        # e75; at ff = 1.00 returns e100; extrapolates linearly outside.
        var eps_lat = e75 + (ff - 0.75) / 0.25 * (e100 - e75)
        var dw = w_supply_in[i] - w_exhaust_in[i]
        var q = eps_lat * m_min * dw
        out_q[i] = q
        # Guard against divide-by-zero when the supply stream is off; in
        # that case EnergyPlus treats the HX as bypassed.
        if m_s > 0.0:
            out_w[i] = w_supply_in[i] - q / m_s
        else:
            out_w[i] = w_supply_in[i]

comptime ONE: Float64 = 1.0
comptime FF_LO: Float64 = 0.75
comptime FF_SPAN: Float64 = 0.25  # 1.0 - 0.75


@export
def hx_air_sensible_batch(
    n: Int,
    t_supply_in_ptr: Int,
    t_exhaust_in_ptr: Int,
    m_dot_supply_ptr: Int,
    m_dot_exhaust_ptr: Int,
    cp_supply_ptr: Int,
    cp_exhaust_ptr: Int,
    eff_75_ptr: Int,
    eff_100_ptr: Int,
    ffraction_ptr: Int,
    out_q_sensible_w_ptr: Int,
    out_t_supply_out_ptr: Int,
) -> None:
    """Evaluate N sensible HX elements in one FFI round trip.

    Writes `q_sensible_w[n]` and `t_supply_out[n]` (°C). No-op for n == 0.
    Guards against zero supply heat-capacity flow by passing the inlet
    temperature through unchanged.
    """
    if n <= 0:
        return

    var t_sup_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_supply_in_ptr
    )
    var t_exh_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_exhaust_in_ptr
    )
    var m_sup = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_supply_ptr
    )
    var m_exh = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_exhaust_ptr
    )
    var cp_sup = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_supply_ptr
    )
    var cp_exh = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_exhaust_ptr
    )
    var e75 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eff_75_ptr
    )
    var e100 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=eff_100_ptr
    )
    var ff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=ffraction_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_sensible_w_ptr
    )
    var out_t = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_supply_out_ptr
    )

    for i in range(n):
        var ff_i = ff[i]
        var e75_i = e75[i]
        var e100_i = e100[i]

        var eps_75 = e75_i + ff_i * (ONE - e75_i)
        var eps_100 = e100_i + ff_i * (ONE - e100_i)
        var eps = eps_75 + (eps_100 - eps_75) * (ff_i - FF_LO) / FF_SPAN

        var c_sup = m_sup[i] * cp_sup[i]
        var c_exh = m_exh[i] * cp_exh[i]
        var c_min = c_sup if c_sup < c_exh else c_exh

        var dt = t_sup_in[i] - t_exh_in[i]
        var q = eps * c_min * dt
        out_q[i] = q
        if c_sup > 0.0:
            out_t[i] = t_sup_in[i] + q / c_sup
        else:
            out_t[i] = t_sup_in[i]

from std.math import min, max


# Hardware-specific SIMD width — tuned for the build target CPU.
comptime W: Int = 8


@always_inline
def _ptr_f64(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _ptr_i8(addr: Int) -> UnsafePointer[Int8, MutAnyOrigin]:
    """Reconstruct a typed Int8 pointer from a raw int64 address."""
    return UnsafePointer[Int8, MutAnyOrigin](unsafe_from_address=addr)


@export
def solve_ideal_loads_batch(
    n: Int,
    t_zone_c_ptr: Int,
    t_heating_sp_ptr: Int,
    t_cooling_sp_ptr: Int,
    ua_w_per_k_ptr: Int,
    max_heat_w_ptr: Int,
    max_cool_w_ptr: Int,
    has_heat_cap_ptr: Int,
    has_cool_cap_ptr: Int,
    out_q_hvac_ptr: Int,
):
    """Batched evaluation of `solve_ideal_loads` over N zones.

    Arguments:
      - `n`                — number of zones in the batch.
      - `t_zone_c_ptr`     — raw int64 addr of `Float64[N]` zone-air temps [°C].
      - `t_heating_sp_ptr` — raw int64 addr of `Float64[N]` heating setpoints [°C].
      - `t_cooling_sp_ptr` — raw int64 addr of `Float64[N]` cooling setpoints [°C].
      - `ua_w_per_k_ptr`   — raw int64 addr of `Float64[N]` UA values [W/K].
      - `max_heat_w_ptr`   — raw int64 addr of `Float64[N]` heating capacity caps.
      - `max_cool_w_ptr`   — raw int64 addr of `Float64[N]` cooling capacity caps.
      - `has_heat_cap_ptr` — raw int64 addr of `Int8[N]`; nonzero ⇒ clamp heating.
      - `has_cool_cap_ptr` — raw int64 addr of `Int8[N]`; nonzero ⇒ clamp cooling.
      - `out_q_hvac_ptr`   — raw int64 addr of `Float64[N]` output buffer.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var tz = _ptr_f64(t_zone_c_ptr)
    var thsp = _ptr_f64(t_heating_sp_ptr)
    var tcsp = _ptr_f64(t_cooling_sp_ptr)
    var ua_arr = _ptr_f64(ua_w_per_k_ptr)
    var maxh = _ptr_f64(max_heat_w_ptr)
    var maxc = _ptr_f64(max_cool_w_ptr)
    var hashc = _ptr_i8(has_heat_cap_ptr)
    var hasc = _ptr_i8(has_cool_cap_ptr)
    var out = _ptr_f64(out_q_hvac_ptr)

    # Vectorised body: process W zones per iteration.
    # Data layout is already SoA — contiguous indexed access maps to SIMD loads.
    var chunk_count = n // W
    var i: Int = 0
    while i < chunk_count:
        # Base offset for this chunk
        var base = i * W

        # ---- Load + compute into SIMD registers ----------------------------
        var t_simd = SIMD[DType.float64, W](0)
        var hsp_simd = SIMD[DType.float64, W](0)
        var csp_simd = SIMD[DType.float64, W](0)
        var k_simd = SIMD[DType.float64, W](0)
        var j: Int = 0
        while j < W:
            t_simd[j] = tz[base + j]
            hsp_simd[j] = thsp[base + j]
            csp_simd[j] = tcsp[base + j]
            k_simd[j] = ua_arr[base + j]
            j += 1

        # Both demands computed branchlessly (FMA).
        var q_heat = k_simd * (hsp_simd - t_simd)
        var q_cool = k_simd * (csp_simd - t_simd)

        # Branchless mode selection via SIMD masks + .select().
        # Mojo 0.26: comparisons are methods (.lt, .gt), not operators,
        # returning SIMD[DType.bool, W].
        var is_heat = t_simd.lt(hsp_simd)
        var is_cool = t_simd.gt(csp_simd)
        var zero_vec: SIMD[DType.float64, W] = SIMD[DType.float64, W](0)
        var result: SIMD[DType.float64, W] = is_cool.select(
            q_cool, is_heat.select(q_heat, zero_vec)
        )

        # --- heating clamp --------------------------------------------------
        var heat_flags = SIMD[DType.int32, W](0)
        var fj: Int = 0
        while fj < W:
            heat_flags[fj] = Int32(hashc[base + fj])
            fj += 1
        var heat_active = heat_flags.ne(SIMD[DType.int32, W](0)) & is_heat
        var max_h_vec = SIMD[DType.float64, W](0)
        var fk: Int = 0
        while fk < W:
            max_h_vec[fk] = maxh[base + fk]
            fk += 1
        result = heat_active.select(min(result, max_h_vec), result)

        # --- cooling clamp --------------------------------------------------
        var cool_flags = SIMD[DType.int32, W](0)
        var fj2: Int = 0
        while fj2 < W:
            cool_flags[fj2] = Int32(hasc[base + fj2])
            fj2 += 1
        var cool_active = cool_flags.ne(SIMD[DType.int32, W](0)) & is_cool
        var abs_q = max(result, -result)
        var neg_maxc_vec = SIMD[DType.float64, W](0)
        var fi: Int = 0
        while fi < W:
            var mc = maxc[base + fi]
            var aq = abs_q[fi]
            neg_maxc_vec[fi] = -(mc if mc < aq else aq)
            fi += 1
        result = cool_active.select(neg_maxc_vec, result)

        # ---- Store results back -------------------------------------------
        var jo: Int = 0
        while jo < W:
            out[base + jo] = result[jo]
            jo += 1

        i += 1

    # Scalar tail for the last n % W zones.
    var start_tail = chunk_count * W
    for idx in range(start_tail, n):
        var t = tz[idx]
        var hsp = thsp[idx]
        var csp = tcsp[idx]
        var k = ua_arr[idx]

        if t < hsp:
            # Heating branch: Q = UA · (T_sp − T_zone), positive.
            var q = k * (hsp - t)
            if Int(hashc[idx]) != 0:
                var cap = maxh[idx]
                if q > cap:
                    q = cap
            out[idx] = q
        elif t > csp:
            # Cooling branch: Q = UA · (T_sp − T_zone), negative. The Python
            # API receives `max_cool_w` as a positive magnitude and clamps at
            # `−max_cool_w` — same convention here.
            var q = k * (csp - t)
            if Int(hasc[idx]) != 0:
                var neg_cap = -maxc[idx]
                if q < neg_cap:
                    q = neg_cap
            out[idx] = q
        else:
            # Dead-band: thermostat in [heating_sp, cooling_sp] ⇒ no load.
            out[idx] = 0.0

@always_inline
def _abs(x: Float64) -> Float64:
    return -x if x < 0.0 else x


@export
def infil_modifier_batch(
    n: Int,
    design_flow_ptr: Int,
    schedule_value_ptr: Int,
    t_zone_ptr: Int,
    t_outdoor_ptr: Int,
    wind_speed_ptr: Int,
    a_ptr: Int,
    b_ptr: Int,
    c_ptr: Int,
    d_ptr: Int,
    out_m_dot_ptr: Int,
) -> None:
    """Batched `ZoneInfiltration:DesignFlowRate` polynomial modifier.

    Evaluates the per-zone instantaneous flow rate

        m_dot[i] = design_flow[i] * schedule_value[i]
                 * (a[i] + b[i] * |t_zone[i] - t_outdoor[i]|
                         + c[i] * v[i] + d[i] * v[i]**2)

    where `v[i] = max(0, wind_speed[i])` — wind speeds are clamped to
    non-negative the same way `ZoneInfiltrationDesignFlowRate.modifier`
    does on the Python side.

    All `*_ptr` arguments are raw int64 addresses of float64[n]
    C-contiguous arrays. `out_m_dot_ptr` is written in place. No-op when
    `n <= 0`.
    """
    if n <= 0:
        return

    var design_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_flow_ptr
    )
    var schedule_value = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_value_ptr
    )
    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var t_outdoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_ptr
    )
    var wind_speed = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wind_speed_ptr
    )
    var a = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=a_ptr)
    var b = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=b_ptr)
    var c = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c_ptr)
    var d = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=d_ptr)
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_m_dot_ptr
    )

    for i in range(n):
        var dt = _abs(t_zone[i] - t_outdoor[i])
        var v_raw = wind_speed[i]
        var v = v_raw if v_raw > 0.0 else 0.0
        var modifier = a[i] + b[i] * dt + c[i] * v + d[i] * v * v
        out[i] = design_flow[i] * schedule_value[i] * modifier

@always_inline
def _inside_solar_distribute(
    n: Int,
    flux_frac: UnsafePointer[Float64, MutAnyOrigin],
    shgc_extra_w: Float64,
    q_const: UnsafePointer[Float64, MutAnyOrigin],
):
    """Fused multiply-add: q_const[i] += shgc_extra_w * flux_frac[i]."""
    for i in range(n):
        q_const[i] += shgc_extra_w * flux_frac[i]


@export
def inside_solar_distribute_batch(
    n: Int,
    flux_frac_addr: Int,
    shgc_extra_w: Float64,
    q_const_addr: Int,
):
    """Distribute scalar shgc_extra_w (W) into per-surface q_const (W/m²).

    For each surface i:
        q_const[i] += shgc_extra_w * flux_frac[i]

    where flux_frac[i] = alpha_inside[i] / total_weight_sum (precomputed,
    units 1/m²), and total_weight_sum = sum_j(area_j * alpha_inside_j).

    Surfaces whose inside layer carries zero absorptance have flux_frac[i]==0
    and receive no increment (exact zero-contribution, not approximation).

    Parameters
    ----------
    n              Number of surfaces (== len(flux_frac) == len(q_const)).
    flux_frac_addr Address of Float64[n] precomputed per-surface fractions.
    shgc_extra_w   Total transmitted-window solar this timestep (W).
    q_const_addr   Address of Float64[n] q_const array to mutate in-place.
    """
    var flux_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=flux_frac_addr
    )
    var q_const = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_const_addr
    )
    _inside_solar_distribute(n, flux_frac, shgc_extra_w, q_const)


@export
def inside_solar_flux_frac_build(
    n: Int,
    area_addr: Int,
    alpha_inside_addr: Int,
    flux_frac_addr: Int,
    result_addr: Int,
):
    """Compute per-surface flux fractions from area and alpha_inside arrays.

    For each surface i, the weight is:
        w[i] = area[i] * alpha_inside[i]

    The normalised per-m² fraction is:
        flux_frac[i] = w[i] / (total_weight * area[i])
                     = alpha_inside[i] / total_weight

    This is the W/m² increment to q_const[i] for each 1 W of shgc_extra_w.

    Writes:
        flux_frac[i] for i in 0..n-1 (Float64[n] at flux_frac_addr).
        result[0]    = total_weight  (scalar; <= 0 signals all-zero case).

    When total_weight <= 0 (all-glass zone or all alpha_inside == 0),
    flux_frac is filled with zeros — the caller should fall back to the
    air-dump residual path (energy-conserving historical fallback).
    """
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_addr
    )
    var alpha = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=alpha_inside_addr
    )
    var flux_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=flux_frac_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    # Pass 1: accumulate total weight.
    var total_w: Float64 = 0.0
    for i in range(n):
        var w = area[i] * alpha[i]
        if w > 0.0:
            total_w += w

    result[0] = total_w

    if total_w <= 0.0:
        # All-glass or all-zero absorptance — write zero fracs.
        for i in range(n):
            flux_frac[i] = 0.0
        return

    # Pass 2: normalise.  flux_frac[i] = alpha[i] / total_w.
    # (area cancels: w[i]/(total_w*area[i]) = alpha[i]/total_w.)
    var inv_total = 1.0 / total_w
    for i in range(n):
        var a = alpha[i]
        if a > 0.0:
            flux_frac[i] = a * inv_total
        else:
            flux_frac[i] = 0.0

@always_inline
def _clamp_nonneg(x: Float64) -> Float64:
    """Clamp x to [0, ∞)."""
    return max(x, 0.0)


@export
def lighting_power_batch(
    n: Int,
    design_w_ptr: Int,
    schedule_frac_ptr: Int,
    dimming_frac_ptr: Int,
    out_q_lights_ptr: Int,
) -> None:
    """Total dimmable lighting power for N zones.

    Computes q_lights[i] = max(0, design_w[i]) * clamp(schedule_frac[i], 0, 1)
                                                * clamp(dimming_frac[i], 0, 1).

    Reads (length n):
      - design_w_ptr       : Float64[n]  design lighting power (W)
      - schedule_frac_ptr  : Float64[n]  schedule multiplier [0, 1]
      - dimming_frac_ptr   : Float64[n]  dimming multiplier [0, 1]

    Writes (length n):
      - out_q_lights_ptr   : Float64[n]  total lighting power (W)
    """
    var design_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_w_ptr
    )
    var schedule_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_frac_ptr
    )
    var dimming_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=dimming_frac_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_lights_ptr
    )

    for i in range(n):
        var w = _clamp_nonneg(design_w[i])
        var sched = _clamp01(schedule_frac[i])
        var dim = _clamp01(dimming_frac[i])
        out_q[i] = w * sched * dim


@export
def lighting_heat_gain_batch(
    n: Int,
    design_w_ptr: Int,
    schedule_frac_ptr: Int,
    dimming_frac_ptr: Int,
    radiant_frac_ptr: Int,
    visible_frac_ptr: Int,
    return_air_frac_ptr: Int,
    lumens_per_watt_ptr: Int,
    zone_area_m2_ptr: Int,
    out_q_radiant_ptr: Int,
    out_q_visible_ptr: Int,
    out_q_convective_ptr: Int,
    out_q_return_ptr: Int,
    out_illuminance_ptr: Int,
) -> None:
    """Full lighting heat gain split for N zones.

    For each zone:
        q_lights     = max(0, design_w) * clamp(schedule_frac, 0, 1)
                                        * clamp(dimming_frac, 0, 1)
        q_radiant    = q_lights * radiant_frac
        q_visible    = q_lights * visible_frac
        q_return_air = q_lights * return_air_frac
        q_convective = max(0, q_lights * (1 - radiant_frac
                                            - visible_frac
                                            - return_air_frac))
        illuminance  = q_lights * lumens_per_watt
                       / max(MIN_AREA, zone_area_m2)   [lux]

    Reads (length n):
      - design_w_ptr        : Float64[n]  design lighting power (W)
      - schedule_frac_ptr   : Float64[n]  schedule multiplier [0, 1]
      - dimming_frac_ptr    : Float64[n]  dimming multiplier [0, 1]
      - radiant_frac_ptr    : Float64[n]  fraction radiated to zone surfaces
      - visible_frac_ptr    : Float64[n]  fraction leaving as visible light
      - return_air_frac_ptr : Float64[n]  fraction to return-air plenum
      - lumens_per_watt_ptr : Float64[n]  luminous efficacy (lm/W)
      - zone_area_m2_ptr    : Float64[n]  zone floor area (m²)

    Writes (length n):
      - out_q_radiant_ptr   : Float64[n]  radiant heat gain (W)
      - out_q_visible_ptr   : Float64[n]  visible heat gain (W)
      - out_q_convective_ptr: Float64[n]  convective heat gain (W)
      - out_q_return_ptr    : Float64[n]  return-air heat gain (W)
      - out_illuminance_ptr : Float64[n]  zone illuminance (lux)
    """
    var design_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_w_ptr
    )
    var schedule_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_frac_ptr
    )
    var dimming_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=dimming_frac_ptr
    )
    var radiant_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=radiant_frac_ptr
    )
    var visible_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=visible_frac_ptr
    )
    var return_air_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=return_air_frac_ptr
    )
    var lumens_per_watt = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=lumens_per_watt_ptr
    )
    var zone_area_m2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=zone_area_m2_ptr
    )
    var out_q_radiant = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_radiant_ptr
    )
    var out_q_visible = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_visible_ptr
    )
    var out_q_convective = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_convective_ptr
    )
    var out_q_return = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_return_ptr
    )
    var out_illuminance = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_illuminance_ptr
    )

    for i in range(n):
        # Total attenuated lighting power with design-power guard.
        var w = _clamp_nonneg(design_w[i])
        var sched = _clamp01(schedule_frac[i])
        var dim = _clamp01(dimming_frac[i])
        var q = w * sched * dim

        # Heat gain fractions.
        var f_rad = radiant_frac[i]
        var f_vis = visible_frac[i]
        var f_ret = return_air_frac[i]

        out_q_radiant[i] = q * f_rad
        out_q_visible[i] = q * f_vis
        out_q_return[i] = q * f_ret
        # Guard convective against negative values from bad fractions.
        out_q_convective[i] = max(0.0, q * (1.0 - f_rad - f_vis - f_ret))

        # Illuminance: power × efficacy / area, area clamped to MIN_AREA.
        var area = max(MIN_AREA, zone_area_m2[i])
        out_illuminance[i] = q * lumens_per_watt[i] / area

@export
def lights_wattage_batch(
    n: Int,
    design_level_w_ptr: Int,
    schedule_value_ptr: Int,
    dim_factor_ptr: Int,
    fraction_replaceable_ptr: Int,
    out_power_w_ptr: Int,
):
    """Per-timestep electrical power for N Lights records.

    Arguments:
      - `n`                         — number of Lights records.
      - `design_level_w_ptr`        — raw int64 address of `float64[n]` design
                                       levels in watts.
      - `schedule_value_ptr`        — raw int64 address of `float64[n]`
                                       schedule values (typically in [0, 1]).
      - `dim_factor_ptr`            — raw int64 address of `float64[n]` dim
                                       factors (typically in [0, 1]).
      - `fraction_replaceable_ptr`  — raw int64 address of `float64[n]`
                                       replaceable fractions (typically in
                                       [0, 1]).
      - `out_power_w_ptr`           — raw int64 address of `float64[n]` output
                                       power buffer.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var design = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_level_w_ptr
    )
    var sched = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_value_ptr
    )
    var dim = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=dim_factor_ptr
    )
    var frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=fraction_replaceable_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_w_ptr
    )

    for i in range(n):
        var fr = frac[i]
        var effective = fr * dim[i] + (1.0 - fr)
        out[i] = design[i] * sched[i] * effective

@export
def aggregate_meters_batch(
    n_steps: Int,
    q_hvac_w_ptr: Int,
    dt_s: Float64,
    out_heating_j_ptr: Int,
    out_cooling_j_ptr: Int,
    out_heating_total_j: Int,
    out_cooling_total_j: Int,
):
    """Aggregate per-timestep q_hvac_w into heating / cooling energy series + totals.

    For each step `i`:
      - `out_heating_j[i] =  q_hvac_w[i] * dt_s` if `q_hvac_w[i] > 0`, else 0.
      - `out_cooling_j[i] = -q_hvac_w[i] * dt_s` if `q_hvac_w[i] < 0`, else 0.

    The scalars at `out_heating_total_j` / `out_cooling_total_j` receive the
    sums of the corresponding per-step series.

    Arguments:
      - `n_steps`              — number of timesteps.
      - `q_hvac_w_ptr`         — raw int64 address of `float64[n_steps]`.
      - `dt_s`                 — timestep length in seconds.
      - `out_heating_j_ptr`    — raw int64 address of `float64[n_steps]`.
      - `out_cooling_j_ptr`    — raw int64 address of `float64[n_steps]`.
      - `out_heating_total_j`  — raw int64 address of a single `float64` slot;
                                  receives the sum of the heating series.
      - `out_cooling_total_j`  — raw int64 address of a single `float64` slot;
                                  receives the sum of the cooling series.

    No-op (totals still zeroed) when `n_steps <= 0`.
    """
    var heat_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_heating_total_j
    )
    var cool_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cooling_total_j
    )

    if n_steps <= 0:
        heat_total[0] = 0.0
        cool_total[0] = 0.0
        return

    var q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_hvac_w_ptr
    )
    var out_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_heating_j_ptr
    )
    var out_cool = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cooling_j_ptr
    )

    var h_sum: Float64 = 0.0
    var c_sum: Float64 = 0.0

    for i in range(n_steps):
        var qi = q[i]
        if qi > 0.0:
            var hj = qi * dt_s
            out_heat[i] = hj
            out_cool[i] = 0.0
            h_sum += hj
        elif qi < 0.0:
            var cj = -qi * dt_s
            out_heat[i] = 0.0
            out_cool[i] = cj
            c_sum += cj
        else:
            out_heat[i] = 0.0
            out_cool[i] = 0.0

    heat_total[0] = h_sum
    cool_total[0] = c_sum

@export
def mowitt_h_outside_batch(
    n_surfaces: Int,
    t_surf_c_ptr: Int,
    t_outdoor_c_ptr: Int,
    wind_speed_m_s_ptr: Int,
    wind_dir_deg_ptr: Int,
    surf_azimuth_deg_ptr: Int,
    out_h_w_m2k_ptr: Int,
) -> None:
    """Batched MoWiTT outside convective film coefficient, W/(m²·K).

    Reads (length n_surfaces):
      - t_surf_c_ptr: Float64[n] surface temperature, °C.
      - t_outdoor_c_ptr: Float64[n] outdoor air temperature, °C.
      - wind_speed_m_s_ptr: Float64[n] local wind speed at surface height
        (per-surface to support height/terrain corrections; clamped to 0).
      - wind_dir_deg_ptr: Float64[n] meteorological wind "from" direction,
        compass degrees (0=N, 90=E, 180=S, 270=W).
      - surf_azimuth_deg_ptr: Float64[n] outward-normal azimuth, compass deg.

    Writes (length n_surfaces):
      - out_h_w_m2k_ptr: Float64[n] combined convective film coefficient
        h_c = sqrt(h_n² + h_f²), with windward/leeward coefficient selection.
    """
    var t_surf = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_surf_c_ptr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_c_ptr
    )
    var v = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wind_speed_m_s_ptr
    )
    var wd = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wind_dir_deg_ptr
    )
    var az = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=surf_azimuth_deg_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_h_w_m2k_ptr
    )

    for i in range(n_surfaces):
        # Natural component — 1/3-power law on |ΔT|.
        var delta_t = t_surf[i] - t_out[i]
        var abs_dt = _abs(delta_t)
        var h_n: Float64 = 0.0
        if abs_dt > 0.0:
            h_n = A_NATURAL * pow(abs_dt, 1.0 / 3.0)

        # Forced component — power law on wind speed (clamped at 0).
        var vi = v[i] if v[i] > 0.0 else 0.0
        var h_f: Float64 = 0.0
        if vi > 0.0:
            if _is_windward(wd[i], az[i]):
                h_f = B_WINDWARD * pow(vi, C_WINDWARD)
            else:
                h_f = B_LEEWARD * pow(vi, C_LEEWARD)

        out[i] = sqrt(h_n * h_n + h_f * h_f)

@always_inline
def _f64_ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _i64_ptr(addr: Int) -> UnsafePointer[Int64, MutAnyOrigin]:
    return UnsafePointer[Int64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _abs(x: Float64) -> Float64:
    return x if x >= 0.0 else -x


@export
def gauss_seidel_iter_batch(
    n_zones: Int,
    lhs_ptr: Int,
    rhs_ptr: Int,
    neighbour_idx_ptr: Int,
    neighbour_coef_ptr: Int,
    n_neighbours_per_zone_ptr: Int,
    t_zone_inout_ptr: Int,
    out_max_delta_ptr: Int,
) -> None:
    """One Gauss-Seidel pass over `n_zones` zone-air temperatures.

    Arguments:
      - `n_zones`                       — N: number of zones.
      - `lhs_ptr`                       — float64[N]; per-zone LHS coefficient.
                                          Must be non-zero.
      - `rhs_ptr`                       — float64[N]; per-zone RHS constant.
      - `neighbour_idx_ptr`             — int64[N * max_k]; row-major.
                                          `neighbour_idx[i * max_k + j]` is the
                                          zone-index of zone i's j-th neighbour.
                                          Only the first
                                          `n_neighbours_per_zone[i]` entries
                                          of each row are read.
      - `neighbour_coef_ptr`            — float64[N * max_k]; row-major.
                                          Coupling coefficient for each
                                          neighbour entry above.
      - `n_neighbours_per_zone_ptr`     — int64[N]; entries per zone row.
                                          The kernel infers `max_k` from
                                          the largest value here (the Python
                                          shim packs all rows to the same
                                          stride, so we pass that stride
                                          implicitly via the buffer layout).
      - `t_zone_inout_ptr`              — float64[N]; in/out zone-air temps.
                                          Updated in place.
      - `out_max_delta_ptr`             — float64[1]; written with the max
                                          |t_new - t_old| across all zones.

    Stride convention: `neighbour_idx_ptr` and `neighbour_coef_ptr` are
    row-padded to a common `max_k` so each row's start is at
    `i * max_k`. We recover `max_k` once at the top by scanning
    `n_neighbours_per_zone` — N is small (handful of zones) so the scan
    is cheap and keeps the API a single Int per zone.
    """
    var out_max_delta = _f64_ptr(out_max_delta_ptr)

    if n_zones <= 0:
        out_max_delta[0] = 0.0
        return

    var lhs = _f64_ptr(lhs_ptr)
    var rhs = _f64_ptr(rhs_ptr)
    var n_nbr = _i64_ptr(n_neighbours_per_zone_ptr)
    var nbr_idx = _i64_ptr(neighbour_idx_ptr)
    var nbr_coef = _f64_ptr(neighbour_coef_ptr)
    var t_zone = _f64_ptr(t_zone_inout_ptr)

    # Recover row stride (max k) from the n_neighbours array.
    var max_k: Int = 0
    for i in range(n_zones):
        var k = Int(n_nbr[i])
        if k > max_k:
            max_k = k

    var max_delta: Float64 = 0.0
    for i in range(n_zones):
        var k = Int(n_nbr[i])
        var row_base = i * max_k
        var acc: Float64 = rhs[i]
        for j in range(k):
            var nb = Int(nbr_idx[row_base + j])
            acc += nbr_coef[row_base + j] * t_zone[nb]
        var t_new = acc / lhs[i]
        var d = _abs(t_new - t_zone[i])
        if d > max_delta:
            max_delta = d
        t_zone[i] = t_new

    out_max_delta[0] = max_delta

from numojo import NDArray, Shape
import numojo as nm


def _ndarray_round_trip(n: Int) raises -> Float64:
    """Build an NDArray of [1, 2, …, n], read it back, return the sum."""
    var shape = Shape(n)
    var arr = NDArray[nm.f64](shape)
    for i in range(n):
        arr.store(i, Float64(i + 1))
    var s: Float64 = 0.0
    for i in range(n):
        s += arr.load(i)
    return s


@export
def numojo_smoke_construct(n: Int) -> Float64:
    """C-ABI wrapper around `_ndarray_round_trip`. Returns NaN on failure."""
    var nan: Float64 = 0.0 / 0.0
    try:
        return _ndarray_round_trip(n)
    except:
        return nan

from math import cos, tan

# Sun altitude below which no shadow is cast (near-horizon guard) [rad]
comptime ALTITUDE_MIN: Float64 = 0.01
# Cosine of relative azimuth below which sun is behind the window
comptime COS_AZ_MIN: Float64 = 0.01
