@export
def overhang_shadow_depth_batch(
    n: Int,
    sun_altitude_rad_ptr: Int,
    sun_azimuth_rel_rad_ptr: Int,
    overhang_depth_m_ptr: Int,
    window_height_m_ptr: Int,
    out_shadow_depth_m_ptr: Int,
) -> None:
    """Vertical shadow depth cast by a horizontal overhang onto a window.

    For each window, the vertical shadow depth (metres) is:

        if sun_altitude_rad < ALTITUDE_MIN:
            shadow_depth = 0.0
        else:
            raw_depth = overhang_depth_m / tan(sun_altitude_rad)
            cos_az    = cos(sun_azimuth_rel_rad)
