                shadow_depth = 0.0
            else:
                shadow_depth = clamp(raw_depth * max(0.0, cos_az), 0.0, SHADOW_MAX)

    Parameters
    ----------
    n                      : number of windows
    sun_altitude_rad_ptr   : Float64[n]  solar altitude angle (rad, ≥0)
    sun_azimuth_rel_rad_ptr: Float64[n]  solar azimuth relative to window normal (rad)
    overhang_depth_m_ptr   : Float64[n]  horizontal overhang projection depth (m)
    window_height_m_ptr    : Float64[n]  window height (m)  [unused here, kept for ABI]
    out_shadow_depth_m_ptr : Float64[n]  vertical shadow depth on window (m)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var sun_alt = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sun_altitude_rad_ptr
    )
    var sun_az = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sun_azimuth_rel_rad_ptr
    )
    var oh_depth = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=overhang_depth_m_ptr
    )
    var win_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=window_height_m_ptr
    )
    var out_depth = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_shadow_depth_m_ptr
    )

    for i in range(n):
        var alt = sun_alt[i]

        # Near-horizon guard: sun too low to cast a meaningful shadow
        if alt < ALTITUDE_MIN:
            out_depth[i] = 0.0
            continue

        # Basic shadow projection: depth = overhang / tan(altitude)
        var raw_depth = oh_depth[i] / tan(alt)

        # Azimuth correction: only windows facing the sun receive shadow
        var cos_az = cos(sun_az[i])
        if cos_az < COS_AZ_MIN:
            out_depth[i] = 0.0
            continue

        # Apply azimuth factor (max with 0.0 defensive against rounding)
        var az_factor = cos_az if cos_az > 0.0 else 0.0
        var shadow = raw_depth * az_factor

        # Clamp to [0, SHADOW_MAX]
        if shadow < 0.0:
            shadow = 0.0
        elif shadow > SHADOW_MAX:
            shadow = SHADOW_MAX

        out_depth[i] = shadow

        # Suppress unused variable warning for win_h (kept for stable ABI)
        _ = win_h[i]


@export
def overhang_shading_fraction_batch(
    n: Int,
    shadow_depth_m_ptr: Int,
    window_height_m_ptr: Int,
    out_shading_fraction_ptr: Int,
) -> None:
    """Fraction of window height covered by the overhang shadow.

    For each window:

        shading_fraction = clamp(shadow_depth_m / max(window_height_m, H_MIN),
                                 0.0, 1.0)

    Parameters
    ----------
    n                      : number of windows
    shadow_depth_m_ptr     : Float64[n]  vertical shadow depth (m)
    window_height_m_ptr    : Float64[n]  window height (m)
    out_shading_fraction_ptr: Float64[n] shading fraction [0, 1]  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var shadow_depth = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=shadow_depth_m_ptr
    )
    var win_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=window_height_m_ptr
    )
    var out_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_shading_fraction_ptr
    )

    for i in range(n):
        var h = win_h[i]
        if h < H_MIN:
            h = H_MIN

        var frac = shadow_depth[i] / h

        # Clamp to [0, 1]
        if frac < 0.0:
            frac = 0.0
        elif frac > 1.0:
            frac = 1.0

        out_frac[i] = frac

from std.math import tan, cos, atan


@export
def overhang_shading_factor_batch(
    n: Int,
    solar_alt_rad_ptr: Int,
    solar_az_rad_ptr: Int,
    window_az_rad_ptr: Int,
    overhang_projection_m_ptr: Int,
    distance_above_m_ptr: Int,
    window_width_m_ptr: Int,
    window_height_m_ptr: Int,
    out_shading_factor_ptr: Int,
) -> None:
    """Closed-form overhang shading factor for `n` windows.

    Inputs (all `Float64[n]`, C-contiguous):
      - solar_alt_rad          solar altitude (rad), 0 at horizon, π/2 zenith.
      - solar_az_rad           solar azimuth (rad), convention shared with
                                window_az (only the *difference* matters).
      - window_az_rad          outward-facing window azimuth (rad).
      - overhang_projection_m  horizontal projection of the overhang from the
                                wall (m), ≥ 0.
      - distance_above_m       vertical gap between the overhang and the top
                                of the window (m), ≥ 0.
      - window_width_m         window width (m), > 0.
      - window_height_m        window height (m), > 0.

    Output: `out_shading_factor_ptr` → Float64[n], shading factor in [0, 1].

    Per-element edge cases handled in-kernel:
      - Sun at/below horizon (`solar_alt ≤ 0`) or behind the wall
        (`|solar_az − window_az| ≥ π/2`, i.e. `cos ≤ 0`): shading_factor = 0.
      - Shadow drop below `distance_above_m`: shading_factor = 0.
      - Shadow taller than the window: clamped to 1 by `min(...)`.
    """
    if n <= 0:
        return

    var solar_alt = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=solar_alt_rad_ptr
    )
    var solar_az = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=solar_az_rad_ptr
    )
    var window_az = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=window_az_rad_ptr
    )
    var proj = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=overhang_projection_m_ptr
    )
    var dist_above = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=distance_above_m_ptr
    )
    var w_width = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=window_width_m_ptr
    )
    var w_height = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=window_height_m_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_shading_factor_ptr
    )

    for i in range(n):
        var alt = solar_alt[i]
        var width = w_width[i]
        var height = w_height[i]

        # Sun below horizon, or degenerate window: no shading from overhang.
        if alt <= 0.0 or width <= 0.0 or height <= 0.0:
            out[i] = 0.0
            continue

        var d_az = solar_az[i] - window_az[i]
        var cos_d = cos(d_az)
        # Sun behind the wall the window is on: overhang casts no shadow on it.
        if cos_d <= 0.0:
            out[i] = 0.0
            continue

        # profile_angle = atan(tan(alt) / cos(d_az))
        # alt ∈ (0, π/2), cos_d ∈ (0, 1] ⇒ tan(alt) finite or +inf at π/2;
        # atan handles +inf cleanly, returning π/2.
        var profile = atan(tan(alt) / cos_d)
        var drop = proj[i] * tan(profile)
        var shadow_h = drop - dist_above[i]
        if shadow_h <= 0.0:
            out[i] = 0.0
            continue

        var occluded_h = shadow_h if shadow_h < height else height
        out[i] = (occluded_h * width) / (width * height)

@export
def people_sensible_latent_batch(
    n: Int,
    n_people_ptr: Int,
    schedule_value_ptr: Int,
    activity_w_ptr: Int,
    out_sensible_w_ptr: Int,
    out_latent_w_ptr: Int,
):
    """Per-timestep sensible/latent heat split for N People records.

    Arguments:
      - `n`                    — number of People records.
      - `n_people_ptr`         — raw int64 address of `float64[n]` number-of-
                                  people values (typically scheduled).
      - `schedule_value_ptr`   — raw int64 address of `float64[n]` schedule
                                  values (typically in [0, 1]).
      - `activity_w_ptr`       — raw int64 address of `float64[n]` per-person
                                  activity level in W/person.
      - `out_sensible_w_ptr`   — raw int64 address of `float64[n]` output
                                  sensible-heat buffer (watts).
      - `out_latent_w_ptr`     — raw int64 address of `float64[n]` output
                                  latent-heat buffer (watts).

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var n_people = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=n_people_ptr
    )
    var sched = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_value_ptr
    )
    var activity = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=activity_w_ptr
    )
    var out_sens = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_sensible_w_ptr
    )
    var out_lat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_latent_w_ptr
    )

    # ASHRAE HoF Ch.18 Table 5 fit constants.
    var act_lo = 70.0  # W/person seated, quiet
    var act_hi = 280.0  # W/person heavy work
    var frac_lo = 0.6  # sensible fraction at act_lo
    var frac_hi = 0.4  # sensible fraction at act_hi
    var slope = (frac_hi - frac_lo) / (act_hi - act_lo)

    for i in range(n):
        var act = activity[i]
        var raw = frac_lo + slope * (act - act_lo)
        # Clamp to [frac_hi, frac_lo] == [0.4, 0.6]. Order matters: lower
        # bound first, upper bound second.
        var sens_frac = raw
        if sens_frac < frac_hi:
            sens_frac = frac_hi
        if sens_frac > frac_lo:
            sens_frac = frac_lo
        var q_total = n_people[i] * sched[i] * act
        out_sens[i] = q_total * sens_frac
        out_lat[i] = q_total * (1.0 - sens_frac)

@export
def pcm_apparent_cp_batch(
    n: Int,
    t_ptr: Int,
    t_melt_lo_ptr: Int,
    t_melt_hi_ptr: Int,
    cp_solid_ptr: Int,
    cp_liquid_ptr: Int,
    latent_heat_ptr: Int,
    out_cp_eff_ptr: Int,
) -> None:
    """Apparent (effective) specific heat capacity via the linear PCM method.

    For each element `i` in `[0, n)`:

        dT = max(1e-6, T_melt_hi[i] - T_melt_lo[i])

        if T[i] < T_melt_lo[i]:
            cp_eff[i] = cp_solid[i]
        elif T[i] > T_melt_hi[i]:
            cp_eff[i] = cp_liquid[i]
        else:
            cp_eff[i] = (cp_solid[i] + cp_liquid[i]) / 2 + latent_heat[i] / dT

    All `*_ptr` arguments are raw int64 addresses of float64[n] C-contiguous
    arrays. `out_cp_eff_ptr` is written in place. No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var t = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=t_ptr)
    var t_melt_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_melt_lo_ptr
    )
    var t_melt_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_melt_hi_ptr
    )
    var cp_solid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_solid_ptr
    )
    var cp_liquid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_liquid_ptr
    )
    var latent_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=latent_heat_ptr
    )
    var out_cp_eff = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cp_eff_ptr
    )

    for i in range(n):
        var ti = t[i]
        var tlo = t_melt_lo[i]
        var thi = t_melt_hi[i]
        var dt_melt = thi - tlo
        if dt_melt < 1e-6:
            dt_melt = 1e-6
        if ti < tlo:
            out_cp_eff[i] = cp_solid[i]
        elif ti > thi:
            out_cp_eff[i] = cp_liquid[i]
        else:
            out_cp_eff[i] = (cp_solid[i] + cp_liquid[i]) * 0.5 + latent_heat[
                i
            ] / dt_melt


@export
def pcm_enthalpy_batch(
    n: Int,
    t_ptr: Int,
    t_melt_lo_ptr: Int,
    t_melt_hi_ptr: Int,
    cp_solid_ptr: Int,
    cp_liquid_ptr: Int,
    latent_heat_ptr: Int,
    t_ref_ptr: Int,
    out_h_ptr: Int,
) -> None:
    """Enthalpy of each PCM element relative to a reference temperature T_ref.

    For each element `i` in `[0, n)`:

        if T[i] < T_melt_lo[i]:
            H[i] = cp_solid[i] * (T[i] - T_ref[i])
        elif T[i] > T_melt_hi[i]:
            H[i] = cp_solid[i] * (T_melt_lo[i] - T_ref[i])
                   + latent_heat[i]
                   + cp_liquid[i] * (T[i] - T_melt_hi[i])
        else:  # partial melt
            frac  = (T[i] - T_melt_lo[i]) / max(1e-6, T_melt_hi[i] - T_melt_lo[i])
            H[i]  = cp_solid[i] * (T_melt_lo[i] - T_ref[i])
                   + frac * latent_heat[i]
                   + (cp_solid[i] + cp_liquid[i]) * 0.5 * (T[i] - T_melt_lo[i])

    All `*_ptr` arguments are raw int64 addresses of float64[n] C-contiguous
    arrays. `out_h_ptr` is written in place. No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var t = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=t_ptr)
    var t_melt_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_melt_lo_ptr
    )
    var t_melt_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_melt_hi_ptr
    )
    var cp_solid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_solid_ptr
    )
    var cp_liquid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_liquid_ptr
    )
    var latent_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=latent_heat_ptr
    )
    var t_ref = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_ref_ptr
    )
    var out_h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_h_ptr
    )

    for i in range(n):
        var ti = t[i]
        var tlo = t_melt_lo[i]
        var thi = t_melt_hi[i]
        var tref = t_ref[i]
        var cps = cp_solid[i]
        var cpl = cp_liquid[i]
        var lh = latent_heat[i]
        var dt_melt = thi - tlo
        if dt_melt < 1e-6:
            dt_melt = 1e-6
        if ti < tlo:
            out_h[i] = cps * (ti - tref)
        elif ti > thi:
            out_h[i] = cps * (tlo - tref) + lh + cpl * (ti - thi)
        else:
            var frac = (ti - tlo) / dt_melt
            out_h[i] = (
                cps * (tlo - tref) + frac * lh + (cps + cpl) * 0.5 * (ti - tlo)
            )


@export
def pcm_melt_fraction_batch(
    n: Int,
    t_ptr: Int,
    t_melt_lo_ptr: Int,
    t_melt_hi_ptr: Int,
    out_frac_ptr: Int,
) -> None:
    """Melt fraction for each PCM element, clamped to [0, 1].

    For each element `i` in `[0, n)`:

        frac[i] = clamp(
            (T[i] - T_melt_lo[i]) / max(1e-6, T_melt_hi[i] - T_melt_lo[i]),
            0.0, 1.0,
        )

    All `*_ptr` arguments are raw int64 addresses of float64[n] C-contiguous
    arrays. `out_frac_ptr` is written in place. No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var t = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=t_ptr)
    var t_melt_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_melt_lo_ptr
    )
    var t_melt_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_melt_hi_ptr
    )
    var out_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_frac_ptr
    )

    for i in range(n):
        var ti = t[i]
        var tlo = t_melt_lo[i]
        var thi = t_melt_hi[i]
        var dt_melt = thi - tlo
        if dt_melt < 1e-6:
            dt_melt = 1e-6
        var frac = (ti - tlo) / dt_melt
        if frac < 0.0:
            frac = 0.0
        elif frac > 1.0:
            frac = 1.0
        out_frac[i] = frac


@export
def pcm_thermal_conductivity_batch(
    n: Int,
    frac_ptr: Int,
    k_solid_ptr: Int,
    k_liquid_ptr: Int,
    out_k_ptr: Int,
) -> None:
    """Linear-interpolation thermal conductivity between solid and liquid phases.

    For each element `i` in `[0, n)`:

        k[i] = k_solid[i] * (1 - frac[i]) + k_liquid[i] * frac[i]

    All `*_ptr` arguments are raw int64 addresses of float64[n] C-contiguous
    arrays. `out_k_ptr` is written in place. No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=frac_ptr
    )
    var k_solid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=k_solid_ptr
    )
    var k_liquid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=k_liquid_ptr
    )
    var out_k = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_k_ptr
    )

    for i in range(n):
        var f = frac[i]
        out_k[i] = k_solid[i] * (1.0 - f) + k_liquid[i] * f

@always_inline
def _f64_ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _sum_capacities(
    n: Int, cap: UnsafePointer[Float64, MutAnyOrigin]
) -> Float64:
    """Horizontal sum of cap[0..n). Returns 0.0 for n <= 0."""
    var total: Float64 = 0.0
    for i in range(n):
        total += cap[i]
    return total


@always_inline
def _clamp01(x: Float64) -> Float64:
    """Clamp x to [0.0, 1.0]."""
    if x < 0.0:
        return 0.0
    if x > 1.0:
        return 1.0
    return x


@export
def proportional_loads_batch(
    n: Int,
    requested_w: Float64,
    cap_ptr: Int,
    out_load_ptr: Int,
) -> None:
    """Distribute requested_w [W] across N equipment items by nominal capacity.

    For each equipment item i in [0, n):

        plr    = min(requested_w / Σ cap[i], 1.0)
        out[i] = cap[i] * plr

    All outputs are 0 when `n <= 0`, `requested_w <= 0`, or `Σ cap <= 0`.

    Arguments:
      - `n`            — number of equipment items.
      - `requested_w`  — aggregate loop demand [W]; non-positive → all-zero.
      - `cap_ptr`      — raw int64 address of `float64[n]` nominal capacities.
      - `out_load_ptr` — raw int64 address of `float64[n]` output load array.
                         Written in place.

    No-op (writes zeros) when `n <= 0`.
    """
    if n <= 0:
        return

    var cap = _f64_ptr(cap_ptr)
    var out = _f64_ptr(out_load_ptr)

    if requested_w <= 0.0:
        for i in range(n):
            out[i] = 0.0
        return

    var total = _sum_capacities(n, cap)
    if total <= 0.0:
        for i in range(n):
            out[i] = 0.0
        return

    var plr = _clamp01(requested_w / total)
    for i in range(n):
        out[i] = cap[i] * plr


@export
def plant_plr_bulk_fraction(
    heating_w: Float64,
    cooling_w: Float64,
    h_total_cap: Float64,
    c_total_cap: Float64,
    out_ptr: Int,
) -> None:
    """Compute the variable-speed pump bulk-flow fraction for one timestep.

    Implements the pump PLR selection from `step_plant_loops` in
    `runtime/plant.py`:

        h_plr   = min(heating_w / h_total_cap, 1.0)   if h_total_cap > 0 else 0
        c_plr   = min(cooling_w / c_total_cap, 1.0)   if c_total_cap > 0 else 0
        result  = max(h_plr, c_plr)

    The result is written to `out_ptr[0]` — a single `float64` slot.

    Arguments:
      - `heating_w`    — heating loop demand [W]; clamped to ≥ 0 internally.
      - `cooling_w`    — cooling loop demand [W]; clamped to ≥ 0 internally.
      - `h_total_cap`  — total nominal heating capacity [W]; 0 → h_plr = 0.
      - `c_total_cap`  — total nominal cooling capacity [W]; 0 → c_plr = 0.
      - `out_ptr`      — raw int64 address of a single `float64` output slot.
    """
    var out = _f64_ptr(out_ptr)

    var hw = heating_w if heating_w > 0.0 else Float64(0.0)
    var cw = cooling_w if cooling_w > 0.0 else Float64(0.0)

    var h_plr: Float64 = 0.0
    if h_total_cap > 0.0:
        h_plr = _clamp01(hw / h_total_cap)

    var c_plr: Float64 = 0.0
    if c_total_cap > 0.0:
        c_plr = _clamp01(cw / c_total_cap)

    var bulk = h_plr if h_plr > c_plr else c_plr
    out[0] = bulk


@export
def proportional_loads_multi_batch(
    n_equip: Int,
    n_loads: Int,
    cap_ptr: Int,
    loads_ptr: Int,
    out_ptr: Int,
) -> None:
    """Distribute M independent load requests across N equipment items.

    Each load `loads[j]` (j in [0, n_loads)) is distributed proportionally
    across the same N-equipment capacity array `cap[0..n_equip)`. The output
    is laid out row-major: `out[j * n_equip + i]` = load assigned to
    equipment i for demand j.

    For each load j:

        plr_j        = min(loads[j] / Σ cap[i], 1.0)  if Σ cap > 0 and loads[j] > 0
        out[j*n + i] = cap[i] * plr_j

    When the total capacity is zero all outputs for that row are zero.

    Arguments:
      - `n_equip`   — number of equipment items (columns in output).
      - `n_loads`   — number of load requests  (rows in output).
      - `cap_ptr`   — raw int64 address of `float64[n_equip]` nominal caps.
      - `loads_ptr` — raw int64 address of `float64[n_loads]` requested loads.
      - `out_ptr`   — raw int64 address of `float64[n_loads * n_equip]` output;
                      row-major (row = load, column = equipment). Written in place.

    No-op when `n_equip <= 0` or `n_loads <= 0`.
    """
    if n_equip <= 0 or n_loads <= 0:
        return

    var cap = _f64_ptr(cap_ptr)
    var loads = _f64_ptr(loads_ptr)
    var out = _f64_ptr(out_ptr)

    var total = _sum_capacities(n_equip, cap)

    for j in range(n_loads):
        var row_base = j * n_equip
        var lj = loads[j]
        if total <= 0.0 or lj <= 0.0:
            for i in range(n_equip):
                out[row_base + i] = 0.0
        else:
            var plr = _clamp01(lj / total)
            for i in range(n_equip):
                out[row_base + i] = cap[i] * plr


@export
def proportional_loads_batch_with_plr(
    n: Int,
    requested_w: Float64,
    cap_ptr: Int,
    out_load_ptr: Int,
    out_plr_ptr: Int,
) -> None:
    """Distribute requested_w across N equipment items, also returning PLR.

    Same as `proportional_loads_batch` but additionally writes the computed
    part-load ratio to `out_plr_ptr[0]` — useful when the caller needs the PLR
    for downstream pump-flow fraction computation.

    Arguments:
      - `n`            — number of equipment items.
      - `requested_w`  — aggregate loop demand [W].
      - `cap_ptr`      — raw int64 address of `float64[n]` nominal capacities.
      - `out_load_ptr` — raw int64 address of `float64[n]` output load array.
      - `out_plr_ptr`  — raw int64 address of a single `float64` PLR slot;
                         receives the clamped PLR in [0, 1].

    No-op (writes zeros + 0.0 PLR) when `n <= 0`.
    """
    var plr_out = _f64_ptr(out_plr_ptr)

    if n <= 0:
        plr_out[0] = 0.0
        return

    var cap = _f64_ptr(cap_ptr)
    var out = _f64_ptr(out_load_ptr)

    if requested_w <= 0.0:
        for i in range(n):
            out[i] = 0.0
        plr_out[0] = 0.0
        return

    var total = _sum_capacities(n, cap)
    if total <= 0.0:
        for i in range(n):
            out[i] = 0.0
        plr_out[0] = 0.0
        return

    var plr = _clamp01(requested_w / total)
    for i in range(n):
        out[i] = cap[i] * plr
    plr_out[0] = plr

comptime MIN_RANGE: Float64 = 1e-6


# ---------------------------------------------------------------------------
# 1. OA-follow setpoint reset
# ---------------------------------------------------------------------------


@export
def plant_setpoint_oa_follow_batch(
    n: Int,
    t_oa_ptr: Int,
    t_set_min_ptr: Int,
    t_set_max_ptr: Int,
    t_oa_low_ptr: Int,
    t_oa_high_ptr: Int,
    out_setpoint_ptr: Int,
) -> None:
    """Linear OA-temperature-follow setpoint reset for plant loops.

    For each loop ``i``:

        range     = t_oa_high[i] - t_oa_low[i]
        oa_frac   = 0.0  if range < MIN_RANGE
                    else clamp((t_oa[i] - t_oa_low[i]) / range, 0.0, 1.0)
        setpoint  = clamp(t_set_min[i] + oa_frac * (t_set_max[i] - t_set_min[i]),
                          t_set_min[i], t_set_max[i])

    Implements EnergyPlus SetpointManager:FollowOutdoorAirTemperature. When
    the OA temperature range is too narrow (< 1e-6) the fractional position is
    clamped to zero so the setpoint equals ``t_set_min``.

    Parameters
    ----------
    n               : number of plant loops
    t_oa_ptr        : Float64[n]  outdoor air temperature (°C or K, same units as range)
    t_set_min_ptr   : Float64[n]  minimum allowable setpoint (°C)
    t_set_max_ptr   : Float64[n]  maximum allowable setpoint (°C)
    t_oa_low_ptr    : Float64[n]  OA temperature at which setpoint = t_set_min (°C)
    t_oa_high_ptr   : Float64[n]  OA temperature at which setpoint = t_set_max (°C)
    out_setpoint_ptr: Float64[n]  resulting supply temperature setpoint (°C) [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var t_oa = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_oa_ptr
    )
    var t_set_min = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_set_min_ptr
    )
    var t_set_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_set_max_ptr
    )
    var t_oa_low = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_oa_low_ptr
    )
    var t_oa_high = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_oa_high_ptr
    )
    var out_sp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_setpoint_ptr
    )

    for i in range(n):
        var oa_range = t_oa_high[i] - t_oa_low[i]
        var oa_frac: Float64
        if oa_range < MIN_RANGE:
            oa_frac = 0.0
        else:
            oa_frac = (t_oa[i] - t_oa_low[i]) / oa_range
            if oa_frac < 0.0:
                oa_frac = 0.0
            elif oa_frac > 1.0:
                oa_frac = 1.0

        var sp = t_set_min[i] + oa_frac * (t_set_max[i] - t_set_min[i])

        # Clamp setpoint to [t_set_min, t_set_max]
        var lo = t_set_min[i]
        var hi = t_set_max[i]
        if sp < lo:
            sp = lo
        elif sp > hi:
            sp = hi

        out_sp[i] = sp


# ---------------------------------------------------------------------------
# 2. Return-temperature-target setpoint reset
# ---------------------------------------------------------------------------


@export
def plant_setpoint_return_target_batch(
    n: Int,
    t_return_ptr: Int,
    t_target_ptr: Int,
    t_set_current_ptr: Int,
    dt_max_ptr: Int,
    out_setpoint_ptr: Int,
) -> None:
    """Proportional setpoint correction to drive return temperature toward target.

    For each loop ``i``:

        error      = t_return[i] - t_target[i]
        correction = clamp(error * 0.5, -dt_max[i], dt_max[i])
        setpoint   = clamp(t_set_current[i] - correction,
                           t_set_current[i] - dt_max[i],
                           t_set_current[i] + dt_max[i])

    A positive error means the return temperature is warmer than the target.
    The proportional gain of 0.5 provides stable convergence. The correction
    and output are bounded by ``dt_max`` to prevent runaway adjustments.

    Implements EnergyPlus SetpointManager:ReturnTemperature logic.

    Parameters
    ----------
    n                 : number of plant loops
    t_return_ptr      : Float64[n]  measured return temperature (°C)
    t_target_ptr      : Float64[n]  desired return temperature target (°C)
    t_set_current_ptr : Float64[n]  current supply temperature setpoint (°C)
    dt_max_ptr        : Float64[n]  maximum setpoint adjustment magnitude (°C)
    out_setpoint_ptr  : Float64[n]  adjusted supply temperature setpoint (°C) [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var t_return = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_return_ptr
    )
    var t_target = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_target_ptr
    )
    var t_set_cur = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_set_current_ptr
    )
    var dt_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=dt_max_ptr
    )
    var out_sp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_setpoint_ptr
    )

    for i in range(n):
        var error = t_return[i] - t_target[i]
        var dt = dt_max[i]

        # Proportional correction, clamped to ±dt_max
        var correction = error * 0.5
        if correction < -dt:
            correction = -dt
        elif correction > dt:
            correction = dt

        var sp = t_set_cur[i] - correction

        # Clamp setpoint to [t_set_current - dt_max, t_set_current + dt_max]
        var sp_lo = t_set_cur[i] - dt
        var sp_hi = t_set_cur[i] + dt
        if sp < sp_lo:
            sp = sp_lo
        elif sp > sp_hi:
            sp = sp_hi

        out_sp[i] = sp


# ---------------------------------------------------------------------------
# 3. Demand-weighted setpoint reset
# ---------------------------------------------------------------------------


@export
def plant_setpoint_demand_weighted_batch(
    n: Int,
    t_set_base_ptr: Int,
    load_frac_ptr: Int,
    delta_reset_ptr: Int,
    out_setpoint_ptr: Int,
) -> None:
    """Demand-weighted plant loop setpoint reset.

    For each loop ``i``:

        load_frac_c = clamp(load_frac[i], 0.0, 1.0)
        setpoint    = t_set_base[i] + (1.0 - load_frac_c) * delta_reset[i]

    At full load (load_frac = 1) the setpoint equals the base setpoint.
    At zero load (load_frac = 0) the setpoint is offset by the full
    ``delta_reset``. For chilled-water loops pass a positive ``delta_reset``
    to raise the setpoint (warmer CW saves energy). For hot-water loops pass
    a negative ``delta_reset`` to lower the setpoint.

    Parameters
    ----------
    n                : number of plant loops
    t_set_base_ptr   : Float64[n]  base (full-load) supply setpoint (°C)
    load_frac_ptr    : Float64[n]  fractional loop load [0, 1] (clamped)
    delta_reset_ptr  : Float64[n]  maximum setpoint shift at zero load (°C)
    out_setpoint_ptr : Float64[n]  resulting supply temperature setpoint (°C) [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var t_set_base = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_set_base_ptr
    )
    var load_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=load_frac_ptr
    )
    var delta_reset = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=delta_reset_ptr
    )
    var out_sp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_setpoint_ptr
    )

    for i in range(n):
        var lf = load_frac[i]
        if lf < 0.0:
            lf = 0.0
        elif lf > 1.0:
            lf = 1.0

        out_sp[i] = t_set_base[i] + (1.0 - lf) * delta_reset[i]

from std.math import exp

# ---- thermodynamic constants -----------------------------------------------

# Magnus-Tetens saturation pressure coefficients (above freezing)
comptime _MAGNUS_A_ABOVE: Float64 = 17.269
comptime _MAGNUS_B_ABOVE: Float64 = 237.3  # °C
comptime _MAGNUS_A_BELOW: Float64 = 21.874
comptime _MAGNUS_B_BELOW: Float64 = 265.5  # °C
comptime _MAGNUS_E0: Float64 = 610.78  # Pa

# Humidity ratio constant: eps = Mw/Md = 18.015268 / 28.966 (ASHRAE)
comptime EPS: Float64 = 0.621945

# Gas constant for dry air, J/(kg·K)
comptime R_DRY: Float64 = 287.042

# Kelvin offset
comptime KELVIN: Float64 = 273.15

# Enthalpy coefficients (simplified, for wet-bulb iteration)
comptime CP_AIR_SIMPLE: Float64 = 1006.0  # J/(kg·°C)
comptime HFG_0: Float64 = 2501000.0  # J/kg at 0 °C
comptime CP_VAP_SIMPLE: Float64 = 1860.0  # J/(kg·°C)

# Ratio of molecular weights used in specific-volume calc
comptime MV_MD_RATIO: Float64 = 1.6078  # Mv/Md = 18.015268/11.204 ≈ ...

# Minimum denominator guard for pressure calculations
comptime _PB_MIN: Float64 = 1.0e-6


@always_inline
def _psat_magnus(t: Float64) -> Float64:
    """Magnus-Tetens saturation pressure [Pa] from temperature [°C].

    Uses two-branch formula:
      T >= 0: psat = exp(17.269 * T / (237.3 + T)) * 610.78
      T <  0: psat = exp(21.874 * T / (265.5 + T)) * 610.78
    """
    if t >= 0.0:
        return exp(_MAGNUS_A_ABOVE * t / (_MAGNUS_B_ABOVE + t)) * _MAGNUS_E0
    else:
        return exp(_MAGNUS_A_BELOW * t / (_MAGNUS_B_BELOW + t)) * _MAGNUS_E0


@always_inline
def _h_tdb_w(tdb: Float64, w: Float64) -> Float64:
    """Moist-air enthalpy [J/kg dry air] from T_dry-bulb [°C] and W [kg/kg].

    h = 1006 * T + W * (2_501_000 + 1860 * T)
    """
    return CP_AIR_SIMPLE * tdb + w * (HFG_0 + CP_VAP_SIMPLE * tdb)


# ---- vectorized batch entry points -----------------------------------------
# Each function takes `n` (element count) as the first argument, followed by
# raw int64 memory addresses for input and output float64 arrays.
# Mojo reconstructs typed pointers via UnsafePointer(unsafe_from_address=...).


@export
def psy_w_fn_tdb_rh_pb_batch(
    n: Int,
    tdb_ptr: Int,
    rh_ptr: Int,
    pb_ptr: Int,
    out_w_ptr: Int,
):
    """Batch humidity ratio W [kg/kg] from T_dry-bulb [°C], RH [0..1], Pb [Pa].

    Algorithm:
      psat = _psat_magnus(tdb)
      pv   = rh * psat
      W    = 0.621945 * pv / max(1e-6, Pb - pv)
      out  = max(0.0, W)
    """
    var tdb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=tdb_ptr)
    var rh = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=rh_ptr)
    var pb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=pb_ptr)
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_w_ptr
    )
    for i in range(n):
        var psat = _psat_magnus(tdb[i])
        var pv = rh[i] * psat
        var denom = pb[i] - pv
        if denom < _PB_MIN:
            denom = _PB_MIN
        var w = EPS * pv / denom
        if w < 0.0:
            w = 0.0
        out[i] = w


@export
def psy_specific_volume_batch(
    n: Int,
    tdb_ptr: Int,
    w_ptr: Int,
    pb_ptr: Int,
    out_v_ptr: Int,
):
    """Batch specific volume [m³/kg dry air] of moist air.

    Algorithm:
      T_K  = tdb + 273.15
      v    = R_dry * T_K * (1 + 1.6078 * W) / Pb

    where R_dry = 287.042 J/(kg·K).
    """
    var tdb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=tdb_ptr)
    var w = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=w_ptr)
    var pb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=pb_ptr)
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_v_ptr
    )
    for i in range(n):
        var t_k = tdb[i] + KELVIN
        out[i] = R_DRY * t_k * (1.0 + MV_MD_RATIO * w[i]) / pb[i]


@export
def psy_twb_fn_tdb_w_pb_batch(
    n: Int,
    tdb_ptr: Int,
    w_ptr: Int,
    pb_ptr: Int,
    out_twb_ptr: Int,
):
    """Batch wet-bulb temperature [°C] from T_dry-bulb [°C], W [kg/kg], Pb [Pa].

    Uses 15 Newton iterations on the adiabatic saturation residual:
      f(Twb) = 1006*(tdb - Twb) - (wsat(Twb) - W) * (2_501_000 + 1860*Twb)

    Starting guess: Twb = tdb - 5.0.
    Result clamped to [-80, tdb].
    """
    comptime MAX_ITER = 15

    var tdb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=tdb_ptr)
    var w = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=w_ptr)
    var pb_arr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=pb_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_twb_ptr
    )

    for i in range(n):
        var t = tdb[i]
        var wi = w[i]
        # Initial guess: 5 °C below dry-bulb (typical spread)
        var twb = t - 5.0

        for _ in range(MAX_ITER):
            var wsat = _psat_magnus(twb)
            # wsat as humidity ratio at Twb
            var pb_i = pb_arr[i]
            var denom_pb = pb_i - wsat
            if denom_pb < _PB_MIN:
                denom_pb = _PB_MIN
            var ws = EPS * wsat / denom_pb

            # Residual: f(Twb) = Cp*(tdb-Twb) - (ws - wi)*(HFG0 + Cp_vap*Twb)
            var hfg_twb = HFG_0 + CP_VAP_SIMPLE * twb
            var f = CP_AIR_SIMPLE * (t - twb) - (ws - wi) * hfg_twb

            # Derivative: df/dTwb = -Cp - (dws/dTwb)*hfg_twb - (ws-wi)*Cp_vap
            # dws/dTwb ≈ ws * psat_deriv / (eps * denom_pb) * eps ... via chain rule
            # psat_deriv via Magnus:
            var psat_val = wsat  # alias for clarity — actually psat value
            var mag_denom: Float64
            if twb >= 0.0:
                mag_denom = _MAGNUS_B_ABOVE + twb
            else:
                mag_denom = _MAGNUS_B_BELOW + twb
            var mag_a: Float64
            if twb >= 0.0:
                mag_a = _MAGNUS_A_ABOVE
            else:
                mag_a = _MAGNUS_A_BELOW
            var dpsat_dtwb = (
                psat_val * mag_a * mag_denom / (mag_denom * mag_denom)
            )
            # Note: psat_val here is actually the raw psat Pa value (not ws).
            # Recompute psat properly:
            var psat_pa = _psat_magnus(twb)
            dpsat_dtwb = psat_pa * mag_a * mag_denom / (mag_denom * mag_denom)
            var dws_dtwb = EPS * dpsat_dtwb * pb_i / (denom_pb * denom_pb)

            var df = (
                -CP_AIR_SIMPLE - dws_dtwb * hfg_twb - (ws - wi) * CP_VAP_SIMPLE
            )

            # Guard against zero derivative
            var abs_df = df if df >= 0.0 else -df
            if abs_df < 1.0e-12:
                break

            var step = f / df
            twb = twb - step

        # Clamp result to physical range
        if twb > t:
            twb = t
        if twb < -80.0:
            twb = -80.0
        out[i] = twb

from std.math import exp, log

# ---- thermodynamic constants ---------------------------------------------
# Constant::Kelvin                       (DataGlobalConstants.hh:611)
comptime KELVIN: Float64 = 273.15
# Constant::TriplePointOfWaterTempKelvin (DataGlobalConstants.hh:612)
comptime TRIPLE_POINT_K: Float64 = 273.16

# Universal gas constants
comptime R_AIR: Float64 = 287.0  # J/(kg·K) — dry air
comptime R_VAPOR: Float64 = 461.52  # J/(kg·K) — water vapor

# Mass ratio MW(air) / MW(H2O) = 28.9645 / 18.01534
comptime MW_AIR_TO_H2O: Float64 = 1.6077687

# Enthalpy coefficients (ASHRAE Fundamentals 1972, p. 100, eqn 32)
comptime CP_AIR: Float64 = 1.00484e3  # J/(kg·°C)
comptime CP_VAPOR: Float64 = 1.85895e3  # J/(kg·°C)
comptime HFG_REF: Float64 = 2.50094e6  # J/kg, latent heat of vaporization at 0 °C

# Lower clamp on humidity ratio in non-_fast variants
comptime W_MIN: Float64 = 1.0e-5

# Hyland-Wexler saturation-pressure polynomial coefficients
# (Psychrometrics.cc:733-739, ice region: T < 273.16 K)
comptime C1: Float64 = -5674.5359
comptime C2: Float64 = 6.3925247
comptime C3: Float64 = -0.9677843e-2
comptime C4: Float64 = 0.62215701e-6
comptime C5: Float64 = 0.20747825e-8
comptime C6: Float64 = -0.9484024e-12
comptime C7: Float64 = 4.1635019
# (Psychrometrics.cc:745-750, water region: 273.16 K ≤ T ≤ 473.15 K)
comptime C8: Float64 = -5800.2206
comptime C9: Float64 = 1.3914993
comptime C10: Float64 = -0.048640239
comptime C11: Float64 = 0.41764768e-4
comptime C12: Float64 = -0.14452093e-7
comptime C13: Float64 = 6.5459673

# Magnus-form coefficients (Alduchov & Eskridge 1996) for the initial guess
# in `psy_tdp_fn_tdb_rh`.  es(T) = 610.94 * exp(17.625 * T / (T + 243.04))
comptime _MAGNUS_A: Float64 = 17.625
comptime _MAGNUS_B: Float64 = 243.04  # °C
comptime _MAGNUS_ES0: Float64 = 610.94  # Pa
# Lower clamp on relative humidity to avoid log(0)
comptime RH_MIN: Float64 = 1.0e-10


@always_inline
def _max(a: Float64, b: Float64) -> Float64:
    return a if a > b else b


# ---- C ABI exports -------------------------------------------------------
# Each function below is the canonical port of an upstream `Psy*` inline.
# Naming: snake_case mirroring the upstream camelCase, prefix `psy_`.


@export
def psy_h_fn_tdb_w(tdb: Float64, dw: Float64) -> Float64:
    """Enthalpy from dry-bulb T and humidity ratio W.

    Mirrors `PsyHFnTdbW` (Psychrometrics.hh:648-666). ASHRAE Fundamentals 1972
    p. 100, eqn 32. Returns J/kg.
    """
    var w = _max(dw, W_MIN)
    return CP_AIR * tdb + w * (HFG_REF + CP_VAPOR * tdb)


@export
def psy_h_fn_tdb_w_fast(tdb: Float64, dw: Float64) -> Float64:
    """As `psy_h_fn_tdb_w` but assumes the caller has already clamped `dw`.

    Mirrors `PsyHFnTdbW_fast` (Psychrometrics.hh:668-677).
    """
    return CP_AIR * tdb + dw * (HFG_REF + CP_VAPOR * tdb)


@export
def psy_tdb_fn_h_w(h: Float64, dw: Float64) -> Float64:
    """Dry-bulb T from enthalpy and humidity ratio (inverse of `psy_h_fn_tdb_w`).

    Mirrors `PsyTdbFnHW` (Psychrometrics.hh:743-762).
    """
    var w = _max(dw, W_MIN)
    return (h - HFG_REF * w) / (CP_AIR + CP_VAPOR * w)


@export
def psy_cp_air_fn_w(dw: Float64) -> Float64:
    """Specific heat of moist air from humidity ratio.

    Mirrors `PsyCpAirFnW` (Psychrometrics.hh:679-716). The static cache from
    upstream is omitted: we want a thread-safe pure function.
    """
    var w = _max(dw, W_MIN)
    return CP_AIR + w * CP_VAPOR


@export
def psy_hfg_air_fn_w_tdb(w: Float64, t: Float64) -> Float64:
    """Latent heat of vaporization (Hg − Hf).

    Mirrors `PsyHfgAirFnWTdb` (Psychrometrics.hh:593-621). `w` is unused
    upstream — the result is per unit moisture mass.
    """
    var temperature = _max(t, 0.0)
    return (HFG_REF + CP_VAPOR * temperature) - (4180.0 * temperature)


@export
def psy_hg_air_fn_w_tdb(w: Float64, t: Float64) -> Float64:
    """Enthalpy of water vapor.

    Mirrors `PsyHgAirFnWTdb` (Psychrometrics.hh:623-646). `w` unused upstream.
    """
    return HFG_REF + CP_VAPOR * t


@export
def psy_rho_air_fn_pb_tdb_w(pb: Float64, tdb: Float64, dw: Float64) -> Float64:
    """Moist-air density from barometric pressure, T_dry-bulb, humidity ratio.

    Mirrors `PsyRhoAirFnPbTdbW` (Psychrometrics.hh:549-574). Ideal-gas law with
    air/water molecular-mass ratio correction.
    """
    var w = _max(dw, W_MIN)
    return pb / (R_AIR * (tdb + KELVIN) * (1.0 + MW_AIR_TO_H2O * w))


@export
def psy_rhov_fn_tdb_rh_lbnd0c(tdb: Float64, rh: Float64) -> Float64:
    """Vapor density from T_dry-bulb and relative humidity (≥ 0 °C).

    Mirrors `PsyRhovFnTdbRhLBnd0C` (Psychrometrics.hh:764-787).
    """
    var t_kel = tdb + KELVIN
    return rh / (R_VAPOR * t_kel) * exp(23.7093 - 4111.0 / (t_kel - 35.45))


@export
def psy_psat_fn_temp(t: Float64) -> Float64:
    """Saturation pressure of water vapor from temperature (°C).

    Mirrors `PsyPsatFnTemp_raw` (Psychrometrics.cc:721-756). Hyland-Wexler
    piecewise polynomial; ice region for T < 273.16 K, water region above,
    clamped at 173.15 K (low) and 473.15 K (high).
    """
    var t_kel = t + KELVIN
    if t_kel < 173.15:
        return 0.001405102123874164
    if t_kel < TRIPLE_POINT_K:
        # Ice region.
        return exp(
            C1 / t_kel
            + C2
            + t_kel * (C3 + t_kel * (C4 + t_kel * (C5 + C6 * t_kel)))
            + C7 * log(t_kel)
        )
    if t_kel <= 473.15:
        # Water region.
        return exp(
            C8 / t_kel
            + C9
            + t_kel * (C10 + t_kel * (C11 + t_kel * C12))
            + C13 * log(t_kel)
        )
    return 1555073.745636215


@export
def psy_w_fn_tdb_rh_pb(tdb: Float64, rh: Float64, pb: Float64) -> Float64:
    """Humidity ratio from T_dry-bulb, relative humidity, pressure.

    Closed-form: W = 0.62198 · (RH · Psat) / (P − RH · Psat). Mirrors
    `PsyWFnTdbRhPb` semantics for the unsaturated case (no error path here —
    that lives in M5).
    """
    var psat = psy_psat_fn_temp(tdb)
    var pw = rh * psat
    return 0.62198 * pw / (pb - pw)


@export
def psy_tdp_fn_tdb_rh(tdb: Float64, rh: Float64) -> Float64:
    """Dew point temperature from T_dry-bulb (°C) and relative humidity (0–1).

    Computes actual vapor pressure as ``RH * Psat(Tdb)`` using the
    Hyland-Wexler saturation pressure, then inverts via Newton-Raphson to
    find the temperature at which ``Psat(Tdp) == Pv``.

    The initial guess uses the Magnus formula (Alduchov & Eskridge 1996
    coefficients): ``es(T) = 610.94 * exp(17.625 * T / (T + 243.04))``,
    inverted analytically. Newton refinement uses the Clausius-Clapeyron
    derivative ``dPsat/dT = L * Psat / (Rv * T_kel^2)`` which converges
    in 3–5 iterations from the Magnus guess.

    Returns °C. Clamps ``rh`` to ``[RH_MIN, 1.0]`` to avoid ``log(0)``.
    """
    comptime _ITMAX = 50
    comptime _TOL: Float64 = 1.0e-6

    # Clamp RH to valid range
    var rh_clamped = rh
    if rh_clamped < RH_MIN:
        rh_clamped = RH_MIN
    if rh_clamped > 1.0:
        rh_clamped = 1.0

    # At saturation, dew point equals dry-bulb
    if rh_clamped >= 1.0:
        return tdb

    # Actual vapor pressure from Hyland-Wexler Psat
    var pv = rh_clamped * psy_psat_fn_temp(tdb)
    if pv <= 0.0:
        return tdb

    # Initial guess via Magnus formula inversion
    # gamma = ln(Pv / ES0), T_guess = B * gamma / (A - gamma)
    var gamma = log(pv / _MAGNUS_ES0)
    var tdp = _MAGNUS_B * gamma / (_MAGNUS_A - gamma)

    # Newton-Raphson refinement using Hyland-Wexler Psat
    for _ in range(_ITMAX):
        var psat_guess = psy_psat_fn_temp(tdp)
        var residual = psat_guess - pv
        var abs_res = residual if residual >= 0.0 else -residual
        if abs_res < _TOL:
            break
        # Clausius-Clapeyron derivative: dPsat/dT = L * Psat / (Rv * T_kel^2)
        var t_kel = tdp + KELVIN
        var dpsat_dt = HFG_REF * psat_guess / (R_VAPOR * t_kel * t_kel)
        if (dpsat_dt if dpsat_dt >= 0.0 else -dpsat_dt) < 1.0e-30:
            break
        tdp = tdp - residual / dpsat_dt

    # Dew point cannot exceed dry-bulb
    if tdp > tdb:
        tdp = tdb
    return tdp


@always_inline
@export
def psy_dew_point_temperature(temp_db: Float64, rel_hum: Float64) -> Float64:
    """Dew point temperature from dry-bulb temperature (°C) and relative humidity (0–1).

    Public alias for `psy_tdp_fn_tdb_rh`. Uses Hyland-Wexler saturation
    pressure for vapor-pressure computation and Newton-Raphson inversion
    with an Arden Buck (1981) Magnus-formula initial guess.

    Returns °C.

    Args:
        temp_db: Dry-bulb temperature in °C.
        rel_hum: Relative humidity as a fraction from 0 to 1.
    """
    return psy_tdp_fn_tdb_rh(temp_db, rel_hum)


# ---- iterative kernels --------------------------------------------------
# `Iterate` is the secant-method root-finder from upstream `General.cc:918`.
# It returns the next guess for X given current (X0, Y0) and previous
# (X1, Y1). Convergence is signalled by `cnvg=1` when |X0 - X1| < tol.

comptime _ITER_SMALL: Float64 = 1.0e-9
comptime _ITER_PERTURB: Float64 = 0.1


@always_inline
def _iterate(
    tol: Float64,
    x0: Float64,
    y0: Float64,
    mut x1: Float64,
    mut y1: Float64,
    iter: Int,
    mut cnvg: Int,
) -> Float64:
    """One step of upstream's `General::Iterate` secant method."""
    if iter != 1:
        if (x0 - x1 if x0 >= x1 else x1 - x0) < tol or y0 == 0.0:
            cnvg = 1
            return x0
    cnvg = 0
    var result_x: Float64
    if iter == 1:
        if (x0 if x0 >= 0.0 else -x0) > _ITER_SMALL:
            result_x = x0 * (1.0 + _ITER_PERTURB)
        else:
            result_x = _ITER_PERTURB
    else:
        var dy = y0 - y1
        if (dy if dy >= 0.0 else -dy) < _ITER_SMALL:
            dy = _ITER_SMALL
        result_x = (y0 * x1 - y1 * x0) / dy
    x1 = x0
    y1 = y0
    return result_x


@export
def psy_twb_fn_tdb_w_pb(tdb: Float64, dw: Float64, patm: Float64) -> Float64:
    """Wet-bulb temperature from T_dry-bulb, humidity ratio, pressure.

    Mirrors `PsyTwbFnTdbWPb` (Psychrometrics.cc:356-566). Iterative — uses
    the secant method on the function `Y(WBT) = W - W*(WBT, Patm)`, where
    W*(WBT, Patm) is the saturation-humidity-ratio relation per ASHRAE
    Fundamentals. Caps WBT at TDB (wet-bulb is always ≤ dry-bulb).

    The `tBoil` upper bound from upstream is omitted: for any reasonable
    psychrometric input the iteration stays well below the boiling point
    even without that clamp. If you hit that path you've already left the
    physically meaningful operating envelope.
    """
    comptime ITMAX = 100
    comptime TOL: Float64 = 1.0e-4

    var w = dw
    if w < 0.0:
        w = 1.0e-5

    var wbt = tdb
    var x1: Float64 = 0.0
    var y1: Float64 = 0.0
    var cnvg = 0
    var iter = 1
    while iter <= ITMAX:
        var psatstar = psy_psat_fn_temp(wbt)
        var wstar = 0.62198 * psatstar / (patm - psatstar)
        var new_w: Float64
        if wbt >= 0.0:
            new_w = ((2501.0 - 2.326 * wbt) * wstar - 1.006 * (tdb - wbt)) / (
                2501.0 + 1.86 * tdb - 4.186 * wbt
            )
        else:
            new_w = ((2830.0 - 0.24 * wbt) * wstar - 1.006 * (tdb - wbt)) / (
                2830.0 + 1.86 * tdb - 2.1 * wbt
            )
        var error = w - new_w
        var result_x = _iterate(TOL, wbt, error, x1, y1, iter, cnvg)
        wbt = result_x
        if cnvg == 1:
            break
        iter += 1

    if wbt > tdb:
        wbt = tdb
    return wbt


# ---- vectorized batch entry points ----------------------------------------
# Each batch function takes raw int64 memory addresses (typically from a
# NumPy array's `__array_interface__["data"][0]`) plus a count. Inside, we
# reconstruct typed pointers via `UnsafePointer[Float64, MutAnyOrigin]
# (unsafe_from_address=...)` — the standard Mojo 26.x pattern for FFI buffers
# (cf. NuMojo `dlpack.from_numpy`).
#
# This amortizes the ~500 ns ctypes overhead over the whole array, so the
# kernel speed matches what we measured in pure-Mojo (1-30 ns/call).
# `UnsafePointer` is in the prelude — no explicit import needed.


@export
def psy_h_fn_tdb_w_batch(tdb_addr: Int, dw_addr: Int, result_addr: Int, n: Int):
    """Batched `psy_h_fn_tdb_w`: result[i] = h(tdb[i], dw[i])."""
    var tdb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=tdb_addr)
    var dw = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=dw_addr)
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )
    for i in range(n):
        var w = _max(dw[i], W_MIN)
        result[i] = CP_AIR * tdb[i] + w * (HFG_REF + CP_VAPOR * tdb[i])


@export
def psy_psat_fn_temp_batch(t_addr: Int, result_addr: Int, n: Int):
    """Batched `psy_psat_fn_temp`."""
    var t = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=t_addr)
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )
    for i in range(n):
        var t_kel = t[i] + KELVIN
        if t_kel < 173.15:
            result[i] = 0.001405102123874164
        elif t_kel < TRIPLE_POINT_K:
            result[i] = exp(
                C1 / t_kel
                + C2
                + t_kel * (C3 + t_kel * (C4 + t_kel * (C5 + C6 * t_kel)))
                + C7 * log(t_kel)
            )
        elif t_kel <= 473.15:
            result[i] = exp(
                C8 / t_kel
                + C9
                + t_kel * (C10 + t_kel * (C11 + t_kel * C12))
                + C13 * log(t_kel)
            )
        else:
            result[i] = 1555073.745636215


@export
def psy_rho_air_fn_pb_tdb_w_batch(
    pb_addr: Int, tdb_addr: Int, dw_addr: Int, result_addr: Int, n: Int
):
    """Batched `psy_rho_air_fn_pb_tdb_w`."""
    var pb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=pb_addr)
    var tdb = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=tdb_addr)
    var dw = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=dw_addr)
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )
    for i in range(n):
        var w = _max(dw[i], W_MIN)
        result[i] = pb[i] / (
            R_AIR * (tdb[i] + KELVIN) * (1.0 + MW_AIR_TO_H2O * w)
        )


@export
def psy_cp_air_fn_w_batch(dw_addr: Int, result_addr: Int, n: Int):
    """Batched `psy_cp_air_fn_w`: result[i] = cp_air(dw[i])."""
    var dw = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=dw_addr)
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )
    for i in range(n):
        var w = _max(dw[i], W_MIN)
        result[i] = CP_AIR + w * CP_VAPOR


@export
def psy_w_fn_tdb_h_batch(
    n: Int, tdb_c_ptr: Int, h_j_per_kg_ptr: Int, out_w_ptr: Int
):
    """Batched humidity ratio from dry-bulb T (°C) and enthalpy (J/kg).

    Algebraic inverse of `psy_h_fn_tdb_w`:
        h = CP_AIR · T + max(W, W_MIN) · (HFG_REF + CP_VAPOR · T)
        ⇒ W = (h − CP_AIR · T) / (HFG_REF + CP_VAPOR · T)
    Result is clamped to W ≥ W_MIN to match upstream behavior.
    """
    var tdb = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=tdb_c_ptr
    )
    var h = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=h_j_per_kg_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_w_ptr
    )
    for i in range(n):
        var t = tdb[i]
        var w = (h[i] - CP_AIR * t) / (HFG_REF + CP_VAPOR * t)
        out[i] = _max(w, W_MIN)

@export
def pump_variable_speed_power_batch(
    n_pumps: Int,
    design_power_w_ptr: Int,
    design_flow_kg_s_ptr: Int,
    actual_flow_kg_s_ptr: Int,
    plr_coeff_c1_ptr: Int,
    plr_coeff_c2_ptr: Int,
    plr_coeff_c3_ptr: Int,
    plr_coeff_c4_ptr: Int,
    out_power_w_ptr: Int,
) -> None:
    """Variable-speed pump electrical power for N pumps in one FFI call.

    Each pump's electrical power is `design_power · (c1 + c2·plr + c3·plr²
    + c4·plr³)` where `plr = actual_flow / design_flow`. When
    `design_flow <= 0` the kernel writes 0 (avoids divide-by-zero on
    off / unsized pumps).

    All eight array arguments are raw int64 addresses to `float64[n_pumps]`
    C-contiguous buffers. The first seven are read-only inputs; the last
    is the output. No-op when `n_pumps <= 0`.
    """
    if n_pumps <= 0:
        return

    var design_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_power_w_ptr
    )
    var design_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_flow_kg_s_ptr
    )
    var actual_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=actual_flow_kg_s_ptr
    )
    var c1 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=plr_coeff_c1_ptr
    )
    var c2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=plr_coeff_c2_ptr
    )
    var c3 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=plr_coeff_c3_ptr
    )
    var c4 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=plr_coeff_c4_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_w_ptr
    )

    for i in range(n_pumps):
        var df = design_flow[i]
        if df <= 0.0:
            out[i] = 0.0
        else:
            var plr = actual_flow[i] / df
            var plr2 = plr * plr
            var plr3 = plr2 * plr
            var frac = c1[i] + c2[i] * plr + c3[i] * plr2 + c4[i] * plr3
            out[i] = design_power[i] * frac

from std.math import exp, pi


@export
def radiant_floor_lowtemp_batch(
    n: Int,
    d_tube_m_ptr: Int,
    l_tube_m_ptr: Int,
    h_fluid_w_m2k_ptr: Int,
    m_dot_fluid_ptr: Int,
    cp_fluid_ptr: Int,
    t_water_in_c_ptr: Int,
    t_floor_c_ptr: Int,
    out_q_to_floor_w_ptr: Int,
    out_t_water_out_c_ptr: Int,
):
    """Per-timestep low-temperature radiant floor heat balance for N surfaces.

    For each radiant surface i in [0, n):
        m_cp = m_dot_fluid[i] * cp_fluid[i]
        if m_cp <= 0:                    # loop off / zero-cp guard
            q = 0
            t_out = t_water_in[i]
        else:
            ntu = π * D[i] * L[i] * h[i] / m_cp
            eps = 1 − exp(−ntu)
            q   = eps * m_cp * (T_water_in[i] − T_floor[i])
            t_out = T_water_in[i] − q / m_cp

    Arguments:
      - `n`                       — number of radiant surfaces.
      - `d_tube_m_ptr`            — raw int64 addr of `float64[n]` tube ID [m].
      - `l_tube_m_ptr`            — raw int64 addr of `float64[n]` tube length [m].
      - `h_fluid_w_m2k_ptr`       — raw int64 addr of `float64[n]` internal
                                     tube convection coefficient [W/m²·K].
      - `m_dot_fluid_ptr`         — raw int64 addr of `float64[n]` mass flow
                                     rate of working fluid [kg/s].
      - `cp_fluid_ptr`            — raw int64 addr of `float64[n]` specific
                                     heat capacity of fluid [J/kg·K].
      - `t_water_in_c_ptr`        — raw int64 addr of `float64[n]` inlet water
                                     temperature [°C].
      - `t_floor_c_ptr`           — raw int64 addr of `float64[n]` floor
                                     surface temperature [°C].
      - `out_q_to_floor_w_ptr`    — raw int64 addr of `float64[n]` output
                                     heat transfer to floor surface [W].
      - `out_t_water_out_c_ptr`   — raw int64 addr of `float64[n]` output
                                     outlet water temperature [°C].

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var d_tube = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=d_tube_m_ptr
    )
    var l_tube = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=l_tube_m_ptr
    )
    var h_fluid = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=h_fluid_w_m2k_ptr
    )
    var m_dot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_fluid_ptr
    )
    var cp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cp_fluid_ptr
    )
    var t_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_water_in_c_ptr
    )
    var t_floor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_floor_c_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_to_floor_w_ptr
    )
    var out_t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_water_out_c_ptr
    )

    for i in range(n):
        var m_cp = m_dot[i] * cp[i]
        var t_in_i = t_in[i]
        if m_cp <= 0.0:
            # Loop off / zero-cp: no heat transfer; outlet equals inlet.
            # Avoids divide-by-zero in NTU and keeps a stalled radiant
            # surface from NaN-poisoning the rest of the zone balance.
            out_q[i] = 0.0
            out_t_out[i] = t_in_i
            continue

        var ntu = pi * d_tube[i] * l_tube[i] * h_fluid[i] / m_cp
        var eps = 1.0 - exp(-ntu)
        var q = eps * m_cp * (t_in_i - t_floor[i])
        out_q[i] = q
        out_t_out[i] = t_in_i - q / m_cp

from std.math import abs, max, min


comptime SIGMA: Float64 = 5.67e-8  # Stefan-Boltzmann constant [W/(m²·K⁴)]
comptime EPSILON: Float64 = 0.9  # surface emissivity
comptime CP_WATER: Float64 = 4186.0  # specific heat of water [J/(kg·K)]


@export
def radiant_surface_mrt_deviation_batch(
    n: Int,
    q_radiant_ptr: Int,
    area_m2_ptr: Int,
    sigma_ptr: Int,
    t_surface_ptr: Int,
    out_dt_mrt_ptr: Int,
):
    """MRT change from radiant surface heat flux for N surfaces.

    For each surface i in [0, n):
        dT_MRT[i] = q_radiant[i] / (4 * EPSILON * SIGMA * T_surface_K[i]^3 * area[i])

    where T_surface_K = T_surface_C + 273.15 and sigma_ptr provides a
    per-element Stefan-Boltzmann constant (allows caller-side overrides, though
    the kernel constant SIGMA=5.67e-8 is used as the reference value).

    Arguments:
      - `n`              — number of radiant surfaces.
      - `q_radiant_ptr`  — raw int64 addr of `float64[n]` radiant heat flux [W].
      - `area_m2_ptr`    — raw int64 addr of `float64[n]` surface area [m²].
      - `sigma_ptr`      — raw int64 addr of `float64[n]` Stefan-Boltzmann
                           constant per surface [W/(m²·K⁴)] (typically 5.67e-8).
      - `t_surface_ptr`  — raw int64 addr of `float64[n]` surface temperature [°C].
      - `out_dt_mrt_ptr` — raw int64 addr of `float64[n]` output MRT deviation [K].

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var q_radiant = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_radiant_ptr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_m2_ptr
    )
    var sigma_arr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sigma_ptr
    )
    var t_surface = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_surface_ptr
    )
    var out_dt_mrt = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_dt_mrt_ptr
    )

    for i in range(n):
        var t_k = t_surface[i] + 273.15
        var t_k3 = t_k * t_k * t_k
        var denom = 4.0 * EPSILON * sigma_arr[i] * t_k3 * area[i]
        if denom <= 0.0:
            out_dt_mrt[i] = 0.0
        else:
            out_dt_mrt[i] = q_radiant[i] / denom


@export
def radiant_surface_water_outlet_batch(
    n: Int,
    t_water_in_ptr: Int,
    q_ptr: Int,
    m_dot_ptr: Int,
    cp_ptr: Int,
    out_t_water_out_ptr: Int,
):
    """Water outlet temperature for N radiant surfaces.

    For each surface i in [0, n):
        T_out[i] = T_water_in[i] + q[i] / max(1e-9, m_dot[i] * cp[i])

    Sign convention: positive q = heating mode (water cools as it delivers heat),
    negative q = cooling mode (water warms as it absorbs heat).

    Arguments:
      - `n`                   — number of radiant surfaces.
      - `t_water_in_ptr`      — raw int64 addr of `float64[n]` inlet water
                                temperature [°C].
      - `q_ptr`               — raw int64 addr of `float64[n]` heat transfer
                                rate [W] (positive = heating, negative = cooling).
      - `m_dot_ptr`           — raw int64 addr of `float64[n]` mass flow rate [kg/s].
      - `cp_ptr`              — raw int64 addr of `float64[n]` specific heat [J/kg·K].
      - `out_t_water_out_ptr` — raw int64 addr of `float64[n]` output outlet
                                water temperature [°C].

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var t_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_water_in_ptr
    )
    var q = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=q_ptr)
    var m_dot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_ptr
    )
    var cp = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=cp_ptr)
    var out_t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_water_out_ptr
    )

    for i in range(n):
        var m_cp = max(1e-9, m_dot[i] * cp[i])
        out_t_out[i] = t_in[i] + q[i] / m_cp


@export
def radiant_surface_zone_heat_fraction_batch(
    n: Int,
    q_total_ptr: Int,
    frac_radiant_ptr: Int,
    frac_convective_ptr: Int,
    out_q_rad_ptr: Int,
    out_q_conv_ptr: Int,
):
    """Split total heat into radiant and convective components for N surfaces.

    For each surface i in [0, n):
        q_rad[i]  = q_total[i] * frac_radiant[i]
        q_conv[i] = q_total[i] * frac_convective[i]

    Guard: frac_radiant + frac_convective is assumed <= 1.0; the remaining
    fraction goes to conduction (not computed here).

    Arguments:
      - `n`                   — number of radiant surfaces.
      - `q_total_ptr`         — raw int64 addr of `float64[n]` total heat [W].
      - `frac_radiant_ptr`    — raw int64 addr of `float64[n]` radiant fraction
                                [0, 1].
      - `frac_convective_ptr` — raw int64 addr of `float64[n]` convective fraction
                                [0, 1].
      - `out_q_rad_ptr`       — raw int64 addr of `float64[n]` output radiant
                                heat [W].
      - `out_q_conv_ptr`      — raw int64 addr of `float64[n]` output convective
                                heat [W].

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var q_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_total_ptr
    )
    var frac_rad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=frac_radiant_ptr
    )
    var frac_conv = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=frac_convective_ptr
    )
    var out_q_rad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_rad_ptr
    )
    var out_q_conv = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_conv_ptr
    )

    for i in range(n):
        var qt = q_total[i]
        # Clamp fractions to [0, 1] individually before applying
        var fr = max(0.0, min(1.0, frac_rad[i]))
        var fc = max(0.0, min(1.0, frac_conv[i]))
        # If fr + fc > 1, renormalise so the split stays within qt
        var fsum = fr + fc
        if fsum > 1.0:
            fr = fr / fsum
            fc = fc / fsum
        out_q_rad[i] = qt * fr
        out_q_conv[i] = qt * fc


@export
def radiant_surface_variable_flow_batch(
    n: Int,
    t_zone_ptr: Int,
    t_setpoint_ptr: Int,
    t_water_in_ptr: Int,
    ua_ptr: Int,
    m_dot_max_ptr: Int,
    cp_ptr: Int,
    out_m_dot_ptr: Int,
    out_q_ptr: Int,
):
    """Variable-flow control for N radiant surfaces (heating or cooling).

    For each surface i in [0, n):
        q_req   = ua[i] * (T_zone[i] - T_setpoint[i])
                    positive → zone warmer than setpoint (cooling needed)
                    negative → zone cooler than setpoint (heating needed)
        m_dot   = q_req / max(1e-9, cp[i] * |T_water_in[i] - T_setpoint[i]|)
        m_dot   = clamp(m_dot, 0, m_dot_max[i])
        q_out   = m_dot * cp[i] * (T_water_in[i] - T_zone[i])
                    negative for cooling mode (cold supply, warm zone)
                    positive for heating mode (hot supply, cool zone)

    Arguments:
      - `n`              — number of radiant surfaces.
      - `t_zone_ptr`     — raw int64 addr of `float64[n]` zone air temperature [°C].
      - `t_setpoint_ptr` — raw int64 addr of `float64[n]` zone setpoint [°C].
      - `t_water_in_ptr` — raw int64 addr of `float64[n]` supply water temperature [°C].
      - `ua_ptr`         — raw int64 addr of `float64[n]` overall conductance [W/K].
      - `m_dot_max_ptr`  — raw int64 addr of `float64[n]` maximum mass flow rate [kg/s].
      - `cp_ptr`         — raw int64 addr of `float64[n]` specific heat [J/kg·K].
      - `out_m_dot_ptr`  — raw int64 addr of `float64[n]` output mass flow rate [kg/s].
      - `out_q_ptr`      — raw int64 addr of `float64[n]` output heat transfer [W].

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var t_set = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_setpoint_ptr
    )
    var t_win = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_water_in_ptr
    )
    var ua = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=ua_ptr)
    var m_dot_max = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_max_ptr
    )
    var cp = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=cp_ptr)
    var out_m_dot = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_m_dot_ptr
    )
    var out_q = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_ptr
    )

    for i in range(n):
        var q_req = ua[i] * (t_zone[i] - t_set[i])
        var dt_water = abs(t_win[i] - t_set[i])
        var m_dot_raw = q_req / max(1e-9, cp[i] * dt_water)
        var m_dot_i = max(0.0, min(m_dot_max[i], m_dot_raw))
        out_m_dot[i] = m_dot_i
        out_q[i] = m_dot_i * cp[i] * (t_win[i] - t_zone[i])


@export
def radiant_surface_condensation_check_batch(
    n: Int,
    t_surface_ptr: Int,
    t_dewpoint_ptr: Int,
    out_risk_ptr: Int,
):
    """Condensation risk for N radiant cooling surfaces.

    For each surface i in [0, n):
        risk[i] = max(0, T_dewpoint[i] - T_surface[i])

    A positive result indicates condensation risk; the value is the margin
    in kelvin by which the surface is below the dew point.

    Arguments:
      - `n`               — number of radiant surfaces.
      - `t_surface_ptr`   — raw int64 addr of `float64[n]` surface temperature [°C].
      - `t_dewpoint_ptr`  — raw int64 addr of `float64[n]` zone dew-point
                            temperature [°C].
      - `out_risk_ptr`    — raw int64 addr of `float64[n]` output condensation
                            risk margin [K] (0 = no risk).

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var t_surface = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_surface_ptr
    )
    var t_dew = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_dewpoint_ptr
    )
    var out_risk = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_risk_ptr
    )

    for i in range(n):
        out_risk[i] = max(0.0, t_dew[i] - t_surface[i])

comptime CASE_SET_T_C: Float64 = -1.0
comptime ZONE_W_REF: Float64 = 0.008
comptime RATED_CAP_REF_W: Float64 = 1900.0
comptime K_SENS_W_PER_M_PER_K: Float64 = 55.0
comptime K_LAT_W_PER_M_PER_KGKG: Float64 = 1.8e5


@always_inline
def _max0(x: Float64) -> Float64:
    return x if x > 0.0 else 0.0


@always_inline
def _clamp01(x: Float64) -> Float64:
    return 0.0 if x < 0.0 else (1.0 if x > 1.0 else x)


@export
def refrigeration_case_load_batch(
    n: Int,
    zone_t_ptr: Int,
    zone_w_ptr: Int,
    case_length_ptr: Int,
    rated_total_ptr: Int,
    rated_lhr_ptr: Int,
    defrost_sched_ptr: Int,
    lighting_ptr: Int,
    anti_sweat_ptr: Int,
    out_sensible_w_ptr: Int,
    out_latent_w_ptr: Int,
    out_total_elec_w_ptr: Int,
) -> None:
    """Compute sensible + latent + non-refrigerant electric loads for N cases.

    All eight input arrays and three output arrays are Float64[n] C-contiguous;
    the kernel receives their raw int64 addresses (the standard FFI shape used
    by every other batch kernel in this tree). No-op when `n <= 0`.

    Inputs:
      - `zone_t_ptr`           — Float64[n], zone dry-bulb temperature, deg C
      - `zone_w_ptr`           — Float64[n], zone humidity ratio, kg/kg
      - `case_length_ptr`      — Float64[n], case length, m
      - `rated_total_ptr`      — Float64[n], rated total cooling capacity, W
      - `rated_lhr_ptr`        — Float64[n], rated latent heat ratio in [0, 1]
      - `defrost_sched_ptr`    — Float64[n], defrost schedule value in [0, 1]
                                  (1 = case fully in defrost → zero refrigeration load)
      - `lighting_ptr`         — Float64[n], case lighting power, W
      - `anti_sweat_ptr`       — Float64[n], anti-sweat heater power, W

    Outputs:
      - `out_sensible_w_ptr`   — Float64[n], sensible cooling load, W (>= 0)
      - `out_latent_w_ptr`     — Float64[n], latent cooling load,   W (>= 0)
      - `out_total_elec_w_ptr` — Float64[n], non-refrigerant elec,  W
    """
    if n <= 0:
        return

    var zone_t = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=zone_t_ptr
    )
    var zone_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=zone_w_ptr
    )
    var case_length = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=case_length_ptr
    )
    var rated_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_total_ptr
    )
    var rated_lhr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rated_lhr_ptr
    )
    var defrost = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=defrost_sched_ptr
    )
    var lighting = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=lighting_ptr
    )
    var anti_sweat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=anti_sweat_ptr
    )
    var out_sens = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_sensible_w_ptr
    )
    var out_lat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_latent_w_ptr
    )
    var out_elec = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_total_elec_w_ptr
    )

    for i in range(n):
        var length_m = case_length[i]
        var defrost_active = _clamp01(defrost[i])
        # 1 - defrost: when defrost == 1 the refrigeration system is off
        # for the entire timestep, so both sensible and latent collapse to 0.
        var avail = 1.0 - defrost_active

        # Capacity scaling: a 3800 W rated case extracts ~2x what a 1900 W
        # rated case does under identical zone conditions. RATED_CAP_REF
        # anchors the linear model so default-sized cases land near rated.
        var cap_ratio = rated_total[i] / RATED_CAP_REF_W

        # Sensible: drive force is (T_zone - T_case_set). When the zone is
        # at or below the case set point there's no sensible gain.
        var dt = zone_t[i] - CASE_SET_T_C
        var sens = K_SENS_W_PER_M_PER_K * length_m * dt * avail * cap_ratio
        out_sens[i] = _max0(sens)

        # Latent: drive force is (W_zone - W_ref). Multiplied by rated LHR
        # so cases tuned for low-humidity duty respond less to a humid zone.
        var dw = zone_w[i] - ZONE_W_REF
        var lat = (
            K_LAT_W_PER_M_PER_KGKG
            * length_m
            * dw
            * avail
            * rated_lhr[i]
            * cap_ratio
        )
        out_lat[i] = _max0(lat)

        # Non-refrigerant electric draw is independent of defrost state in
        # this surrogate (lights stay on, anti-sweat heaters always run).
        out_elec[i] = lighting[i] + anti_sweat[i]

@always_inline
def _f64_ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _max0(x: Float64) -> Float64:
    return x if x > 0.0 else 0.0


@always_inline
def _clamp01(x: Float64) -> Float64:
    return 0.0 if x < 0.0 else (1.0 if x > 1.0 else x)


@export
def refrigeration_case_credit_batch(
    n: Int,
    # Zone air state per case (broadcast or per-case)
    zone_temp_c_ptr: Int,
    # Per-case design parameters
    case_length_m_ptr: Int,
    case_temp_c_ptr: Int,
    rated_ambient_c_ptr: Int,
    rated_total_per_m_ptr: Int,
    rated_lhr_ptr: Int,
    rated_rtf_ptr: Int,
    # Schedule / fraction inputs (pre-looked-up by Python caller)
    avail_ptr: Int,
    credit_frac_ptr: Int,
    light_frac_ptr: Int,
    defrost_frac_ptr: Int,
    # Per-unit-length power parameters
    fan_power_per_m_ptr: Int,
    light_power_per_m_ptr: Int,
    anti_sweat_per_m_ptr: Int,
    defrost_power_per_m_ptr: Int,
    # Pre-evaluated latent curve multiplier (1.0 when no curve)
    latent_curve_mult_ptr: Int,
    # Outputs
    out_sensible_w_ptr: Int,
    out_latent_w_ptr: Int,
    out_electric_w_ptr: Int,
) -> None:
    """Compute (sensible_w, latent_w, electric_w) for N refrigeration cases.

    All input and output arrays are Float64[n] C-contiguous; addresses are
    passed as raw int64 following the standard FFI shape used by every other
    batch kernel in this tree. No-op when n <= 0.

    Inputs:
      zone_temp_c_ptr        — Float64[n], host-zone dry-bulb temperature, °C
      case_length_m_ptr      — Float64[n], case length, m
      case_temp_c_ptr        — Float64[n], case operating temperature, °C
      rated_ambient_c_ptr    — Float64[n], rated ambient (zone) temperature, °C
      rated_total_per_m_ptr  — Float64[n], rated total cooling capacity, W/m
      rated_lhr_ptr          — Float64[n], rated latent heat ratio in [0, 1]
      rated_rtf_ptr          — Float64[n], rated runtime fraction in [0, 1]
      avail_ptr              — Float64[n], availability schedule value in [0, 1]
      credit_frac_ptr        — Float64[n], case-credit fraction schedule value
      light_frac_ptr         — Float64[n], case-lighting schedule value
      defrost_frac_ptr       — Float64[n], defrost schedule value in [0, 1]
      fan_power_per_m_ptr    — Float64[n], operating fan power, W/m
      light_power_per_m_ptr  — Float64[n], installed lighting power, W/m
      anti_sweat_per_m_ptr   — Float64[n], anti-sweat heater power, W/m
      defrost_power_per_m_ptr— Float64[n], defrost heater power, W/m
      latent_curve_mult_ptr  — Float64[n], pre-evaluated latent curve multiplier

    Outputs:
      out_sensible_w_ptr     — Float64[n], net sensible zone gain, W
                               (positive heats zone, negative cools it)
      out_latent_w_ptr       — Float64[n], latent zone gain, W (<= 0)
      out_electric_w_ptr     — Float64[n], total electric draw, W (>= 0)
    """
    if n <= 0:
        return

    var zone_temp_c = _f64_ptr(zone_temp_c_ptr)
    var case_length_m = _f64_ptr(case_length_m_ptr)
    var case_temp_c = _f64_ptr(case_temp_c_ptr)
    var rated_ambient_c = _f64_ptr(rated_ambient_c_ptr)
    var rated_total_per_m = _f64_ptr(rated_total_per_m_ptr)
    var rated_lhr = _f64_ptr(rated_lhr_ptr)
    var rated_rtf = _f64_ptr(rated_rtf_ptr)
    var avail = _f64_ptr(avail_ptr)
    var credit_frac = _f64_ptr(credit_frac_ptr)
    var light_frac = _f64_ptr(light_frac_ptr)
    var defrost_frac = _f64_ptr(defrost_frac_ptr)
    var fan_power_per_m = _f64_ptr(fan_power_per_m_ptr)
    var light_power_per_m = _f64_ptr(light_power_per_m_ptr)
    var anti_sweat_per_m = _f64_ptr(anti_sweat_per_m_ptr)
    var defrost_power_per_m = _f64_ptr(defrost_power_per_m_ptr)
    var latent_curve_mult = _f64_ptr(latent_curve_mult_ptr)
    var out_sens = _f64_ptr(out_sensible_w_ptr)
    var out_lat = _f64_ptr(out_latent_w_ptr)
    var out_elec = _f64_ptr(out_electric_w_ptr)

    for i in range(n):
        var av = avail[i]

        # Availability gates everything: case off → all zeros.
        if av <= 0.0:
            out_sens[i] = 0.0
            out_lat[i] = 0.0
            out_elec[i] = 0.0
            continue

        var length_m = case_length_m[i]

        # ── Electric end-uses ──────────────────────────────────────────
        var fan_w = fan_power_per_m[i] * length_m

        var light_frac_i = _max0(light_frac[i])
        var lighting_w = light_power_per_m[i] * length_m * light_frac_i

        var anti_sweat_w = anti_sweat_per_m[i] * length_m

        var defrost_frac_i = _max0(defrost_frac[i])
        var defrost_w = defrost_power_per_m[i] * length_m * defrost_frac_i

        var electric_w = fan_w + lighting_w + anti_sweat_w + defrost_w

        # ── Sensible case credit (UA linear model) ─────────────────────
        var lhr = _clamp01(rated_lhr[i])
        var rated_sens_per_m = rated_total_per_m[i] * _max0(1.0 - lhr)
        var rated_lat_per_m = rated_total_per_m[i] * _max0(lhr)
        var rtf = rated_rtf[i]
        var cfrac = credit_frac[i]

        var t_case = case_temp_c[i]
        var dt_rated = rated_ambient_c[i] - t_case
        var dt_zone = zone_temp_c[i] - t_case
        var sens_ratio: Float64
        if dt_rated <= 0.0 or dt_zone <= 0.0:
            sens_ratio = 0.0
        else:
            sens_ratio = dt_zone / dt_rated

        var sensible_credit_w = (
            rated_sens_per_m * length_m * sens_ratio * rtf * av * cfrac
        )

        # ── Latent case credit ─────────────────────────────────────────
        # Defrost drip-down: credit is zero while defrost is active.
        var avail_for_lat = _max0(1.0 - _clamp01(defrost_frac_i))
        var latent_credit_w = _max0(
            rated_lat_per_m
            * length_m
            * latent_curve_mult[i]
            * rtf
            * av
            * cfrac
            * avail_for_lat
        )

        # ── Zone heat-balance contributions ───────────────────────────
        out_sens[i] = electric_w - sensible_credit_w
        out_lat[i] = -latent_credit_w
        out_elec[i] = electric_w

@always_inline
def _f64_ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _clamp01(x: Float64) -> Float64:
    return 0.0 if x < 0.0 else (1.0 if x > 1.0 else x)


@always_inline
def _max0(x: Float64) -> Float64:
    return x if x > 0.0 else 0.0


@export
def refrigeration_rack_power_batch(
    n: Int,
    total_case_load_w_ptr: Int,
    rated_rack_capacity_w_ptr: Int,
    design_cop_ptr: Int,
    design_fan_power_w_ptr: Int,
    out_compressor_elec_w_ptr: Int,
    out_fan_elec_w_ptr: Int,
    out_total_elec_w_ptr: Int,
    out_heat_rejection_w_ptr: Int,
) -> None:
    """Compute compressor rack power and heat rejection for N racks.

    All four input arrays and four output arrays are Float64[n]
    C-contiguous; raw int64 addresses follow the standard FFI shape.
    No-op when `n <= 0`.

    Inputs:
      - `total_case_load_w_ptr`      — Float64[n], sum of served case loads, W (>= 0)
      - `rated_rack_capacity_w_ptr`  — Float64[n], rated rack cooling capacity, W (> 0)
      - `design_cop_ptr`             — Float64[n], design COP (> 0)
      - `design_fan_power_w_ptr`     — Float64[n], condenser fan power at full load, W

    Outputs:
      - `out_compressor_elec_w_ptr`  — Float64[n], compressor electrical input, W
      - `out_fan_elec_w_ptr`         — Float64[n], condenser fan electrical input, W
      - `out_total_elec_w_ptr`       — Float64[n], total rack electrical draw, W
      - `out_heat_rejection_w_ptr`   — Float64[n], total heat rejection to sink, W
    """
    if n <= 0:
        return

    var case_load = _f64_ptr(total_case_load_w_ptr)
    var rated_cap = _f64_ptr(rated_rack_capacity_w_ptr)
    var cop = _f64_ptr(design_cop_ptr)
    var fan_power = _f64_ptr(design_fan_power_w_ptr)
    var out_comp = _f64_ptr(out_compressor_elec_w_ptr)
    var out_fan = _f64_ptr(out_fan_elec_w_ptr)
    var out_total = _f64_ptr(out_total_elec_w_ptr)
    var out_hr = _f64_ptr(out_heat_rejection_w_ptr)

    for i in range(n):
        var c = cop[i]
        var load = _max0(case_load[i])

        if c <= 0.0:
            out_comp[i] = 0.0
            out_fan[i] = 0.0
            out_total[i] = 0.0
            out_hr[i] = 0.0
            continue

        # Part-load ratio drives condenser fan power.
        var cap = rated_cap[i]
        var plr: Float64
        if cap > 0.0:
            plr = _clamp01(load / cap)
        else:
            plr = 1.0

        var comp_elec = load / c
        var fan_elec = fan_power[i] * plr
        var total_elec = comp_elec + fan_elec
        # Heat rejected to the condenser sink = refrigeration load + compressor work.
        # Fan heat is rejected to ambient separately (condenser air-side); not added
        # here so callers can account for it per their condenser model.
        var heat_rej = load + comp_elec

        out_comp[i] = comp_elec
        out_fan[i] = fan_elec
        out_total[i] = total_elec
        out_hr[i] = heat_rej

from std.math import pow, max, min

comptime CP_AIR: Float64 = 1006.0          # specific heat of air (J/kg·K)
comptime EER_MIN: Float64 = 1.0            # minimum effective EER denominator
comptime EFF_MIN: Float64 = 0.5            # minimum heating efficiency denominator
comptime MIN_MDOTCP: Float64 = 1.0e-3     # minimum m_dot*cp denominator (W/K)
comptime K_ODB: Float64 = -0.008          # ODB correction slope (1/°C)
comptime T_ODB_RATED: Float64 = 35.0      # rated outdoor dry-bulb temperature (°C)
comptime FAN_EXP: Float64 = 3.0           # fan cube-law exponent
comptime ODB_CORR_LO: Float64 = 0.5       # lower clamp on odb_correction
comptime ODB_CORR_HI: Float64 = 1.2       # upper clamp on odb_correction
comptime ZERO: Float64 = 0.0
comptime ONE: Float64 = 1.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _clamp(v: Float64, lo: Float64, hi: Float64) -> Float64:
    """Clamp v to [lo, hi]."""
    if v < lo:
        return lo
    if v > hi:
        return hi
    return v


@always_inline
def _eer_adjusted(eer_rated: Float64, t_odb: Float64) -> Float64:
    """Compute outdoor-temperature-corrected EER."""
    var eer_safe = max(ZERO, eer_rated)
    var odb_corr = ONE + K_ODB * (t_odb - T_ODB_RATED)
    var odb_clamped = _clamp(odb_corr, ODB_CORR_LO, ODB_CORR_HI)
    return eer_safe * odb_clamped


@always_inline
def _cooling_step(
    capacity: Float64,
    eer_rated: Float64,
    t_odb: Float64,
    t_return: Float64,
    m_dot: Float64,
    plr: Float64,
) -> (Float64, Float64, Float64):
    """Compute (q_cooling, w_cooling, t_supply) for one cooling unit."""
    var cap = max(ZERO, capacity)
    var plr_c = _clamp(plr, ZERO, ONE)
    var q = _clamp(cap * plr_c, ZERO, cap)
    var eer_adj = _eer_adjusted(eer_rated, t_odb)
    var w = q / max(EER_MIN, eer_adj)
    var mdot_safe = max(ZERO, m_dot)
    var mdotcp = max(MIN_MDOTCP, mdot_safe * CP_AIR)
    var t_sup = t_return - q / mdotcp
    return q, w, t_sup


@always_inline
def _heating_step(
    capacity: Float64,
    eff: Float64,
    t_return: Float64,
    m_dot: Float64,
    plr: Float64,
) -> (Float64, Float64, Float64):
    """Compute (q_heating, w_heating, t_supply) for one heating unit."""
    var cap = max(ZERO, capacity)
    var plr_c = _clamp(plr, ZERO, ONE)
    var q = _clamp(cap * plr_c, ZERO, cap)
    var w = q / max(EFF_MIN, eff)
    var mdot_safe = max(ZERO, m_dot)
    var mdotcp = max(MIN_MDOTCP, mdot_safe * CP_AIR)
    var t_sup = t_return + q / mdotcp
    return q, w, t_sup


@export
def rtu_cooling_batch(
    n: Int,
    capacity_cooling_ptr: Int,
    eer_rated_ptr: Int,
    t_odb_ptr: Int,
    t_return_ptr: Int,
    m_dot_ptr: Int,
    plr_ptr: Int,
    out_q_cooling_ptr: Int,
    out_w_cooling_ptr: Int,
    out_t_supply_ptr: Int,
):
    """Batched RTU cooling-only performance (no fan, no heating).

    For each unit i in [0, n):

        odb_correction = 1 + K_ODB * (t_odb[i] - T_ODB_RATED)
        eer_adjusted   = max(0, eer_rated[i]) * clamp(odb_correction, 0.5, 1.2)
        plr_c          = clamp(plr[i], 0.0, 1.0)
        q_cooling[i]   = clamp(capacity_cooling[i] * plr_c, 0, capacity_cooling[i])
        w_cooling[i]   = q_cooling[i] / max(EER_MIN=1.0, eer_adjusted)
        t_supply[i]    = t_return[i] - q_cooling[i] / max(1e-3, m_dot[i]*1006)

    Guards:
      capacity_cooling, eer_rated, m_dot clamped >= 0.
      plr clamped to [0, 1].

    Arguments:
      - `n`                  — batch size.
      - `capacity_cooling_ptr` — float64[n] rated cooling capacity (W).
      - `eer_rated_ptr`      — float64[n] rated EER (W/W) at standard conditions.
      - `t_odb_ptr`          — float64[n] outdoor dry-bulb temperature (°C).
      - `t_return_ptr`       — float64[n] return-air (entering) temperature (°C).
      - `m_dot_ptr`          — float64[n] air mass flow rate (kg/s).
      - `plr_ptr`            — float64[n] part-load ratio [0, 1] (clamped internally).
      - `out_q_cooling_ptr`  — float64[n] actual cooling output (W).
      - `out_w_cooling_ptr`  — float64[n] compressor power (W).
      - `out_t_supply_ptr`   — float64[n] supply-air temperature (°C).

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var cap_c = _ptr(capacity_cooling_ptr)
    var eer_r = _ptr(eer_rated_ptr)
    var t_odb = _ptr(t_odb_ptr)
    var t_ret = _ptr(t_return_ptr)
    var m_dot = _ptr(m_dot_ptr)
    var plr = _ptr(plr_ptr)
    var out_q = _ptr(out_q_cooling_ptr)
    var out_w = _ptr(out_w_cooling_ptr)
    var out_ts = _ptr(out_t_supply_ptr)

    for i in range(n):
        var q: Float64
        var w: Float64
        var ts: Float64
        q, w, ts = _cooling_step(
            cap_c[i], eer_r[i], t_odb[i], t_ret[i], m_dot[i], plr[i]
        )
        out_q[i] = q
        out_w[i] = w
        out_ts[i] = ts


@export
def rtu_full_batch(
    n: Int,
    capacity_cooling_ptr: Int,
    capacity_heating_ptr: Int,
    eer_rated_ptr: Int,
    eff_heating_ptr: Int,
    w_fan_rated_ptr: Int,
    t_odb_ptr: Int,
    t_return_ptr: Int,
    m_dot_ptr: Int,
    plr_ptr: Int,
    mode_ptr: Int,
    out_q_heat_cool_ptr: Int,
    out_w_total_ptr: Int,
    out_t_supply_ptr: Int,
):
    """Full RTU timestep: cooling or heating + supply fan.

    For each unit i in [0, n):

      mode[i] == 0.0  →  cooling:
        odb_correction = 1 + K_ODB * (t_odb[i] - T_ODB_RATED)
        eer_adjusted   = max(0, eer_rated[i]) * clamp(odb_correction, 0.5, 1.2)
        plr_c          = clamp(plr[i], 0.0, 1.0)
        q_cool         = clamp(capacity_cooling[i]*plr_c, 0, capacity_cooling[i])
        w_cool         = q_cool / max(EER_MIN=1.0, eer_adjusted)
        w_heat         = 0
        t_supply[i]    = t_return[i] - q_cool / max(1e-3, m_dot[i]*1006)

      mode[i] == 1.0  →  heating:
        plr_c          = clamp(plr[i], 0.0, 1.0)
        q_heat         = clamp(capacity_heating[i]*plr_c, 0, capacity_heating[i])
        w_heat         = q_heat / max(EFF_MIN=0.5, eff_heating[i])
        w_cool         = 0
        t_supply[i]    = t_return[i] + q_heat / max(1e-3, m_dot[i]*1006)

      Fan (always):
        plr_c          = clamp(plr[i], 0.0, 1.0)
        w_fan[i]       = w_fan_rated[i] * pow(plr_c, 3.0)

      w_total[i]     = w_cool + w_heat + w_fan[i]
      out_q_heat_cool[i] = active mode q (>= 0)

    Guards:
      capacities, eer_rated, m_dot clamped >= 0.
      plr clamped to [0, 1].
      inactive branch's coil power is zero.

    Arguments:
      - `n`                    — batch size.
      - `capacity_cooling_ptr` — float64[n] cooling capacity (W).
      - `capacity_heating_ptr` — float64[n] heating capacity (W).
      - `eer_rated_ptr`        — float64[n] rated EER (W/W).
      - `eff_heating_ptr`      — float64[n] heating efficiency (fraction).
      - `w_fan_rated_ptr`      — float64[n] rated fan power at PLR=1 (W).
      - `t_odb_ptr`            — float64[n] outdoor dry-bulb temperature (°C).
      - `t_return_ptr`         — float64[n] return-air temperature (°C).
      - `m_dot_ptr`            — float64[n] air mass flow rate (kg/s).
      - `plr_ptr`              — float64[n] part-load ratio (clamped to [0,1]).
      - `mode_ptr`             — float64[n] operating mode (0.0=cooling, 1.0=heating).
      - `out_q_heat_cool_ptr`  — float64[n] active thermal output (W).
      - `out_w_total_ptr`      — float64[n] total electrical power (W).
      - `out_t_supply_ptr`     — float64[n] supply-air temperature (°C).

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var cap_c = _ptr(capacity_cooling_ptr)
    var cap_h = _ptr(capacity_heating_ptr)
    var eer_r = _ptr(eer_rated_ptr)
    var eff_h = _ptr(eff_heating_ptr)
    var w_fan_r = _ptr(w_fan_rated_ptr)
    var t_odb = _ptr(t_odb_ptr)
    var t_ret = _ptr(t_return_ptr)
    var m_dot = _ptr(m_dot_ptr)
    var plr = _ptr(plr_ptr)
    var mode = _ptr(mode_ptr)
    var out_q = _ptr(out_q_heat_cool_ptr)
    var out_w = _ptr(out_w_total_ptr)
    var out_ts = _ptr(out_t_supply_ptr)

    for i in range(n):
        var plr_c = _clamp(plr[i], ZERO, ONE)
        var w_fan = w_fan_r[i] * pow(plr_c, FAN_EXP)

        var q_active: Float64
        var w_coil: Float64
        var ts: Float64

        if mode[i] == ONE:
            # Heating branch
            var q: Float64
            var w: Float64
            q, w, ts = _heating_step(
                cap_h[i], eff_h[i], t_ret[i], m_dot[i], plr[i]
            )
            q_active = q
            w_coil = w
        else:
            # Cooling branch (default)
            var q: Float64
            var w: Float64
            q, w, ts = _cooling_step(
                cap_c[i], eer_r[i], t_odb[i], t_ret[i], m_dot[i], plr[i]
            )
            q_active = q
            w_coil = w

        out_q[i] = q_active
        out_w[i] = w_coil + w_fan
        out_ts[i] = ts

@export
def schedule_year_lookup_batch(
    n_queries: Int,
    query_doy_ptr: Int,
    n_ranges: Int,
    range_start_doy_ptr: Int,
    range_end_doy_ptr: Int,
    range_day_index_ptr: Int,
    out_day_index_ptr: Int,
):
    """Resolve N day-of-year queries to their active Schedule:Day index.

    Arguments:
      - `n_queries`             — N: number of day-of-year queries.
      - `query_doy_ptr`         — raw int64 address of `int64[N]` day-of-year
                                   queries (1-based or 0-based, the kernel
                                   does not interpret the values).
      - `n_ranges`              — M: number of Schedule:Year ranges.
      - `range_start_doy_ptr`   — raw int64 address of `int64[M]` inclusive
                                   range start day-of-year values.
      - `range_end_doy_ptr`     — raw int64 address of `int64[M]` inclusive
                                   range end day-of-year values.
      - `range_day_index_ptr`   — raw int64 address of `int64[M]` Schedule:Day
                                   indices aligned with the range arrays.
      - `out_day_index_ptr`     — raw int64 address of `int64[N]` output
                                   buffer.

    Behaviour: for each query `i`, scan ranges in order and write the first
    `range_day_index[k]` where
    `range_start_doy[k] <= query_doy[i] <= range_end_doy[k]`. If no range
    matches, write `-1`.

    No-op when `n_queries == 0`. When `n_ranges == 0` every output slot
    becomes `-1` (fallthrough sentinel).
    """
    if n_queries <= 0:
        return

    var queries = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=query_doy_ptr
    )
    var out = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=out_day_index_ptr
    )

    if n_ranges <= 0:
        for i in range(n_queries):
            out[i] = Int64(-1)
        return

    var starts = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=range_start_doy_ptr
    )
    var ends = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=range_end_doy_ptr
    )
    var day_idx = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=range_day_index_ptr
    )

    for i in range(n_queries):
        var d = queries[i]
        var resolved = Int64(-1)
        for k in range(n_ranges):
            if starts[k] <= d and d <= ends[k]:
                resolved = day_idx[k]
                break
        out[i] = resolved

@export
def setpoint_dual_setband_batch(
    n: Int,
    t_zone_ptr: Int,
    heating_sp_ptr: Int,
    cooling_sp_ptr: Int,
    out_mode_ptr: Int,
    out_active_sp_ptr: Int,
) -> None:
    """Evaluate the DualSetpointWithDeadband thermostat for `n` zones.

    Arguments:
      - `n`                  — number of zone × timestep records.
      - `t_zone_ptr`         — Float64[n] zone air temperature (°C).
      - `heating_sp_ptr`     — Float64[n] heating setpoint (°C).
      - `cooling_sp_ptr`     — Float64[n] cooling setpoint (°C).
      - `out_mode_ptr`       — Int8[n] output mode buffer. Values:
                                0 = DEAD_BAND, 1 = HEATING, 2 = COOLING.
      - `out_active_sp_ptr`  — Float64[n] output active setpoint (°C);
                                NaN in the DEAD_BAND case.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var heating_sp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=heating_sp_ptr
    )
    var cooling_sp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cooling_sp_ptr
    )
    var out_mode = UnsafePointer[Int8, MutAnyOrigin](
        unsafe_from_address=out_mode_ptr
    )
    var out_active_sp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_active_sp_ptr
    )

    var nan_f64: Float64 = 0.0 / 0.0

    for i in range(n):
        var tz = t_zone[i]
        var hsp = heating_sp[i]
        var csp = cooling_sp[i]
        if tz < hsp:
            out_mode[i] = Int8(1)
            out_active_sp[i] = hsp
        elif tz > csp:
            out_mode[i] = Int8(2)
            out_active_sp[i] = csp
        else:
            out_mode[i] = Int8(0)
            out_active_sp[i] = nan_f64

@always_inline
def _lerp_clamped(
    oat: Float64,
    t_lo: Float64,
    t_hi: Float64,
    sp_lo: Float64,
    sp_hi: Float64,
) -> Float64:
    """Linearly interpolate setpoint from OAT, clamped to [sp_lo, sp_hi].

    When t_hi == t_lo (degenerate zero-width band) return sp_lo to
    avoid divide-by-zero and match EnergyPlus's fallback behaviour.

    The `sp_lo` / `sp_hi` values follow the IDD convention where
    `setpoint_at_outdoor_low_temperature` is the setpoint when OAT is
    at or below `outdoor_low_temperature`, and
    `setpoint_at_outdoor_high_temperature` is the setpoint when OAT is
    at or above `outdoor_high_temperature`. The two setpoint values may
    be in any order (chilled-water reset typically has sp_lo > sp_hi;
    hot-water reset has sp_lo < sp_hi); clamping is to the
    [min(sp_lo,sp_hi), max(sp_lo,sp_hi)] interval.
    """
    var dt_band = t_hi - t_lo
    # Guard against zero-width band.
    var eps: Float64 = 1.0e-12
    if dt_band < eps and dt_band > -eps:
        return sp_lo

    var sp_raw = sp_lo + (sp_hi - sp_lo) / dt_band * (oat - t_lo)

    # Clamp to the [sp_lo, sp_hi] interval regardless of orientation.
    var sp_min = sp_lo
    var sp_max = sp_hi
    if sp_lo > sp_hi:
        sp_min = sp_hi
        sp_max = sp_lo

    if sp_raw < sp_min:
        return sp_min
    if sp_raw > sp_max:
        return sp_max
    return sp_raw


@export
def setpoint_oa_reset_batch(
    n: Int,
    oat_ptr: Int,
    sp_lo_ptr: Int,
    t_lo_ptr: Int,
    sp_hi_ptr: Int,
    t_hi_ptr: Int,
    has_secondary_ptr: Int,
    sp_lo2_ptr: Int,
    t_lo2_ptr: Int,
    sp_hi2_ptr: Int,
    t_hi2_ptr: Int,
    out_setpoint_ptr: Int,
) -> None:
    """Evaluate SetpointManager:OutdoorAirReset for N managers per timestep.

    For each manager i in [0, n):

        sp_primary = lerp_clamped(oat[i], t_lo[i], t_hi[i],
                                  sp_lo[i], sp_hi[i])

        if has_secondary[i] != 0:
            sp_secondary = lerp_clamped(oat[i], t_lo2[i], t_hi2[i],
                                        sp_lo2[i], sp_hi2[i])
            out[i] = (sp_primary + sp_secondary) * 0.5
        else:
            out[i] = sp_primary

    Arguments:
      - `n`                — number of managers in the batch.
      - `oat_ptr`          — Float64[n] current outdoor air dry-bulb (°C).
      - `sp_lo_ptr`        — Float64[n] setpoint at outdoor low T (°C or
                             other unit matching control_variable).
      - `t_lo_ptr`         — Float64[n] outdoor low temperature (°C).
      - `sp_hi_ptr`        — Float64[n] setpoint at outdoor high T.
      - `t_hi_ptr`         — Float64[n] outdoor high temperature (°C).
      - `has_secondary_ptr`— Float64[n] != 0 when a secondary segment is
                             active for this manager, 0 otherwise.
      - `sp_lo2_ptr`       — Float64[n] secondary setpoint at low T.
      - `t_lo2_ptr`        — Float64[n] secondary outdoor low T.
      - `sp_hi2_ptr`       — Float64[n] secondary setpoint at high T.
      - `t_hi2_ptr`        — Float64[n] secondary outdoor high T.
      - `out_setpoint_ptr` — Float64[n] output setpoint buffer.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var oat = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=oat_ptr)
    var sp_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sp_lo_ptr
    )
    var t_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_lo_ptr
    )
    var sp_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sp_hi_ptr
    )
    var t_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_hi_ptr
    )
    var has_sec = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=has_secondary_ptr
    )
    var sp_lo2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sp_lo2_ptr
    )
    var t_lo2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_lo2_ptr
    )
    var sp_hi2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sp_hi2_ptr
    )
    var t_hi2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_hi2_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_setpoint_ptr
    )

    for i in range(n):
        var sp_primary = _lerp_clamped(
            oat[i], t_lo[i], t_hi[i], sp_lo[i], sp_hi[i]
        )

        if has_sec[i] != 0.0:
            var sp_secondary = _lerp_clamped(
                oat[i], t_lo2[i], t_hi2[i], sp_lo2[i], sp_hi2[i]
            )
            out[i] = (sp_primary + sp_secondary) * 0.5
        else:
            out[i] = sp_primary

@always_inline
def _roll_and_insert(
    ptr: UnsafePointer[Float64, MutAnyOrigin], n: Int, new_val: Float64
):
    """In-place right-shift by 1, then write `new_val` at index 0."""
    var i = n - 1
    while i > 0:
        ptr[i] = ptr[i - 1]
        i -= 1
    ptr[0] = new_val


@export
def simulate_step_simple(
    n_surf: Int,
    surf_args_addr: Int,
    area_addr: Int,
    t_outside_now_addr: Int,
    adiabatic_mask_addr: Int,
    air_capacitance_jk: Float64,
    dt_seconds: Float64,
    t_zone_old_c: Float64,
    q_int_w: Float64,
    q_air_const_w: Float64,
    m_dot_cp_w_per_k: Float64,
    result_addr: Int,
    s_args_addr: Int,
    s_inside_now_addr: Int,
):
    """One simple-path timestep: flux decompose -> air balance -> step advance.

    Subsumes ctf_decompose_flux_batch_reduce + the Python implicit-Euler
    line + ctf_step_batch into a single FFI dispatch. Reuses the same
    12-Int64-per-surface surf_args packing as the per-surface batch
    entries (see ctf.mojo).

    Restricted to the simple path: internal_lw_model="none", no HVAC,
    no Carroll lagged/implicit, no fenestration SHGC injection. Branchy
    paths stay in Python until slices 4-5 extend the entry.

    `adiabatic_mask_addr` points at a UInt8[n_surf] buffer: when mask[i]
    is non-zero, the surface's outside boundary tracks `t_zone_new` (the
    just-solved zone temperature) instead of `t_outside_now[i]` during
    phase 3's state advance. Mirrors the runtime/ctf.py legacy
    `if b.boundary_kind == _BoundaryKind.ADIABATIC: t_outside_now = t_inside_now`
    branch.

    Writes result[0] = t_zone_new_c, result[1] = q_surf_total_w.
    """
    var args = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=surf_args_addr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_addr
    )
    var t_outside_now = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outside_now_addr
    )
    var adiabatic_mask = UnsafePointer[UInt8, MutAnyOrigin](
        unsafe_from_address=adiabatic_mask_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    # ---- Phase 1: decompose flux per surface, area-weighted zone reduction.
    # Mirrors ctf_decompose_flux_batch_reduce. Reads pre-roll history
    # arrays (state.t_in_hist[0] is *previous step*'s t_in, etc.).
    var sum_a_const: Float64 = 0.0
    var sum_a_coef: Float64 = 0.0

    for i in range(n_surf):
        var base = 12 * i
        var z = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 0])
        )
        var z_n = Int(args[base + 1])
        var y = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 2])
        )
        var y_n = Int(args[base + 3])
        var f = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 6])
        )
        var f_n = Int(args[base + 7])
        var t_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )

        var q_coef = -z[0]
        var q_const: Float64 = 0.0
        for k in range(1, z_n):
            q_const -= z[k] * t_in_h[k - 1]
        q_const += y[0] * t_outside_now[i]
        for k in range(1, y_n):
            q_const += y[k] * t_out_h[k - 1]
        for k in range(f_n):
            q_const -= f[k] * q_in_h[k]

        # M6.x foundation (#463a): S-input contribution.
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                q_const += s_inf[0] * s_inside_now_arr[i]
                for k in range(1, s_inf_n):
                    q_const += s_inf[k] * s_hist[k - 1]

        var a = area[i]
        sum_a_const += q_const * a
        sum_a_coef += q_coef * a

    # ---- Phase 2: air balance. Fold airflow before the implicit-Euler form:
    #   sum_a_const += q_air_const_w   (airflow heat into the zone)
    #   sum_a_coef  -= m_dot_cp_w_per_k (linearised airflow coefficient)
    # Then: t_zone_new = (t_zone * C + dt * (sum_const + q_int)) / (C - dt * sum_coef).
    var sum_const_eff = sum_a_const + q_air_const_w
    var sum_coef_eff = sum_a_coef - m_dot_cp_w_per_k

    var denom = air_capacitance_jk - dt_seconds * sum_coef_eff
    var t_zone_new = (
        t_zone_old_c * air_capacitance_jk
        + dt_seconds * (sum_const_eff + q_int_w)
    ) / denom

    # ---- Phase 3: per-surface CTF step advance with t_in = t_zone_new.
    # Mirrors ctf_step_batch and accumulates q_surf_total in the same
    # loop. For adiabatic surfaces the caller passes t_outside_now[i] =
    # t_zone_new (Y = 0 makes them equivalent either way).
    var q_surf_total: Float64 = 0.0
    for i in range(n_surf):
        var base = 12 * i
        var z = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 0])
        )
        var z_n = Int(args[base + 1])
        var y = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 2])
        )
        var y_n = Int(args[base + 3])
        var x = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 4])
        )
        var x_n = Int(args[base + 5])
        var f = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 6])
        )
        var f_n = Int(args[base + 7])
        var t_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )
        var q_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 11])
        )

        # Roll temperature histories; insert current values at index 0.
        # Adiabatic surfaces track t_zone_new on their outside boundary
        # (Y = 0 makes q_in independent, but q_out's t_out_h history
        # feeds future F-recursion convolutions, so it must be tracked
        # consistently with the legacy Python `if ADIABATIC: t_out = t_in` branch).
        var t_out_for_step: Float64
        if adiabatic_mask[i] != 0:
            t_out_for_step = t_zone_new
        else:
            t_out_for_step = t_outside_now[i]
        _roll_and_insert(t_in_h, z_n, t_zone_new)
        _roll_and_insert(t_out_h, y_n, t_out_for_step)

        # Temperature-driven flux terms (same as ctf_step).
        var q_in: Float64 = 0.0
        var q_out: Float64 = 0.0
        for k in range(z_n):
            q_in -= z[k] * t_in_h[k]
        for k in range(y_n):
            q_in += y[k] * t_out_h[k]
            q_out += y[k] * t_in_h[k]
        for k in range(x_n):
            q_out -= x[k] * t_out_h[k]

        # M6.x foundation (#463a): roll s_inside history & convolve.
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                _roll_and_insert(s_hist, s_inf_n, s_inside_now_arr[i])
                for k in range(s_inf_n):
                    q_in += s_inf[k] * s_hist[k]

        # Phi-recursion flux-history feedback (reads BEFORE rolling).
        for k in range(f_n):
            q_in -= f[k] * q_in_h[k]
            q_out -= f[k] * q_out_h[k]

        var nf1 = f_n + 1
        _roll_and_insert(q_in_h, nf1, q_in)
        _roll_and_insert(q_out_h, nf1, q_out)

        q_surf_total += q_in * area[i]

    result[0] = t_zone_new
    result[1] = q_surf_total


@export
def simulate_step_carroll_mrt(
    n_surf: Int,
    surf_args_addr: Int,
    area_addr: Int,
    t_outside_now_addr: Int,
    adiabatic_mask_addr: Int,
    h_conv_in_addr: Int,
    mrt_fp_addr: Int,
    tilts_deg_addr: Int,
    inside_conv_algo: Int,
    air_capacitance_jk: Float64,
    dt_seconds: Float64,
    t_zone_old_c: Float64,
    q_int_w: Float64,
    q_air_const_w: Float64,
    m_dot_cp_w_per_k: Float64,
    result_addr: Int,
    s_args_addr: Int,
    s_inside_now_addr: Int,
):
    """One carroll-MRT lagged timestep: simple-path body + LW injection.

    Extension of `simulate_step_simple` that additionally:
      - Computes per-surface inside-face temperature:
            T_si_i_K = t_zone_new + q_in_i / h_conv_in_i + 273.15
      - Computes the energy-conserving MRT temperature:
            T_r^4 = sum_i A_i F'_i T_si_i^4 / sum_i A_i F'_i
      - Computes per-surface longwave flux and injects back into
        the freshly-rolled q_inside history slot 0:
            q_lw_i = F'_i * (T_r^4 - T_si_i^4)
            q_in_h[0] += q_lw_i

    Restricted to `internal_lw_model="carroll_mrt"` (lagged) with the
    `inside_convection_algorithm="constant"` predicate active (a single
    per-surface h_conv_in scalar). HVAC, SHGC, OSC, and the implicit
    Carroll variant remain in the Python loop.

    Writes result[0] = t_zone_new_c, result[1] = q_surf_total_w (the
    same area-weighted sum as the simple kernel; q_lw injection does
    not affect q_surf_total since it lands in history, not in the
    current step's reported q_in).
    """
    var args = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=surf_args_addr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_addr
    )
    var t_outside_now = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outside_now_addr
    )
    var adiabatic_mask = UnsafePointer[UInt8, MutAnyOrigin](
        unsafe_from_address=adiabatic_mask_addr
    )
    var h_conv_in = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=h_conv_in_addr
    )
    var mrt_fp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=mrt_fp_addr
    )
    var tilts_deg = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=tilts_deg_addr
    )
    var result = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=result_addr
    )

    # ASHRAE Simple inside-conv tabular values (matches
    # solar/convection_inside_simple.py).
    var H_VERT: Float64 = 3.076
    var H_STABLE: Float64 = 0.948
    var H_UNSTABLE: Float64 = 4.040
    var TILT_HALF_BAND: Float64 = 22.5

    # ---- Phase 1: decompose flux per surface, area-weighted zone reduction.
    var sum_a_const: Float64 = 0.0
    var sum_a_coef: Float64 = 0.0

    for i in range(n_surf):
        var base = 12 * i
        var z = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 0])
        )
        var z_n = Int(args[base + 1])
        var y = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 2])
        )
        var y_n = Int(args[base + 3])
        var f = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 6])
        )
        var f_n = Int(args[base + 7])
        var t_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )

        var q_coef = -z[0]
        var q_const: Float64 = 0.0
        for k in range(1, z_n):
            q_const -= z[k] * t_in_h[k - 1]
        q_const += y[0] * t_outside_now[i]
        for k in range(1, y_n):
            q_const += y[k] * t_out_h[k - 1]
        for k in range(f_n):
            q_const -= f[k] * q_in_h[k]

        # M6.x foundation (#463a): S-input contribution.
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                q_const += s_inf[0] * s_inside_now_arr[i]
                for k in range(1, s_inf_n):
                    q_const += s_inf[k] * s_hist[k - 1]

        var a = area[i]
        sum_a_const += q_const * a
        sum_a_coef += q_coef * a

    # ---- Phase 2: air balance with airflow folded in.
    var sum_const_eff = sum_a_const + q_air_const_w
    var sum_coef_eff = sum_a_coef - m_dot_cp_w_per_k
    var denom = air_capacitance_jk - dt_seconds * sum_coef_eff
    var t_zone_new = (
        t_zone_old_c * air_capacitance_jk
        + dt_seconds * (sum_const_eff + q_int_w)
    ) / denom

    # ---- Phase 3: per-surface CTF step advance with t_in = t_zone_new.
    # Same as simulate_step_simple; additionally remember q_in per surface
    # so the MRT closure can derive T_si.
    var q_surf_total: Float64 = 0.0
    # Stack-style: allocate a small dynamic buffer for per-surface q_in.
    # The carroll_mrt path also needs the q_in_h pointer per surface to
    # write back the LW injection; we stash that as well.
    var q_in_per = alloc[Float64](n_surf)
    var q_in_h_ptrs = alloc[Int64](n_surf)

    for i in range(n_surf):
        var base = 12 * i
        var z = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 0])
        )
        var z_n = Int(args[base + 1])
        var y = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 2])
        )
        var y_n = Int(args[base + 3])
        var x = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 4])
        )
        var x_n = Int(args[base + 5])
        var f = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 6])
        )
        var f_n = Int(args[base + 7])
        var t_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 8])
        )
        var t_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 9])
        )
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 10])
        )
        var q_out_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(args[base + 11])
        )

        var t_out_for_step: Float64
        if adiabatic_mask[i] != 0:
            t_out_for_step = t_zone_new
        else:
            t_out_for_step = t_outside_now[i]
        _roll_and_insert(t_in_h, z_n, t_zone_new)
        _roll_and_insert(t_out_h, y_n, t_out_for_step)

        var q_in: Float64 = 0.0
        var q_out: Float64 = 0.0
        for k in range(z_n):
            q_in -= z[k] * t_in_h[k]
        for k in range(y_n):
            q_in += y[k] * t_out_h[k]
            q_out += y[k] * t_in_h[k]
        for k in range(x_n):
            q_out -= x[k] * t_out_h[k]

        # M6.x foundation (#463a): roll s_inside history & convolve.
        if s_args_addr != 0:
            var s_args = UnsafePointer[Int64, MutAnyOrigin](
                unsafe_from_address=s_args_addr
            )
            var s_inside_now_arr = UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=s_inside_now_addr
            )
            var s_base = 3 * i
            var s_inf_n = Int(s_args[s_base + 1])
            if s_inf_n > 0:
                var s_inf = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 0])
                )
                var s_hist = UnsafePointer[Float64, MutAnyOrigin](
                    unsafe_from_address=Int(s_args[s_base + 2])
                )
                _roll_and_insert(s_hist, s_inf_n, s_inside_now_arr[i])
                for k in range(s_inf_n):
                    q_in += s_inf[k] * s_hist[k]

        for k in range(f_n):
            q_in -= f[k] * q_in_h[k]
            q_out -= f[k] * q_out_h[k]

        var nf1 = f_n + 1
        _roll_and_insert(q_in_h, nf1, q_in)
        _roll_and_insert(q_out_h, nf1, q_out)

        q_surf_total += q_in * area[i]
        q_in_per[i] = q_in
        q_in_h_ptrs[i] = Int64(Int(args[base + 10]))

    # ---- Phase 4: Carroll MRT lagged longwave injection.
    # Step 4a: T_si_i_K = t_zone_new + q_in_i / h_conv_in_i + 273.15
    # Step 4b: T_r^4 = sum_i (A_i F'_i T_si_i^4) / sum_i (A_i F'_i)
    # Step 4c: q_lw_i = F'_i * (T_r^4 - T_si_i^4); inject into q_in_h[0].
    #
    # We compute T_si^4 once per surface in a local buffer to avoid a
    # second pow on the injection pass.
    var t_si4 = alloc[Float64](n_surf)
    var num: Float64 = 0.0
    var den: Float64 = 0.0
    for i in range(n_surf):
        # h_eff: either the constant bundle h (algo=0) or the ASHRAE
        # Simple table (algo=1). Simple does a one-step iteration:
        # approximate T_si first with the constant h to pick the
        # stable/unstable branch, then use the table h for the final
        # T_si.
        var h_eff: Float64 = h_conv_in[i]
        if inside_conv_algo == 1:
            var tilt = tilts_deg[i]
            var dtilt = tilt - 90.0
            if dtilt < 0.0:
                dtilt = -dtilt
            if dtilt <= TILT_HALF_BAND:
                h_eff = H_VERT
            else:
                # Approximate T_si with the bundle's constant h_conv_in
                # to classify the buoyancy regime.
                var t_si_approx = t_zone_new + q_in_per[i] / h_conv_in[i]
                if tilt < 90.0 - TILT_HALF_BAND:
                    # Ceiling-type
                    if t_si_approx >= t_zone_new:
                        h_eff = H_STABLE
                    else:
                        h_eff = H_UNSTABLE
                else:
                    # Floor-type
                    if t_si_approx >= t_zone_new:
                        h_eff = H_UNSTABLE
                    else:
                        h_eff = H_STABLE
        var t_si_k = t_zone_new + q_in_per[i] / h_eff + 273.15
        var t4 = t_si_k * t_si_k
        t4 = t4 * t4
        t_si4[i] = t4
        var w = area[i] * mrt_fp[i]
        num += w * t4
        den += w

    var t_r4: Float64 = 0.0
    if den > 0.0:
        t_r4 = num / den

    for i in range(n_surf):
        var q_lw = mrt_fp[i] * (t_r4 - t_si4[i])
        var q_in_h = UnsafePointer[Float64, MutAnyOrigin](
            unsafe_from_address=Int(q_in_h_ptrs[i])
        )
        # q_inside[0] was just written by _roll_and_insert above.
        q_in_h[0] += q_lw

    q_in_per.free()
    q_in_h_ptrs.free()
    t_si4.free()

    result[0] = t_zone_new
    result[1] = q_surf_total

from std.math import cos

# Maximum incidence angle before glazing is treated as fully blocking [rad]
comptime THETA_MAX: Float64 = 1.5708  # ≈ pi/2
# Minimum allowed cosine to guard against division near 90° [dimensionless]
comptime COS_MIN: Float64 = 0.01
# Maximum allowed IAM value (normal incidence = 1.0 by definition)
comptime IAM_MAX: Float64 = 1.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def incidence_angle_modifier_batch(
    n: Int,
    theta_ptr: Int,
    a0_ptr: Int,
    a1_ptr: Int,
    a2_ptr: Int,
    out_iam_ptr: Int,
) -> None:
    """ASHRAE Incidence Angle Modifier (IAM) polynomial correction for N glazings.

    For each glazing i:

        theta = clamp(theta[i], 0, THETA_MAX)
        If theta >= THETA_MAX: IAM = 0  (glazing fully blocks at or above 90°)
        Otherwise:
          ct   = clamp(cos(theta), COS_MIN, 1.0)
          icm1 = 1/ct - 1.0
          IAM  = clamp(1 + a1*icm1 + a2*icm1^2, 0, IAM_MAX)

    Note: a0 is unused in the ASHRAE model (IAM(theta=0)=1 by definition);
    it is accepted for API compatibility.

    Parameters
    ----------
    n          : number of glazings
    theta_ptr  : Float64[n]  incidence angle (rad), clamped to [0, THETA_MAX]
    a0_ptr     : Float64[n]  unused constant term (API compatibility)
    a1_ptr     : Float64[n]  first-order IAM coefficient, clamped to [-1, 0]
    a2_ptr     : Float64[n]  second-order IAM coefficient, clamped to [-1, 0]
    out_iam_ptr: Float64[n]  incidence angle modifier [0, 1]  [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var theta = _ptr(theta_ptr)
    var a1 = _ptr(a1_ptr)
    var a2 = _ptr(a2_ptr)
    var out_iam = _ptr(out_iam_ptr)

    for i in range(n):
        # Clamp theta to [0, THETA_MAX]
        var th = theta[i]
        if th < 0.0:
            th = 0.0
        if th > THETA_MAX:
            th = THETA_MAX

        # Above (or at) THETA_MAX: glazing blocks all transmission
        if th >= THETA_MAX:
            out_iam[i] = 0.0
            continue

        # Clamp cosine to [COS_MIN, 1.0] to guard division near 90°
        var ct = cos(th)
        if ct < COS_MIN:
            ct = COS_MIN
        if ct > 1.0:
            ct = 1.0

        # Clamp a1 and a2 to [-1, 0] (negative for glass)
        var a1i = a1[i]
        if a1i < -1.0:
            a1i = -1.0
        if a1i > 0.0:
            a1i = 0.0

        var a2i = a2[i]
        if a2i < -1.0:
            a2i = -1.0
        if a2i > 0.0:
            a2i = 0.0

        # ASHRAE IAM polynomial
        var icm1 = 1.0 / ct - 1.0
        var iam = 1.0 + a1i * icm1 + a2i * (icm1 * icm1)

        # Clamp IAM to [0, IAM_MAX]
        if iam < 0.0:
            iam = 0.0
        if iam > IAM_MAX:
            iam = IAM_MAX

        out_iam[i] = iam


@export
def glazing_transmittance_corrected_batch(
    n: Int,
    tau_normal_ptr: Int,
    iam_ptr: Int,
    out_tau_ptr: Int,
) -> None:
    """Angle-corrected glazing transmittance for N glazings.

    For each glazing i:

        tau_n  = clamp(tau_normal[i], 0, 1)
        iam_i  = clamp(iam[i],        0, 1)
        tau[i] = clamp(tau_n * iam_i, 0, tau_n)

    Parameters
    ----------
    n              : number of glazings
    tau_normal_ptr : Float64[n]  normal-incidence transmittance [0, 1]
    iam_ptr        : Float64[n]  incidence angle modifier [0, 1]
    out_tau_ptr    : Float64[n]  corrected transmittance [0, tau_normal]  [output]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var tau_normal = _ptr(tau_normal_ptr)
    var iam = _ptr(iam_ptr)
    var out_tau = _ptr(out_tau_ptr)

    for i in range(n):
        # Clamp tau_normal to [0, 1]
        var tau_n = tau_normal[i]
        if tau_n < 0.0:
            tau_n = 0.0
        if tau_n > 1.0:
            tau_n = 1.0

        # Clamp IAM to [0, 1]
        var iam_i = iam[i]
        if iam_i < 0.0:
            iam_i = 0.0
        if iam_i > 1.0:
            iam_i = 1.0

        # Corrected transmittance, clamped to [0, tau_n]
        var tau = tau_n * iam_i
        if tau < 0.0:
            tau = 0.0
        if tau > tau_n:
            tau = tau_n

        out_tau[i] = tau

var u = jme / 10.0
    var eps0_arcsec = (
        84381.448
        - 4680.93 * u
        - 1.55 * u * u
        + 1999.25 * u * u * u
        - 51.38 * u * u * u * u
        - 249.67 * u * u * u * u * u
        - 39.05 * u * u * u * u * u * u
        + 7.12 * u * u * u * u * u * u * u
        + 27.87 * u * u * u * u * u * u * u * u
        + 5.79 * u * u * u * u * u * u * u * u * u
        + 2.45 * u * u * u * u * u * u * u * u * u * u
    )
    return eps0_arcsec / 3600.0


# ----------------------------------------------------------------------------
# Core per-timestep SPA computation (scalar, called once per Julian date).
# Writes results into the mut output parameters.
# ----------------------------------------------------------------------------


@always_inline
def _spa_scalar(
    jd: Float64,
    delta_t_seconds: Float64,
    latitude_deg: Float64,
    longitude_deg: Float64,
    elevation_m: Float64,
    pressure_mbar: Float64,
    temperature_c: Float64,
    atmospheric_refraction_deg: Float64,
    mut out_alt: Float64,
    mut out_az: Float64,
    mut out_zen: Float64,
    mut out_decl: Float64,
    mut out_ha: Float64,
):
    var jde = jd + delta_t_seconds / 86400.0
    var jc = (jd - 2451545.0) / 36525.0
    var jce = (jde - 2451545.0) / 36525.0
    var jme = jce / 10.0

    var l_deg = _heliocentric_longitude_deg(jme)
    var b_deg = _heliocentric_latitude_deg(jme)
    var r_au = _earth_radius_au(jme)

    var theta_deg = _mod360(l_deg + 180.0)
    var beta_deg = -b_deg

    var delta_psi_deg: Float64 = 0.0
    var delta_eps_deg: Float64 = 0.0
    _nutation(jce, delta_psi_deg, delta_eps_deg)

    var eps0_deg = _mean_obliquity_deg(jme)
    var eps_deg = eps0_deg + delta_eps_deg

    var delta_tau_deg = -20.4898 / (3600.0 * r_au)
    var lambda_deg = theta_deg + delta_psi_deg + delta_tau_deg

    # Apparent sidereal time at Greenwich.
    var nu0_deg = _mod360(
        280.46061837
        + 360.98564736629 * (jd - 2451545.0)
        + 0.000387933 * jc * jc
        - (jc * jc * jc) / 38710000.0
    )
    var nu_deg = nu0_deg + delta_psi_deg * cos(_rad(eps_deg))

    # Geocentric right ascension and declination.
    var lam_r = _rad(lambda_deg)
    var eps_r = _rad(eps_deg)
    var beta_r = _rad(beta_deg)
    var alpha_r = atan2(
        sin(lam_r) * cos(eps_r) - tan(beta_r) * sin(eps_r),
        cos(lam_r),
    )
    var alpha_deg = _mod360(_deg(alpha_r))
    var delta_r = asin(
        _clamp(
            sin(beta_r) * cos(eps_r) + cos(beta_r) * sin(eps_r) * sin(lam_r),
            -1.0,
            1.0,
        )
    )

    # Observer local hour angle.
    var h_deg = _mod360(nu_deg + longitude_deg - alpha_deg)

    # Topocentric parallax corrections.
    var phi_r = _rad(latitude_deg)
    var xi_deg = 8.794 / (3600.0 * r_au)
    var xi_r = _rad(xi_deg)
    var u_p = atan2(0.99664719 * sin(phi_r), cos(phi_r))
    var x_term = cos(u_p) + (elevation_m / 6378140.0) * cos(phi_r)
    var y_term = 0.99664719 * sin(u_p) + (elevation_m / 6378140.0) * sin(phi_r)

    var h_r = _rad(h_deg)
    var delta_alpha_r = atan2(
        -x_term * sin(xi_r) * sin(h_r),
        cos(delta_r) - x_term * sin(xi_r) * cos(h_r),
    )
    var delta_alpha_deg = _deg(delta_alpha_r)

    var delta_prime_r = atan2(
        (sin(delta_r) - y_term * sin(xi_r)) * cos(delta_alpha_r),
        cos(delta_r) - x_term * sin(xi_r) * cos(h_r),
    )

    var h_prime_deg = h_deg - delta_alpha_deg
    var h_prime_r = _rad(h_prime_deg)

    # Topocentric elevation (true).
    var sin_e0 = sin(phi_r) * sin(delta_prime_r) + cos(phi_r) * cos(
        delta_prime_r
    ) * cos(h_prime_r)
    var e0_deg = _deg(asin(_clamp(sin_e0, -1.0, 1.0)))

    # Atmospheric refraction (only near/above horizon).
    var delta_e_deg: Float64 = 0.0
    if e0_deg + atmospheric_refraction_deg >= 0.0:
        var tan_arg = _rad(e0_deg + 10.3 / (e0_deg + 5.11))
        var denom = 60.0 * tan(tan_arg)
        if denom != 0.0:
            delta_e_deg = (
                (pressure_mbar / 1010.0)
                * (283.0 / (273.0 + temperature_c))
                * (1.02 / denom)
            )

    var e_deg = e0_deg + delta_e_deg

    # Topocentric azimuth: astronomers' (0=S, +west) → navigators' (0=N, +east).
    var gamma_r = atan2(
        sin(h_prime_r),
        cos(h_prime_r) * sin(phi_r) - tan(delta_prime_r) * cos(phi_r),
    )
    var gamma_deg = _mod360(_deg(gamma_r))

    out_alt = e_deg
    out_az = _mod360(gamma_deg + 180.0)
    out_zen = 90.0 - e_deg
    out_decl = _deg(delta_prime_r)
    out_ha = h_prime_deg


