    out_azimuth_addr: Int,
    out_zenith_addr: Int,
    out_declination_addr: Int,
    out_hour_angle_addr: Int,
) -> None:
    """NREL SPA solar position for N Julian dates at one site.

    Reads Float64[n] at jd_addr (Julian dates, UT).
    Writes Float64[n] to each output array:
      out_altitude_addr    — apparent solar altitude (degrees, + above horizon)
      out_azimuth_addr     — azimuth clockwise from north (0=N, 90=E, …)
      out_zenith_addr      — apparent zenith angle (degrees)
      out_declination_addr — topocentric declination (degrees)
      out_hour_angle_addr  — topocentric hour angle (degrees, 0=solar noon)

    Site parameters are scalar (constant across the batch):
      delta_t_seconds             — TT − UT (≈ 67 s in 2003; 0 is fine)
      latitude_deg                — positive north
      longitude_deg               — positive east
      elevation_m                 — metres above mean sea level
      pressure_mbar               — station pressure for refraction (default 1013.25)
      temperature_c               — temperature for refraction (default 11)
      atmospheric_refraction_deg  — refraction threshold (default 0.5667)
    """
    var jd = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=jd_addr)
    var out_alt = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_altitude_addr
    )
    var out_az = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_azimuth_addr
    )
    var out_zen = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_zenith_addr
    )
    var out_decl = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_declination_addr
    )
    var out_ha = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_hour_angle_addr
    )

    for i in range(n):
        var alt: Float64 = 0.0
        var az: Float64 = 0.0
        var zen: Float64 = 0.0
        var decl: Float64 = 0.0
        var ha: Float64 = 0.0
        _spa_scalar(
            jd[i],
            delta_t_seconds,
            latitude_deg,
            longitude_deg,
            elevation_m,
            pressure_mbar,
            temperature_c,
            atmospheric_refraction_deg,
            alt,
            az,
            zen,
            decl,
            ha,
        )
        out_alt[i] = alt
        out_az[i] = az
        out_zen[i] = zen
        out_decl[i] = decl
        out_ha[i] = ha

from std.math import exp

# Latent heat of vaporisation of water at ~25 °C [J/kg]
comptime H_FG: Float64 = 2442000.0
# Stefan-Boltzmann constant [W/(m²·K⁴)]
comptime SIGMA: Float64 = 5.67e-8
# Water emissivity (grey-body, long-wave)
comptime EPSILON_WATER: Float64 = 0.95
# Kelvin offset
comptime KELVIN_OFFSET: Float64 = 273.15
# Magnus equation coefficients (Tetens approximation)
comptime MAGNUS_A: Float64 = 17.269
comptime MAGNUS_B: Float64 = 237.3
# Saturation vapour pressure at 0 °C [Pa]
comptime P_SAT_0: Float64 = 610.5


@export
def pool_evaporation_rate_batch(
    n: Int,
    t_pool_c_ptr: Int,
    t_room_c_ptr: Int,
    rh_room_ptr: Int,
    v_air_ptr: Int,
    area_m2_ptr: Int,
    out_m_evap_ptr: Int,
) -> None:
    """Evaporation mass-flux from N indoor swimming pools.

    Uses the Tetens (Magnus) saturation vapour pressure formula and a
    wind-speed-dependent evaporation coefficient from the EnergyPlus
    SwimmingPool:Indoor model:

        Pv_pool = 610.5 * exp(17.269 * T_pool / (237.3 + T_pool))  (Pa)
        Pv_room = rh_room * 610.5 * exp(17.269 * T_room / (237.3 + T_room))
        C_evap  = (0.089 + 0.0782 * v_air) × 1e-5  kg/(s·m²·Pa)
        m_evap  = C_evap * area * max(0, Pv_pool - Pv_room)  (kg/s)

    Parameters
    ----------
    n              : number of pools
    t_pool_c_ptr   : Float64[n]  pool water surface temperature (°C)
    t_room_c_ptr   : Float64[n]  indoor air (room) temperature (°C)
    rh_room_ptr    : Float64[n]  room relative humidity (0–1 fraction)
    v_air_ptr      : Float64[n]  air velocity above pool surface (m/s)
    area_m2_ptr    : Float64[n]  pool surface area (m²)
    out_m_evap_ptr : Float64[n]  evaporation rate (kg/s)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var t_pool = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_pool_c_ptr
    )
    var t_room = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_room_c_ptr
    )
    var rh_room = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rh_room_ptr
    )
    var v_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=v_air_ptr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_m2_ptr
    )
    var out_m_evap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_m_evap_ptr
    )

    for i in range(n):
        var tp = t_pool[i]
        var tr = t_room[i]

        # Saturation vapour pressure at pool surface (Pa)
        var pv_pool = P_SAT_0 * exp(MAGNUS_A * tp / (MAGNUS_B + tp))

        # Partial pressure of vapour in room (Pa)
        var pv_room = (
            rh_room[i] * P_SAT_0 * exp(MAGNUS_A * tr / (MAGNUS_B + tr))
        )

        # Evaporation coefficient [kg/(s·m²·Pa)]
        var c_evap = (0.089 + 0.0782 * v_air[i]) * 1.0e-5

        # Pressure difference — clamp to zero if room is more humid than pool
        var dp = pv_pool - pv_room
        if dp < 0.0:
            dp = 0.0

        out_m_evap[i] = c_evap * area[i] * dp


@export
def pool_evaporation_heat_loss_batch(
    n: Int,
    m_evap_ptr: Int,
    h_fg_ptr: Int,
    out_q_evap_ptr: Int,
) -> None:
    """Evaporative heat loss from N indoor swimming pools.

    Latent heat carried away by evaporating water:

        q_evap = m_evap * h_fg  (W)

    h_fg is passed per-pool to allow caller-supplied values (e.g. temperature-
    dependent). The kernel constant H_FG = 2 442 000 J/kg may be used as the
    default by the Python wrapper.

    Parameters
    ----------
    n              : number of pools
    m_evap_ptr     : Float64[n]  evaporation rate (kg/s)
    h_fg_ptr       : Float64[n]  latent heat of vaporisation (J/kg)
    out_q_evap_ptr : Float64[n]  evaporative heat loss (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var m_evap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_evap_ptr
    )
    var h_fg = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=h_fg_ptr
    )
    var out_q_evap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_evap_ptr
    )

    for i in range(n):
        out_q_evap[i] = m_evap[i] * h_fg[i]


@export
def pool_convective_heat_loss_batch(
    n: Int,
    t_pool_c_ptr: Int,
    t_room_c_ptr: Int,
    h_conv_ptr: Int,
    area_m2_ptr: Int,
    out_q_conv_ptr: Int,
) -> None:
    """Convective heat loss from N indoor swimming pools to room air.

        q_conv = h_conv * area * (T_pool - T_room)  (W)

    Positive result → pool is losing heat to the room air.

    Parameters
    ----------
    n              : number of pools
    t_pool_c_ptr   : Float64[n]  pool water surface temperature (°C)
    t_room_c_ptr   : Float64[n]  room air temperature (°C)
    h_conv_ptr     : Float64[n]  convective heat transfer coefficient (W/(m²·K))
    area_m2_ptr    : Float64[n]  pool surface area (m²)
    out_q_conv_ptr : Float64[n]  convective heat loss (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var t_pool = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_pool_c_ptr
    )
    var t_room = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_room_c_ptr
    )
    var h_conv = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=h_conv_ptr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_m2_ptr
    )
    var out_q_conv = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_conv_ptr
    )

    for i in range(n):
        out_q_conv[i] = h_conv[i] * area[i] * (t_pool[i] - t_room[i])


@export
def pool_radiant_heat_loss_batch(
    n: Int,
    t_pool_c_ptr: Int,
    t_room_c_ptr: Int,
    area_m2_ptr: Int,
    out_q_rad_ptr: Int,
) -> None:
    """Linearised radiant heat loss from N indoor swimming pools to room surfaces.

    Stefan-Boltzmann radiation linearised around the mean of pool and room
    temperatures:

        T_pool_K  = T_pool_c + 273.15
        T_room_K  = T_room_c + 273.15
        T_mean_K  = (T_pool_K + T_room_K) / 2
        h_rad     = 4 * EPSILON_WATER * SIGMA * T_mean_K^3
        q_rad     = h_rad * area * (T_pool_c - T_room_c)  (W)

    Positive result → pool is losing energy to room surfaces (pool warmer
    than room).

    Parameters
    ----------
    n              : number of pools
    t_pool_c_ptr   : Float64[n]  pool water surface temperature (°C)
    t_room_c_ptr   : Float64[n]  room mean radiant temperature (°C)
    area_m2_ptr    : Float64[n]  pool surface area (m²)
    out_q_rad_ptr  : Float64[n]  radiant heat loss (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var t_pool = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_pool_c_ptr
    )
    var t_room = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_room_c_ptr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_m2_ptr
    )
    var out_q_rad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_rad_ptr
    )

    for i in range(n):
        var tp_k = t_pool[i] + KELVIN_OFFSET
        var tr_k = t_room[i] + KELVIN_OFFSET
        var tm_k = (tp_k + tr_k) * 0.5

        # T_mean_K^3 via explicit multiplication — no pow() call
        var tm3 = tm_k * tm_k * tm_k

        var h_rad = 4.0 * EPSILON_WATER * SIGMA * tm3
        out_q_rad[i] = h_rad * area[i] * (t_pool[i] - t_room[i])


@export
def pool_heat_requirement_batch(
    n: Int,
    q_evap_ptr: Int,
    q_conv_ptr: Int,
    q_rad_ptr: Int,
    q_solar_ptr: Int,
    out_q_heat_ptr: Int,
) -> None:
    """Total heating requirement for N indoor swimming pools.

    Sums all heat losses and subtracts solar gain; clamps negative values to
    zero (the pool needs no heating when gains exceed losses):

        q_heat = max(0, q_evap + q_conv + q_rad - q_solar)  (W)

    Parameters
    ----------
    n              : number of pools
    q_evap_ptr     : Float64[n]  evaporative heat loss (W)
    q_conv_ptr     : Float64[n]  convective heat loss (W)
    q_rad_ptr      : Float64[n]  radiant heat loss (W)
    q_solar_ptr    : Float64[n]  shortwave solar absorbed by pool (W, a gain)
    out_q_heat_ptr : Float64[n]  net heating requirement (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var q_evap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_evap_ptr
    )
    var q_conv = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_conv_ptr
    )
    var q_rad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_rad_ptr
    )
    var q_solar = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_solar_ptr
    )
    var out_q_heat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_heat_ptr
    )

    for i in range(n):
        var q_loss = q_evap[i] + q_conv[i] + q_rad[i] - q_solar[i]
        if q_loss < 0.0:
            q_loss = 0.0
        out_q_heat[i] = q_loss

var delta_t = t_surf_c - t_air_c
    var abs_dt = _abs(delta_t)
    if abs_dt == 0.0:
        return 0.0

    var abs_dt_cbrt = pow(abs_dt, 1.0 / 3.0)

    if _abs(tilt_deg - 90.0) < VERTICAL_TOL_DEG:
        return VERTICAL_COEF * abs_dt_cbrt

    var cos_tilt = cos(_rad(tilt_deg))
    var abs_cos = _abs(cos_tilt)
    var enhanced = (delta_t * cos_tilt) > 0.0
    if enhanced:
        return ENHANCED_NUM * abs_dt_cbrt / (ENHANCED_DEN - abs_cos)
    return REDUCED_NUM * abs_dt_cbrt / (REDUCED_DEN + abs_cos)


@always_inline
def _windward_cos(
    surface_normal_az_deg: Float64, wind_direction_deg: Float64
) -> Float64:
    """cos of angle between outward surface normal and wind "to" direction.

    `wind_direction_deg` is the meteorological "from" direction (compass
    degrees, 0=N). The wind "to" direction is therefore +180°. The
    surface is windward when this cosine exceeds `WINDWARD_COS_THRESHOLD`.
    """
    # Difference between normal-az and wind-to-az, in radians. cos() is
    # 2π-periodic so we don't need to reduce modulo 360 first.
    var wind_to = wind_direction_deg + 180.0
    return cos(_rad(surface_normal_az_deg - wind_to))


@export
def tarp_h_outside_batch(
    n_surfaces: Int,
    wind_speed_m_s: Float64,
    wind_direction_deg: Float64,
    surface_normal_az_deg_ptr: Int,
    surface_tilt_deg_ptr: Int,
    t_surf_c_ptr: Int,
    t_outdoor_c_ptr: Int,
    roughness_idx_ptr: Int,
    out_h_w_m2k_ptr: Int,
) -> None:
    """Batched TARP outside convective film coefficient, W/(m²·K).

    Writes `h_forced + h_natural` for each of N surfaces in one FFI call.

    Reads (length n_surfaces):
      - surface_normal_az_deg_ptr: Float64[n] outward-normal azimuth, deg
        (compass; 0=N, 90=E, 180=S, 270=W).
      - surface_tilt_deg_ptr: Float64[n] tilt from horizontal up, deg
        (0=roof, 90=wall, 180=floor).
      - t_surf_c_ptr: Float64[n] surface temperature, °C.
      - t_outdoor_c_ptr: Float64[n] outdoor air temperature, °C
        (per-surface to support local microclimate; usually broadcast
        from a single weather value on the Python side).
      - roughness_idx_ptr: Int[n] roughness class, 0=VeryRough … 5=VerySmooth.

    Writes (length n_surfaces):
      - out_h_w_m2k_ptr: Float64[n] convective film coefficient.

    Wind speed is shared across all surfaces (single weather timestep);
    negative wind speeds clamp to still air.
    """
    var v = wind_speed_m_s if wind_speed_m_s > 0.0 else 0.0
    var v_forced = FORCED_PREFACTOR * v

    var az = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=surface_normal_az_deg_ptr
    )
    var tilt = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=surface_tilt_deg_ptr
    )
    var t_surf = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_surf_c_ptr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_c_ptr
    )
    var rough = UnsafePointer[Int64, MutAnyOrigin](
        unsafe_from_address=roughness_idx_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_h_w_m2k_ptr
    )

    for i in range(n_surfaces):
        var w_f = _w_roughness(Int(rough[i]))

        # Forced component — windward / leeward split on wind-to-normal cos.
        var h_f: Float64 = 0.0
        if v > 0.0:
            var cos_a = _windward_cos(az[i], wind_direction_deg)
            var directional = (
                1.0 if cos_a > WINDWARD_COS_THRESHOLD else LEEWARD_FACTOR
            )
            h_f = w_f * v_forced * directional

        # Natural component — Walton 1983, tilt + heat-flow direction.
        var h_n = _h_natural(t_surf[i], t_out[i], tilt[i])

        out[i] = h_f + h_n

comptime MIN_SHR: Float64 = 0.5
comptime MAX_SHR: Float64 = 1.0
comptime MIN_W: Float64 = 1e-6
comptime MIN_POWER: Float64 = 1e-6


@always_inline
def _clamp_f64(v: Float64, lo: Float64, hi: Float64) -> Float64:
    if v < lo:
        return lo
    if v > hi:
        return hi
    return v


@export
def vsdx_speed_interpolation_batch(
    n: Int,
    cap_low_ptr: Int,
    cap_high_ptr: Int,
    pow_low_ptr: Int,
    pow_high_ptr: Int,
    speed_frac_ptr: Int,
    out_cap_ptr: Int,
    out_power_ptr: Int,
) -> None:
    """Linear interpolation of capacity and power between two speed levels.

    For each coil i:

        speed_frac[i] clamped to [0, 1]
        cap[i]   = cap_low[i]   + speed_frac[i] * (cap_high[i]   - cap_low[i])
        power[i] = pow_low[i]   + speed_frac[i] * (pow_high[i]   - pow_low[i])

    Parameters
    ----------
    n            : number of coils
    cap_low_ptr  : Float64[n]  rated capacity at lower speed level (W)
    cap_high_ptr : Float64[n]  rated capacity at upper speed level (W)
    pow_low_ptr  : Float64[n]  rated power at lower speed level (W)
    pow_high_ptr : Float64[n]  rated power at upper speed level (W)
    speed_frac_ptr : Float64[n]  interpolation fraction in [0, 1]
    out_cap_ptr  : Float64[n]  interpolated capacity (W)       [output]
    out_power_ptr: Float64[n]  interpolated power (W)          [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var cap_low = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_low_ptr
    )
    var cap_high = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_high_ptr
    )
    var pow_low = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=pow_low_ptr
    )
    var pow_high = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=pow_high_ptr
    )
    var speed_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_frac_ptr
    )
    var out_cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cap_ptr
    )
    var out_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_ptr
    )

    for i in range(n):
        var sf = _clamp_f64(speed_frac[i], 0.0, 1.0)
        out_cap[i] = cap_low[i] + sf * (cap_high[i] - cap_low[i])
        out_power[i] = pow_low[i] + sf * (pow_high[i] - pow_low[i])


@export
def vsdx_sensible_heat_ratio_batch(
    n: Int,
    cap_total_ptr: Int,
    shr_ref_ptr: Int,
    w_air_ptr: Int,
    w_sat_ptr: Int,
    out_shr_ptr: Int,
    out_q_sensible_ptr: Int,
    out_q_latent_ptr: Int,
) -> None:
    """SHR correction from humidity ratios; split total capacity into components.

    For each coil i:

        shr[i]        = shr_ref[i] * (w_sat[i] / max(w_air[i], MIN_W))
        shr[i]        clamped to [MIN_SHR, MAX_SHR]
        q_sensible[i] = cap_total[i] * shr[i]
        q_latent[i]   = cap_total[i] * (1 - shr[i])

    If cap_total[i] < MIN_POWER all three outputs are zero.

    Parameters
    ----------
    n                 : number of coils
    cap_total_ptr     : Float64[n]  total cooling capacity (W)
    shr_ref_ptr       : Float64[n]  reference SHR at rated conditions [-]
    w_air_ptr         : Float64[n]  entering air humidity ratio (kg/kg)
    w_sat_ptr         : Float64[n]  saturation humidity ratio at coil surface (kg/kg)
    out_shr_ptr       : Float64[n]  corrected SHR [-]                [output]
    out_q_sensible_ptr: Float64[n]  sensible cooling capacity (W)    [output]
    out_q_latent_ptr  : Float64[n]  latent cooling capacity (W)      [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var cap_total = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_total_ptr
    )
    var shr_ref = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=shr_ref_ptr
    )
    var w_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_air_ptr
    )
    var w_sat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_sat_ptr
    )
    var out_shr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_shr_ptr
    )
    var out_q_sensible = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_sensible_ptr
    )
    var out_q_latent = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_latent_ptr
    )

    for i in range(n):
        var cap = cap_total[i]
        if cap < MIN_POWER:
            out_shr[i] = 0.0
            out_q_sensible[i] = 0.0
            out_q_latent[i] = 0.0
            continue

        var w_a = w_air[i]
        if w_a < MIN_W:
            w_a = MIN_W

        var shr = shr_ref[i] * (w_sat[i] / w_a)
        shr = _clamp_f64(shr, MIN_SHR, MAX_SHR)

        out_shr[i] = shr
        out_q_sensible[i] = cap * shr
        out_q_latent[i] = cap * (1.0 - shr)


@export
def vsdx_full_batch(
    n: Int,
    cap_low_ptr: Int,
    cap_high_ptr: Int,
    pow_low_ptr: Int,
    pow_high_ptr: Int,
    speed_frac_ptr: Int,
    shr_ref_ptr: Int,
    w_air_ptr: Int,
    w_sat_ptr: Int,
    out_cap_ptr: Int,
    out_q_sensible_ptr: Int,
    out_q_latent_ptr: Int,
    out_power_ptr: Int,
    out_cop_ptr: Int,
) -> None:
    """Full variable-speed DX pipeline: interpolation → SHR split → COP.

    For each coil i:

        speed_frac[i] clamped to [0, 1]
        cap[i]        = cap_low[i]   + speed_frac[i] * (cap_high[i]   - cap_low[i])
        power[i]      = pow_low[i]   + speed_frac[i] * (pow_high[i]   - pow_low[i])

        shr[i]        = shr_ref[i] * (w_sat[i] / max(w_air[i], MIN_W))
        shr[i]        clamped to [MIN_SHR, MAX_SHR]
        q_sensible[i] = cap[i] * shr[i]
        q_latent[i]   = cap[i] * (1 - shr[i])

        cop[i]        = cap[i] / power[i]  if power[i] > MIN_POWER else 0

    Parameters
    ----------
    n                 : number of coils
    cap_low_ptr       : Float64[n]  capacity at lower speed level (W)
    cap_high_ptr      : Float64[n]  capacity at upper speed level (W)
    pow_low_ptr       : Float64[n]  power at lower speed level (W)
    pow_high_ptr      : Float64[n]  power at upper speed level (W)
    speed_frac_ptr    : Float64[n]  speed interpolation fraction [0, 1]
    shr_ref_ptr       : Float64[n]  reference SHR at rated conditions [-]
    w_air_ptr         : Float64[n]  entering air humidity ratio (kg/kg)
    w_sat_ptr         : Float64[n]  saturation humidity ratio (kg/kg)
    out_cap_ptr       : Float64[n]  interpolated capacity (W)          [output]
    out_q_sensible_ptr: Float64[n]  sensible cooling capacity (W)      [output]
    out_q_latent_ptr  : Float64[n]  latent cooling capacity (W)        [output]
    out_power_ptr     : Float64[n]  interpolated power (W)             [output]
    out_cop_ptr       : Float64[n]  coefficient of performance [-]     [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var cap_low = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_low_ptr
    )
    var cap_high = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_high_ptr
    )
    var pow_low = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=pow_low_ptr
    )
    var pow_high = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=pow_high_ptr
    )
    var speed_frac = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=speed_frac_ptr
    )
    var shr_ref = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=shr_ref_ptr
    )
    var w_air = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_air_ptr
    )
    var w_sat = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=w_sat_ptr
    )
    var out_cap = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cap_ptr
    )
    var out_q_sensible = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_sensible_ptr
    )
    var out_q_latent = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_latent_ptr
    )
    var out_power = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_power_ptr
    )
    var out_cop = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_cop_ptr
    )

    for i in range(n):
        # ------------------------------------------------------------------
        # Step 1 — speed interpolation
        # ------------------------------------------------------------------
        var sf = _clamp_f64(speed_frac[i], 0.0, 1.0)
        var cap = cap_low[i] + sf * (cap_high[i] - cap_low[i])
        var power = pow_low[i] + sf * (pow_high[i] - pow_low[i])

        # ------------------------------------------------------------------
        # Step 2 — SHR correction and capacity split
        # ------------------------------------------------------------------
        var w_a = w_air[i]
        if w_a < MIN_W:
            w_a = MIN_W
        var shr = shr_ref[i] * (w_sat[i] / w_a)
        shr = _clamp_f64(shr, MIN_SHR, MAX_SHR)

        var q_sensible = cap * shr
        var q_latent = cap * (1.0 - shr)

        # ------------------------------------------------------------------
        # Step 3 — COP
        # ------------------------------------------------------------------
        var cop: Float64
        if power > MIN_POWER:
            cop = cap / power
        else:
            cop = 0.0

        # Write outputs
        out_cap[i] = cap
        out_q_sensible[i] = q_sensible
        out_q_latent[i] = q_latent
        out_power[i] = power
        out_cop[i] = cop

from std.math import isnan, isinf


@always_inline
def _is_nonfinite(x: Float64) -> Bool:
    return isnan(x) or isinf(x)


@export
def vent_clamp_sum(
    n: Int,
    out_m_dot_ptr: Int,
    design_flow_ptr: Int,
    sched_ptr: Int,
    k: Float64,
    out_sum_ptr: Int,
) -> None:
    """Fused NaN-guard + clamp + horizontal sum for ventilation m_dot arrays.

    For each element i in [0, n):

        1. If out_m_dot[i] is NaN or ±inf → replace with 0.0
        2. cap[i] = k * design_flow[i] * max(sched[i], 0.0)
        3. out_m_dot[i] = clamp(out_m_dot[i], 0.0, cap[i])

    Then writes sum(out_m_dot[0..n)) into `out_sum_ptr[0]`.

    Arguments:
      - `n`              — number of ventilation / earthtube records.
      - `out_m_dot_ptr`  — Float64[n]: m_dot per record (written in-place).
      - `design_flow_ptr`— Float64[n]: design volumetric flow per record (m³/s).
      - `sched_ptr`      — Float64[n]: schedule value per record (dimensionless).
      - `k`              — scalar clamp multiplier (e.g. 10.0 from
                            `_VENT_MAX_MODIFIER_MULTIPLIER`).
      - `out_sum_ptr`    — Float64[1]: receives the horizontal sum of the
                            clamped m_dot values.

    No-op body (sum = 0) when `n <= 0`.
    """
    if n <= 0:
        if out_sum_ptr != 0:
            UnsafePointer[Float64, MutAnyOrigin](
                unsafe_from_address=out_sum_ptr
            )[0] = 0.0
        return

    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_m_dot_ptr
    )
    var design_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_flow_ptr
    )
    var sched = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=sched_ptr
    )

    var total: Float64 = 0.0
    for i in range(n):
        var v = out[i]
        # Step 1: guard NaN / ±inf
        if _is_nonfinite(v):
            v = 0.0
        # Step 2: per-record upper cap = k * design_flow[i] * max(sched[i], 0)
        var s = sched[i]
        var s_pos = s if s > 0.0 else 0.0
        var cap = k * design_flow[i] * s_pos
        # Step 3: clamp to [0, cap]
        if v < 0.0:
            v = 0.0
        elif v > cap:
            v = cap
        out[i] = v
        total += v

    if out_sum_ptr != 0:
        UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=out_sum_ptr)[
            0
        ] = total

@export
def vent_modifier_batch(
    n: Int,
    design_flow_ptr: Int,
    schedule_value_ptr: Int,
    t_zone_ptr: Int,
    t_outdoor_ptr: Int,
    wind_speed_ptr: Int,
    a_ptr: Int,
    b_ptr: Int,
    c_ptr: Int,
    d_ptr: Int,
    out_m_dot_ptr: Int,
) -> None:
    """Batch polynomial-modifier × schedule × design-flow per zone.

    Arguments:
      - `n`                  — number of ventilation records.
      - `design_flow_ptr`    — Float64[n] design flow rate per record
                                (m³/s in the runtime, but the kernel is
                                unit-agnostic — it simply multiplies).
      - `schedule_value_ptr` — Float64[n] schedule fractional values.
      - `t_zone_ptr`         — Float64[n] zone air temperature (°C).
      - `t_outdoor_ptr`      — Float64[n] outdoor air temperature (°C).
      - `wind_speed_ptr`     — Float64[n] wind speed (m/s).
      - `a_ptr`              — Float64[n] constant-term coefficient A.
      - `b_ptr`              — Float64[n] |ΔT| linear coefficient B (1/K).
      - `c_ptr`              — Float64[n] wind linear coefficient C (s/m).
      - `d_ptr`              — Float64[n] wind quadratic coefficient D (s²/m²).
      - `out_m_dot_ptr`      — Float64[n] output buffer; receives
                                design_flow × schedule × modifier per record.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var design_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_flow_ptr
    )
    var schedule_value = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_value_ptr
    )
    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var t_outdoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_ptr
    )
    var wind_speed = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wind_speed_ptr
    )
    var a = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=a_ptr)
    var b = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=b_ptr)
    var c = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=c_ptr)
    var d = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=d_ptr)
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_m_dot_ptr
    )

    for i in range(n):
        var dt = t_zone[i] - t_outdoor[i]
        var dt_abs = -dt if dt < 0.0 else dt
        var v = wind_speed[i]
        var modifier = a[i] + b[i] * dt_abs + c[i] * v + d[i] * v * v
        out[i] = design_flow[i] * schedule_value[i] * modifier

@export
def vent_threshold_gate_batch(
    n: Int,
    t_zone_ptr: Int,
    t_outdoor_ptr: Int,
    wind_speed_ptr: Int,
    min_indoor_ptr: Int,
    max_indoor_ptr: Int,
    min_outdoor_ptr: Int,
    max_outdoor_ptr: Int,
    delta_t_min_ptr: Int,
    max_wind_ptr: Int,
    out_gate_ptr: Int,
) -> None:
    """Evaluate the AND-of-thresholds gate for `n` ventilation records.

    Arguments:
      - `n`               — number of ventilation records.
      - `t_zone_ptr`      — Float64[n] zone air temperature (°C).
      - `t_outdoor_ptr`   — Float64[n] outdoor air temperature (°C).
      - `wind_speed_ptr`  — Float64[n] wind speed (m/s).
      - `min_indoor_ptr`  — Float64[n] minimum indoor T threshold (°C);
                            use −FLT_MAX to disable.
      - `max_indoor_ptr`  — Float64[n] maximum indoor T threshold (°C);
                            use +FLT_MAX to disable.
      - `min_outdoor_ptr` — Float64[n] minimum outdoor T threshold (°C);
                            use −FLT_MAX to disable.
      - `max_outdoor_ptr` — Float64[n] maximum outdoor T threshold (°C);
                            use +FLT_MAX to disable.
      - `delta_t_min_ptr` — Float64[n] minimum (T_zone − T_outdoor) (K);
                            use −FLT_MAX to disable.
      - `max_wind_ptr`    — Float64[n] maximum wind speed (m/s);
                            use +FLT_MAX to disable.
      - `out_gate_ptr`    — Float64[n] output buffer; receives 1.0 when
                            all gates pass, 0.0 otherwise.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var t_outdoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_ptr
    )
    var wind_speed = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wind_speed_ptr
    )
    var min_indoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=min_indoor_ptr
    )
    var max_indoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=max_indoor_ptr
    )
    var min_outdoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=min_outdoor_ptr
    )
    var max_outdoor = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=max_outdoor_ptr
    )
    var delta_t_min = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=delta_t_min_ptr
    )
    var max_wind = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=max_wind_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_gate_ptr
    )

    for i in range(n):
        var tz = t_zone[i]
        var to = t_outdoor[i]
        var ws = wind_speed[i]
        var active = (
            tz >= min_indoor[i]
            and tz <= max_indoor[i]
            and to >= min_outdoor[i]
            and to <= max_outdoor[i]
            and (tz - to) >= delta_t_min[i]
            and ws <= max_wind[i]
        )
        out[i] = 1.0 if active else 0.0

from std.math import max, min

# Specific heat of water [J/(kg·K)]
comptime CP_WATER: Float64 = 4186.0
# Minimum mass flow rate guard [kg/s] — prevents division-by-zero
comptime MIN_MDOT: Float64 = 1e-9
# Minimum load guard [W] — prevents division-by-zero in f_econ
comptime MIN_Q: Float64 = 1.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def waterside_econ_available_batch(
    n: Int,
    t_chw_supply_ptr: Int,
    t_cw_supply_ptr: Int,
    dt_approach_ptr: Int,
    out_available_ptr: Int,
) -> None:
    """Evaluate waterside economizer availability for N chilled-water plants.

    The economizer is available when condenser water can cool chilled water
    with an approach temperature margin:

        available[i] = 1.0  if T_cw_supply[i] + dt_approach[i] < T_chw_supply[i]
                       0.0  otherwise

    A typical approach delta is 1–2 K.

    Arguments:
      - `n`                 — number of plant records.
      - `t_chw_supply_ptr`  — Float64[n] chilled-water supply temperature setpoint (°C).
      - `t_cw_supply_ptr`   — Float64[n] condenser-water supply temperature (°C).
      - `dt_approach_ptr`   — Float64[n] approach temperature delta (K).
      - `out_available_ptr` — Float64[n] output availability flag (1.0 or 0.0).

    No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var tchw = _ptr(t_chw_supply_ptr)
    var tcw = _ptr(t_cw_supply_ptr)
    var dt = _ptr(dt_approach_ptr)
    var out = _ptr(out_available_ptr)

    for i in range(n):
        if tcw[i] + dt[i] < tchw[i]:
            out[i] = 1.0
        else:
            out[i] = 0.0


@export
def waterside_econ_load_batch(
    n: Int,
    q_chw_load_ptr: Int,
    t_chw_supply_ptr: Int,
    t_chw_return_ptr: Int,
    t_cw_supply_ptr: Int,
    m_dot_cw_ptr: Int,
    out_q_econ_ptr: Int,
    out_f_econ_ptr: Int,
) -> None:
    """Compute waterside economizer heat transfer and load fraction for N plants.

    Maximum heat transfer is limited by condenser-water capacity:

        Q_cw_max[i]  = m_dot_cw[i] * CP_WATER * (T_chw_return[i] - T_cw_supply[i])
        Q_econ[i]    = min(Q_chw_load[i], max(0, Q_cw_max[i]))
        f_econ[i]    = Q_econ[i] / max(MIN_Q, Q_chw_load[i])
        f_econ[i]    = clamp(f_econ[i], 0.0, 1.0)

    m_dot_cw is clamped to [MIN_MDOT, inf] to prevent divide-by-zero.

    Arguments:
      - `n`                — number of plant records.
      - `q_chw_load_ptr`   — Float64[n] chilled-water cooling load (W).
      - `t_chw_supply_ptr` — Float64[n] chilled-water supply temperature setpoint (°C).
      - `t_chw_return_ptr` — Float64[n] chilled-water return temperature (°C).
      - `t_cw_supply_ptr`  — Float64[n] condenser-water supply temperature (°C).
      - `m_dot_cw_ptr`     — Float64[n] condenser-water mass flow rate (kg/s).
      - `out_q_econ_ptr`   — Float64[n] economizer heat transfer (W)   [output].
      - `out_f_econ_ptr`   — Float64[n] fraction of load met [-]        [output].

    No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var q_load = _ptr(q_chw_load_ptr)
    var t_chw_sup = _ptr(t_chw_supply_ptr)
    var t_chw_ret = _ptr(t_chw_return_ptr)
    var t_cw_sup = _ptr(t_cw_supply_ptr)
    var m_dot = _ptr(m_dot_cw_ptr)
    var out_q = _ptr(out_q_econ_ptr)
    var out_f = _ptr(out_f_econ_ptr)

    for i in range(n):
        # Clamp mass flow rate to avoid zero-capacity degenerate case
        var mdot = max(MIN_MDOT, m_dot[i])

        # Maximum heat the condenser water loop can absorb
        var q_cw_max = mdot * CP_WATER * (t_chw_ret[i] - t_cw_sup[i])

        # Economizer heat transfer: limited by CW capacity and the actual load
        var q_econ = min(q_load[i], max(0.0, q_cw_max))

        # Fraction of load met (guarded denominator)
        var denom = max(MIN_Q, q_load[i])
        var f = q_econ / denom

        # Clamp fraction to [0, 1]
        if f < 0.0:
            f = 0.0
        if f > 1.0:
            f = 1.0

        out_q[i] = q_econ
        out_f[i] = f

from std.math import tan, sin, cos


@always_inline
def _f64_ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _scalar_beam_transmittance(
    slat_angle_rad: Float64,
    solar_altitude: Float64,
    slat_width: Float64,
    slat_separation: Float64,
) -> Float64:
    """Geometric beam transmittance through horizontal blind slats (scalar).

    Args:
      slat_angle_rad  : slat tilt angle from horizontal (rad)
      solar_altitude  : solar altitude angle (rad); must be > 0.01 rad
      slat_width      : slat width (m)
      slat_separation : slat-to-slat separation (m)

    Returns transmittance in [0, 1].
    """
    # Guard low altitude to avoid division issues
    var alt = solar_altitude
    if alt < 0.01:
        alt = 0.01
    var tan_alt = tan(alt)

    # Effective slat spacing relative to width
    var s_eff = slat_separation * cos(slat_angle_rad)

    # Projected slat height in the plane perpendicular to beam
    var h_proj = slat_width * sin(slat_angle_rad)

    # Shadow fraction cast by one slat on the gap
    var denom = s_eff
    if denom < 1.0e-6:
        denom = 1.0e-6
    var f_shadow = h_proj * tan_alt / denom
    if f_shadow < 0.0:
        f_shadow = 0.0
    if f_shadow > 1.0:
        f_shadow = 1.0

    var tau = 1.0 - f_shadow
    if tau < 0.0:
        tau = 0.0
    return tau


@export
def blind_beam_transmittance_batch(
    n: Int,
    slat_angle_rad_ptr: Int,
    solar_altitude_ptr: Int,
    slat_width_ptr: Int,
    slat_separation_ptr: Int,
    out_tau_beam_ptr: Int,
) -> None:
    """Geometric beam transmittance through horizontal blind slats for N windows.

    For each window i:
        tan_alt    = tan(max(solar_altitude[i], 0.01))
        s_eff      = slat_separation[i] * cos(slat_angle_rad[i])
        h_proj     = slat_width[i] * sin(slat_angle_rad[i])
        f_shadow   = clamp(h_proj * tan_alt / max(s_eff, 1e-6), 0, 1)
        tau_beam   = max(0, 1 - f_shadow)

    Arguments:
      - n                  : number of windows
      - slat_angle_rad_ptr : float64[n] slat tilt from horizontal (rad)
      - solar_altitude_ptr : float64[n] solar altitude angle (rad)
      - slat_width_ptr     : float64[n] slat width (m)
      - slat_separation_ptr: float64[n] centre-to-centre slat spacing (m)
      - out_tau_beam_ptr   : float64[n] output beam transmittance in [0, 1]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var slat_angle = _f64_ptr(slat_angle_rad_ptr)
    var solar_alt = _f64_ptr(solar_altitude_ptr)
    var slat_w = _f64_ptr(slat_width_ptr)
    var slat_sep = _f64_ptr(slat_separation_ptr)
    var out_tau = _f64_ptr(out_tau_beam_ptr)

    for i in range(n):
        out_tau[i] = _scalar_beam_transmittance(
            slat_angle[i], solar_alt[i], slat_w[i], slat_sep[i]
        )


@export
def blind_diffuse_transmittance_batch(
    n: Int,
    slat_angle_rad_ptr: Int,
    slat_width_ptr: Int,
    slat_separation_ptr: Int,
    slat_reflectance_ptr: Int,
    out_tau_diff_ptr: Int,
) -> None:
    """Simplified isotropic diffuse transmittance through horizontal blind slats.

    For each window i (slat_angle clamped to [0, pi/2]):
        ratio   = slat_width[i] / max(slat_separation[i], 1e-9)
        tau_diff = (1 - ratio) * (1 + slat_reflectance[i] * ratio)
        tau_diff is clamped to [0, 1].

    Arguments:
      - n                    : number of windows
      - slat_angle_rad_ptr   : float64[n] slat tilt angle (rad) — clamped to [0, π/2]
      - slat_width_ptr       : float64[n] slat width (m)
      - slat_separation_ptr  : float64[n] centre-to-centre slat spacing (m)
      - slat_reflectance_ptr : float64[n] slat solar reflectance in [0, 1]
      - out_tau_diff_ptr     : float64[n] output diffuse transmittance in [0, 1]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var slat_angle = _f64_ptr(slat_angle_rad_ptr)
    var slat_w = _f64_ptr(slat_width_ptr)
    var slat_sep = _f64_ptr(slat_separation_ptr)
    var slat_refl = _f64_ptr(slat_reflectance_ptr)
    var out_tau = _f64_ptr(out_tau_diff_ptr)

    comptime PI_OVER_2: Float64 = 1.5707963267948966

    for i in range(n):
        # Clamp slat angle to [0, pi/2] — only the angle-independent diffuse
        # formula is used here; the angle argument is accepted for API symmetry
        # but the simplified isotropic formula does not directly depend on it.
        var ang = slat_angle[i]
        if ang < 0.0:
            ang = 0.0
        if ang > PI_OVER_2:
            ang = PI_OVER_2
        _ = ang  # suppress unused variable warning

        var sep = slat_sep[i]
        if sep < 1.0e-9:
            sep = 1.0e-9

        var ratio = slat_w[i] / sep
        var tau = (1.0 - ratio) * (1.0 + slat_refl[i] * ratio)

        if tau < 0.0:
            tau = 0.0
        if tau > 1.0:
            tau = 1.0

        out_tau[i] = tau


@export
def blind_adjusted_shgc_batch(
    n: Int,
    shgc_bare_ptr: Int,
    tau_beam_ptr: Int,
    tau_diff_ptr: Int,
    beam_fraction_ptr: Int,
    out_shgc_blind_ptr: Int,
) -> None:
    """Combined SHGC with blind in place of bare glazing.

    For each window i:
        SHGC_blind = (beam_fraction[i] * tau_beam[i]
                      + (1 - beam_fraction[i]) * tau_diff[i])
                     * shgc_bare[i]
        Clamped to [0, shgc_bare[i]].

    Arguments:
      - n                 : number of windows
      - shgc_bare_ptr     : float64[n] bare glazing SHGC in [0, 1]
      - tau_beam_ptr      : float64[n] blind beam transmittance in [0, 1]
      - tau_diff_ptr      : float64[n] blind diffuse transmittance in [0, 1]
      - beam_fraction_ptr : float64[n] fraction of incident solar that is beam
      - out_shgc_blind_ptr: float64[n] output combined SHGC in [0, shgc_bare]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var shgc_bare = _f64_ptr(shgc_bare_ptr)
    var tau_beam = _f64_ptr(tau_beam_ptr)
    var tau_diff = _f64_ptr(tau_diff_ptr)
    var beam_frac = _f64_ptr(beam_fraction_ptr)
    var out_shgc = _f64_ptr(out_shgc_blind_ptr)

    for i in range(n):
        var bf = beam_frac[i]
        var tau_eff = bf * tau_beam[i] + (1.0 - bf) * tau_diff[i]
        var shgc_b = shgc_bare[i]
        var shgc_bl = tau_eff * shgc_b

        if shgc_bl < 0.0:
            shgc_bl = 0.0
        if shgc_bl > shgc_b:
            shgc_bl = shgc_b

        out_shgc[i] = shgc_bl


@export
def blind_interior_slat_absorptance_batch(
    n: Int,
    slat_angle_rad_ptr: Int,
    tau_beam_ptr: Int,
    solar_absorptance_ptr: Int,
    area_ratio_ptr: Int,
    out_q_absorbed_ptr: Int,
) -> None:
    """Heat absorbed by blind slats per unit incident irradiance.

    For each window i:
        q_abs = (1 - tau_beam[i]) * solar_absorptance[i] * area_ratio[i]

    area_ratio is the ratio of blind slat area to window aperture area
    (typically ~1.0). The result is in W/m² when multiplied by incident
    irradiance G [W/m²] outside this kernel.

    Arguments:
      - n                    : number of windows
      - slat_angle_rad_ptr   : float64[n] slat angle (rad) — accepted for
                               symmetry but not used directly in this formula
      - tau_beam_ptr         : float64[n] beam transmittance through blind
      - solar_absorptance_ptr: float64[n] slat solar absorptance in [0, 1]
      - area_ratio_ptr       : float64[n] blind area / window area (~1.0)
      - out_q_absorbed_ptr   : float64[n] output absorbed fraction in [0, 1]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var slat_angle = _f64_ptr(slat_angle_rad_ptr)
    var tau_beam = _f64_ptr(tau_beam_ptr)
    var absorptance = _f64_ptr(solar_absorptance_ptr)
    var area_ratio = _f64_ptr(area_ratio_ptr)
    var out_q = _f64_ptr(out_q_absorbed_ptr)

    for i in range(n):
        _ = slat_angle[i]  # accepted for API symmetry
        var q = (1.0 - tau_beam[i]) * absorptance[i] * area_ratio[i]
        if q < 0.0:
            q = 0.0
        out_q[i] = q

@export
def window_simple_glazing_q_batch(
    n_windows: Int,
    u_factor_w_m2k_ptr: Int,
    shgc_ptr: Int,
    t_outdoor_ptr: Int,
    t_zone_ptr: Int,
    incident_solar_w_m2_ptr: Int,
    area_m2_ptr: Int,
    out_q_w_ptr: Int,
) -> None:
    """Steady-state SimpleGlazingSystem window heat flow for N windows.

    Computes per-window:
        q[i] = area[i] * (U[i] * (T_outdoor[i] - T_zone[i])
                          + SHGC[i] * incident_solar[i])

    Sign: q > 0 means net heat flow INTO the zone (conductive gain when
    T_outdoor > T_zone, plus the SHGC-weighted shortwave gain).

    All input pointers are raw int64 addresses of float64 buffers of
    length N. The kernel writes float64[N] to `out_q_w_ptr`.
    """
    var u = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=u_factor_w_m2k_ptr
    )
    var shgc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=shgc_ptr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_ptr
    )
    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_ptr
    )
    var inc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=incident_solar_w_m2_ptr
    )
    var area = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=area_m2_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_w_ptr
    )

    for i in range(n_windows):
        var q_cond = u[i] * (t_out[i] - t_zone[i])
        var q_solar = shgc[i] * inc[i]
        out[i] = area[i] * (q_cond + q_solar)

comptime EDGE_BAND_M: Float64 = 0.0635


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def window_frame_divider_h_batch(
    n: Int,
    a_glass_total_ptr: Int,
    perimeter_m_ptr: Int,
    frame_width_m_ptr: Int,
    divider_length_m_ptr: Int,
    divider_width_m_ptr: Int,
    u_center_ptr: Int,
    u_edge_ptr: Int,
    u_frame_ptr: Int,
    u_divider_ptr: Int,
    t_outdoor_ptr: Int,
    t_indoor_ptr: Int,
    out_q_through_w_ptr: Int,
    out_u_effective_ptr: Int,
) -> None:
    """Evaluate N WindowProperty:FrameAndDivider records in one FFI call.

    Writes:
      - `out_q_through_w[n]` — overall conducted heat through the window, W
        (positive: outdoor → indoor).
      - `out_u_effective[n]` — area-weighted effective U, W/(m²·K).

    No-op when `n <= 0`. When the total apparent area collapses to zero, both
    outputs are written as 0.0.
    """
    if n <= 0:
        return

    var a_glass = _ptr(a_glass_total_ptr)
    var perim = _ptr(perimeter_m_ptr)
    var fw = _ptr(frame_width_m_ptr)
    var dl = _ptr(divider_length_m_ptr)
    var dw = _ptr(divider_width_m_ptr)
    var u_c = _ptr(u_center_ptr)
    var u_e = _ptr(u_edge_ptr)
    var u_f = _ptr(u_frame_ptr)
    var u_d = _ptr(u_divider_ptr)
    var t_out = _ptr(t_outdoor_ptr)
    var t_in = _ptr(t_indoor_ptr)
    var out_q = _ptr(out_q_through_w_ptr)
    var out_u = _ptr(out_u_effective_ptr)

    for i in range(n):
        var a_g_total = a_glass[i]
        var a_edge = perim[i] * EDGE_BAND_M
        # Saturate the edge band at the actual glass area — a 2.5" band on a
        # very small lite would otherwise produce a negative center area.
        if a_edge > a_g_total:
            a_edge = a_g_total
        var a_center = a_g_total - a_edge
        var a_frame = perim[i] * fw[i]
        var a_div = dl[i] * dw[i]
        var a_total = a_g_total + a_frame + a_div

        if a_total > 0.0:
            var u_eff = (
                u_c[i] * a_center
                + u_e[i] * a_edge
                + u_f[i] * a_frame
                + u_d[i] * a_div
            ) / a_total
            out_u[i] = u_eff
            out_q[i] = u_eff * a_total * (t_out[i] - t_in[i])
        else:
            out_u[i] = 0.0
            out_q[i] = 0.0

comptime MAX_PANES: Int = 4
comptime MAX_BOUNCE_ITERS: Int = 64
comptime BOUNCE_TOL: Float64 = 1.0e-14


@always_inline
def _f64_ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _i32_ptr(addr: Int) -> UnsafePointer[Int32, MutAnyOrigin]:
    """Reconstruct a typed Int32 pointer from a raw int64 address."""
    return UnsafePointer[Int32, MutAnyOrigin](unsafe_from_address=addr)


@export
def window_layer_solar_batch(
    n: Int,
    n_panes_ptr: Int,
    tau_ptr: Int,
    alpha_ptr: Int,
    rho_front_ptr: Int,
    rho_back_ptr: Int,
    out_alpha_per_layer_ptr: Int,
    out_tau_total_ptr: Int,
) -> None:
    """Multi-bounce per-layer solar absorption for N multi-pane windows.

    For each window `i`, with `m = n_panes[i]` panes (1..MAX_PANES) and
    per-layer optical properties indexed `i*MAX_PANES + k` for k in [0, m):

        alpha_per_layer[i, k] = fraction of front-incident unit solar
                                absorbed by pane k (multi-bounce accounted)
        tau_total[i]          = fraction transmitted all the way through

    Pane k has:
        tau_k        — transmittance (symmetric front/back)
        alpha_k      — absorptance (informational; the kernel uses
                          1 - tau_k - rho_front_k and 1 - tau_k - rho_back_k
                          internally so the caller can supply either side's
                          alpha for sanity/reporting)
        rho_front_k  — front-face reflectance (light from gap k-1)
        rho_back_k   — back-face reflectance (light from gap k)

    Slots beyond `n_panes[i]` in `alpha_per_layer` are zeroed.

    Arguments:
      - `n`                        — number of windows.
      - `n_panes_ptr`              — int32[n] per-window pane count.
      - `tau_ptr`                  — float64[n*MAX_PANES] per-layer τ.
      - `alpha_ptr`                — float64[n*MAX_PANES] per-layer α (unused
                                       internally; kept for the documented
                                       FFI shape and possible future use).
      - `rho_front_ptr`            — float64[n*MAX_PANES] per-layer front ρ.
      - `rho_back_ptr`             — float64[n*MAX_PANES] per-layer back ρ.
      - `out_alpha_per_layer_ptr`  — float64[n*MAX_PANES] output, in place.
      - `out_tau_total_ptr`        — float64[n] output, in place.

    No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var n_panes = _i32_ptr(n_panes_ptr)
    var tau = _f64_ptr(tau_ptr)
    # alpha is read for completeness but absorption is computed from
    # 1 - tau - rho_side; suppress unused-arg by accepting the pointer.
    _ = alpha_ptr
    var rho_f = _f64_ptr(rho_front_ptr)
    var rho_b = _f64_ptr(rho_back_ptr)
    var out_alpha = _f64_ptr(out_alpha_per_layer_ptr)
    var out_tau = _f64_ptr(out_tau_total_ptr)

    for i in range(n):
        var base: Int = i * MAX_PANES
        var m: Int = Int(n_panes[i])
        if m < 1:
            m = 0
        if m > MAX_PANES:
            m = MAX_PANES

        # Zero output slots up front so unused panes report 0 absorption.
        comptime for k in range(MAX_PANES):
            out_alpha[base + k] = 0.0
        out_tau[i] = 0.0

        if m == 0:
            continue

        # Local per-pane arrays. Using InlineArray to keep everything on
        # the stack — MAX_PANES is comptime-known.
        var f_in = InlineArray[Float64, MAX_PANES](fill=0.0)
        var b_in = InlineArray[Float64, MAX_PANES](fill=0.0)
        var tau_k = InlineArray[Float64, MAX_PANES](fill=0.0)
        var rho_f_k = InlineArray[Float64, MAX_PANES](fill=0.0)
        var rho_b_k = InlineArray[Float64, MAX_PANES](fill=0.0)
        var abs_f_k = InlineArray[Float64, MAX_PANES](fill=0.0)
        var abs_b_k = InlineArray[Float64, MAX_PANES](fill=0.0)
        var absorbed = InlineArray[Float64, MAX_PANES](fill=0.0)

        # Load and derive per-side absorptances so they sum to unity:
        #   alpha_front_k = 1 - tau_k - rho_front_k
        #   alpha_back_k  = 1 - tau_k - rho_back_k
        # Negative values (from inconsistent caller input) are clamped to 0.
        for k in range(m):
            var tk = tau[base + k]
            var rfk = rho_f[base + k]
            var rbk = rho_b[base + k]
            tau_k[k] = tk
            rho_f_k[k] = rfk
            rho_b_k[k] = rbk
            var af = 1.0 - tk - rfk
            var ab = 1.0 - tk - rbk
            if af < 0.0:
                af = 0.0
            if ab < 0.0:
                ab = 0.0
            abs_f_k[k] = af
            abs_b_k[k] = ab

        # Seed: unit forward flux entering pane 0's front face.
        f_in[0] = 1.0
        var tau_total: Float64 = 0.0

        # Iterate bounce passes until residual flux falls below tolerance.
        for _it in range(MAX_BOUNCE_ITERS):
            var new_f = InlineArray[Float64, MAX_PANES](fill=0.0)
            var new_b = InlineArray[Float64, MAX_PANES](fill=0.0)
            var residual: Float64 = 0.0

            for k in range(m):
                var fk = f_in[k]
                var bk = b_in[k]
                if fk == 0.0 and bk == 0.0:
                    continue

                absorbed[k] += abs_f_k[k] * fk + abs_b_k[k] * bk

                # Forward-going flux exiting pane k toward gap k (next pane).
                var fwd_out = tau_k[k] * fk + rho_b_k[k] * bk
                # Backward-going flux exiting pane k toward gap k-1.
                var bwd_out = rho_f_k[k] * fk + tau_k[k] * bk

                if k + 1 < m:
                    new_f[k + 1] += fwd_out
                    residual += fwd_out
                else:
                    # Exits to inside — counts as overall transmittance.
                    tau_total += fwd_out

                if k > 0:
                    new_b[k - 1] += bwd_out
                    residual += bwd_out
                # If k == 0 the backward flux exits to outside (reflected
                # back to environment) and is not absorbed by any pane.

            for k in range(m):
                f_in[k] = new_f[k]
                b_in[k] = new_b[k]

            if residual < BOUNCE_TOL:
                break

        for k in range(m):
            out_alpha[base + k] = absorbed[k]
        out_tau[i] = tau_total

comptime CP_AIR: Float64 = 1.00484e3

# Default E+ polynomial coefficients (ZoneInfiltration:DesignFlowRate,
# ZoneVentilation:DesignFlowRate IDD defaults).
comptime POLY_A: Float64 = 1.0
comptime POLY_B: Float64 = 0.0
comptime POLY_C: Float64 = 0.0
comptime POLY_D: Float64 = 0.0


@always_inline
def _abs(x: Float64) -> Float64:
    return x if x >= 0.0 else -x


@always_inline
def _max0(x: Float64) -> Float64:
    return x if x > 0.0 else 0.0


@always_inline
def _polynomial_modifier(
    t_zone_c: Float64, t_outdoor_c: Float64, wind_speed_m_s: Float64
) -> Float64:
    """Mirrors `_polynomial_modifier` / `ZoneInfiltrationDesignFlowRate.modifier`.

    Returns `A + B*|T_zone - T_outdoor| + C*V + D*V^2` with `V` clamped to
    >= 0. With the E+ default coefficients (A=1, others=0) this collapses
    to a constant 1.0; the polynomial shape is preserved so a future
    extension can take per-record coefficients.
    """
    var dt = _abs(t_zone_c - t_outdoor_c)
    var v = _max0(wind_speed_m_s)
    return POLY_A + POLY_B * dt + POLY_C * v + POLY_D * v * v


@export
def zone_air_balance_step(
    t_zone_c_addr: Int,
    t_outdoor_c_addr: Int,
    wind_speed_m_s_addr: Int,
    infiltration_design_flow_rate_addr: Int,
    ventilation_design_flow_rate_addr: Int,
    afn_inflow_kg_s_addr: Int,
    rho_cp_addr: Int,
    m_dot_cp_out_addr: Int,
    q_air_const_out_addr: Int,
):
    """One per-zone air balance step.

    All inputs/outputs are raw int64 memory addresses of single `Float64`
    cells (or `Float64` buffers; only `[0]` is touched). The shim layer in
    `src/energyplus_mojo/kernels/zone_air_balance.py` passes
    `ctypes.byref(...)` for scalars.

    Outputs:
      - `m_dot_cp_out`   — total zone-air heat capacitance rate (W/K).
      - `q_air_const_out`— RHS load contribution (W); for the
                           Infiltration/Ventilation/AFN-only flavour this is
                           simply `m_dot_cp * T_outdoor`.
    """
    var t_zone = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_c_addr
    )[0]
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_c_addr
    )[0]
    var wind = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=wind_speed_m_s_addr
    )[0]
    var design_inf = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=infiltration_design_flow_rate_addr
    )[0]
    var design_vent = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=ventilation_design_flow_rate_addr
    )[0]
    var afn = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=afn_inflow_kg_s_addr
    )[0]
    var rho_cp = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=rho_cp_addr
    )[0]

    var modifier = _polynomial_modifier(t_zone, t_out, wind)

    # Infiltration + Ventilation: volumetric flow * rho_cp -> W/K.
    var q_vol = (design_inf + design_vent) * modifier
    var m_dot_cp_inf_vent = rho_cp * q_vol

    # AFN inflow is already in kg/s; convert to W/K with cp_air.
    var m_dot_cp_afn = CP_AIR * afn

    var m_dot_cp = m_dot_cp_inf_vent + m_dot_cp_afn
    var q_const = m_dot_cp * t_out

    var m_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=m_dot_cp_out_addr
    )
    var q_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=q_air_const_out_addr
    )
    m_out[0] = m_dot_cp
    q_out[0] = q_const

@export
def zone_baseboard_otc_batch(
    n: Int,
    cap_at_low_t_ptr: Int,
    low_t_ptr: Int,
    cap_at_high_t_ptr: Int,
    high_t_ptr: Int,
    t_outdoor_c_ptr: Int,
    availability_ptr: Int,
    frac_radiant_ptr: Int,
    out_q_actual_ptr: Int,
    out_q_radiant_ptr: Int,
    out_q_convect_ptr: Int,
):
    """Batched outdoor-temperature-controlled baseboard capacity evaluation.

    For each baseboard i in [0, n):

        slope     = (cap_hi − cap_lo) / max(t_hi − t_lo, 1e-12)
        cap       = clamp(cap_lo + slope * (t_out − t_lo), cap_lo, cap_hi)
        q_actual  = cap * availability
        q_radiant = q_actual * frac_radiant
        q_convect = q_actual * (1 − frac_radiant)

    Arguments:
      - `n`                — number of baseboard units in the batch.
      - `cap_at_low_t_ptr` — float64[N] capacity at low-temperature design
                             point (W).
      - `low_t_ptr`        — float64[N] low-temperature design point (°C).
      - `cap_at_high_t_ptr`— float64[N] capacity at high-temperature design
                             point (W).
      - `high_t_ptr`       — float64[N] high-temperature design point (°C).
      - `t_outdoor_c_ptr`  — float64[N] current outdoor dry-bulb temp (°C).
      - `availability_ptr` — float64[N] schedule value in [0, 1].
      - `frac_radiant_ptr` — float64[N] radiant fraction in [0, 1].
      - `out_q_actual_ptr` — float64[N] output: total heat to zone (W).
      - `out_q_radiant_ptr`— float64[N] output: radiant component (W).
      - `out_q_convect_ptr`— float64[N] output: convective component (W).

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var cap_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_at_low_t_ptr
    )
    var t_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=low_t_ptr
    )
    var cap_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=cap_at_high_t_ptr
    )
    var t_hi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=high_t_ptr
    )
    var t_out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_outdoor_c_ptr
    )
    var avail = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=availability_ptr
    )
    var frad = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=frac_radiant_ptr
    )
    var out_qa = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_actual_ptr
    )
    var out_qr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_radiant_ptr
    )
    var out_qc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_q_convect_ptr
    )

    # Minimum denominator guard — prevents divide-by-zero when the two
    # design-point temperatures are identical (zero-width band). In that
    # limit cap = cap_lo for all t_out, which the formula naturally gives
    # because slope → 0 when the denominator is floored.
    var eps: Float64 = 1.0e-12

    for i in range(n):
        var clo = cap_lo[i]
        var chi = cap_hi[i]
        var tlo = t_lo[i]
        var thi = t_hi[i]
        var tout = t_out[i]
        var av = avail[i]
        var fr = frad[i]

        # Clamp radiant fraction defensively to [0, 1].
        if fr < 0.0:
            fr = 0.0
        if fr > 1.0:
            fr = 1.0

        var dt_band = thi - tlo
        if dt_band < 0.0:
            dt_band = -dt_band
        if dt_band < eps:
            dt_band = eps

        # Linear interpolation between the two capacity design points.
        var slope = (chi - clo) / dt_band
        var cap_interp = clo + slope * (tout - tlo)

        # Clamp to the [cap_lo, cap_hi] range — handles both the below-low and
        # above-high extrapolation cases, and also the inverted-band case where
        # cap_lo > cap_hi (unusual but valid IDD data).
        var cap_clamped: Float64
        if clo <= chi:
            # Normal orientation: low cap at low temp, high cap at high temp.
            if cap_interp < clo:
                cap_clamped = clo
            elif cap_interp > chi:
                cap_clamped = chi
            else:
                cap_clamped = cap_interp
        else:
            # Inverted orientation: clamp to [chi, clo] instead.
            if cap_interp < chi:
                cap_clamped = chi
            elif cap_interp > clo:
                cap_clamped = clo
            else:
                cap_clamped = cap_interp

        # Apply availability schedule (0 when unit is off, 1 when on).
        var qa: Float64
        if av <= 0.0:
            qa = 0.0
        else:
            qa = cap_clamped * av

        out_qa[i] = qa
        out_qr[i] = qa * fr
        out_qc[i] = qa * (1.0 - fr)

@export
def zone_capacitance_mult_batch(
    n: Int,
    c_base_t_ptr: Int,
    c_base_w_ptr: Int,
    c_base_co2_ptr: Int,
    c_base_gc_ptr: Int,
    mult_t_ptr: Int,
    mult_w_ptr: Int,
    mult_co2_ptr: Int,
    mult_gc_ptr: Int,
    out_t_ptr: Int,
    out_w_ptr: Int,
    out_co2_ptr: Int,
    out_gc_ptr: Int,
) -> None:
    """Scale the four base air-balance capacitance terms per zone.

    For each zone `i` in `[0, n)`:

        out_t[i]   = c_base_t[i]   * mult_t[i]
        out_w[i]   = c_base_w[i]   * mult_w[i]
        out_co2[i] = c_base_co2[i] * mult_co2[i]
        out_gc[i]  = c_base_gc[i]  * mult_gc[i]

    All `*_ptr` arguments are raw int64 addresses of float64[n]
    C-contiguous arrays. The four `out_*_ptr` buffers are written in
    place. No-op when `n <= 0`.
    """
    if n <= 0:
        return

    var c_base_t = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_base_t_ptr
    )
    var c_base_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_base_w_ptr
    )
    var c_base_co2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_base_co2_ptr
    )
    var c_base_gc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=c_base_gc_ptr
    )
    var mult_t = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=mult_t_ptr
    )
    var mult_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=mult_w_ptr
    )
    var mult_co2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=mult_co2_ptr
    )
    var mult_gc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=mult_gc_ptr
    )
    var out_t = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_t_ptr
    )
    var out_w = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_w_ptr
    )
    var out_co2 = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_co2_ptr
    )
    var out_gc = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_gc_ptr
    )

    for i in range(n):
        out_t[i] = c_base_t[i] * mult_t[i]
        out_w[i] = c_base_w[i] * mult_w[i]
        out_co2[i] = c_base_co2[i] * mult_co2[i]
        out_gc[i] = c_base_gc[i] * mult_gc[i]

@export
def zone_cross_mixing_m_dot_batch(
    n_links: Int,
    design_flow_kg_s_ptr: Int,
    schedule_value_ptr: Int,
    t_zone_a_ptr: Int,
    t_zone_b_ptr: Int,
    t_delta_lo_ptr: Int,
    out_m_dot_ptr: Int,
) -> None:
    """Evaluate N `ZoneCrossMixing` link mass flows in a single FFI call.

    Arguments:
      - `n_links`              — N: number of cross-mixing links.
      - `design_flow_kg_s_ptr` — raw int64 address of `float64[N]`: per-link
                                  design mass-flow rate (kg/s).
      - `schedule_value_ptr`   — raw int64 address of `float64[N]`: per-link
                                  schedule fraction at the current timestep.
      - `t_zone_a_ptr`         — raw int64 address of `float64[N]`: zone-A
                                  air temperature (deg C).
      - `t_zone_b_ptr`         — raw int64 address of `float64[N]`: zone-B
                                  air temperature (deg C).
      - `t_delta_lo_ptr`       — raw int64 address of `float64[N]`: per-link
                                  `delta_temperature_c` gate threshold (deg C).
      - `out_m_dot_ptr`        — raw int64 address of `float64[N]` output:
                                  the realised bidirectional mass flow (kg/s),
                                  equal in magnitude in both directions.

    For each link i:

        dT       = T_a[i] - T_b[i]
        gate     = (abs(dT) >= delta_lo[i])  AND  (schedule[i] > 0.0)
        out[i]   = design_flow[i] * schedule[i]  if gate else 0.0

    Caller applies `+out[i]` as inflow to *both* zones (the energy term is
    `m_dot * c_p * (T_other - T_self)` for each side, so it's symmetric and
    no sign-flip is needed here).

    No-op when `n_links == 0`.
    """
    if n_links <= 0:
        return

    var design_flow = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=design_flow_kg_s_ptr
    )
    var schedule = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=schedule_value_ptr
    )
    var t_a = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_a_ptr
    )
    var t_b = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_zone_b_ptr
    )
    var delta_lo = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=t_delta_lo_ptr
    )
    var out = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_m_dot_ptr
    )

    for i in range(n_links):
        var sched = schedule[i]
        var dT = t_a[i] - t_b[i]
        var abs_dT = dT if dT >= 0.0 else -dT
        if sched > 0.0 and abs_dT >= delta_lo[i]:
            out[i] = design_flow[i] * sched
        else:
            out[i] = 0.0

comptime CP_AIR: Float64 = 1006.0
comptime MIN_MDOT: Float64 = 1e-6


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def window_ac_capacity_batch(
    n: Int,
    q_rated_ptr: Int,  # rated cooling capacity (W), float64[n]
    cap_ft_ptr: Int,  # capacity correction f(Twb, Tcond), float64[n]
    cap_fflow_ptr: Int,  # capacity correction f(flow_ratio), float64[n]
    out_q_total_ptr: Int,  # output: corrected total cooling capacity (W), float64[n]
) -> None:
    """Batch corrected total cooling capacity for N window AC units.

    For each of the N units (index i):

      q_total[i] = q_rated[i] * cap_ft[i] * cap_fflow[i]

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var qr = _ptr(q_rated_ptr)
    var cft = _ptr(cap_ft_ptr)
    var cff = _ptr(cap_fflow_ptr)
    var qt = _ptr(out_q_total_ptr)
    for i in range(n):
        qt[i] = qr[i] * cft[i] * cff[i]


@export
def window_ac_power_batch(
    n: Int,
    q_total_ptr: Int,  # corrected total cooling capacity (W), float64[n]
    eer_rated_ptr: Int,  # rated EER (W/W), float64[n]
    eir_ft_ptr: Int,  # EIR correction f(Twb, Tcond), float64[n]
    eir_fflow_ptr: Int,  # EIR correction f(flow_ratio), float64[n]
    out_w_elec_ptr: Int,  # output: electrical power draw (W), float64[n]
) -> None:
    """Batch electrical power draw for N window AC units.

    For each of the N units (index i):

      eir[i]    = (1 / max(0.1, eer_rated[i])) * eir_ft[i] * eir_fflow[i]
      w_elec[i] = q_total[i] * eir[i]

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var qt = _ptr(q_total_ptr)
    var er = _ptr(eer_rated_ptr)
    var eft = _ptr(eir_ft_ptr)
    var eff = _ptr(eir_fflow_ptr)
    var we = _ptr(out_w_elec_ptr)

    comptime EER_MIN: Float64 = 0.1

    for i in range(n):
        var eer = er[i]
        if eer < EER_MIN:
            eer = EER_MIN
        var eir = (1.0 / eer) * eft[i] * eff[i]
        we[i] = qt[i] * eir


@export
def window_ac_full_batch(
    n: Int,
    q_rated_ptr: Int,  # rated cooling capacity (W), float64[n]
    eer_rated_ptr: Int,  # rated EER (W/W), float64[n]
    cap_ft_ptr: Int,  # capacity correction f(Twb, Tcond), float64[n]
    cap_fflow_ptr: Int,  # capacity correction f(flow_ratio), float64[n]
    eir_ft_ptr: Int,  # EIR correction f(Twb, Tcond), float64[n]
    eir_fflow_ptr: Int,  # EIR correction f(flow_ratio), float64[n]
    shr_rated_ptr: Int,  # rated sensible heat ratio [-], float64[n]
    t_inlet_ptr: Int,  # zone inlet air temperature (°C), float64[n]
    m_dot_ptr: Int,  # supply air mass flow rate (kg/s), float64[n]
    out_q_total_ptr: Int,  # output: total cooling capacity (W), float64[n]
    out_q_sens_ptr: Int,  # output: sensible cooling (W), float64[n]
    out_q_lat_ptr: Int,  # output: latent cooling (W), float64[n]
    out_w_elec_ptr: Int,  # output: electrical power draw (W), float64[n]
    out_t_supply_ptr: Int,  # output: supply air temperature (°C), float64[n]
) -> None:
    """Batch full window AC calculation for N cooling-only units.

    For each of the N units (index i):

      q_total[i]   = q_rated[i] * cap_ft[i] * cap_fflow[i]
      eir[i]       = (1 / max(0.1, eer_rated[i])) * eir_ft[i] * eir_fflow[i]
      w_elec[i]    = q_total[i] * eir[i]
      shr[i]       = clamp(shr_rated[i], 0.0, 1.0)
      q_sens[i]    = q_total[i] * shr[i]
      q_lat[i]     = q_total[i] * (1 - shr[i])
      mdot[i]      = max(MIN_MDOT, m_dot[i])
      t_supply[i]  = t_inlet[i] - q_sens[i] / (mdot[i] * CP_AIR)

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var qr = _ptr(q_rated_ptr)
    var er = _ptr(eer_rated_ptr)
    var cft = _ptr(cap_ft_ptr)
    var cff = _ptr(cap_fflow_ptr)
    var eft = _ptr(eir_ft_ptr)
    var eff = _ptr(eir_fflow_ptr)
    var shr_r = _ptr(shr_rated_ptr)
    var tin = _ptr(t_inlet_ptr)
    var mdot = _ptr(m_dot_ptr)
    var oqt = _ptr(out_q_total_ptr)
    var oqs = _ptr(out_q_sens_ptr)
    var oql = _ptr(out_q_lat_ptr)
    var owe = _ptr(out_w_elec_ptr)
    var ots = _ptr(out_t_supply_ptr)

    comptime EER_MIN: Float64 = 0.1

    for i in range(n):
        var q_total = qr[i] * cft[i] * cff[i]

        var eer = er[i]
        if eer < EER_MIN:
            eer = EER_MIN
        var eir = (1.0 / eer) * eft[i] * eff[i]
        var w_elec = q_total * eir

        var shr = shr_r[i]
        if shr < 0.0:
            shr = 0.0
        if shr > 1.0:
            shr = 1.0

        var q_sens = q_total * shr
        var q_lat = q_total * (1.0 - shr)

        var md = mdot[i]
        if md < MIN_MDOT:
            md = MIN_MDOT
        var t_supply = tin[i] - q_sens / (md * CP_AIR)

        oqt[i] = q_total
        oqs[i] = q_sens
        oql[i] = q_lat
        owe[i] = w_elec
        ots[i] = t_supply

comptime CP_AIR: Float64 = 1006.0

# Guard against near-zero denominators in the implicit Euler solver.
comptime DENOM_EPS: Float64 = 1e-9


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def zone_infiltration_sensible_load_batch(
    n: Int,
    rho_ptr: Int,
    cp_ptr: Int,
    flow_m3s_ptr: Int,
    t_outdoor_ptr: Int,
    t_zone_ptr: Int,
    out_q_ptr: Int,
):
    """Sensible heat load from infiltration/ventilation for N zones.

    For each zone i:

        out[i] = rho[i] * cp[i] * flow_m3s[i] * (t_outdoor[i] - t_zone[i])

    Positive when outdoor temperature exceeds zone temperature (heat gain).

    Arguments:
      - `n`            — number of zones.
      - `rho_ptr`      — float64[N] zone-air density (kg/m³).
      - `cp_ptr`       — float64[N] specific heat (J/(kg·K)).
      - `flow_m3s_ptr` — float64[N] infiltration volumetric flow (m³/s).
      - `t_outdoor_ptr`— float64[N] outdoor dry-bulb temperature (°C).
      - `t_zone_ptr`   — float64[N] zone air temperature (°C).
      - `out_q_ptr`    — float64[N] output sensible load (W), written in place.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var rho = _ptr(rho_ptr)
    var cp = _ptr(cp_ptr)
    var flow = _ptr(flow_m3s_ptr)
    var t_out = _ptr(t_outdoor_ptr)
    var t_zone = _ptr(t_zone_ptr)
    var out_q = _ptr(out_q_ptr)

    for i in range(n):
        out_q[i] = rho[i] * cp[i] * flow[i] * (t_out[i] - t_zone[i])


@export
def zone_mixing_heat_transfer_batch(
    n: Int,
    m_dot_ptr: Int,
    cp_ptr: Int,
    t_source_ptr: Int,
    t_dest_ptr: Int,
    out_q_src_ptr: Int,
    out_q_dest_ptr: Int,
):
    """Heat transferred between zones via mixing for N links.

    For each link i:

        q = m_dot[i] * cp[i] * (t_source[i] - t_dest[i])
        out_q_src[i]  = -q   # heat removed from source zone
        out_q_dest[i] =  q   # heat added to destination zone

    Arguments:
      - `n`             — number of mixing links.
      - `m_dot_ptr`     — float64[N] mass flow rate (kg/s).
      - `cp_ptr`        — float64[N] specific heat (J/(kg·K)).
      - `t_source_ptr`  — float64[N] source zone temperature (°C).
      - `t_dest_ptr`    — float64[N] destination zone temperature (°C).
      - `out_q_src_ptr` — float64[N] heat removed from source zone (W),
                          written in place.
      - `out_q_dest_ptr`— float64[N] heat added to destination zone (W),
                          written in place.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var m_dot = _ptr(m_dot_ptr)
    var cp = _ptr(cp_ptr)
    var t_src = _ptr(t_source_ptr)
    var t_dst = _ptr(t_dest_ptr)
    var out_src = _ptr(out_q_src_ptr)
    var out_dst = _ptr(out_q_dest_ptr)

    for i in range(n):
        var q = m_dot[i] * cp[i] * (t_src[i] - t_dst[i])
        out_src[i] = -q
        out_dst[i] = q


@export
def zone_plenum_heat_transfer_batch(
    n: Int,
    m_dot_ptr: Int,
    cp_ptr: Int,
    t_supply_ptr: Int,
    t_plenum_ptr: Int,
    area_ptr: Int,
    u_ceiling_ptr: Int,
    t_zone_above_ptr: Int,
    out_q_hvac_ptr: Int,
    out_q_cond_ptr: Int,
):
    """Supply-air HVAC heat and ceiling-conduction heat for N plenum zones.

    For each plenum zone i:

        q_hvac = m_dot[i] * cp[i] * (t_supply[i] - t_plenum[i])
        q_cond = u_ceiling[i] * area[i] * (t_zone_above[i] - t_plenum[i])

    Arguments:
      - `n`               — number of plenum zones.
      - `m_dot_ptr`       — float64[N] HVAC supply mass flow (kg/s).
      - `cp_ptr`          — float64[N] specific heat (J/(kg·K)).
      - `t_supply_ptr`    — float64[N] supply air temperature (°C).
      - `t_plenum_ptr`    — float64[N] plenum air temperature (°C).
      - `area_ptr`        — float64[N] ceiling area (m²).
      - `u_ceiling_ptr`   — float64[N] ceiling U-value (W/(m²·K)).
      - `t_zone_above_ptr`— float64[N] temperature of zone above the
                            plenum ceiling (°C).
      - `out_q_hvac_ptr`  — float64[N] HVAC heat delivered (W), written
                            in place.
      - `out_q_cond_ptr`  — float64[N] ceiling conduction heat (W),
                            written in place.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var m_dot = _ptr(m_dot_ptr)
    var cp = _ptr(cp_ptr)
    var t_sup = _ptr(t_supply_ptr)
    var t_plen = _ptr(t_plenum_ptr)
    var area = _ptr(area_ptr)
    var u_ceil = _ptr(u_ceiling_ptr)
    var t_above = _ptr(t_zone_above_ptr)
    var out_hvac = _ptr(out_q_hvac_ptr)
    var out_cond = _ptr(out_q_cond_ptr)

    for i in range(n):
        out_hvac[i] = m_dot[i] * cp[i] * (t_sup[i] - t_plen[i])
        out_cond[i] = u_ceil[i] * area[i] * (t_above[i] - t_plen[i])


@export
def zone_air_energy_balance_batch(
    n: Int,
    q_const_ptr: Int,
    q_coef_ptr: Int,
    c_zone_ptr: Int,
    dt_s_ptr: Int,
    t_prev_ptr: Int,
    out_t_new_ptr: Int,
):
    """Implicit Euler zone air temperature update for N zones.

    Solves the linearized heat balance:

        C * (T_new - T_prev) / dt = Q_const + Q_coef * T_new

    Rearranging for T_new:

        T_new = (C/dt * T_prev + Q_const) / (C/dt - Q_coef)

    When the denominator magnitude is below DENOM_EPS the zone is
    thermally unconstrained and T_new falls back to T_prev.

    Arguments:
      - `n`           — number of zones.
      - `q_const_ptr` — float64[N] constant part of the RHS heat load (W).
      - `q_coef_ptr`  — float64[N] temperature-coefficient of the load
                        (W/K); must be <= 0 for a stable implicit step.
      - `c_zone_ptr`  — float64[N] zone air thermal capacitance (J/K).
      - `dt_s_ptr`    — float64[N] timestep duration (s).
      - `t_prev_ptr`  — float64[N] zone air temperature at the previous
                        timestep (°C).
      - `out_t_new_ptr`— float64[N] updated zone air temperature (°C),
                         written in place.

    No-op when `n == 0`.
    """
    if n <= 0:
        return

    var q_const = _ptr(q_const_ptr)
    var q_coef = _ptr(q_coef_ptr)
    var c_zone = _ptr(c_zone_ptr)
    var dt_s = _ptr(dt_s_ptr)
    var t_prev = _ptr(t_prev_ptr)
    var out = _ptr(out_t_new_ptr)

    for i in range(n):
        var cap_over_dt = c_zone[i] / dt_s[i]
        var denom = cap_over_dt - q_coef[i]
        if denom < DENOM_EPS:
            out[i] = t_prev[i]
        else:
            out[i] = (cap_over_dt * t_prev[i] + q_const[i]) / denom

@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    """Reconstruct a typed Float64 pointer from a raw int64 address."""
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@always_inline
def _is_nan(x: Float64) -> Bool:
    """NaN-only test: NaN is the one value not equal to itself."""
    return x != x


@export
def zone_mixing_m_dot_batch(
    n_links: Int,
    design_flow_kg_s_ptr: Int,
    schedule_value_ptr: Int,
    t_zone_ptr: Int,
    t_source_ptr: Int,
    t_min_indoor_ptr: Int,
    t_max_indoor_ptr: Int,
    t_delta_lo_ptr: Int,
    t_delta_hi_ptr: Int,
    out_m_dot_ptr: Int,
):
    """Per-link mass-flow rate for N ZoneMixing links in one FFI call.

    For each link i, computes:

        gate = 1.0 if all enabled constraints pass else 0.0
        out[i] = design_flow[i] * schedule[i] * gate

    A constraint is "enabled" when its bound array entry is not NaN.
    NaN therefore acts as the "no limit" sentinel — matching the way
    the IDD defaults map to Python `None` upstream.

    Arguments:
      - `n_links`              — N: number of ZoneMixing links.
      - `design_flow_kg_s_ptr` — float64[N] design mass-flow (kg/s).
      - `schedule_value_ptr`   — float64[N] schedule multiplier (0..1
                                  typically; not range-checked here).
      - `t_zone_ptr`           — float64[N] receiving-zone air temp (°C).
      - `t_source_ptr`         — float64[N] source-zone air temp (°C).
      - `t_min_indoor_ptr`     — float64[N] min indoor temp gate (°C);
                                  NaN disables the check.
      - `t_max_indoor_ptr`     — float64[N] max indoor temp gate (°C);
                                  NaN disables the check.
      - `t_delta_lo_ptr`       — float64[N] minimum (t_zone - t_source)
                                  ΔT (K); NaN disables the check.
      - `t_delta_hi_ptr`       — float64[N] maximum (t_zone - t_source)
                                  ΔT (K); NaN disables the check.
      - `out_m_dot_ptr`        — float64[N] output mass-flow (kg/s),
                                  written in place.

    No-op when `n_links == 0`.
    """
    if n_links <= 0:
        return

    var design = _ptr(design_flow_kg_s_ptr)
    var sched = _ptr(schedule_value_ptr)
    var t_zone = _ptr(t_zone_ptr)
    var t_src = _ptr(t_source_ptr)
    var t_lo_in = _ptr(t_min_indoor_ptr)
    var t_hi_in = _ptr(t_max_indoor_ptr)
    var dt_lo = _ptr(t_delta_lo_ptr)
    var dt_hi = _ptr(t_delta_hi_ptr)
    var out = _ptr(out_m_dot_ptr)

    for i in range(n_links):
        var tz = t_zone[i]
        var ts = t_src[i]
        var dt = tz - ts

        var ok: Bool = True

        var lo = t_lo_in[i]
        if not _is_nan(lo):
            if tz < lo:
                ok = False

        if ok:
            var hi = t_hi_in[i]
            if not _is_nan(hi):
                if tz > hi:
                    ok = False

        if ok:
            var dlo = dt_lo[i]
            if not _is_nan(dlo):
                if dt < dlo:
                    ok = False

        if ok:
            var dhi = dt_hi[i]
            if not _is_nan(dhi):
                if dt > dhi:
                    ok = False

        if ok:
            out[i] = design[i] * sched[i]
        else:
            out[i] = 0.0

from std.math import max, min

# Specific heat of air [J/(kg·K)]
comptime CP_AIR: Float64 = 1006.0
# Latent heat of vaporisation of water [J/kg]
comptime H_VAPORIZATION: Float64 = 2.5e6
# Maximum allowed mass flow rate [kg/s]
comptime MDOT_MAX: Float64 = 100.0
# Maximum allowed heat transfer magnitude [W]
comptime Q_MAX: Float64 = 1e7
# Temperature bounds [°C]
comptime T_MIN: Float64 = -50.0
comptime T_MAX: Float64 = 60.0
# Humidity ratio bounds [kg/kg]
comptime W_MIN: Float64 = 0.0
comptime W_MAX: Float64 = 0.05


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
    return UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=addr)


@export
def zone_mixing_sensible_batch(
    n: Int,
    m_dot_mix_ptr: Int,
    t_source_ptr: Int,
    t_receiving_ptr: Int,
    out_q_sens_ptr: Int,
) -> None:
    """Sensible heat transferred to a receiving zone from inter-zone air mixing.

    For each mixing object i:

        m_dot  = clamp(m_dot_mix[i], 0, MDOT_MAX)
        t_src  = clamp(t_source[i],    T_MIN, T_MAX)
        t_recv = clamp(t_receiving[i], T_MIN, T_MAX)
        q_sens = clamp(m_dot * CP_AIR * (t_src - t_recv), -Q_MAX, Q_MAX)

    A positive result means the receiving zone gains sensible heat (source zone
    is warmer). Negative means the receiving zone loses heat to the source.

    Parameters
    ----------
    n               : number of mixing objects
    m_dot_mix_ptr   : Float64[n]  mass flow rate of mixed air (kg/s)
    t_source_ptr    : Float64[n]  source zone dry-bulb temperature (°C)
    t_receiving_ptr : Float64[n]  receiving zone dry-bulb temperature (°C)
    out_q_sens_ptr  : Float64[n]  sensible heat gain to receiving zone (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var m_dot = _ptr(m_dot_mix_ptr)
    var t_src = _ptr(t_source_ptr)
    var t_recv = _ptr(t_receiving_ptr)
    var out_q = _ptr(out_q_sens_ptr)

    for i in range(n):
        var md = max(Float64(0.0), min(m_dot[i], MDOT_MAX))
        var ts = max(T_MIN, min(t_src[i], T_MAX))
        var tr = max(T_MIN, min(t_recv[i], T_MAX))
        var q = md * CP_AIR * (ts - tr)
        out_q[i] = max(-Q_MAX, min(q, Q_MAX))


@export
def zone_mixing_latent_batch(
    n: Int,
    m_dot_mix_ptr: Int,
    w_source_ptr: Int,
    w_receiving_ptr: Int,
    out_q_lat_ptr: Int,
) -> None:
    """Latent heat transferred to a receiving zone from inter-zone air mixing.

    For each mixing object i:

        m_dot  = clamp(m_dot_mix[i], 0, MDOT_MAX)
        w_src  = clamp(w_source[i],    W_MIN, W_MAX)
        w_recv = clamp(w_receiving[i], W_MIN, W_MAX)
        q_lat  = clamp(m_dot * H_VAPORIZATION * (w_src - w_recv), -Q_MAX, Q_MAX)

    A positive result means the receiving zone gains latent heat (source zone is
    more humid). Negative means the receiving zone loses moisture to the source.

    Parameters
    ----------
    n               : number of mixing objects
    m_dot_mix_ptr   : Float64[n]  mass flow rate of mixed air (kg/s)
    w_source_ptr    : Float64[n]  source zone humidity ratio (kg/kg)
    w_receiving_ptr : Float64[n]  receiving zone humidity ratio (kg/kg)
    out_q_lat_ptr   : Float64[n]  latent heat gain to receiving zone (W)  [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var m_dot = _ptr(m_dot_mix_ptr)
    var w_src = _ptr(w_source_ptr)
    var w_recv = _ptr(w_receiving_ptr)
    var out_q = _ptr(out_q_lat_ptr)

    for i in range(n):
        var md = max(Float64(0.0), min(m_dot[i], MDOT_MAX))
        var ws = max(W_MIN, min(w_src[i], W_MAX))
        var wr = max(W_MIN, min(w_recv[i], W_MAX))
        var q = md * H_VAPORIZATION * (ws - wr)
        out_q[i] = max(-Q_MAX, min(q, Q_MAX))

from std.math import max, min

# Minimum primary airflow guard [m³/s] — prevents division by zero.
comptime MIN_VPZ: Float64 = 1e-6
# Minimum zone air distribution effectiveness clamp [dimensionless].
comptime MIN_EZ: Float64 = 0.1
# Maximum zone air distribution effectiveness clamp [dimensionless].
comptime MAX_EZ: Float64 = 2.0


@always_inline
