@export
def zone_oa_fraction_batch(
    n: Int,
    voz_ptr: Int,
    vpz_ptr: Int,
    ez_ptr: Int,
    out_frac_ptr: Int,
) -> None:
    """Zone outdoor air fraction per ASHRAE 62.1 §6.2.

    For each zone i, computes:

        Vpz_i   = max(Vpz[i], MIN_VPZ)              # guard zero primary flow
        Ez_i    = clamp(Ez[i], MIN_EZ, MAX_EZ)       # valid effectiveness range
        frac[i] = clamp(Voz[i] / (Vpz_i * Ez_i), 0, 1)

    Arguments:
      - `n`            — number of zones in the batch.
      - `voz_ptr`      — float64[N] design zone outdoor air flow (m³/s).
      - `vpz_ptr`      — float64[N] primary (supply) airflow to zone (m³/s).
      - `ez_ptr`       — float64[N] zone air distribution effectiveness [-].
      - `out_frac_ptr` — float64[N] output zone OA fraction [0, 1].

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var voz = _ptr(voz_ptr)
    var vpz = _ptr(vpz_ptr)
    var ez = _ptr(ez_ptr)
    var out = _ptr(out_frac_ptr)
    for i in range(n):
        var vpz_i = max(vpz[i], MIN_VPZ)
        var ez_i = max(min(ez[i], MAX_EZ), MIN_EZ)
        var frac = voz[i] / (vpz_i * ez_i)
        out[i] = max(0.0, min(1.0, frac))


@export
def zone_primary_oa_flow_batch(
    n: Int,
    vpz_ptr: Int,
    frac_ptr: Int,
    out_flow_ptr: Int,
) -> None:
    """Actual outdoor air delivered from primary airflow and OA fraction.

    For each zone i, computes:

        actual_oa[i] = Vpz[i] * frac[i]

    This converts the dimensionless OA fraction back to a volumetric flow
    (m³/s) based on the zone primary supply airflow.

    Arguments:
      - `n`             — number of zones in the batch.
      - `vpz_ptr`       — float64[N] primary (supply) airflow to zone (m³/s).
      - `frac_ptr`      — float64[N] zone OA fraction [0, 1].
      - `out_flow_ptr`  — float64[N] output actual OA flow delivered (m³/s).

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var vpz = _ptr(vpz_ptr)
    var frac = _ptr(frac_ptr)
    var out = _ptr(out_flow_ptr)
    for i in range(n):
        out[i] = vpz[i] * frac[i]


@export
def zone_oa_full_batch(
    n: Int,
    voz_ptr: Int,
    vpz_ptr: Int,
    ez_ptr: Int,
    out_frac_ptr: Int,
    out_flow_ptr: Int,
) -> None:
    """Combined zone OA fraction and actual OA flow in a single pass.

    For each zone i, computes both:

        Vpz_i        = max(Vpz[i], MIN_VPZ)
        Ez_i         = clamp(Ez[i], MIN_EZ, MAX_EZ)
        frac[i]      = clamp(Voz[i] / (Vpz_i * Ez_i), 0, 1)
        actual_oa[i] = Vpz[i] * frac[i]

    Combines ``zone_oa_fraction_batch`` and ``zone_primary_oa_flow_batch``
    into one pass to avoid re-loading Vpz from memory twice when both
    outputs are needed.

    Arguments:
      - `n`             — number of zones in the batch.
      - `voz_ptr`       — float64[N] design zone outdoor air flow (m³/s).
      - `vpz_ptr`       — float64[N] primary (supply) airflow to zone (m³/s).
      - `ez_ptr`        — float64[N] zone air distribution effectiveness [-].
      - `out_frac_ptr`  — float64[N] output zone OA fraction [0, 1].
      - `out_flow_ptr`  — float64[N] output actual OA flow delivered (m³/s).

    No-op when n <= 0.
    """
    if n <= 0:
        return
    var voz = _ptr(voz_ptr)
    var vpz = _ptr(vpz_ptr)
    var ez = _ptr(ez_ptr)
    var out_frac = _ptr(out_frac_ptr)
    var out_flow = _ptr(out_flow_ptr)
    for i in range(n):
        var vpz_i = max(vpz[i], MIN_VPZ)
        var ez_i = max(min(ez[i], MAX_EZ), MIN_EZ)
        var frac = max(0.0, min(1.0, voz[i] / (vpz_i * ez_i)))
        out_frac[i] = frac
        out_flow[i] = vpz[i] * frac

from std.math import max, min

# Temperature clamping bounds [°C]
comptime T_MIN: Float64 = -20.0
comptime T_MAX: Float64 = 60.0
# Deviation clamping bounds [K]
comptime DEV_MIN: Float64 = -30.0
comptime DEV_MAX: Float64 = 30.0
# Reset signal clamping bounds
comptime SIGNAL_MIN: Float64 = -10.0
comptime SIGNAL_MAX: Float64 = 10.0
# Maximum proportional gain
comptime KP_MAX: Float64 = 5.0


@always_inline
def _ptr(addr: Int) -> UnsafePointer[Float64, MutAnyOrigin]:
