@export
def supply_temp_deviation_batch(
    n: Int,
    t_supply_actual_ptr: Int,
    t_supply_setpoint_ptr: Int,
    out_deviation_ptr: Int,
) -> None:
    """Compute supply air temperature deviation from setpoint for N zones.

    For each zone i:

        T_actual_clamped[i]   = clamp(T_supply_actual[i],   T_MIN, T_MAX)
        T_setpoint_clamped[i] = clamp(T_supply_setpoint[i], T_MIN, T_MAX)
        deviation[i]          = clamp(T_actual_clamped[i] - T_setpoint_clamped[i],
                                      DEV_MIN, DEV_MAX)

    Constants: T_MIN=-20.0, T_MAX=60.0, DEV_MIN=-30.0, DEV_MAX=30.0

    Parameters
    ----------
    n                    : number of zones
    t_supply_actual_ptr  : Float64[n]  actual supply air temperature (°C)
    t_supply_setpoint_ptr: Float64[n]  supply air temperature setpoint (°C)
    out_deviation_ptr    : Float64[n]  deviation output (K)  [written]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var t_actual = _ptr(t_supply_actual_ptr)
    var t_setpoint = _ptr(t_supply_setpoint_ptr)
    var out_dev = _ptr(out_deviation_ptr)

    for i in range(n):
        var ta = max(T_MIN, min(T_MAX, t_actual[i]))
        var ts = max(T_MIN, min(T_MAX, t_setpoint[i]))
        var dev = max(DEV_MIN, min(DEV_MAX, ta - ts))
        out_dev[i] = dev


@export
def supply_temp_reset_signal_batch(
    n: Int,
    deviation_ptr: Int,
    kp_ptr: Int,
    ki_state_ptr: Int,
    out_signal_ptr: Int,
    out_ki_state_new_ptr: Int,
) -> None:
    """Compute proportional reset signal from supply temperature deviation for N zones.

    Proportional-only reset signal (simplified PI without actual integration):

        kp_clamped[i]    = clamp(kp[i], 0.0, KP_MAX)
        dev_clamped[i]   = clamp(deviation[i], DEV_MIN, DEV_MAX)
        signal[i]        = clamp(kp_clamped[i] * dev_clamped[i],
                                 SIGNAL_MIN, SIGNAL_MAX)
        ki_state_new[i]  = ki_state[i]   (pass-through, reserved for future use)

    Constants: SIGNAL_MIN=-10.0, SIGNAL_MAX=10.0, KP_MAX=5.0,
               DEV_MIN=-30.0, DEV_MAX=30.0

    Parameters
    ----------
    n                   : number of zones
    deviation_ptr       : Float64[n]  supply temperature deviation (K)
    kp_ptr              : Float64[n]  proportional gain
    ki_state_ptr        : Float64[n]  integral state (pass-through, not used)
    out_signal_ptr      : Float64[n]  reset signal output           [written]
    out_ki_state_new_ptr: Float64[n]  updated integral state output [written]

    No-op when n <= 0.
    """
    if n <= 0:
        return

    var deviation = _ptr(deviation_ptr)
    var kp = _ptr(kp_ptr)
    var ki_state = _ptr(ki_state_ptr)
    var out_signal = _ptr(out_signal_ptr)
    var out_ki_state_new = _ptr(out_ki_state_new_ptr)

    for i in range(n):
        var kp_c = max(0.0, min(KP_MAX, kp[i]))
        var dev_c = max(DEV_MIN, min(DEV_MAX, deviation[i]))
        var sig = max(SIGNAL_MIN, min(SIGNAL_MAX, kp_c * dev_c))
        out_signal[i] = sig
        out_ki_state_new[i] = ki_state[i]

from std.math import log, exp, max, min

# Minimum luminance to guard against log(0) [cd/m²]
comptime LUM_MIN: Float64 = 1.0
# Minimum solid angle to guard against log(0) [sr]
comptime OMEGA_MIN: Float64 = 1e-6
# Minimum Guth position index (≥ 1 by definition)
comptime P_MIN: Float64 = 1.0
# DGI clamping bounds
comptime DGI_MIN: Float64 = 0.0
comptime DGI_MAX: Float64 = 40.0


@export
def window_daylight_glare_index_batch(
    n: Int,
    luminance_source_ptr: Int,
    omega_source_ptr: Int,
    background_luminance_ptr: Int,
    position_index_ptr: Int,
    out_dgi_ptr: Int,
) -> None:
    """Hopkinson/IES Daylight Glare Index for N window sources.

    For each window i:

        lum_s   = max(LUM_MIN,   luminance_source[i])
        omega_s = max(OMEGA_MIN, omega_source[i])
        lum_bg  = max(LUM_MIN,   background_luminance[i])
        p       = max(P_MIN,     position_index[i])

        dgi = 10 * log10(
                  0.478 * exp(1.6 * log(lum_s)) * exp(0.8 * log(omega_s))
                  / (lum_bg + 0.07 * exp(0.5 * log(omega_s)) * lum_s)
                  / p
              )
        dgi = clamp(dgi, DGI_MIN, DGI_MAX)

    Parameters
    ----------
    n                       : number of windows
    luminance_source_ptr    : Float64[n]  window / source luminance (cd/m²)
    omega_source_ptr        : Float64[n]  solid angle subtended by source (sr)
    background_luminance_ptr: Float64[n]  background luminance in field of view (cd/m²)
    position_index_ptr      : Float64[n]  Guth position index (dimensionless, ≥ 1)
    out_dgi_ptr             : Float64[n]  daylight glare index (0–40) [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var lum_src = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=luminance_source_ptr
    )
    var omega_src = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=omega_source_ptr
    )
    var lum_bg_ptr = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=background_luminance_ptr
    )
    var pos_idx = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=position_index_ptr
    )
    var out_dgi = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_dgi_ptr
    )

    # log10(x) = log(x) / log(10)
    var inv_log10: Float64 = 1.0 / log(10.0)

    for i in range(n):
        # ------------------------------------------------------------------
        # Step 1 — Apply guards to all inputs
        # ------------------------------------------------------------------
        var lum_s = max(LUM_MIN, lum_src[i])
        var omega_s = max(OMEGA_MIN, omega_src[i])
        var lum_bg = max(LUM_MIN, lum_bg_ptr[i])
        var p = max(P_MIN, pos_idx[i])

        # ------------------------------------------------------------------
        # Step 2 — Compute DGI via log/exp (avoids pow())
        # ------------------------------------------------------------------
        var log_lum_s = log(lum_s)
        var log_omega_s = log(omega_s)

        var numerator = 0.478 * exp(1.6 * log_lum_s) * exp(0.8 * log_omega_s)
        var denominator = (lum_bg + 0.07 * exp(0.5 * log_omega_s) * lum_s) * p

        var dgi = 10.0 * log(numerator / denominator) * inv_log10

        # ------------------------------------------------------------------
        # Step 3 — Clamp to valid DGI range
        # ------------------------------------------------------------------
        out_dgi[i] = max(DGI_MIN, min(DGI_MAX, dgi))


@export
def window_glare_comfort_rating_batch(
    n: Int,
    dgi_ptr: Int,
    out_rating_ptr: Int,
) -> None:
    """IES glare comfort rating (1–5) for N DGI values.

    Threshold mapping (Hopkinson/IES):
        DGI < 16  → 1.0  (imperceptible)
        DGI < 20  → 2.0  (just perceptible)
        DGI < 24  → 3.0  (just acceptable)
        DGI < 28  → 4.0  (just uncomfortable)
        DGI >= 28 → 5.0  (just intolerable)

    Parameters
    ----------
    n               : number of zones / DGI values
    dgi_ptr         : Float64[n]  daylight glare index values
    out_rating_ptr  : Float64[n]  comfort ratings (1.0–5.0) [output]

    No-op when n == 0.
    """
    if n <= 0:
        return

    var dgi = UnsafePointer[Float64, MutAnyOrigin](unsafe_from_address=dgi_ptr)
    var out_rating = UnsafePointer[Float64, MutAnyOrigin](
        unsafe_from_address=out_rating_ptr
    )

    for i in range(n):
        var d = dgi[i]
        var rating: Float64
        if d < 16.0:
            rating = 1.0
        elif d < 20.0:
            rating = 2.0
        elif d < 24.0:
            rating = 3.0
        elif d < 28.0:
            rating = 4.0
        else:
            rating = 5.0
        out_rating[i] = rating
